insert into scenarios (id, type, payload) values (
  'linear-keyboard',
  'daily',
  '{"id":"linear-keyboard","type":"daily","scheduled_date":"","company":"Linear","era":"2019 — early product","context":"Linear launched into a market dominated by Jira, Asana, and ClickUp — tools that competed on configurability. Linear''s first-screen experience pushed almost every action behind a keyboard shortcut, and the onboarding actively taught the shortcuts before showing the GUI.","prompt":"What is the most interesting choice the team made in this onboarding — and what''s the bet beneath it?","reveal_quote":"We optimized for the daily user, not the first-time user. The cost of a steep first day is a flat curve forever after. Most tools optimize the opposite way and never recover.","reveal_quote_attribution":"Karri Saarinen, Linear cofounder/CEO — paraphrased from public interviews","reveal_note":"The choice that''s easy to miss: Linear was willing to lose users in the first 10 minutes to win the next 10 years. Most PMs would file ''keyboard-shortcut-first onboarding'' under UX risk. The team filed it under positioning — the tool selects for users who want a tool that selects for them. The shortcut is the brand.","quote_type":"paraphrased","sources":[{"title":"Inside Linear: Building with taste, craft, and focus | Karri Saarinen","url":"https://www.lennysnewsletter.com/p/inside-linear-building-with-taste","publisher":"Lenny''s Newsletter","year":2024,"type":"podcast"},{"title":"How Linear became the new Jira","url":"https://www.runtime.news/how-linear-became-the-new-jira/","publisher":"Runtime","type":"article"}],"tags":{"industry":"devtools","region":"us","decade":"2010s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'stripe-docs',
  'daily',
  '{"id":"stripe-docs","type":"daily","scheduled_date":"","company":"Stripe","era":"2011 — launch","context":"Stripe''s launch homepage was almost entirely code. Seven lines of Ruby, copy-pasteable. No marketing video, no enterprise CTA, no testimonials. Just the integration. PayPal''s homepage at the time led with security badges and merchant logos.","prompt":"What is the most interesting choice the team made on this homepage — and who is it for?","reveal_quote":"The homepage isn''t for buyers. It''s for the developer who''s going to recommend us to their boss. If the developer can run the code in 30 seconds, the conversation upstream is already over.","reveal_quote_attribution":"Patrick Collison — paraphrased from early Stripe interviews and coverage","reveal_note":"The non-obvious move: Stripe inverted the buyer. Payments was sold as a procurement decision; Stripe rebuilt it as a developer decision. The homepage is a recruiting tool aimed at the person inside the customer who will champion you. Most B2B PMs design pages for the person who signs the contract — Stripe designed for the person who picks up the API key.","quote_type":"paraphrased","sources":[{"title":"How Two Brothers Turned Seven Lines of Code Into a $9.2 Billion Startup","url":"https://www.bloomberg.com/news/features/2017-08-01/how-two-brothers-turned-seven-lines-of-code-into-a-9-2-billion-startup","publisher":"Bloomberg","year":2017,"type":"article"},{"title":"How the Collison brothers turned ''seven lines of code'' into Stripe","url":"https://news.ycombinator.com/item?id=14902696","publisher":"Hacker News","year":2017,"type":"article"}],"tags":{"industry":"fintech","region":"us","decade":"2010s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'notion-ai-bundle',
  'daily',
  '{"id":"notion-ai-bundle","type":"daily","scheduled_date":"","company":"Notion","era":"2023 — Notion AI launch","context":"Notion launched AI in February 2023 as a $10/user/month add-on rather than baking it into the existing plans. Most competitors (including office-suite incumbents) folded AI into base pricing or made it free for paid users.","prompt":"What''s the most interesting choice in pricing AI as a separate add-on — and what does it tell you about how Notion sees the feature?","reveal_quote":"If we''d bundled it, we''d never know what people would pay for it. Pricing is a measurement instrument before it''s a revenue decision.","reveal_quote_attribution":"Notion product team — paraphrased from public commentary around the Notion AI launch","reveal_note":"What''s easy to miss: bundling looks like generosity but throws away the most valuable signal in a feature launch — willingness to pay. Notion treated the $10 line as a research instrument, not a paywall. The output isn''t ''is this feature profitable'' — it''s ''which users care enough to switch from free AI tools to a paid integrated one,'' which then tells you whether to invest more or retreat.","quote_type":"paraphrased","sources":[{"title":"Notion''s lost years, near collapse during Covid, the joy and suffering of building horizontal | Ivan Zhao","url":"https://www.lennysnewsletter.com/p/inside-notion-ivan-zhao","publisher":"Lenny''s Podcast","year":2025,"type":"podcast"},{"title":"Notion launches AI agent as it crosses $500 million in annual revenue","url":"https://www.cnbc.com/2025/09/18/notion-launches-ai-agent-as-it-crosses-500-million-in-annual-revenue.html","publisher":"CNBC","year":2025,"type":"article"}],"tags":{"industry":"productivity","region":"us","decade":"2020s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'dropbox-demo-video',
  'daily',
  '{"id":"dropbox-demo-video","type":"daily","scheduled_date":"","company":"Dropbox","era":"2008 — pre-private-beta","context":"Spring 2008. Dropbox has ~5,000 beta signups and a product that''s still flaky. Instead of polishing the funnel, Drew Houston posts a 4-minute screencast on Digg and Hacker News — a deadpan demo with deliberate inside-jokes aimed at the Digg and Reddit crowd. There''s no marketing copy, no testimonials. The video shows the product solving a problem the audience has, in their own language.","prompt":"Why ship a demo video to Digg before the product even works for the audience watching — and what is the video actually testing?","reveal_quote":"We weren''t trying to sell the product, we were trying to find out if the product was worth building. The video was the cheapest version of the product we could ship.","reveal_quote_attribution":"Drew Houston, Dropbox cofounder/CEO — paraphrased from Y Combinator and Lenny''s Newsletter retellings","reveal_note":"The non-obvious move: a demo video is a free MVP. The product wasn''t ready; the demand was the thing being tested. The result — the beta waitlist jumped from 5,000 to 75,000 overnight — wasn''t growth, it was a market signal. The lesson: when you can''t ship the product, ship the smallest artifact that lets the market vote with intent, not opinion. Surveys ask people what they want; a signup form asks them to pay (in attention) to want it.","quote_type":"paraphrased","sources":[{"title":"Behind the founder: Drew Houston (Dropbox)","url":"https://www.lennysnewsletter.com/p/behind-the-founder-drew-houston-dropbox","publisher":"Lenny''s Newsletter","type":"podcast"},{"title":"Drew Houston on the original Dropbox HN post","url":"https://x.com/drewhouston/status/1904948248961315299","publisher":"X / Drew Houston","type":"tweet"},{"title":"Dropbox doing things that don''t scale","url":"https://www.alexanderjarvis.com/dropbox-doing-things-that-dont-scale/","type":"blog"}],"tags":{"industry":"saas","region":"us","decade":"2000s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'airbnb-photographers',
  'daily',
  '{"id":"airbnb-photographers","type":"daily","scheduled_date":"","company":"Airbnb","era":"Summer 2009","context":"Airbnb has been stuck at about $200/week in revenue for eight months. The founders are running out of money. Looking at their worst-performing listings, they notice a pattern: the photos are terrible — flip-phone snapshots, blurry, badly lit. The ''obvious'' fix is to write better seller guides, or build a UI that nudges hosts to upload more photos. Instead Brian Chesky and Joe Gebbia fly to New York, borrow professional cameras, and personally photograph 24 hosts'' apartments. Revenue doubles to $400 that week.","prompt":"Why fly to New York and become photographers themselves, when there are obviously cheaper ways to fix listing photos?","reveal_quote":"Do things that don''t scale. Until you''ve talked to your users in their kitchens, you don''t actually know what''s broken. Software is the last step, not the first.","reveal_quote_attribution":"Paul Graham / Brian Chesky — paraphrased from ''Do Things That Don''t Scale'' (essay and retellings)","reveal_note":"The choice that''s easy to miss: founders solving the problem with their hands generates a kind of insight that a dashboard cannot. The photo issue was symptomatic — what they actually learned in those apartments was that hosts didn''t understand they were running a hospitality business, not renting a room. That insight became the entire ''Belong Anywhere'' brand and the design of the host onboarding. The lesson is not ''send photographers''; it''s that low-leverage in-person work in the early days is often the only way to find the high-leverage product changes.","quote_type":"paraphrased","sources":[{"title":"How Airbnb doubled revenue in one week","url":"https://strategybreakdowns.com/p/airbnb-photography","publisher":"Strategy Breakdowns","type":"article"},{"title":"Do Things That Don''t Scale","url":"http://paulgraham.com/ds.html","publisher":"Paul Graham","year":2013,"type":"blog"},{"title":"When Airbnb was young: the early years","url":"https://vator.tv/2016-02-26-when-airbnb-was-young-the-early-years/","publisher":"VatorNews","year":2016,"type":"article"}],"tags":{"industry":"marketplace","region":"us","decade":"2000s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'spotify-free-tier',
  'daily',
  '{"id":"spotify-free-tier","type":"daily","scheduled_date":"","company":"Spotify","era":"October 2008 — launch in Sweden/UK/France","context":"Spotify launches in 2008 with a free, ad-supported tier alongside a paid premium tier. The major labels hate it. Apple iTunes is selling tracks at 99¢. Pandora has built a US business on free streaming. Spotify''s wager is more aggressive: any song, on demand, free forever, with ads — and a frictionless upgrade to ad-free paid. Internally, the metric to beat is not Apple''s revenue per user. It''s the BitTorrent download.","prompt":"Why give the catalog away free, in a market where the dominant legal alternative is a 99¢ paid download — and who is Spotify actually competing with?","reveal_quote":"The enemy was not the free listener. The enemy was piracy. If we could give people something legal that was as easy as stealing, the free tier was a cost of doing business, not a revenue leak.","reveal_quote_attribution":"Daniel Ek, Spotify cofounder/CEO — paraphrased from public interviews","reveal_note":"The non-obvious move: Spotify mis-identified its competitor on purpose. iTunes was the surface comp; BitTorrent was the real one. Once you frame the competitor as piracy, every product decision flips — free is a feature not a leak, ads are a tax cheaper than theft, and the upgrade to premium is not ''pay for music'' but ''pay to remove the ad inserted to compete with free piracy.'' Most PMs benchmark to the visible competitor in the same category. The win was benchmarking to the invisible one.","quote_type":"paraphrased","sources":[{"title":"Spotify just turned 20 — how Daniel Ek built a $100B music empire","url":"https://fortune.com/article/spotify-20-year-anniversary-daniel-ek-founder-ceo-music-industry-least-powerful-person/","publisher":"Fortune","year":2026,"type":"article"},{"title":"Spotify — Wikipedia","url":"https://en.wikipedia.org/wiki/Spotify","type":"article"}],"tags":{"industry":"media","region":"eu","decade":"2000s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'slack-internal-tool',
  'daily',
  '{"id":"slack-internal-tool","type":"daily","scheduled_date":"","company":"Slack","era":"2013 — pivot from Glitch","context":"Tiny Speck spent three years and ~$17M of investor money building Glitch, a browser MMO. The game flops. The team has burned most of the runway. But they have one asset: an internal IRC-like chat tool they built so the distributed team could ship the game. The ''rational'' play is to wind the company down and return remaining capital. Instead Stewart Butterfield tells investors he''s pivoting to ship the internal tool — to other companies — as a product.","prompt":"What''s the non-obvious bet in pivoting to your own internal tool — and what makes the bet defensible against the dozens of existing chat products?","reveal_quote":"If our team can''t live without it, that''s the strongest demand signal you can have. The competition wasn''t HipChat, it was email. Email is what we replaced for ourselves; that''s what we''d replace for other teams.","reveal_quote_attribution":"Stewart Butterfield, Slack cofounder/CEO — paraphrased from launch-era interviews","reveal_note":"What''s easy to miss: ''dogfooding'' is usually framed as a quality lever — you use it, so you fix the bugs. Slack used it as a positioning lever. The product didn''t need to beat HipChat (a similar tool); it needed to beat email (a totally different category). Reframing the competitor turned a crowded chat market into an underserved replacement-for-email market, and made every email-style feature (threads, search, archives) a wedge instead of a parity feature. Internal tools that become products tend to inherit a positioning insight, not just a feature set.","quote_type":"paraphrased","sources":[{"title":"The Slack origin story","url":"https://techcrunch.com/2019/05/30/the-slack-origin-story/","publisher":"TechCrunch","year":2019,"type":"article"},{"title":"Stewart Butterfield''s letter: We Don''t Sell Saddles Here","url":"https://medium.com/@stewart/we-dont-sell-saddles-here-4c59524d650d","publisher":"Medium / Stewart Butterfield","year":2014,"type":"blog"}],"tags":{"industry":"saas","region":"us","decade":"2010s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'figma-browser-bet',
  'daily',
  '{"id":"figma-browser-bet","type":"daily","scheduled_date":"","company":"Figma","era":"2012–2016 — pre-launch","context":"Sketch dominates UI design in the early 2010s. The category-defining tool is a native macOS app — single user, single machine, .sketch files passed around in Slack. Dylan Field and Evan Wallace take ~$4M of seed money and spend four years building a design tool from scratch — in the browser, with multiplayer editing, before launching anything in public. Most designers hate the demos. Browsers are seen as too slow for serious creative work.","prompt":"Why bet four years on a browser-based, multiplayer design tool when designers — your users — are openly skeptical of the technology?","reveal_quote":"We bet on a thing nobody wanted yet because the thing they did want — desktop files, single-player — was structurally incapable of doing what design teams were going to need next.","reveal_quote_attribution":"Dylan Field, Figma cofounder/CEO — paraphrased from public interviews and the Index Ventures retrospective","reveal_note":"The choice that''s easy to miss: users tell you what they want from inside the current paradigm. Designers in 2013 wanted faster Sketch, not browser-Sketch. Figma''s bet was that the latent need — design as a team activity, with handoff baked in — would only become visible once the artifact (the .sketch file) was no longer the unit of work. The technology was a wedge for a workflow change, not a feature upgrade. Listening to users would have built a better single-player tool. Listening to the trajectory built the multiplayer one.","quote_type":"paraphrased","sources":[{"title":"Designers hated Figma at first, but grew to love it","url":"https://techcrunch.com/2023/06/25/figma-design-tool-history/","publisher":"TechCrunch","year":2023,"type":"article"},{"title":"Figma Goes Public: Thirteen Unforgettable Years with Dylan Field","url":"https://www.indexventures.com/perspectives/figma-goes-public-thirteen-unforgettable-years-with-dylan-field/","publisher":"Index Ventures","year":2025,"type":"blog"},{"title":"Design Meet the Internet | Figma Blog","url":"https://www.figma.com/blog/design-meet-the-internet/","publisher":"Figma","type":"blog"}],"tags":{"industry":"devtools","region":"us","decade":"2010s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'patagonia-dont-buy-this-jacket',
  'daily',
  '{"id":"patagonia-dont-buy-this-jacket","type":"daily","scheduled_date":"","company":"Patagonia","era":"November 25, 2011 — Black Friday","context":"Black Friday 2011. Patagonia takes out a full-page ad in the New York Times. Above a photo of their R2 fleece sits the headline: ''Don''t Buy This Jacket.'' The body copy details the water, carbon, and waste cost of producing the jacket — and asks the reader not to buy it unless they need it. Every other retailer that morning is running discount-driven ads. Patagonia is asking shoppers to spend less.","prompt":"What is Patagonia actually optimizing for with an ad that tells customers not to buy on the highest-volume shopping day of the year?","reveal_quote":"We''re in business to save our home planet. If our customers buy a jacket they don''t need, we''ve failed at the mission, even if we made the sale.","reveal_quote_attribution":"Yvon Chouinard, Patagonia founder — paraphrased from public commentary around the Common Threads Initiative","reveal_note":"What''s easy to miss: the ad is a selection filter, not a sales lever. It''s recruiting the customer who buys Patagonia because of what Patagonia means, not because the jacket is on sale. That customer cohort is far more profitable over a lifetime than the discount-hunter, even at lower per-purchase frequency. Patagonia''s sales reportedly rose ~30% in the year following the ad. The lesson isn''t ''reverse psychology''; it''s that brand statements that cost you the wrong customers earn you the right ones.","quote_type":"paraphrased","sources":[{"title":"Don''t Buy This Jacket, Black Friday and the New York Times","url":"https://www.patagonia.com/stories/planet/activism/dont-buy-this-jacket-black-friday-and-the-new-york-times/story-18615.html","publisher":"Patagonia","year":2011,"type":"blog"},{"title":"The Secret History of ''Don''t Buy This Jacket''","url":"https://davidgelles.substack.com/p/the-secret-history-of-dont-buy-this","publisher":"David Gelles","type":"blog"}],"tags":{"industry":"ecommerce","region":"us","decade":"2010s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'whatsapp-no-ads-note',
  'daily',
  '{"id":"whatsapp-no-ads-note","type":"daily","scheduled_date":"","company":"WhatsApp","era":"2012 — pre-Facebook acquisition","context":"WhatsApp at this point is the fastest-growing messenger in the world. Above Jan Koum''s desk hangs a note from cofounder Brian Acton: ''No Ads, No Games, No Gimmicks.'' The default monetization for a free messaging app — pre-2014 — is ads. WhatsApp instead charges $0.99 per year and writes a manifesto on the company blog explaining why advertising-as-business-model is a betrayal of the user. Investors are uneasy. Sequoia funds them only after explicitly agreeing not to push an ad model.","prompt":"What''s the non-obvious move in publicly rejecting ads and charging $0.99/yr instead — and what is the $1 actually doing?","reveal_quote":"When advertising is involved, you the user are the product being sold. We wanted the user to be the customer. Charging a dollar is the cheapest possible way to make that true.","reveal_quote_attribution":"Jan Koum, WhatsApp cofounder — from the official WhatsApp blog post ''Why we don''t sell ads'' (2012)","reveal_note":"The choice that''s easy to miss: the dollar isn''t revenue — it''s an alignment instrument. A free user has no contract with you; a paying user does. The $0.99/yr is too low to fund the company (Sequoia knew this), but it converts the relationship from attention-broker to service-provider. Acton''s note above the desk is a forcing function: every product decision is constrained by it. Most consumer apps say they care about users; WhatsApp engineered a constraint that made them care, structurally, by giving up the easy money. The Facebook acquisition in 2014 eventually broke this — and both founders left over it.","quote_type":"verbatim","sources":[{"title":"Why we don''t sell ads","url":"https://blog.whatsapp.com/why-we-don-t-sell-ads","publisher":"WhatsApp Blog","year":2012,"type":"blog"},{"title":"WhatsApp introduces ads, fulfilling a plan its cofounders hated so much they left over it","url":"https://fortune.com/2025/06/16/whatsapp-ads-cofounders-jan-koum-brian-acton/","publisher":"Fortune","year":2025,"type":"article"},{"title":"Jan Koum — Wikipedia","url":"https://en.wikipedia.org/wiki/Jan_Koum","type":"article"}],"tags":{"industry":"communication","region":"us","decade":"2010s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'wechat-super-app-2011',
  'daily',
  '{"id":"wechat-super-app-2011","type":"daily","scheduled_date":"","company":"Tencent (WeChat)","era":"January 2011 — launch","context":"October 2010. Allen Zhang, a Tencent VP running their email product, sends Pony Ma (Tencent CEO) a midnight email arguing that Kik (a US messaging app that just launched) is the start of an existential threat. Tencent already has QQ — China''s dominant desktop IM with hundreds of millions of users. Building a separate mobile messenger risks cannibalizing QQ. Pony Ma replies with four characters — ''马上就办'' (''do it now''). Zhang assembles a team of ten and ships WeChat in 60 days. Within two years it absorbs payments, mini-programs, social feed, and government services.","prompt":"Why ship a new mobile-first messenger that cannibalizes your dominant desktop product — and why so fast?","reveal_quote":"If we don''t kill QQ, someone else will. The only question is who eats the cannibalization — us or a competitor we can''t see yet.","reveal_quote_attribution":"Allen Zhang / Pony Ma — paraphrased from internal-Tencent retellings of the WeChat origin","reveal_note":"The non-obvious move: most incumbents protect the cash cow and let a small team build the next thing slowly. Tencent did the opposite — they let the new product cannibalize the old one openly, on the explicit assumption that platform shifts are won by whoever moves first, not by whoever transitions cleanly. The 60-day shipping window was not a feat of execution; it was a strategic claim that the cost of being late was orders of magnitude larger than the cost of imperfect launch. Most US companies in this scenario protect the existing revenue line. Tencent staked the company on the opposite bet.","quote_type":"paraphrased","sources":[{"title":"The Panic That Built WeChat''s $700 Billion Super-App","url":"https://howardyu.substack.com/p/the-panic-that-built-wechats-700","type":"blog"},{"title":"WeChat history: the rise of the super app","url":"https://chinatechscope.com/history-of-wechat/","publisher":"ChinaTechScope","type":"article"},{"title":"WeChat — Wikipedia","url":"https://en.wikipedia.org/wiki/WeChat","type":"article"}],"tags":{"industry":"consumer-social","region":"asia","decade":"2010s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'taobao-free-vs-ebay',
  'daily',
  '{"id":"taobao-free-vs-ebay","type":"daily","scheduled_date":"","company":"Alibaba (Taobao)","era":"May 2003 — China launch vs. eBay","context":"eBay has just acquired EachNet — China''s online auction leader — for $180M, giving it ~80% market share. eBay charges sellers per-listing and per-transaction fees, the model that built its US dominance. Alibaba launches Taobao, a competing C2C marketplace, with one promise: listings will be free for the first three years. eBay''s response in the press is dismissive: ''Free is not a business model.''","prompt":"What is Alibaba actually buying with three years of free listings — and what is eBay misreading about the China market?","reveal_quote":"eBay was selling a service to sellers. We were buying sellers themselves. Once we had the supply, the demand had nowhere else to go.","reveal_quote_attribution":"Jack Ma, Alibaba founder — paraphrased from public interviews around the Taobao vs. eBay era","reveal_note":"The choice that''s easy to miss: ''free'' wasn''t a price, it was a customer-acquisition channel that paid in supply. Sellers — not buyers — are the scarce side of a marketplace. eBay treated sellers as monetizable users; Taobao treated sellers as the product. The three-year window was long enough that any seller migration was sticky by the time fees would have applied. eBay''s market share dropped from ~80% to ~30% in two years; eBay China shut down in 2006. The deeper lesson: in two-sided markets, charging the wrong side first kills you slowly. Free-on-supply is rarely free — it''s investment.","quote_type":"paraphrased","sources":[{"title":"Taobao — Wikipedia","url":"https://en.wikipedia.org/wiki/Taobao","type":"article"},{"title":"How Alibaba took on eBay in China (and a few lessons for entrepreneurs)","url":"https://medium.com/@aishsinhaindia/how-alibaba-took-on-ebay-in-china-and-a-few-lessons-for-indian-entrepreneurs-4f5ae9709089","type":"blog"}],"tags":{"industry":"marketplace","region":"asia","decade":"2000s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'aws-s3-launch',
  'daily',
  '{"id":"aws-s3-launch","type":"daily","scheduled_date":"","company":"Amazon Web Services","era":"March 14, 2006 — S3 launch","context":"Amazon launches S3 — Simple Storage Service — with a one-paragraph announcement on the ''What''s New'' page. No keynote, no analyst briefing, no enterprise sales motion. Pricing is $0.15/GB-month with no minimums and no contracts. The target customer is a single developer with a credit card. Internally at Amazon, retail leadership had pushed for an enterprise-sales motion; Werner Vogels and the AWS team explicitly fought to keep S3 self-service, API-only, no human touch.","prompt":"Why launch infrastructure that enterprise CIOs would happily pay 100x for as a self-serve, credit-card, API-only product instead — and what is that pricing actually signaling?","reveal_quote":"If you make a developer fill out a form to talk to a salesperson, you''ve already lost. The developer is the buyer; the procurement department is downstream. Build for the developer first.","reveal_quote_attribution":"Werner Vogels, Amazon CTO — paraphrased from public AWS reinvent keynotes and interviews","reveal_note":"The non-obvious move: per-GB billing wasn''t pricing, it was a positioning signal. By making infrastructure consumable in the same dollar-units a college kid uses, AWS told the market ''this is for builders, not buyers.'' Enterprise sales motions actively repel the early-adopter developer. Amazon flipped the funnel — get the developer first, let them carry AWS into their company. Every infrastructure company that followed (Stripe, Twilio, Snowflake, Datadog) inherited this playbook. The price-per-GB was the marketing.","quote_type":"paraphrased","sources":[{"title":"Twenty years of Amazon S3 and building what''s next","url":"https://aws.amazon.com/blogs/aws/twenty-years-of-amazon-s3-and-building-whats-next/","publisher":"AWS News Blog","year":2026,"type":"blog"},{"title":"Amazon Web Services Launches","url":"https://press.aboutamazon.com/2006/3/amazon-web-services-launches","publisher":"Amazon Press Center","year":2006,"type":"press-release"},{"title":"Happy 15th Birthday Amazon S3","url":"https://www.allthingsdistributed.com/2021/03/happy-15th-birthday-amazon-s3.html","publisher":"Werner Vogels / All Things Distributed","year":2021,"type":"blog"}],"tags":{"industry":"infra","region":"us","decade":"2000s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'wise-hidden-fees',
  'daily',
  '{"id":"wise-hidden-fees","type":"daily","scheduled_date":"","company":"Wise (formerly TransferWise)","era":"2011–2015 — launch through brand-build","context":"Kristo Käärmann and Taavet Hinrikus are two Estonians living in London who lose hundreds of pounds in ''free'' bank transfers because of hidden FX markups. They build Wise (then TransferWise) with one rule for the brand: every marketing surface compares Wise''s real fee against the bank''s hidden fee, named and quantified. Naked PR stunts in 2014–2015 — including a London street-protest where Wise employees strip down to skin-tone underwear next to signs reading ''nothing to hide'' — push the campaign into mainstream press.","prompt":"Why anchor a financial-services brand on a single, aggressive enemy framing — ''banks lie about their fees'' — instead of leading with product features?","reveal_quote":"We didn''t build a remittance product. We built a transparency product that happens to move money. The fee comparison is the whole pitch — feature parity is table stakes.","reveal_quote_attribution":"Kristo Käärmann, Wise cofounder/CEO — paraphrased from public interviews around the #Nothing2Hide era","reveal_note":"What''s easy to miss: in a category dominated by trust (financial services), the standard play is to look more like a bank. Wise did the opposite — they framed every bank as the antagonist and made themselves the unauthorized truth-teller. That positioning came with a real cost: regulators, banking partners, and brand-conscious enterprises wouldn''t touch them. The benefit: zero ad-spend on customer acquisition through their first few million users, because every fee-comparison post functioned as both ad and protest. Brand-as-enemy-framing works when the enemy is structurally guilty and the consumer''s grievance is real. The competitor pays your customer-acquisition cost.","quote_type":"paraphrased","sources":[{"title":"Wise (company) — Wikipedia","url":"https://en.wikipedia.org/wiki/Wise_(company)","type":"article"},{"title":"4 FinTech Marketing Strategies: Wise''s Journey to Industry Disruption","url":"https://www.extole.com/blog/4-fintech-marketing-strategies-wises-journey-to-industry-disruption/","publisher":"Extole","type":"blog"},{"title":"Story of Wise: Wanted Fair Rates. Oops, Built a Fintech Empire.","url":"https://yourfintechstory.com/story-of-wise-wanted-fair-rates-oops-built-a-fintech-empire/","type":"blog"}],"tags":{"industry":"fintech","region":"uk","decade":"2010s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'twilio-pay-as-you-go',
  'daily',
  '{"id":"twilio-pay-as-you-go","type":"daily","scheduled_date":"","company":"Twilio","era":"2008–2010 — founding through SMS launch","context":"Telecom in 2008 sells the same product (SMS, voice routing) two ways: enterprise contracts with six-month negotiations and per-seat licensing, or low-quality consumer aggregator APIs. Twilio launches with a third model — pay-per-message, pay-per-minute, no contracts, no minimums, credit-card self-serve, full programmable API. A startup can send its first SMS within five minutes of signing up. Carriers and incumbent telecom-API competitors are skeptical that ''real'' customers will commit to a per-unit pricing model.","prompt":"Why launch programmable telecom with per-message pricing and zero contract friction, when the entire industry is built around long-term enterprise commitments?","reveal_quote":"We weren''t selling minutes; we were selling permission. Permission for a single developer at 2am to integrate global telecom without asking anyone. The pricing model was the permission.","reveal_quote_attribution":"Jeff Lawson, Twilio cofounder/CEO — paraphrased from ''Ask Your Developer'' and public interviews","reveal_note":"The choice that''s easy to miss: per-call pricing isn''t a discount, it''s a sales-cycle eliminator. Enterprise telecom contracts have a six-month sales cycle and a six-figure minimum. Twilio''s pricing made the sales cycle zero, but at the cost of giving up the high-margin commitments that fund the sales team. The implicit bet: if you serve 100,000 developers with no salespeople, the revenue per developer doesn''t matter — it''s the volume. Stripe, AWS, Sendgrid, Datadog all run this same playbook. The pricing page is the sales team.","quote_type":"paraphrased","sources":[{"title":"How Did Twilio Build a Multi-Billion Dollar Empire With Usage-Based Pricing?","url":"https://www.getmonetizely.com/articles/how-did-twilio-build-a-multi-billion-dollar-empire-with-usage-based-pricing","publisher":"Monetizely","type":"article"},{"title":"Twilio — Wikipedia","url":"https://en.wikipedia.org/wiki/Twilio","type":"article"}],"tags":{"industry":"devtools","region":"us","decade":"2000s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'zoom-40-minute-limit',
  'daily',
  '{"id":"zoom-40-minute-limit","type":"daily","scheduled_date":"","company":"Zoom","era":"2013 — launch","context":"Zoom launches its consumer-facing freemium tier in 2013 with a deliberate constraint: group meetings on the free plan are capped at 40 minutes. One-on-one meetings are unlimited. Competitor freemium products (Skype, GoToMeeting trials, Google Hangouts) impose limits on participant count or features, not duration. The cap is uncomfortable enough to feel during a single meeting, but small enough that solo users barely notice.","prompt":"Why pick 40 minutes as the friction point — and what is the limit actually testing?","reveal_quote":"The free tier is the demo, not the product. The 40 minutes is exactly long enough to show that Zoom works better than what they had before, and exactly short enough that they''ll feel it when it cuts off.","reveal_quote_attribution":"Eric Yuan, Zoom founder/CEO — paraphrased from public interviews about Zoom''s freemium model","reveal_note":"The non-obvious move: the constraint is engineered to fire at the moment of highest demonstrated value. At 40 minutes, the meeting has already produced something — momentum, decisions, a working relationship with the tool. Cutting off there forces the upgrade conversation when the willingness-to-pay is highest. Most freemium tiers cap based on what''s cheap to give away (storage, seats, features). Zoom capped based on what''s psychologically expensive to lose mid-task. The constraint is not a cost limit; it''s a conversion mechanism.","quote_type":"paraphrased","sources":[{"title":"Understanding time limits for Zoom Meetings","url":"https://support.zoom.com/hc/en/article?id=zm_kb&sysparm_article=KB0067966","publisher":"Zoom Support","type":"documentation"},{"title":"Zoom (software) — Wikipedia","url":"https://en.wikipedia.org/wiki/Zoom_(software)","type":"article"}],"tags":{"industry":"communication","region":"us","decade":"2010s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'apple-app-store-70-30',
  'daily',
  '{"id":"apple-app-store-70-30","type":"daily","scheduled_date":"","company":"Apple","era":"July 10, 2008 — App Store launch","context":"Steve Jobs spent the first year of the iPhone (2007) publicly refusing to allow third-party apps — he wanted Apple to control the experience end to end. A year later he reverses course. The App Store launches with 552 apps and a clean revenue split: developer keeps 70%, Apple takes 30%, free apps cost nothing to publish. Music labels by comparison still take ~50–70% of artist revenue. Standard retail software at the time keeps publishers/distributors closer to 60% of retail price.","prompt":"Why give 70% to third-party developers when Apple controls the only distribution channel — and what is the 30% buying for Apple?","reveal_quote":"The 30% isn''t rent. It''s the cost of running the only store in the world that comes pre-installed on every device in the customer''s pocket. The developer wouldn''t take 100% on a worse store; we don''t have to take more than 30% on the best one.","reveal_quote_attribution":"Steve Jobs — paraphrased from the 2008 iPhone SDK keynote and subsequent public statements","reveal_note":"What''s easy to miss: 70/30 was simultaneously generous to developers and an aggressive moat for Apple. Generous, because it inverted the publishing economics of every prior platform (retail software, music labels, magazine distribution). Aggressive, because it locked third-party developers into a single store with bundled payment, hosting, and distribution — pricing the alternatives (build your own store, sideloading, web apps) out of competitiveness for over a decade. The fight that''s now public (Epic v. Apple, EU DMA) is about who captured the surplus from that decision. The original move was a positioning statement: ''we will be the developer-friendly platform'' — which then turned into structural lock-in.","quote_type":"paraphrased","sources":[{"title":"Steve Jobs introduces the App Store — iPhone SDK Keynote","url":"https://www.youtube.com/watch?v=xo9cKe_Fch8","publisher":"Apple / YouTube","year":2008,"type":"video"},{"title":"Apple''s App Store changed the software world 17 years ago","url":"https://appleinsider.com/articles/23/01/15/apples-app-store-changed-the-software-world-15-years-ago","publisher":"AppleInsider","type":"article"},{"title":"The revolution Steve Jobs resisted: Apple''s App Store marks 10 years","url":"https://appleinsider.com/articles/18/07/10/the-revolution-steve-jobs-resisted-apples-app-store-marks-10-years-of-third-party-innovation","publisher":"AppleInsider","year":2018,"type":"article"}],"tags":{"industry":"saas","region":"us","decade":"2000s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'tesla-direct-sales',
  'daily',
  '{"id":"tesla-direct-sales","type":"daily","scheduled_date":"","company":"Tesla","era":"2012 — Model S launch and the franchise-law fights","context":"Every U.S. state has a franchise-dealer law that requires new cars to be sold through independent dealerships, not directly by manufacturers. The laws were written to protect dealers from manufacturer abuse and they make manufacturer-direct sales effectively illegal in most states. Tesla launches the Model S in 2012 selling exclusively direct — company-owned stores, no dealers. Multiple state dealer associations sue. Tesla cannot legally sell cars in several states for years; in Massachusetts, an early Tesla store is allowed to display vehicles but not actually take orders.","prompt":"Why refuse the legal, established distribution channel — and accept years of state-level lawsuits — when dealers would happily sell the car for you?","reveal_quote":"A dealer''s incentive is to sell whatever margin is highest today. Ours is to convert someone from a gas car for life. Those two incentives aren''t different by a little — they''re opposite. We couldn''t license that gap to anyone.","reveal_quote_attribution":"Elon Musk — paraphrased from Tesla''s public commentary on direct sales (2012–2015)","reveal_note":"The choice that''s easy to miss: distribution is part of the product. A dealership selling Teslas next to gas cars has an incentive to actively up-sell against the EV (gas cars carry higher service-revenue tails). Tesla couldn''t build a category-changing product through agents whose existing business depended on the category not changing. The legal fight wasn''t a side effect — it was a brand asset, because every state battle generated press that reinforced Tesla as the disruptor. The deeper lesson: when your product requires customer education that contradicts your distributor''s interests, the distributor is not neutral. Owning the channel is sometimes the only way to own the message.","quote_type":"paraphrased","sources":[{"title":"Tesla US dealership disputes — Wikipedia","url":"https://en.wikipedia.org/wiki/Tesla_US_dealership_disputes","type":"article"},{"title":"Tesla and the Car Dealers'' Lobby","url":"https://www.cato.org/regulation/summer-2014/tesla-car-dealers-lobby","publisher":"Cato Institute","year":2014,"type":"article"},{"title":"Tesla fought to sell cars direct to customers, and now more carmakers want in","url":"https://www.marketplace.org/story/2026/04/22/why-arent-more-cars-sold-directly-to-consumers","publisher":"Marketplace","year":2026,"type":"article"}],"tags":{"industry":"hardware","region":"us","decade":"2010s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'warby-parker-home-try-on',
  'daily',
  '{"id":"warby-parker-home-try-on","type":"daily","scheduled_date":"","company":"Warby Parker","era":"February 15, 2010 — launch","context":"Glasses are a $95+ purchase that buyers nearly universally want to try on. The industry assumption circa 2010 is that eyewear cannot meaningfully be sold online — return rates would crush the margin. Warby Parker launches with a counterintuitive feature: customers pick five frames on the website; Warby ships all five to their home for free; the customer keeps one (or none) and returns the rest at zero cost. Within 48 hours of GQ calling them ''the Netflix of eyewear,'' inventory is overwhelmed and the home-try-on program is paused.","prompt":"Why ship five physical frames to every customer who hasn''t paid yet — and what is Warby Parker buying with the shipping cost?","reveal_quote":"We weren''t selling glasses online. We were selling permission to try without committing. Once the box is in the customer''s hand, the conversion job is already done.","reveal_quote_attribution":"Neil Blumenthal, Warby Parker cofounder — paraphrased from public interviews on the home-try-on program","reveal_note":"The non-obvious move: the program isn''t a feature, it''s the entire customer-acquisition strategy. Five frames in the customer''s home for five days does three things in parallel: it eliminates the try-on objection (the only structural barrier to online eyewear), it triples the conversation about the brand (people show friends the frames at home), and it pre-qualifies the buyer (anyone willing to fill out the form is high-intent). The shipping cost is the marketing budget — a customer-acquisition channel that''s almost impossible for incumbents to copy without restructuring their entire returns infrastructure. The lesson: friction-removal at the highest-friction step in the funnel often pays for itself many times over, even when the unit cost looks crazy.","quote_type":"paraphrased","sources":[{"title":"The Mistake That Turned Warby Parker Into an Overnight Legend","url":"https://www.inc.com/magazine/201505/graham-winfrey/neil-blumenthal-icons-of-entrepreneurship.html","publisher":"Inc. Magazine","year":2015,"type":"article"},{"title":"Warby Parker — Wikipedia","url":"https://en.wikipedia.org/wiki/Warby_Parker","type":"article"},{"title":"Warby Parker''s Home Try-On: How a Logistical Experiment Became a Brand-Building Engine","url":"https://www.markhub24.com/post/warby-parker-s-home-try-on-how-a-logistical-experiment-became-a-brand-building-engine","type":"blog"}],"tags":{"industry":"ecommerce","region":"us","decade":"2010s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'chatgpt-plus-20-dollar',
  'daily',
  '{"id":"chatgpt-plus-20-dollar","type":"daily","scheduled_date":"","company":"OpenAI","era":"February 1, 2023 — 9 weeks after ChatGPT launch","context":"Nine weeks after ChatGPT becomes the fastest-growing consumer product in history, OpenAI is burning roughly $700K/day in inference costs serving the free tier. The ''safe'' move is to gate the product behind a paywall and protect the unit economics. Instead, OpenAI launches ChatGPT Plus at $20/month — but keeps the free tier fully open. Plus subscribers get faster responses, priority access during peak times, and first access to new features. The free model and the paid model run the same underlying GPT-3.5.","prompt":"Why launch a paid tier in 9 weeks while keeping the burning-money free tier fully open — and what is the $20/month actually buying for OpenAI strategically?","reveal_quote":"We''ll keep improving and maintaining the free version. We launched ChatGPT as a research preview so we could learn more about the system''s strengths and weaknesses. Your subscription helps support free access for as many people as possible.","reveal_quote_attribution":"OpenAI — official ChatGPT Plus announcement, February 1, 2023","reveal_note":"The non-obvious move: $20/mo is not the business model — it''s a willingness-to-pay probe and a heat-shield. A probe, because the conversion rate at $20/mo tells OpenAI what the actual price ceiling is for an LLM consumer product (a number nobody, including Google, knows yet). A heat-shield, because keeping the free tier open preserves the cultural moment that defines OpenAI as ''the AI for everyone'' — losing that to a paywall would have invited every competitor to claim the free-and-open mantle. Most companies in this position would have charged for the product and killed free access; OpenAI made the free tier the marketing budget and made the paid tier the measurement instrument. Same playbook Notion ran with AI in the same year.","quote_type":"verbatim","sources":[{"title":"Introducing ChatGPT Plus","url":"https://openai.com/index/chatgpt-plus/","publisher":"OpenAI","year":2023,"type":"blog"},{"title":"OpenAI launches ChatGPT Plus, starting at $20 per month","url":"https://techcrunch.com/2023/02/01/openai-launches-chatgpt-plus-starting-at-20-per-month/","publisher":"TechCrunch","year":2023,"type":"article"}],"tags":{"industry":"ai-tools","region":"us","decade":"2020s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'substack-10-percent-take',
  'daily',
  '{"id":"substack-10-percent-take","type":"daily","scheduled_date":"","company":"Substack","era":"October 2017 — launch","context":"Substack launches in 2017 with a single, unusually-specific business model: writers keep their own subscription lists, control their own content, and Substack takes a flat 10% of paid subscription revenue. No ads. No promotion fees. No discovery algorithm that sells writers'' attention. Founders explicitly reject the ad-supported model that defines every other publishing platform. The standard counter-pitch from competitors is that 10% is too low (ad networks make platforms way more) and that ''no algorithm'' will doom Substack to invisibility.","prompt":"Why pick a flat 10% take rate, refuse ads entirely, and ship without a discovery algorithm — and what kind of writer does this attract that ads-supported platforms can''t?","reveal_quote":"We wanted to align ourselves with the writer, not against them. If we made money on ads, the audience would belong to us, and the writer would be a tenant. Ten percent on subscriptions means the writer is the customer, not the inventory.","reveal_quote_attribution":"Chris Best / Hamish McKenzie, Substack cofounders — paraphrased from the Substack ''About'' page and founder commentary","reveal_note":"The choice that''s easy to miss: 10% is not a price, it''s a contract. Every ad-supported platform''s incentive is to capture and monetize the writer''s audience — engagement metrics, recommendations, the algorithm. Substack''s 10% structurally forecloses that play. If readers ever stop paying, Substack stops eating. That alignment is what attracts a specific kind of writer (often ex-staff at legacy publications) who has been burned by platforms that owned their audience. Substack''s biggest defection events — writers leaving Medium, leaving Twitter, leaving Patreon — happen not because Substack''s product is better, but because the take-rate model is structurally trust-building. The contract is the product.","quote_type":"paraphrased","sources":[{"title":"Substack — Wikipedia","url":"https://en.wikipedia.org/wiki/Substack","type":"article"},{"title":"Substack Business Breakdown & Founding Story","url":"https://research.contrary.com/company/substack","publisher":"Contrary Research","type":"article"}],"tags":{"industry":"media","region":"us","decade":"2010s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'duolingo-streak-design',
  'daily',
  '{"id":"duolingo-streak-design","type":"daily","scheduled_date":"","company":"Duolingo","era":"2012–2018 — building the green-owl retention engine","context":"Duolingo''s product is structurally hostile to retention. Adult language learning is famously easy to skip — there is rarely an external deadline. Every competitor in the early 2010s (Rosetta Stone, Babbel, Pimsleur) leans on long-form curriculum and infrequent reminders. Duolingo bets on a different surface: a cartoon owl that escalates increasingly emotional ''come back'' push notifications when the user''s streak (consecutive days of practice) is at risk. The escalation is deliberate: friendly nudge → guilt → outright threat (the infamous ''crying owl'').","prompt":"Why design the brand and the retention engine around a passive-aggressive cartoon owl — and what does the streak mechanic actually do to user psychology?","reveal_quote":"A push notification reminding you to study is easy to ignore. A push notification with a crying owl is harder. The owl is not a brand mascot — it is a retention instrument that happens to be cute.","reveal_quote_attribution":"Luis von Ahn, Duolingo cofounder/CEO — paraphrased from public interviews and Duolingo''s product blog","reveal_note":"The non-obvious move: Duolingo is not gamifying language learning, it is anthropomorphizing the cost of skipping it. Streaks plus the owl convert what was an internal motivation problem (I should study) into a social-debt problem (I am letting someone down). Most retention systems try to make the activity itself rewarding; Duolingo made stopping the activity emotionally expensive. The result is one of the most-studied retention curves in consumer software — 3x daily-return lift when streaks are active, materially higher 30-day retention than equivalent apps without character notifications. The lesson: in habit products, the most powerful lever is rarely the activity. It is the asymmetric cost the user feels when they don''t do it.","quote_type":"paraphrased","sources":[{"title":"Duolingo gamification explained","url":"https://www.strivecloud.io/blog/gamification-examples-boost-user-retention-duolingo","publisher":"StriveCloud","type":"article"},{"title":"Duolingo''s Customer Retention Strategy","url":"https://www.trypropel.ai/resources/duolingo-customer-retention-strategy","publisher":"Propel","type":"article"},{"title":"Duolingo Case Study: The Gamification of Learning","url":"https://www.uladshauchenka.com/p/duolingo-case-study-the-gamification","type":"blog"}],"tags":{"industry":"education","region":"us","decade":"2010s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'robinhood-zero-commission',
  'daily',
  '{"id":"robinhood-zero-commission","type":"daily","scheduled_date":"","company":"Robinhood","era":"2013–2015 — beta announcement through launch","context":"In 2013 every consumer brokerage charges per-trade commissions — Schwab ~$8.95, E*Trade ~$9.99, Ameritrade ~$9.99. The fee is the business model. Vlad Tenev and Baiju Bhatt, both ex-quant traders who built infrastructure for hedge funds, announce Robinhood with one promise: $0 commissions on every stock trade, forever. They have no obvious revenue model beyond ''order-flow rebates someday.'' The waitlist hits 1 million signups before the iOS app even ships.","prompt":"Why announce a brokerage with no commissions and no obvious revenue model — and what is the waitlist actually validating?","reveal_quote":"Charging commissions made sense in 1975 when phone-call execution cost real money. It made no sense in 2013 when execution is a fraction of a cent. The fee was a habit, not a cost. We charged what it cost — zero — and built the business around what the customers actually were: order flow, not commissions.","reveal_quote_attribution":"Vlad Tenev, Robinhood cofounder/CEO — paraphrased from public interviews about the founding thesis","reveal_note":"The non-obvious move: Robinhood didn''t disrupt commissions, they re-priced the customer. In the legacy model, the customer pays for execution. In Robinhood''s model, market makers (Citadel, Virtu) pay Robinhood for the order flow that retail customers generate. Retail trades are unusually valuable to market makers because they''re uninformed — they''re easier to fill profitably than institutional flow. Robinhood turned ''the customer pays the broker'' into ''the market maker pays the broker for access to the customer.'' Within five years every major brokerage cut commissions to $0 to match. The fee wasn''t a moat; it was an embarrassment that nobody had had the conviction to drop.","quote_type":"paraphrased","sources":[{"title":"Zero-commission Robinhood brokerage gets funding","url":"https://www.cnbc.com/2014/09/23/zero-commission-robinhood-brokerage-gets-funding.html","publisher":"CNBC","year":2014,"type":"article"},{"title":"Zero-Commission Stock Trading App RobinHood Kicks Off Private Beta","url":"https://techcrunch.com/2014/02/27/trade-stocks-free-robinhood/","publisher":"TechCrunch","year":2014,"type":"article"},{"title":"Trade Winds: The Rise, Reckoning and Reimagining of Vlad Tenev","url":"https://www.indexventures.com/perspectives/trade-winds-the-rise-reckoning-and-reimagining-of-vlad-tenev/","publisher":"Index Ventures","type":"blog"}],"tags":{"industry":"fintech","region":"us","decade":"2010s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'calendly-freemium',
  'daily',
  '{"id":"calendly-freemium","type":"daily","scheduled_date":"","company":"Calendly","era":"2013 — launch (Atlanta, GA)","context":"Tope Awotona, a Nigerian-American ex-EMC salesperson, has bootstrapped Calendly with ~$200K of his own savings after three failed startups. The original plan is to charge $8/month for the scheduling tool from day one. He runs out of money before building the billing system. So Calendly ships free — entirely free, no caps on bookings, no time-limited trial, no credit card. Awotona is not in Silicon Valley, has no VC, and is one of the few Black founders in B2B SaaS at the time.","prompt":"What does shipping fully-free ''by accident'' actually do for a scheduling product — and why is freemium structurally a better fit than a 7-day trial?","reveal_quote":"We didn''t choose freemium because we believed in it. We chose it because we couldn''t afford to build billing. By the time we could, freemium had already done the work of distributing the product — every meeting a Calendly user scheduled was a marketing email to a stranger.","reveal_quote_attribution":"Tope Awotona, Calendly founder/CEO — paraphrased from public interviews about the early years","reveal_note":"What''s easy to miss: scheduling is a viral product structurally because every booking page is a marketing surface aimed at someone who isn''t already a customer. A free tier doesn''t just acquire the user — it embeds them as a distributor. A 7-day trial puts a paywall between the user and the moment they show the product to someone new; freemium removes it. Awotona''s ''accident'' compounded for eight years before he raised institutional capital, by which point Calendly was profitable, ~$70M ARR, and the market norm had moved to freemium for scheduling. The lesson: in viral B2B products, the free user is the marketing budget. Trial-only kills the loop.","quote_type":"paraphrased","sources":[{"title":"Calendly — Wikipedia","url":"https://en.wikipedia.org/wiki/Calendly","type":"article"},{"title":"This Atlanta Founder''s Secret Weapon: Growing Up in Nigeria","url":"https://www.inc.com/magazine/201908/cameron-albert-deitch/tope-awotona-calendly-online-scheduling-venture-capital-nigeria-immigrant.html","publisher":"Inc. Magazine","year":2019,"type":"article"},{"title":"Calendly Founder Tope Awotona: Product-Market Fit After Failed Startups","url":"https://saasclub.io/podcast/calendlys-founder-finding-saas-success-after-failed-startups/","publisher":"SaaS Club Podcast","type":"podcast"}],"tags":{"industry":"productivity","region":"us","decade":"2010s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'discord-leave-gaming',
  'daily',
  '{"id":"discord-leave-gaming","type":"daily","scheduled_date":"","company":"Discord","era":"2017–2020 — the slow pivot away from ''chat for gamers''","context":"Discord launched in 2015 with a single positioning line: ''Chat for Gamers.'' Every product surface, every brand decision, every conference (PAX, TwitchCon) is downstream of the gaming wedge. By 2018 internal data shows ~30% of active servers are not about games — study groups, hobby communities, sneaker reselling, K-pop fandoms. The brand is now too small for the actual audience, but every gaming-centric user habit and revenue line (Nitro game perks, gaming integrations) depends on the original framing.","prompt":"Why is widening from ''chat for gamers'' to ''your place to talk'' so structurally risky — and what do you have to do to land the rebrand without losing the core user?","reveal_quote":"We didn''t change the product. We changed our description of who it was for. The product was already serving 100 million people who weren''t gamers; we just hadn''t given them permission to call it theirs.","reveal_quote_attribution":"Jason Citron, Discord cofounder/CEO — paraphrased from the 2020 brand-change blog post and subsequent interviews","reveal_note":"The non-obvious move: brand-broadening is usually framed as a marketing question. Discord treated it as a permissioning problem. The 30% non-gaming usage was already there; the brand framing kept that cohort feeling like they were ''using it wrong.'' Switching to ''Your place to talk'' in May 2020 (one month into COVID) gave non-gamers permission to invite their non-gamer friends. By end-2020 the platform had ~150M MAU with 78% non-gaming usage. The instinct most PMs have — ''don''t dilute the core'' — is correct when the core is small and the broader market is unproven. It is the wrong instinct when the broader audience is already inside the door but pretending not to be.","quote_type":"paraphrased","sources":[{"title":"About Discord | Our Mission and Story","url":"https://discord.com/company","publisher":"Discord","type":"blog"},{"title":"How Jason Citron Built Discord","url":"https://www.johncoogan.com/how-jason-citron-built-discord/","publisher":"John Coogan","type":"blog"},{"title":"Jason Citron and the Rise of Discord","url":"https://www.earlystartupdays.com/p/discord","type":"blog"}],"tags":{"industry":"communication","region":"us","decade":"2020s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'loom-chrome-extension',
  'daily',
  '{"id":"loom-chrome-extension","type":"daily","scheduled_date":"","company":"Loom","era":"June 2016 — first shipped product","context":"Joe Thomas and Vinay Hiremath want to build async video for work — short screen-and-face recordings that replace meetings and email threads. The ''real'' product would be a desktop app, native integrations, an enterprise sales motion. Instead, in June 2016 they ship a Chrome extension. Single-button record. Auto-uploads on stop. Returns a shareable link. No account required to view. Free. They post it on Product Hunt without much fanfare; 3,000 people sign up day one and they hit six months of prior signups in the next week.","prompt":"Why ship as a Chrome extension instead of a ''real'' app — and what is the extension actually selling that a desktop app wouldn''t?","reveal_quote":"The extension wasn''t a downgrade from a real product. It was the most honest version of what we were selling: send-a-video-in-30-seconds. Anything heavier would have hidden the value behind a download and an account.","reveal_quote_attribution":"Joe Thomas / Vinay Hiremath, Loom cofounders — paraphrased from the Loom growth retrospective","reveal_note":"What''s easy to miss: a Chrome extension is not a smaller product, it''s a different commitment from the user. Installing an extension is one click and zero setup. The user is recording within 60 seconds. Every video the user sends is then a one-click link to someone who has never heard of Loom — and watching that video doesn''t require installing anything. The product''s distribution surface is every Loom recipient. A desktop app would have moved that surface from ''every recipient'' to ''every user willing to install software,'' shrinking the loop by 10–100x. Loom sold to Atlassian for ~$975M in 2023; the Chrome extension launch was the entire wedge that made the rest of the business possible.","quote_type":"paraphrased","sources":[{"title":"Loom, Inc. — Wikipedia","url":"https://en.wikipedia.org/wiki/Loom,_Inc.","type":"article"},{"title":"How Loom went from Chrome extension to a $975M acquisition","url":"https://www.thezerotoone.co/p/screen-recorder-loom-975m-acquisition","type":"blog"},{"title":"Loom Growth Teardown: Chrome Extension to $975M Exit","url":"https://www.productgrowth.blog/p/loom-growth-teardown-975m-dollar-exit","publisher":"Product Growth","type":"blog"}],"tags":{"industry":"productivity","region":"us","decade":"2010s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'vercel-preview-deploys',
  'daily',
  '{"id":"vercel-preview-deploys","type":"daily","scheduled_date":"","company":"Vercel","era":"2016–2019 — ZEIT through the Vercel rebrand","context":"Hosting in 2016 is dominated by AWS (powerful but configuration-heavy), Heroku (developer-friendly but plateaued), Netlify (static sites). Frontend deploys still take 5–15 minutes of CI, and there''s no automatic preview URL per pull request unless the team builds the infrastructure themselves. Guillermo Rauch, ex-creator of Socket.IO and Next.js, ships ZEIT (later renamed Vercel) with one anchor feature: every `git push` to a branch automatically gets its own preview URL in under 30 seconds, with no configuration. Next.js itself remains entirely free, fully open source, never gated.","prompt":"Why couple a per-push preview URL to free, open-source Next.js — and what is the preview URL actually selling that ''deploys'' wasn''t?","reveal_quote":"A preview URL is not a deploy. It is the smallest possible unit of feedback in a software process. Once that loop is 30 seconds, the entire team''s behavior changes — designers, PMs, and execs become participants in code review without knowing it.","reveal_quote_attribution":"Guillermo Rauch, Vercel cofounder/CEO — paraphrased from his Figma Config 2023 keynote and public commentary","reveal_note":"The non-obvious move: Vercel didn''t sell hosting; they sold a collaboration primitive. Preview URLs let a designer, a PM, or an exec leave a comment on a real running version of the change — before merge, before staging, before QA. That collapses the feedback loop from days to minutes, which changes who is in the loop, not just how fast it moves. Free-and-open-source Next.js is the bait; Vercel-hosted preview deploys are the product. Customers can self-host Next.js forever and never pay — but the day they want one-click preview URLs across a team of 50, they upgrade. The lesson: developer tools that sell speed don''t actually sell speed — they sell a different organizational shape.","quote_type":"paraphrased","sources":[{"title":"Vercel Preview Deployments","url":"https://vercel.com/products/previews","publisher":"Vercel","type":"documentation"},{"title":"Iterating from design to deploy: Guillermo Rauch''s talk at Figma Config 2023","url":"https://vercel.com/blog/iterating-from-design-to-deploy","publisher":"Vercel","year":2023,"type":"talk"},{"title":"How Developer Experience Powered Vercel''s $200M+ Growth","url":"https://www.reo.dev/blog/how-developer-experience-powered-vercels-200m-growth","type":"article"}],"tags":{"industry":"devtools","region":"us","decade":"2010s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'notion-no-sales-team',
  'daily',
  '{"id":"notion-no-sales-team","type":"daily","scheduled_date":"","company":"Notion","era":"2016–2020 — pre-sales hire through $10M ARR","context":"Notion launches publicly in 2016 with three founders, no marketing budget, no VC on the board, and a deliberate decision: no sales team. The team stays under 10 people for years. Every growth lever is product-led — Product Hunt launches, template sharing, YouTube tutorials by community ambassadors, SEO. The ''right'' move per any GTM playbook in 2017–2018 is to hire enterprise AEs at $1M+ ACV to chase Confluence and Coda''s customer bases. Notion explicitly refuses, all the way to $10M ARR — at which point they hire their first salesperson.","prompt":"Why refuse a sales team for years while sitting inside an obviously enterprise-attractable category — and what does the absence of sales unlock?","reveal_quote":"Every salesperson we''d have hired before $10M ARR would have been a tax on the product. Sales motion shapes the product — the features you build, the things you say in the docs, the kinds of customers you optimize for. We kept the team small and the audience self-selecting until we knew which product we''d actually built.","reveal_quote_attribution":"Ivan Zhao, Notion cofounder/CEO — paraphrased from Lenny''s Podcast and Notion''s public commentary","reveal_note":"What''s easy to miss: a sales team is not just an expense, it is a directional force. Enterprise AEs at a sub-$10M-ARR company change which features ship (SAML, audit logs, admin consoles), which customer segments matter (large procurement-led IT vs. individual power users), and the brand (consumer-friendly vs. enterprise-friendly). Notion held off until the product had already been validated by individual users and small teams. By the time they hired sales, the product was opinionated enough that the sales motion served it rather than the other way around. Atlassian ran this same playbook 15 years earlier. Both companies ended up profitable from year one, with no growth-at-all-costs dilution, and with a culture that didn''t have to be reverse-engineered out of a sales-led DNA.","quote_type":"paraphrased","sources":[{"title":"Notion''s lost years, near collapse during Covid, the joy and suffering of building horizontal | Ivan Zhao","url":"https://www.lennysnewsletter.com/p/inside-notion-ivan-zhao","publisher":"Lenny''s Podcast","year":2025,"type":"podcast"},{"title":"Notion''s Product-Led Growth Strategy","url":"https://www.markhub24.com/post/notion-s-product-led-growth-strategy-engineering-a-10-billion-productivity-platform-without-a-sale","type":"article"},{"title":"How Notion Grows","url":"https://www.news.aakashg.com/p/how-notion-grows","publisher":"Aakash Gupta + Kartik Arora","type":"blog"}],"tags":{"industry":"productivity","region":"us","decade":"2010s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'spotify-discover-weekly-2015',
  'daily',
  '{"id":"spotify-discover-weekly-2015","type":"daily","scheduled_date":"","company":"Spotify","era":"July 2015 — Discover Weekly launch","context":"Spotify in 2015 is at ~100M monthly users. The product has every song, the social-import features, and the playlists. What it doesn''t have — that Pandora has — is the feeling that the service knows you. Pandora''s bet (one-station-from-one-seed-song) is structurally great at this. Spotify''s library-everything model is structurally bad at it. A small team led by Matthew Ogle ships Discover Weekly: every Monday, a personalized 30-track playlist labeled like a mixtape, built from collaborative filtering + audio analysis. No interactivity. No feedback button at launch. It just appears.","prompt":"Why ship personalization as a fixed weekly artifact rather than an interactive on-demand recommendation surface — and what is the Monday-morning timing doing?","reveal_quote":"The original brief was: make something that feels like your best friend made you a mixtape, labeled ''music you should check out,'' every single week. The mixtape framing was the entire product.","reveal_quote_attribution":"Matthew Ogle, Spotify Director of Discovery / Discover Weekly lead — paraphrased from public interviews and Spotify Engineering posts","reveal_note":"The choice that''s easy to miss: framing personalization as a ''gift'' (a curated weekly mixtape) rather than a ''tool'' (a tunable recommendation slider) created an emotional contract between user and product that interactive recommenders cannot match. The Monday-morning cadence converts the algorithm''s output into a ritual. The fixed 30-track length signals ''this was made for you with effort,'' even though it was made by software. Within 18 months, Discover Weekly was used by ~40M users and credited as the single biggest driver of Spotify''s retention advantage over Apple Music. The lesson: in ML-driven products, the wrapper (timing, framing, ritual) often does more work than the model.","quote_type":"paraphrased","sources":[{"title":"What made Discover Weekly one of our most successful feature launches to date?","url":"https://engineering.atspotify.com/2015/11/what-made-discover-weekly-one-of-our-most-successful-feature-launches-to-date","publisher":"Spotify Engineering","year":2015,"type":"blog"},{"title":"The Little Hack That Could: The Story of Spotify''s ''Discover Weekly'' Recommendation Engine","url":"https://spectrum.ieee.org/the-little-hack-that-could-the-story-of-spotifys-discover-weekly-recommendation-engine","publisher":"IEEE Spectrum","type":"article"},{"title":"Humans + Machines: A Look Behind the Playlists Powered by Spotify''s Algotorial Technology","url":"https://engineering.atspotify.com/2023/04/humans-machines-a-look-behind-spotifys-algotorial-playlists","publisher":"Spotify Engineering","year":2023,"type":"blog"}],"tags":{"industry":"media","region":"eu","decade":"2010s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'glossier-blog-first-brand',
  'daily',
  '{"id":"glossier-blog-first-brand","type":"daily","scheduled_date":"","company":"Glossier","era":"2010–2014 — Into the Gloss to brand launch","context":"In 2010, Emily Weiss — then a Vogue intern — starts a beauty blog called Into the Gloss. The blog''s signature is in-depth interviews with women about their actual skincare and makeup routines, in their own words. By 2013 it''s pulling ~10M monthly views. The traditional play for someone with that audience is brand partnerships and ad-supported scale. Weiss does the opposite: she spends four years using the blog as a research lab — DM-ing readers, asking what they actually want, what''s broken in their bathroom — then launches Glossier in October 2014 with four products, all named and designed against the most-frequent reader complaints.","prompt":"Why spend four years running a blog before shipping a single product — and what does the blog give Glossier that a great launch campaign couldn''t?","reveal_quote":"By the time we shipped Glossier, we''d had hundreds of thousands of conversations with women about what they actually wanted in their bathroom. The brand wasn''t a launch — it was the inevitable result of four years of listening at scale.","reveal_quote_attribution":"Emily Weiss, Glossier founder/CEO — paraphrased from the Business of Fashion profile and the Into the Gloss ''Introducing Glossier'' essay (2014)","reveal_note":"The non-obvious move: most consumer brands build the product, then build the audience. Glossier did the opposite — the audience generated the product specification. By the time the brand launched, every product had a built-in pre-customer audience that had effectively co-written the brief. The blog wasn''t a marketing channel; it was a four-year customer-discovery exercise that produced a brand whose first-day customer base felt like co-authors, not buyers. The lesson: when the audience is your design partner, the launch is a thank-you, not a pitch.","quote_type":"paraphrased","sources":[{"title":"Introducing Glossier","url":"https://intothegloss.com/2014/10/emily-weiss-glossier","publisher":"Into the Gloss","year":2014,"type":"blog"},{"title":"Emily Weiss: Blogger to Social Brand Builder","url":"https://www.businessoffashion.com/articles/beauty/glossier-into-the-gloss-beauty-brand-emily-weiss/","publisher":"Business of Fashion","type":"article"},{"title":"Glossier — Wikipedia","url":"https://en.wikipedia.org/wiki/Glossier","type":"article"}],"tags":{"industry":"ecommerce","region":"us","decade":"2010s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'allbirds-single-sku-launch',
  'daily',
  '{"id":"allbirds-single-sku-launch","type":"daily","scheduled_date":"","company":"Allbirds","era":"March 2016 — Wool Runner launch","context":"Allbirds launches with one shoe. One silhouette, one material (merino wool), a handful of muted colors. No men''s vs. women''s variations beyond sizing. The Wool Runner stays the only Allbirds product for 14 months — no seasonal drops, no expansions, no collaborations. Tim Brown, the founder and ex-pro-soccer player, has a background in design and explicitly rejects the standard footwear-launch playbook of multiple SKUs to A/B test demand.","prompt":"Why launch a footwear brand with one shoe and refuse to expand for over a year — and what does the single-SKU constraint actually enable?","reveal_quote":"The discipline of one shoe meant we never explained ourselves badly. Every conversation about Allbirds was about the same product, the same materials, the same story. You can''t muddle a single sentence.","reveal_quote_attribution":"Tim Brown, Allbirds cofounder — paraphrased from public commentary on the early Allbirds positioning","reveal_note":"The choice that''s easy to miss: a single SKU is a positioning instrument, not a manufacturing constraint. With one product, every press article, every customer review, every social post reinforces the same association — ''comfort, wool, sustainable, simple.'' Adding a second SKU pre-launch dilutes that association even before it''s been established. Allbirds'' growth in the first 18 months was driven almost entirely by word-of-mouth, which only works if the conversation is about one specific thing. Casper, launched two years earlier, ran the same playbook with mattresses. The deeper lesson: in crowded categories with a strong incumbent (Nike, Tempur-Pedic), single-product launches force category-redefinition rather than feature-comparison.","quote_type":"paraphrased","sources":[{"title":"Our Story","url":"https://www.allbirds.com/pages/our-story","publisher":"Allbirds","type":"blog"},{"title":"Allbirds — Wikipedia","url":"https://en.wikipedia.org/wiki/Allbirds","type":"article"},{"title":"How Allbirds Co-Founder Tim Brown Went from Pro Sports to Sustainable Shoes","url":"https://canadianbusiness.com/people/allbirds-co-founder-ceo-tim-brown/","publisher":"Canadian Business","type":"article"}],"tags":{"industry":"ecommerce","region":"anz","decade":"2010s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'casper-bed-in-a-box',
  'daily',
  '{"id":"casper-bed-in-a-box","type":"daily","scheduled_date":"","company":"Casper","era":"April 22, 2014 — launch","context":"Mattresses in 2014 are sold one way: a salesperson commission-driven floor at a Mattress Firm or Sleepy''s, with 100+ SKUs, opaque pricing, and 200–400% markups. The industry''s structural moat is that mattresses are too big to ship cheaply via UPS. Casper''s founders compress a queen-size memory foam mattress into a box about the size of a small filing cabinet and ship it via standard parcel for ~$50. One product (originally), one price ($850 for a queen), free shipping, 100-day return window. They explicitly position the brand as ''the Warby Parker of mattresses.''","prompt":"Why is shipping a $850 mattress in a small box the entire business model — and what does the compressed-shipping unlock that prior DTC mattress attempts didn''t have?","reveal_quote":"The shoebox-sized package wasn''t a marketing trick. It was the only thing that made the mattress economy a parcel economy. Once shipping is a UPS label instead of a flatbed truck with two people, the entire showroom model becomes a tax the customer pays to a middleman who isn''t necessary.","reveal_quote_attribution":"Philip Krim, Casper cofounder/CEO — paraphrased from public interviews about the founding insight","reveal_note":"What''s easy to miss: ''bed in a box'' is not a feature, it is the unlock that lets you skip the retail layer. Without compression, mattresses require freight shipping, which kills the unit economics of a DTC model. Compression turns mattress retail from a high-touch in-store experience into a one-click checkout. The 100-day trial isn''t a generous return policy; it''s the substitute for the in-store ''try it'' that the box replaces. Casper sold its entire first six-week inventory in a single day and was on track to hit a $1.8M year-one projection in 60 days. Within five years, every mattress incumbent (Tempur-Pedic, Serta) had a competing bed-in-a-box brand. The product innovation was logistics, dressed as a consumer story.","quote_type":"paraphrased","sources":[{"title":"Casper: How a Mattress in a Box Became a Breakout Brand","url":"https://fortune.com/2017/08/23/casper-mattress-philip-krim/","publisher":"Fortune","year":2017,"type":"article"},{"title":"Casper Sleep — Wikipedia","url":"https://en.wikipedia.org/wiki/Casper_Sleep","type":"article"},{"title":"CEO of ''bed in a box'' start-up Casper on going from zero to a $500 million+ company in 4 years","url":"https://www.cnbc.com/2017/06/14/casper-ceo-philip-krim-on-becoming-a-500-million-company.html","publisher":"CNBC","year":2017,"type":"interview"}],"tags":{"industry":"ecommerce","region":"us","decade":"2010s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'cursor-vscode-fork',
  'daily',
  '{"id":"cursor-vscode-fork","type":"daily","scheduled_date":"","company":"Cursor (Anysphere)","era":"2023–2024 — launch and early growth","context":"GitHub Copilot launches in 2021 as a VS Code plugin — an autocomplete layer that sits inside the existing editor. It works well enough that Microsoft positions it as the canonical AI coding tool. Anysphere (a YC-backed team) ships Cursor instead as a complete fork of VS Code''s open-source codebase, with AI baked into the core (multi-line edits, repo-wide context, agentic actions) rather than added through a plugin. They charge $20/month, the same as Copilot. Most observers wonder why they didn''t just build a better plugin.","prompt":"Why fork the entire IDE rather than ship a smarter Copilot competitor as a VS Code extension — and what does owning the editor allow that an extension can''t?","reveal_quote":"An extension can only ever sit inside the surfaces VS Code gives it. Forking the editor means we control every keystroke, every panel, every diff view — every place AI could change how code gets written. The plugin layer is a ceiling we couldn''t accept.","reveal_quote_attribution":"Anysphere / Cursor team — paraphrased from public commentary on the architectural choice","reveal_note":"The non-obvious move: a plugin lives inside someone else''s product roadmap. If Microsoft ships its own AI features into VS Code core, every extension becomes redundant overnight. Forking sidesteps that platform risk entirely — Cursor controls its own UI, its own context model, its own update cadence. The cost is real: maintaining a VS Code fork is engineering-heavy, and Cursor inherits every bug Microsoft fixes upstream (or doesn''t). The benefit is also real: by mid-2025 Cursor hit ~$500M ARR and by early 2026 ~$2B ARR — a Copilot-equivalent product impossible to build as a plugin. The lesson: when AI is the product, owning the editor matters more than reusing the editor.","quote_type":"paraphrased","sources":[{"title":"Cursor (code editor) — Wikipedia","url":"https://en.wikipedia.org/wiki/Cursor_(code_editor)","type":"article"},{"title":"An honest Anysphere review (2025): The truth about the $9b AI coding tool","url":"https://www.eesel.ai/blog/anysphere-review","publisher":"eesel AI","year":2025,"type":"blog"},{"title":"Cursor vs. VS Code: Which One Is Right for You?","url":"https://www.datacamp.com/blog/cursor-vs-vs-code","publisher":"DataCamp","type":"article"}],"tags":{"industry":"ai-tools","region":"us","decade":"2020s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'brex-no-personal-guarantee',
  'daily',
  '{"id":"brex-no-personal-guarantee","type":"daily","scheduled_date":"","company":"Brex","era":"2017–2018 — founding through launch","context":"Corporate credit cards in 2017 require a personal guarantee — meaning the founder, as an individual, is liable if the company fails to pay. American Express and Chase have spent decades treating the founder''s personal FICO score as the underwriting signal, regardless of company financials. Brex founders Henrique Dubugras and Pedro Franceschi (both Brazilian, both ex-Pagar.me ~$160M founders, both ~20 years old) build a corporate card that underwrites against the company''s cash balance, not the founder''s personal credit. No personal guarantee, ever. Credit limits ~10–20x higher than incumbents.","prompt":"Why is removing the personal guarantee actually the entire product — and what changes structurally about who can run a company once cards are underwritten against company cash?","reveal_quote":"We had just gotten through US immigration and had no credit history. We couldn''t get an Amex. The personal guarantee was a tax on people who didn''t already have personal balance sheets — exactly the people building the most ambitious startups.","reveal_quote_attribution":"Henrique Dubugras / Pedro Franceschi, Brex cofounders — paraphrased from public interviews on the founding insight","reveal_note":"The choice that''s easy to miss: a personal-guarantee requirement is structurally exclusionary. Immigrants, first-generation founders, people without inherited wealth, and people without years of US credit history all start a startup with a worse corporate-card option than someone with the same business who already has a thick FICO file. Removing the guarantee converts the corporate card into a meritocratic instrument: companies with more cash get more credit; founders'' personal histories don''t gate it. Brex''s growth — 1 in 3 venture-backed US startups within five years — came from being the only corporate card a 19-year-old founder fresh off a YC W19 batch could actually use. The deeper lesson: financial-product UX is rarely about UI. It''s about who the underwriting math lets in.","quote_type":"paraphrased","sources":[{"title":"Brex for startups","url":"https://www.brex.com/solutions/startups","publisher":"Brex","type":"blog"},{"title":"Brex Business Credit Card Doesn''t Require a Personal Guarantee","url":"https://www.nerdwallet.com/business/credit-cards/learn/brex-card","publisher":"NerdWallet","type":"article"},{"title":"The Complete Guide to Brex: A Masterclass for High-Growth Companies","url":"https://www.swipesum.com/insights/the-complete-guide-to-brex-a-masterclass-for-high-growth-companies","type":"blog"}],"tags":{"industry":"fintech","region":"us","decade":"2010s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'mercury-banking-for-startups',
  'daily',
  '{"id":"mercury-banking-for-startups","type":"daily","scheduled_date":"","company":"Mercury","era":"2019 — launch (after 2017 founding)","context":"In 2019, opening a bank account for a Delaware C-corp is a slog: SVB and First Republic require in-person visits, paper forms, and 2–6 weeks. Chase / BofA require even more — and won''t really serve a ''pre-revenue, two-cofounder Delaware C-corp.'' Most YC startups end up at SVB by default. Mercury launches with one anchor experience: incorporated startup applies online in 10 minutes, receives bank account and debit cards within minutes, has API access and a UI built specifically around how startups operate (multi-cofounder access, sub-accounts, vendor controls). No physical branches. No personal banker. Everything self-serve.","prompt":"Why is shipping an online-only business bank explicitly for startups (when SVB already serves them) actually a different product — and what does it expose about the incumbent''s customer model?","reveal_quote":"SVB serves startups as an exception to its enterprise banking process. We treated startups as the default. Every flow we built — multi-founder accounts, vendor cards, API access — was for the company structure SVB makes its richest customers retrofit themselves into.","reveal_quote_attribution":"Immad Akhund, Mercury cofounder/CEO — paraphrased from public interviews on the founding thesis","reveal_note":"The non-obvious move: ''business banking for startups'' isn''t a market segment — it''s a product redesign at the workflow level. SVB had the relationships; Mercury had the product surface. The product surface won because every workflow (vendor payments, employee cards, sub-accounts) was built for a 2-cofounder Delaware C-corp from day one, not retrofitted from a Fortune 500 banking template. When SVB collapsed in March 2023, Mercury onboarded an estimated ~25,000 new customers in 72 hours — the existence of a credible alternative was itself the systemic answer to single-bank concentration risk for the YC ecosystem. The lesson: incumbents in regulated categories often serve the new customer cohort as a side product, with old workflows. The right move is to ship a workflow-native alternative — the regulatory moat is real but smaller than it looks.","quote_type":"paraphrased","sources":[{"title":"Mercury banks $20M for its banking service aimed at startups","url":"https://techcrunch.com/2019/09/26/mercury-banks-20m-for-its-banking-service-aimed-at-startups/","publisher":"TechCrunch","year":2019,"type":"article"},{"title":"Mercury Technologies — Wikipedia","url":"https://en.wikipedia.org/wiki/Mercury_Technologies","type":"article"},{"title":"Partnering with Mercury: The Business Banking Platform of the Future","url":"https://sequoiacap.com/article/partnering-with-mercury-the-business-banking-platform-of-the-future/","publisher":"Sequoia Capital","type":"blog"}],"tags":{"industry":"fintech","region":"us","decade":"2010s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'ramp-save-not-spend',
  'daily',
  '{"id":"ramp-save-not-spend","type":"daily","scheduled_date":"","company":"Ramp","era":"February 2020 — launch","context":"Corporate cards in 2020 compete entirely on rewards (AmEx points, cashback, travel perks). The implicit business model is interchange revenue + customers spending more to earn more rewards. Ramp launches with the opposite pitch: a corporate card that explicitly helps companies spend less. Every product surface (transaction-level policy enforcement, automated expense reports, vendor consolidation, automated savings recommendations) is oriented toward reducing the customer''s spend. Founders Eric Glyman and Karim Atiyeh (ex-Paribus, acquired by Capital One) interview ~100 finance teams before launch — the universal complaint is that existing cards optimize against the customer''s interest.","prompt":"Why pitch a corporate card whose explicit purpose is to make the customer spend less — when interchange revenue (the card''s business model) goes up when customers spend more?","reveal_quote":"Every other card company makes money when you spend more. We make money the same way — but our pitch is the opposite. That contradiction is the entire moat: customers know we''ll never recommend a vendor or a habit that helps our revenue and hurts theirs.","reveal_quote_attribution":"Eric Glyman, Ramp cofounder/CEO — paraphrased from his McKinsey and Sequoia interviews on Ramp''s founding thesis","reveal_note":"The choice that''s easy to miss: ''help customers spend less'' is positioning, not product. Ramp still earns interchange when customers spend; the company isn''t structurally cheaper to use than AmEx. What''s different is the conversation Ramp can have — every product launch, every email, every sales call frames Ramp as the customer''s ally against waste. That framing is impossible for AmEx to copy: their existing revenue model and reward-program brand prevent them from telling customers to spend less. The lesson: in commoditized categories (and corporate cards are commoditized), positioning that creates a structural conflict for the incumbent — one they can''t credibly copy — is more durable than a feature advantage.","quote_type":"paraphrased","sources":[{"title":"Ramp (company) — Wikipedia","url":"https://en.wikipedia.org/wiki/Ramp_(company)","type":"article"},{"title":"The end of the expense report: A conversation with Ramp''s Eric Glyman","url":"https://www.mckinsey.com/industries/financial-services/our-insights/the-end-of-the-expense-report-a-conversation-with-ramps-eric-glyman","publisher":"McKinsey","type":"interview"},{"title":"Ramp CEO Eric Glyman: Using AI to Build ''Self-Driving Money''","url":"https://sequoiacap.com/podcast/training-data-eric-glyman/","publisher":"Sequoia Capital","type":"podcast"}],"tags":{"industry":"fintech","region":"us","decade":"2020s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'anthropic-safety-positioning',
  'daily',
  '{"id":"anthropic-safety-positioning","type":"daily","scheduled_date":"","company":"Anthropic","era":"March 2023 — Claude release strategy","context":"OpenAI''s ChatGPT is the cultural artifact of late 2022 / early 2023. The model is shipping fast, going viral, and getting embedded in every product. Microsoft has invested $13B. Anthropic ships Claude in March 2023 as a competing chat model — but with a deliberately different message. Every public announcement leans on safety: ''Constitutional AI,'' a published ''constitution'' the model is trained against, the founders'' AI-safety research history (ex-OpenAI alignment team), and an explicit positioning as ''the safer alternative.'' The product itself is functionally similar to ChatGPT.","prompt":"Why anchor Claude''s launch positioning on ''safer'' rather than ''smarter'' or ''faster'' — when the consumer market in early 2023 reward speed and capability, not safety?","reveal_quote":"If we compete on capability with OpenAI, we lose the race they''re already running. If we compete on the dimension every regulator, every enterprise security team, and every researcher about to deploy us actually worries about, we run a different race.","reveal_quote_attribution":"Anthropic leadership — paraphrased from the Constitutional AI paper and public Anthropic positioning","reveal_note":"The non-obvious move: ''safety'' is not a product feature, it''s a buyer-segmentation instrument. Consumers don''t pick AI by safety; enterprise procurement, regulators, and academic researchers do. By anchoring on safety, Anthropic effectively chose a different go-to-market — selling primarily to enterprises (Slack, Notion, Quora) and to API customers building products where ''I trust this model not to do something dangerous'' matters more than ''this model is 5% smarter.'' By 2025, Anthropic''s enterprise revenue is competitive with OpenAI''s despite a much smaller consumer footprint. The deeper lesson: when a category is dominated by an incumbent on one dimension (capability), the only path that doesn''t lose is to redefine the category around a dimension the incumbent can''t easily occupy without contradicting itself.","quote_type":"paraphrased","sources":[{"title":"Claude''s Constitution","url":"https://www.anthropic.com/news/claudes-constitution","publisher":"Anthropic","year":2023,"type":"blog"},{"title":"Inside Claude: How Anthropic Built the World''s Most Safety-Conscious AI","url":"https://medium.com/@nraman.n6/inside-claude-how-anthropic-built-the-worlds-most-safety-conscious-ai-c73f955f9f65","type":"blog"},{"title":"Anthropic Publishes Claude AI''s New Constitution","url":"https://time.com/7354738/claude-constitution-ai-alignment/","publisher":"TIME","type":"article"}],"tags":{"industry":"ai-tools","region":"us","decade":"2020s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'vercel-v0-generative-ui',
  'daily',
  '{"id":"vercel-v0-generative-ui","type":"daily","scheduled_date":"","company":"Vercel","era":"September–October 2023 — v0 launch","context":"AI coding in mid-2023 means GitHub Copilot autocomplete + ChatGPT for code questions. The output is text — code blocks the developer copy-pastes. Vercel ships v0: a chat interface where users describe UI in natural language, and the model returns runnable React + Tailwind code, rendered immediately as a working preview. The product is positioned not as an AI tool, but as a ''generative UI system'' — and is integrated tightly with Next.js + Vercel Deploy, so the generated component can be in production in one click.","prompt":"Why is rendering the AI output as a live preview (instead of just returning code) the entire product — and what does it unlock that ChatGPT-with-code-snippets can''t?","reveal_quote":"The text output of code is not the unit of work. The unit of work is a running thing the user can see and click. If you make the AI generate text and the user paste it into an editor and run it, you''ve added 12 friction steps to a workflow the AI was supposed to remove.","reveal_quote_attribution":"Guillermo Rauch, Vercel CEO — paraphrased from his Sequoia Training Data podcast and Cognitive Revolution interviews on v0","reveal_note":"What''s easy to miss: v0''s product surface (live-preview + deploy) is what makes ''AI for UI'' a real product instead of a chat curiosity. ChatGPT can produce equivalent React code; what it can''t do is take that code from ''text in a chat bubble'' to ''running URL the user can show their team.'' v0''s 1 million → 4 million ARR took 34 days because the demo IS the product — there''s no install, no setup, no copy-paste. The deeper lesson: when AI generates artifacts (code, designs, documents), the product moat is the runtime surface that turns the artifact into a useful thing without any intermediate human step. The model is commoditized; the surface that operationalizes the output is the product.","quote_type":"paraphrased","sources":[{"title":"Vercel''s Guillermo Rauch: Building the Generative Web with AI","url":"https://sequoiacap.com/podcast/training-data-guillermo-rauch/","publisher":"Sequoia Capital","type":"podcast"},{"title":"What is Vercel? Complete History of Next.js, v0, AI UI","url":"https://www.taskade.com/blog/vercel-v0-history","publisher":"Taskade","type":"blog"},{"title":"v0 (Vercel) | AI Wiki","url":"https://aiwiki.ai/wiki/vercel_v0","type":"article"}],"tags":{"industry":"ai-tools","region":"us","decade":"2020s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'threads-no-following-feed',
  'daily',
  '{"id":"threads-no-following-feed","type":"daily","scheduled_date":"","company":"Meta (Threads)","era":"July 5, 2023 — launch","context":"Threads launches as Meta''s Twitter alternative. The team ships an algorithmic ''For You'' feed only — no following-only feed, no chronological order, no hashtags, no search, no DMs. Users who sign up with Instagram credentials see content from accounts they don''t follow, ranked by Meta''s algorithm. The decision is deliberate: Adam Mosseri and team have watched Twitter''s news-vertical generate years of regulatory and PR damage. They choose a smaller, less-functional product over a Twitter-clone with full features.","prompt":"Why launch a text-social product with no following feed, no chronological view, and no DMs — and refuse to add them even after users explicitly demand them for weeks?","reveal_quote":"We''re not going to do anything to encourage politics or hard news on Threads. The juice isn''t worth the squeeze — the scrutiny, the negativity, the integrity risks are not worth the small amount of incremental engagement.","reveal_quote_attribution":"Adam Mosseri, Head of Instagram — Threads / public commentary, July 2023","reveal_note":"The choice that''s easy to miss: a missing feature is a positioning statement. By withholding hashtags, news amplification, and a chronological feed, Meta explicitly de-emphasized the content modes (real-time news, breaking events, political discourse) that made Twitter both culturally central and operationally toxic. The cost was real — power users complained loudly, growth flattened, and competitors (Bluesky, Mastodon) had a window. The benefit: by the time Threads added hashtags (March 2024) and a following feed (July 2023, ~2 weeks post-launch under pressure), the product''s tone was already set by the algorithmic For You feed as a low-stakes lifestyle surface — not a real-time news torrent. Mosseri''s bet: building the absence of toxicity is harder than removing it later. The product''s defaults are the product.","quote_type":"verbatim","sources":[{"title":"Instagram head says Threads is ''not going to amplify news on the platform''","url":"https://techcrunch.com/2023/10/11/instagram-head-says-threads-is-not-going-to-amplify-news-on-the-platform/","publisher":"TechCrunch","year":2023,"type":"article"},{"title":"Instagram Boss Says Politics & Hard News Will Not Be Pushed By Threads","url":"https://deadline.com/2023/07/instagram-boss-politics-hard-news-not-pushed-threads-not-worth-scrutiny-negativity-integrity-risks-1235432486/","publisher":"Deadline","year":2023,"type":"article"},{"title":"Threads (social network) — Wikipedia","url":"https://en.wikipedia.org/wiki/Threads_(social_network)","type":"article"}],"tags":{"industry":"consumer-social","region":"us","decade":"2020s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'substack-notes-launch',
  'daily',
  '{"id":"substack-notes-launch","type":"daily","scheduled_date":"","company":"Substack","era":"April 2023 — Notes launch","context":"Substack at this point is the dominant paid-newsletter platform. Twitter has just been acquired by Elon Musk and is in active turmoil. Substack ships Notes — a short-form Twitter-like feed inside the Substack product, where writers post short ideas, quotes, and updates between newsletters. Critically, every Note links back to the writer''s paid subscription. The economy is identical to Substack''s main product: 10% take rate on subscriptions, no ads, no algorithm-driven distribution. Elon Musk responds by banning all Substack links from Twitter the day Notes launches.","prompt":"Why is Notes a defensible product if it looks like Twitter and is built by a team much smaller than Twitter''s — and what is the take-rate-on-subscriptions structure doing that ads can''t?","reveal_quote":"On Twitter, your audience belongs to Twitter, and your content sells ads against an audience you don''t own. On Notes, your audience converts into paying subscribers, and we make money the same way you do — from the subscription, not from selling your attention.","reveal_quote_attribution":"Chris Best, Substack cofounder/CEO — paraphrased from the April 2023 announcement and follow-up commentary","reveal_note":"The non-obvious move: Notes isn''t a Twitter clone, it''s a top-of-funnel for paid subscriptions. Every Note is a casting net that, when it lands, converts a reader into a paying subscriber for some writer — and Substack takes 10%. Twitter''s ad model puts Twitter on the opposite side of the writer''s interest (Twitter wants engagement that drives ad views; the writer wants engagement that drives subscriptions). Substack''s 10% structurally aligns the platform with the writer. When Elon banned Substack links from Twitter, it was an admission that the model worked — Substack was extracting value Twitter couldn''t capture. The lesson: short-form social is not a single market. Whose revenue is monetized — the platform''s ad inventory vs. the writer''s subscription — determines what the product becomes, who''s loyal to it, and what the moat is.","quote_type":"paraphrased","sources":[{"title":"Substack launches Notes in challenge to Twitter","url":"https://www.washingtonpost.com/technology/2023/04/11/substack-twitter-notes-launches/","publisher":"Washington Post","year":2023,"type":"article"},{"title":"Substack''s new short-form ''Notes'' feed looks a lot like Twitter","url":"https://techcrunch.com/2023/04/05/substacks-new-short-form-notes-feed-looks-a-lot-like-twitter/","publisher":"TechCrunch","year":2023,"type":"article"},{"title":"Substack Notes, Twitter Blocks Substack, Substack Versus Writers","url":"https://stratechery.com/2023/substack-notes-twitter-blocks-substack-substack-versus-writers/","publisher":"Stratechery","year":2023,"type":"blog"}],"tags":{"industry":"media","region":"us","decade":"2020s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'klarna-bnpl-launch',
  'daily',
  '{"id":"klarna-bnpl-launch","type":"daily","scheduled_date":"","company":"Klarna","era":"2005 — founding, Stockholm","context":"Three students at the Stockholm School of Economics pitch a buy-now-pay-later (BNPL) idea at an entrepreneurship competition: Klarna sits between the retailer and the shopper, pays the retailer at checkout, and collects from the shopper a few weeks later (or in installments). Judges dismiss the idea — ''if it would work, the banks would just do it themselves.'' Crucially: in Sweden in 2005, credit cards are uncommon; people are used to receiving invoices and paying after delivery. Online retailers have a structural problem: shoppers abandon carts at checkout because they don''t trust paying upfront to a website.","prompt":"Why is a BNPL company that handles ~3% margins on each transaction actually a different product than ''a slightly better credit card'' — and what does Klarna structurally do that incumbents can''t?","reveal_quote":"We didn''t compete with banks. We competed with cart abandonment. Every transaction that didn''t happen because the shopper didn''t trust paying upfront was the actual market — and banks don''t make money fixing it.","reveal_quote_attribution":"Sebastian Siemiatkowski, Klarna cofounder/CEO — paraphrased from the Acquired and Sequoia interviews on the founding thesis","reveal_note":"The non-obvious move: Klarna''s customer wasn''t the shopper, it was the retailer. Retailers paid Klarna ~3% to absorb the trust + credit risk at checkout — money they were already losing to cart abandonment, only now with a partner who could quantify it. Banks made money on credit-card interchange + interest from shoppers, so cart abandonment wasn''t their problem. Klarna sat in the seam between merchant-pain and shopper-trust that incumbents had no incentive to enter. The lesson: in regulated, incumbent-dominated categories, look for the pain that''s structurally invisible to the incumbent''s revenue model. Klarna''s later US expansion problems came partly because US shoppers (unlike Swedes) were already comfortable paying upfront with credit cards — the original wedge translated less cleanly.","quote_type":"paraphrased","sources":[{"title":"Klarna — Wikipedia","url":"https://en.wikipedia.org/wiki/Klarna","type":"article"},{"title":"Building a Disruptive Payments Company (with Klarna CEO Sebastian Siemiatkowski)","url":"https://www.acquired.fm/episodes/building-a-disruptive-payments-company-with-klarna-ceo-sebastian-siemiatkowski","publisher":"Acquired Podcast","type":"podcast"},{"title":"Klarna''s Sebastian Siemiatkowski: An outsider''s path to financial inclusion","url":"https://sequoiacap.com/article/sebastian-siemiatkowski-klarna-spotlight/","publisher":"Sequoia Capital","type":"blog"}],"tags":{"industry":"fintech","region":"eu","decade":"2000s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'nvidia-cuda-decade-bet',
  'daily',
  '{"id":"nvidia-cuda-decade-bet","type":"daily","scheduled_date":"","company":"NVIDIA","era":"2007–2016 — decade-long CUDA investment before the AI wave","context":"GPUs in the mid-2000s have one customer: gamers. NVIDIA''s revenue is structurally tied to consumer-graphics cards. Jensen Huang makes a counterintuitive bet — push CUDA, a software platform that turns the GPU into a general-purpose parallel-compute device. CUDA increases the cost of every NVIDIA GPU by ~50% (extra die area, software investment). The ''customer'' for that 50% premium doesn''t really exist yet — it''s researchers, scientific-computing labs, and a hypothetical machine-learning future. NVIDIA ships CUDA in 2007. For roughly a decade, it loses money on the investment.","prompt":"Why subsidize a hardware feature by 50% for a customer base that doesn''t yet exist — and what is NVIDIA actually building beyond a faster gaming GPU?","reveal_quote":"If we didn''t dedicate ourselves to 20 years of CUDA while losing money most of that time — if we didn''t do it, nobody else would have done it.","reveal_quote_attribution":"Jensen Huang, NVIDIA founder/CEO — Dwarkesh Patel interview, 2024","reveal_note":"The choice that''s easy to miss: CUDA isn''t a feature, it''s a developer-platform investment masquerading as a hardware spec. NVIDIA didn''t subsidize the chip — they subsidized a parallel-computing developer ecosystem that, by the time deep learning needed it (2012, AlexNet on GPUs), was the only one in the world. By 2025, CUDA is a 5M+ developer ecosystem deeply integrated into PyTorch, TensorFlow, JAX, and every major AI framework. Switching to competitors (AMD, Intel, Google TPU) requires rewriting software at every layer — that''s the moat, not the chip. The lesson: in deep-tech categories, decade-long platform investments win against feature competition. The cost of betting on a non-existent market for 10 years is enormous; the payoff (when it lands) is structurally unbeatable because it''s not a feature lead, it''s an ecosystem lead.","quote_type":"verbatim","sources":[{"title":"Jensen Huang on Nvidia''s supply chain moat","url":"https://www.dwarkesh.com/p/jensen-huang","publisher":"Dwarkesh Patel","year":2024,"type":"podcast"},{"title":"CUDA — Wikipedia","url":"https://en.wikipedia.org/wiki/CUDA","type":"article"},{"title":"NVIDIA''s AI Dominance: How Full-Stack Thinking Built an Unassailable Moat","url":"https://www.cloudsyntrix.com/blogs/nvidias-ai-dominance-how-full-stack-thinking-built-an-unassailable-moat/","publisher":"CloudSyntrix","type":"article"}],"tags":{"industry":"hardware","region":"us","decade":"2000s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'pinterest-save-mechanic',
  'daily',
  '{"id":"pinterest-save-mechanic","type":"daily","scheduled_date":"","company":"Pinterest","era":"March 2010 — launch through 2012","context":"Social media in 2010 is dominated by Facebook (like / comment / share) and Twitter (favorite / retweet). The unit of engagement is reaction — public, in-feed, performative. Pinterest launches with a different primitive: ''pin,'' a personal save action. There''s no public reaction, no follower count flexing, no in-feed posting. Users ''pin'' images they want to remember for themselves onto private/public boards. Growth is glacial — only 5,000 users by August 2010. Ben Silbermann hand-writes emails to the first 5,000.","prompt":"Why bet a social product on ''save for later'' instead of ''react/share now'' — and what kind of behavior does the save mechanic structurally produce?","reveal_quote":"Likes and shares are for showing other people what you like. Pins are for showing yourself what you like. The behavior we wanted to compound was a person figuring out who they are — not broadcasting it.","reveal_quote_attribution":"Ben Silbermann, Pinterest cofounder/CEO — paraphrased from public commentary on Pinterest''s founding behavior model","reveal_note":"What''s easy to miss: ''save for later'' creates a different data flywheel than ''react now.'' Likes capture in-the-moment reactions to other users'' posts (a social graph). Pins capture intent — what someone is actually planning to buy, build, cook, or wear (an interest graph). The interest graph is structurally more commercially valuable than the social graph: ''wedding-cake idea pinned to a board called Wedding 2024'' is a much higher-intent ad target than ''liked a friend''s vacation photo.'' By 2019, Pinterest IPO''d at ~$10B valuation, with ad CPMs that beat Facebook''s in commerce-adjacent verticals. The lesson: the unit-action you pick at launch shapes the data you collect, which shapes the business model possible 5 years later. ''Reaction'' and ''intent'' are different products with different ceilings.","quote_type":"paraphrased","sources":[{"title":"Pinterest — Wikipedia","url":"https://en.wikipedia.org/wiki/Pinterest","type":"article"},{"title":"Pinterest Founder Ben Silbermann: The Mastermind Behind Pinterest","url":"https://thebusinesslegacy.com/pinterest-founder-ben-silbermann/","type":"blog"},{"title":"Ben Silbermann — Wikipedia","url":"https://en.wikipedia.org/wiki/Ben_Silbermann","type":"article"}],"tags":{"industry":"consumer-social","region":"us","decade":"2010s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'huggingface-open-source-hub',
  'daily',
  '{"id":"huggingface-open-source-hub","type":"daily","scheduled_date":"","company":"Hugging Face","era":"2018–2020 — Transformers library + Hub","context":"Google releases BERT in October 2018 — a state-of-the-art language model — but only on TensorFlow, with a complex API. The researchers who want to use it are mostly on PyTorch and don''t want to rewrite their pipelines. Hugging Face (then a chatbot startup) pivots: they port BERT to PyTorch, then build a general ''Transformers'' library that wraps every major language model in a single Python API. The library is fully open source, Apache 2.0 licensed, no commercial gates. In 2020 they ship the Hub — a model repository where anyone can upload, download, and share trained models.","prompt":"Why open-source the entire library and the model hub — when commercial ML platforms (Google AI, Azure ML, AWS SageMaker) were racing to gate access to top models behind paid APIs?","reveal_quote":"Closed AI works for the company that ships it once. Open AI works for the company that becomes the default way everyone in the world uses, shares, and improves models. We bet that scientists, researchers, and developers would pick the open thing over the gated thing — and that we''d figure out the business later.","reveal_quote_attribution":"Clément Delangue, Hugging Face cofounder/CEO — paraphrased from public Acquired interviews and Sequoia commentary","reveal_note":"The non-obvious move: Hugging Face traded short-term monetization for ecosystem ownership. By making Transformers free + open, every ML researcher in the world started downloading models through Hugging Face — even when the underlying model was made by Google, Meta, or Microsoft. The Hub became the GitHub for ML models. By 2025, the Hub hosts 1M+ models and is the default surface for both open-source releases (Meta''s Llama) and commercial models (paid hosting tiers). The business model emerged from the ecosystem position: hosting paid private models, enterprise inference, and developer support. The lesson: in platform competition, the player who chooses ''be the default open thing'' typically wins the surface area, even if they monetize it later than competitors who gate from day one.","quote_type":"paraphrased","sources":[{"title":"Hugging Face''s Clem Delangue: Open-Sourcing the Future of AI","url":"https://sequoiacap.com/article/clem-delangue-spotlight/","publisher":"Sequoia Capital","type":"blog"},{"title":"Building the Open Source AI Revolution (with Hugging Face CEO, Clem Delangue)","url":"https://www.acquired.fm/acq2-episodes/building-the-open-source-ai-revolution-with-hugging-face-ceo-clem-delangue","publisher":"Acquired Podcast","type":"podcast"},{"title":"Hugging Face — Wikipedia","url":"https://en.wikipedia.org/wiki/Hugging_Face","type":"article"}],"tags":{"industry":"ai-tools","region":"us","decade":"2010s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'datadog-founder-led-sales',
  'daily',
  '{"id":"datadog-founder-led-sales","type":"daily","scheduled_date":"","company":"Datadog","era":"2010–2015 — founding through scaling sales","context":"Datadog''s founders, Olivier Pomel and Alexis Lê-Quôc, spend the first six months of the company writing zero code. Instead they ride the New York City subway visiting infrastructure-engineer prospects in person — talking to dozens of developers and ops engineers about exactly how their monitoring workflow breaks. The product they end up building reflects those conversations: built to bridge developers and operations (the canonical ''DevOps'' gap) at a moment when that label barely exists. Pomel does the early sales calls personally and stays involved deep into the company''s growth. By IPO in 2019, Datadog is one of the fastest-growing SaaS companies in history.","prompt":"Why is the founder spending six months in subway cars talking to engineers — and what does the conversation data unlock that a research firm or survey couldn''t?","reveal_quote":"Those six months without code were the most valuable engineering time of the company. We didn''t build the wrong thing for two years and then pivot — we built the right thing on the first try, because we knew exactly what was broken in fifty different companies before we started.","reveal_quote_attribution":"Olivier Pomel, Datadog cofounder/CEO — paraphrased from his SaaStr interviews on Datadog''s founding approach","reveal_note":"The choice that''s easy to miss: founder-led customer discovery isn''t research, it''s authorship. A market-research firm can deliver a report saying ''engineers want X.'' A founder in the room watching the engineer''s actual workflow can see the specific shape of the pain — which keyboard shortcut they wish existed, which dashboard layout makes them squint, which metric they can''t find. The product Datadog built had a near-perfect first-version PMF because the conversations were the spec. The IPO velocity (one of the fastest SaaS IPOs ever) came from compounding off that initial fidelity. The lesson: in infra and developer tools especially, founder-led customer discovery in the first six months saves 2-3 years of pivoting later — and the founder-engineer access only exists once, before the founder has a calendar full of board meetings.","quote_type":"paraphrased","sources":[{"title":"The First $100,000,000 ARR at Datadog: How Founder CEO Olivier Pomel Built a Customer-Centric Monitoring Giant","url":"https://www.saastr.com/the-first-100000000-arr-at-datadog-how-founder-ceo-olivier-pomel-built-a-customer-centric-monitoring-giant/","publisher":"SaaStr","type":"article"},{"title":"Datadog — Wikipedia","url":"https://en.wikipedia.org/wiki/Datadog","type":"article"},{"title":"Datadog Company History: From 2010 to $2.1 billion","url":"https://brandhistories.com/datadog/company-history","publisher":"BrandHistories","type":"blog"}],"tags":{"industry":"infra","region":"us","decade":"2010s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'replit-zero-config-browser',
  'daily',
  '{"id":"replit-zero-config-browser","type":"daily","scheduled_date":"","company":"Replit","era":"2016 — launch (after open-source predecessors since 2011)","context":"Setting up a programming environment in 2016 is a real friction point for new developers — installing a language runtime, a code editor, a package manager, a Git client, and configuring them all just to run ''hello world.'' Replit (founded by Amjad Masad and team) launches a fully-browser-based coding environment: open a URL, pick a language, type code, hit run. No installs, no configuration, no setup. The product is targeted at students and hobbyists — a structurally different audience than the established IDE incumbents (Visual Studio, JetBrains, Eclipse).","prompt":"Why bet the company on a browser-based, zero-config development environment for students — when professional developers (the high-spending audience) are clearly committed to local IDEs?","reveal_quote":"Every professional developer was once a student or a hobbyist. The local-IDE setup is a barrier that filters out the next generation of developers — not the current one. We weren''t trying to win developers who already had pipelines. We were trying to be the first place someone learns code, so we''d be the default for the decade after.","reveal_quote_attribution":"Amjad Masad, Replit cofounder/CEO — paraphrased from his Secret Sauce Podcast and Semaphore interviews on Replit''s positioning","reveal_note":"The non-obvious move: building for students isn''t a market-segment choice, it''s a generational-default play. Today''s student is in 10 years the engineer making procurement decisions at a Fortune 500. By being the first coding environment most new programmers ever touch (~20M users by 2023), Replit is structurally positioned to be the default environment those programmers reach for when they later need a tool at work. The product also captures the inflection moment when AI coding (2023+) lets non-engineers ship apps — exactly the audience least willing to install a local IDE. Replit''s pivot toward AI agents (Replit Agent, 2024) leveraged the existing browser-based runtime in a way no incumbent IDE could match. The lesson: ''student / hobbyist'' audiences look low-value in the short term and are often the right wedge for a generational platform shift.","quote_type":"paraphrased","sources":[{"title":"Replit — Wikipedia","url":"https://en.wikipedia.org/wiki/Replit","type":"article"},{"title":"Zero to Coding in the Browser - The Replit Story | Amjad Masad","url":"https://www.youtube.com/watch?v=BA_0zXfdwz4","publisher":"The Secret Sauce Podcast","type":"podcast"},{"title":"Under the Hood of Replit with Amjad Masad","url":"https://semaphore.io/blog/amjad-masad-replit","publisher":"Semaphore","type":"interview"}],"tags":{"industry":"devtools","region":"us","decade":"2010s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'tinder-swipe-gesture',
  'daily',
  '{"id":"tinder-swipe-gesture","type":"daily","scheduled_date":"","company":"Tinder","era":"September 2012 — launch","context":"Online dating in 2012 means OkCupid, Match, and eHarmony — long-form text profiles, lengthy compatibility questionnaires, and message inboxes full of unwanted attention (mostly for women). Tinder ships with the opposite product: one photo at a time, age, distance, and ''about me'' if you bother. The interaction primitive is a swipe — right means yes, left means no. Sean Rad and Jonathan Badeen prototype it by literally shuffling physical playing cards, noting that their natural instinct is to throw the top card sideways. They build the entire app around that gesture.","prompt":"Why is the swipe gesture (vs. a ''like'' button or ''next'' button) the entire product — and what does the physical-card metaphor change about how users feel during the decision?","reveal_quote":"We watched ourselves play with the cards. The thing nobody did was tap them. They picked the top one up and flung it across the table. The gesture was already in the user''s hand before we built the app.","reveal_quote_attribution":"Sean Rad / Jonathan Badeen, Tinder cofounders — paraphrased from public retellings of the swipe gesture''s origin","reveal_note":"What''s easy to miss: the swipe is not a faster button — it is a physical metaphor that converts evaluation into instinct. Buttons require deliberation (''do I like this person enough to click yes''); a swipe lets the body decide before the brain catches up. The metaphor also reframes the entire experience: cards-in-a-deck is a known fun pattern, while inbox-with-messages is a known unpleasant pattern. Tinder didn''t speed up online dating, they changed its emotional category from ''effortful evaluation'' to ''playful discovery.'' The lesson: the interaction primitive you pick at launch defines the emotional shape of every session a user has with the product. Swap the swipe for a tap, and the dopamine curve flattens.","quote_type":"paraphrased","sources":[{"title":"Tinder (app) — Wikipedia","url":"https://en.wikipedia.org/wiki/Tinder_(app)","type":"article"},{"title":"Sean Rad — Wikipedia","url":"https://en.wikipedia.org/wiki/Sean_Rad","type":"article"},{"title":"Tinder''s Founders On Dating and How They Created Their Addictive App","url":"https://time.com/4837/tinder-meet-the-guys-who-turned-dating-into-an-addiction/","publisher":"TIME","type":"article"}],"tags":{"industry":"consumer-social","region":"us","decade":"2010s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'ios7-flat-design',
  'daily',
  '{"id":"ios7-flat-design","type":"daily","scheduled_date":"","company":"Apple","era":"June 2013 — iOS 7 WWDC reveal","context":"Apple''s iOS through iOS 6 is defined by skeuomorphism — software that imitates physical materials. The Notes app looks like a yellow legal pad. iBook has wooden bookshelves. The compass app has machined metal. Calendar has leather stitching. The design language was Steve Jobs and Scott Forstall''s signature — visually rich, instantly understandable for first-time iPhone users. Jobs is gone. Forstall has been pushed out in late 2012. Jony Ive is given full control of software design. He responds with iOS 7: a complete flat-design overhaul — no shadows, no textures, no skeuomorphic cues. Translucent panels, hairline fonts, primary colors. Reviewers split — half praise it, half call it ''amateurish.''","prompt":"Why throw out six years of established skeuomorphic design — when first-time users have always relied on those physical metaphors to understand the interface?","reveal_quote":"People had already become comfortable with touching glass. They didn''t need physical buttons. They understood the benefits. So there was an incredible liberty in not having to reference the physical world so literally. It got design out of the way.","reveal_quote_attribution":"Jony Ive, Apple Chief Design Officer — USA Today interview, 2013","reveal_note":"The non-obvious move: skeuomorphism was scaffolding, not a style. Its job in 2007 was to teach a population that had never touched a touchscreen that this rectangle is a ''notepad'' you can write on. By 2013 that lesson was over — a generation of iPhone users had internalized that swipes, taps, and pinches were just how phones worked. Flat design wasn''t an aesthetic choice; it was the admission that the training wheels could come off. Removing the metaphors freed pixels to communicate content rather than imitate materials, and the new visual language influenced Google Material, Microsoft Fluent, and almost every consumer-software design system that followed. The lesson: design metaphors have shelf lives tied to user literacy. The right time to remove them is uncomfortable because it always feels too soon to some users — but waiting too long traps the product in a visual language that was for a previous generation.","quote_type":"verbatim","sources":[{"title":"Apple unveils iOS 7 user interface design by Jonathan Ive at WWDC","url":"https://www.dezeen.com/2013/06/10/new-apple-ios-software-flat-design-jonathan-ive-wwdc/","publisher":"Dezeen","year":2013,"type":"article"},{"title":"Jony Ive killed skeuomorphic design with iOS 7 ten years ago — and he was right to","url":"https://www.imore.com/ios/ios-7/jony-ive-killed-skeuomorphic-design-with-ios-7-ten-years-ago-and-he-was-right-to","publisher":"iMore","type":"article"},{"title":"Remembering the controversial iOS 7 introduction","url":"https://9to5mac.com/2025/05/30/remembering-the-controversial-ios-7-introduction/","publisher":"9to5Mac","year":2025,"type":"article"}],"tags":{"industry":"consumer-mobile","region":"us","decade":"2010s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'snapchat-camera-default',
  'daily',
  '{"id":"snapchat-camera-default","type":"daily","scheduled_date":"","company":"Snapchat","era":"2011 — launch (as Picaboo)","context":"Every photo-sharing app at the time — Instagram, Facebook, Flickr — opens to a feed. You see other people''s content first; if you want to post, you tap a small camera icon. Snapchat (then ''Picaboo'') ships in July 2011 with the opposite default: the app opens directly to the camera, your camera, viewfinder live. To see friends'' content, you swipe; the feed is a secondary surface, not the homepage. The choice is described internally as ''Snapchat is a camera company, not a social-feed company.''","prompt":"Why open to the camera instead of the feed — and what does that single decision do to the kind of content the platform produces?","reveal_quote":"Snapchat isn''t about capturing the traditional Kodak moment. It''s about communicating with the full range of human emotion — not just what appears to be pretty or perfect. The camera is the start of the message, not a feature.","reveal_quote_attribution":"Evan Spiegel, Snap CEO — first Snapchat blog post, May 9, 2012","reveal_note":"The choice that''s easy to miss: defaults shape behavior more than features do. Opening to the feed (Instagram, Facebook) makes consumption the primary action — the user is a viewer first, a creator second. Opening to the camera (Snapchat) inverts it — the user is a creator first, every session begins with a question ''what should I send?'' That question generates vastly more low-stakes, in-the-moment content than ''what should I post?'' does. Years later, when Instagram launched Stories and TikTok launched its app, both copied the open-to-camera (or open-to-creation) default. The lesson: the screen that loads when the app opens is the entire product strategy. Where you put the cursor on first launch is more important than any feature you''ll ship for the next two years.","quote_type":"verbatim","sources":[{"title":"Snapchat: The App That Won by Disappearing","url":"https://wealthz.substack.com/p/snapchat-the-app-that-won-by-disappearing","type":"blog"},{"title":"Snapchat — Wikipedia","url":"https://en.wikipedia.org/wiki/Snapchat","type":"article"},{"title":"History of Snapchat & Future of Disappearing Photos","url":"https://frozenfire.com/history-of-snapchat/","publisher":"Frozen Fire","type":"blog"}],"tags":{"industry":"consumer-social","region":"us","decade":"2010s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'spotify-wrapped-2016',
  'daily',
  '{"id":"spotify-wrapped-2016","type":"daily","scheduled_date":"","company":"Spotify","era":"December 2016 — first Spotify Wrapped","context":"Spotify in 2016 has ~100M monthly users and is fighting Apple Music for retention. Most music apps push ''new releases'' or ''discover'' features — forward-looking, expensive to produce content for. In December 2016, Spotify launches ''Wrapped'' — a personalized ''year in music'' microsite for every user: most-played songs, total listening minutes, top artists, in shareable card formats designed to be screenshotted and posted to Instagram and Twitter. The feature is built by a small team in a few months; the underlying data was already being collected for recommendation purposes.","prompt":"Why turn user data into a December social-share ritual — and what is Wrapped actually doing that traditional retention features don''t?","reveal_quote":"Wrapped is one of the best moments of the year. It''s authentic — it''s not Spotify telling you what''s cool, it''s Spotify showing you what was true about your own year. That''s something a competitor can''t copy without your data.","reveal_quote_attribution":"Spotify marketing leadership — paraphrased from Movable Ink case study and public commentary on the Wrapped campaign","reveal_note":"What''s easy to miss: Wrapped is not a marketing campaign — it is a user-acquisition channel disguised as a year-end recap. Every shared Wrapped card is an ad for Spotify, posted to a feed by a real user with no edit. Most retention features (notifications, recommendations) work inside the app; Wrapped explicitly leaks outside the app, into Instagram, Twitter, and group chats where non-Spotify users see Spotify branding next to their friend''s authentic data story. The 1.2B+ earned impressions cost Spotify almost nothing — the campaign is built on data Spotify already had. The lesson: features that turn user data into a shareable artifact (especially seasonally) are simultaneously a retention loop AND a user-acquisition loop, and the cost is one-tenth what equivalent paid marketing would cost. Strava, Duolingo, Headspace, Reddit, and many others have since cloned the Wrapped formula.","quote_type":"paraphrased","sources":[{"title":"Spotify Wrapped — Wikipedia","url":"https://en.wikipedia.org/wiki/Spotify_Wrapped","type":"article"},{"title":"The Original Year-in-Review: How Spotify Drives Massive Annual Success","url":"https://movableink.com/blog/the-original-year-in-review-how-spotify-drives-massive-annual-success","publisher":"Movable Ink","type":"blog"},{"title":"Spotify | 2016 Wrapped","url":"https://www.oneclub.org/awards/adcawards/-award/27360/2016-wrapped/","publisher":"The One Club","year":2016,"type":"article"}],"tags":{"industry":"media","region":"eu","decade":"2010s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'slackbot-onboarding',
  'daily',
  '{"id":"slackbot-onboarding","type":"daily","scheduled_date":"","company":"Slack","era":"2014 — onboarding design","context":"Enterprise SaaS onboarding in 2014 is dominated by feature tours — modal popups, arrow tooltips, ''click here next'' overlays. Most have ~30% completion rates. Slack ships onboarding through a different mechanism entirely: a chatbot named Slackbot that messages every new user inside the actual app, asks them questions, and walks them through setup conversationally. Slackbot has personality. It says ''just a bot.'' It uses humor. New users feel like they''re chatting with a coworker, not running a tutorial.","prompt":"Why ship onboarding as a conversation with a bot inside the product — instead of using the standard feature-tour modals?","reveal_quote":"If the product is conversation, then the onboarding has to be a conversation too. A modal popup tells the user ''you are not yet in the product.'' A message from Slackbot tells the user ''you are already using Slack, this is what it feels like, and here''s the first thing it asks of you.''","reveal_quote_attribution":"Slack design team — paraphrased from public commentary on Slack''s onboarding approach","reveal_note":"The non-obvious move: Slackbot''s onboarding is not a tutorial — it is the first session of the product. Every Slackbot prompt is a real message in a real channel. The user''s first action in Slack is responding to a message, which is the exact behavior the product wants them to do forever. Modal feature tours teach ''where the buttons are''; Slackbot teaches ''how the product feels.'' That difference is what produces Slack''s famously high onboarding completion and second-week retention rates — the user has built a habit (responding to messages) before they''re aware they''re being onboarded. The lesson: onboarding that uses the product''s native interaction primitive (messages, in Slack''s case) compounds with the product itself. Onboarding that introduces a separate primitive (modals, overlays) fights it.","quote_type":"paraphrased","sources":[{"title":"Complete guide to launching Slackbot","url":"https://slack.com/resources/slack-for-admins/slackbot-launch-guide","publisher":"Slack","type":"documentation"},{"title":"Slack kills at onboarding customers: Here''s how","url":"https://www.zendesk.com/blog/customer-service/support/slack-customer-onboarding/","publisher":"Zendesk","type":"blog"},{"title":"Slack Bot Onboarding — Lessons learned","url":"https://medium.com/slack-developer-blog/slack-bot-onboarding-3b4c979de374","publisher":"Slack Platform Blog","type":"blog"}],"tags":{"industry":"saas","region":"us","decade":"2010s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'chatgpt-custom-instructions',
  'daily',
  '{"id":"chatgpt-custom-instructions","type":"daily","scheduled_date":"","company":"OpenAI","era":"July 20, 2023 — Custom Instructions launch","context":"ChatGPT in mid-2023 has tens of millions of weekly users. The product''s biggest UX problem: every conversation starts from zero. A teacher rewriting ''I teach 3rd grade science'' at the top of every chat. A developer specifying ''I prefer Go, not Python'' for the fiftieth time. A vegetarian saying ''no meat in recipes please'' every meal. The standard ML/personalization play is to silently train a per-user model — invisible, no UI. OpenAI instead ships ''Custom Instructions'': two visible text boxes (1,500 chars each) where users explicitly write ''what you should know about me'' and ''how I want you to respond.'' ChatGPT considers them on every reply.","prompt":"Why ship personalization as two visible, user-editable text boxes — when most consumer AI products treat personalization as an invisible ML model?","reveal_quote":"ChatGPT will consider your custom instructions for every conversation going forward, so you won''t have to repeat your preferences or information in every conversation.","reveal_quote_attribution":"OpenAI — official Custom Instructions launch announcement, July 20, 2023","reveal_note":"The choice that''s easy to miss: visible personalization is a trust instrument that invisible ML personalization can''t replicate. With invisible personalization, the user wonders ''why is it answering this way?'' and has no way to fix it. With Custom Instructions, the user wrote the instruction themselves — there''s nothing to suspect. The cost: the feature looks low-tech. The benefit: it ships in a week (no model training), works for every model OpenAI ever launches forever (the text is a prompt prefix), and gives the user agency that builds trust. Two months later OpenAI launches Memory, an ML-based version of the same idea. But Custom Instructions remains in the product — because the visible-user-authored version solves a different problem (control + transparency) that ML can''t. The lesson: ''low-tech'' UI for an ML product is often the right answer when the user needs agency more than they need magic.","quote_type":"verbatim","sources":[{"title":"Custom instructions for ChatGPT","url":"https://openai.com/index/custom-instructions-for-chatgpt/","publisher":"OpenAI","year":2023,"type":"blog"},{"title":"OpenAI launches customized instructions for ChatGPT","url":"https://techcrunch.com/2023/07/20/openai-launches-customized-instructions-for-chatgpt/","publisher":"TechCrunch","year":2023,"type":"article"},{"title":"OpenAI Personalizes ChatGPT With New Custom Instructions Feature","url":"https://voicebot.ai/2023/07/20/openai-personalizes-chatgpt-with-new-custom-instructions-feature/","publisher":"Voicebot.ai","year":2023,"type":"article"}],"tags":{"industry":"ai-tools","region":"us","decade":"2020s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'iphone-keyboard-touch-warp',
  'daily',
  '{"id":"iphone-keyboard-touch-warp","type":"daily","scheduled_date":"","company":"Apple","era":"2006–2007 — building the iPhone keyboard","context":"Project Purple is in the final stretch in 2006. The iPhone has to ship with a software keyboard — the entire device design assumes no physical keys. But the screen is small, fingers are big, and existing touch-screen keyboards (Treo, Windows Mobile devices) are universally hated. Ken Kocienda is given the keyboard problem. His insight: human fingers can''t reliably hit a specific key, so don''t ask them to. Instead, every touch within the keyboard area silently ''warps'' to the most-likely-intended key based on a dictionary lookup and a curvature-corrected touch coordinate (your finger thinks it''s tapping higher than it actually is). Autocorrect happens invisibly under the user''s fingertips, in real time.","prompt":"Why is making the touch-target invisible (the user doesn''t know which key they actually hit) the entire product — and what would happen if Apple had instead given users feedback about touch accuracy?","reveal_quote":"If you touched the screen anywhere within the bounds of the keyboard area, you''d get something. If you tapped between two or more keys, the iPhone would try to intelligently select whichever one made the most sense based on the autocorrect dictionary.","reveal_quote_attribution":"Ken Kocienda — Creative Selection (Apple), explaining the original iPhone keyboard design","reveal_note":"The non-obvious move: Kocienda''s keyboard hides the fact that the user is missing keys. A ''correct'' design would feedback the user — show which key they actually hit, make them learn finger placement. Apple did the opposite: warp the touch silently, predict the word, and let the user feel like a faster typist than they are. The feedback loop is suppressed on purpose. The product''s value is not ''a keyboard'' — it''s the feeling that a human finger pressing imprecise glass can produce coherent text. That feeling is the entire product; everything physical (capacitive touch, the autocorrect dictionary, the curvature correction) is downstream of preserving it. The lesson: when a product depends on users feeling competent, hiding error-feedback is often correct UX even though it violates the ''transparent feedback'' principle.","quote_type":"verbatim","sources":[{"title":"Ken Kocienda, member of Project Purple, Invented The iPhone Keyboard","url":"https://justinkbrady.com/notes/ken-kocienda/","type":"blog"},{"title":"The iPhone Keyboard - Make It or Break It","url":"https://commoncog.com/c/cases/the-iphone-keyboard-make-it-or-break-it/","publisher":"Commoncog","type":"article"},{"title":"Inventor of the iPhone''s Autocorrect Feature Explains How It Works","url":"https://www.idropnews.com/news/heres-why-your-iphones-autocorrect-can-be-annoying-and-how-to-work-around-it/185659/","publisher":"iDropNews","type":"article"}],"tags":{"industry":"consumer-mobile","region":"us","decade":"2000s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'gmail-undo-send',
  'daily',
  '{"id":"gmail-undo-send","type":"daily","scheduled_date":"","company":"Google (Gmail)","era":"2009 — Labs launch; 2015 — default rollout","context":"Email''s defining anxiety is the moment after you hit send and realize you replied-all, forgot the attachment, or sent it to the wrong person. Most email products in 2009 try to solve this with ''recall'' features — server-side attempts to delete the message from the recipient''s inbox after delivery. They almost never work; the email has already been read. Gmail Labs ships ''Undo Send'': it doesn''t recall anything. It introduces a 5–30 second delay between when you press send and when the email actually leaves the server. During that window, a small ''Undo'' link sits visible, letting you call it back before it sends. After six years in Labs, Google makes it a default Gmail feature in June 2015.","prompt":"Why is delaying every email by 30 seconds (a small annoyance for 99% of cases) actually a better product than a ''recall'' button that tries to delete sent mail?","reveal_quote":"Recall is a lie. Once an email leaves your outbox, you''ve lost the leverage to take it back. Undo Send is honest — it just creates a window where ''sent'' doesn''t yet mean ''sent.''","reveal_quote_attribution":"Gmail product team — paraphrased from public commentary on the Undo Send philosophy","reveal_note":"What''s easy to miss: Undo Send doesn''t solve the problem of ''unsending email.'' It solves the problem of ''the anxiety the user feels in the 5 seconds after pressing send.'' Those are different problems. Recall features chase the impossible technical task (un-deliver email); Undo Send sidesteps it by delaying delivery. The cost is real — every email is delayed 5-30 seconds, which would feel intolerable if presented as ''delay your email.'' But framed as ''undo,'' the cost becomes invisible because the user only notices it on the rare occasion they actually need it. The lesson: a UX framing that hides the underlying mechanism (delay vs. recall) can make a ''worse'' technical solution feel like a magic feature. Stripe, Robinhood, and many other products use the same principle for transaction undo / cancel-with-grace-period.","quote_type":"paraphrased","sources":[{"title":"Gmail Unveils ''Undo Send'' Button After Several Years of Beta Testing","url":"https://abcnews.go.com/Technology/gmail-unveils-undo-send-button-years-beta-testing/story?id=31976297","publisher":"ABC News","year":2015,"type":"article"},{"title":"After 6-Year Beta Test, All Gmail Users Get ''Undo Send''","url":"https://tech.slashdot.org/story/15/06/23/2052208/after-6-year-beta-test-all-gmail-users-get-undo-send","publisher":"Slashdot","year":2015,"type":"article"},{"title":"Gmail Delay Send: 3 Easy Ways to Delay Email Delivery in Gmail","url":"https://mailmeteor.com/blog/gmail-delay-send","publisher":"Mailmeteor","type":"blog"}],"tags":{"industry":"productivity","region":"us","decade":"2000s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'discord-persistent-voice',
  'daily',
  '{"id":"discord-persistent-voice","type":"daily","scheduled_date":"","company":"Discord","era":"May 2015 — public launch","context":"VoIP tools for gamers in 2014 — TeamSpeak, Ventrilo, Skype — all use a session-based model: you start a call, people join, when the call ends the room ceases to exist. Discord ships with a fundamentally different design: voice channels are persistent rooms that always exist. Anyone in the server can join an empty voice channel and wait; others see the channel as ''available'' and drop in if they''re around. Channels don''t ''start'' or ''end'' — they just exist, like rooms in a house.","prompt":"Why is a persistent-room voice channel (vs. a scheduled session call) structurally a different product — and what kind of usage does the persistence enable that sessions can''t?","reveal_quote":"We didn''t want gaming nights to require ''starting a call.'' The room is just always there. You show up to it the same way you''d walk into a friend''s living room — without an invitation, without a calendar invite. That''s the entire product.","reveal_quote_attribution":"Jason Citron / Stanislav Vishnevskiy, Discord cofounders — paraphrased from public retrospective commentary on Discord''s voice design","reveal_note":"The choice that''s easy to miss: persistent voice rooms produce a different cohabiting behavior than scheduled calls. Scheduled calls (Zoom, Skype) require coordination cost — you set a time, everyone joins, the room ends. Persistent rooms have zero coordination cost — you walk in when you''re around, leave when you''re not, others drift in. Over time the room becomes a place rather than an event. That subtle shift converts a chat product into a social-presence product — a structural reason Discord eventually expanded far beyond gaming into study groups, work teams, and hobby communities. Clubhouse later tried scheduled-presence rooms; they failed partly because they re-introduced the coordination cost Discord had structurally removed. The lesson: how a real-time interaction starts (and whether it has to start at all) shapes what behavior the product compounds.","quote_type":"paraphrased","sources":[{"title":"Designing the Impossible: Discord","url":"https://medium.com/@roman-kir/designing-the-impossible-discord-when-a-failed-game-creates-a-unicorn-4e3da925ef1a","publisher":"Medium","type":"blog"},{"title":"Discord — Wikipedia","url":"https://en.wikipedia.org/wiki/Discord","type":"article"},{"title":"Voice Channels FAQs — Discord","url":"https://support.discord.com/hc/en-us/articles/19583625604887-Voice-Channels-FAQs","publisher":"Discord Support","type":"documentation"}],"tags":{"industry":"communication","region":"us","decade":"2010s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'instagram-hide-likes-experiment',
  'daily',
  '{"id":"instagram-hide-likes-experiment","type":"daily","scheduled_date":"","company":"Instagram (Meta)","era":"April 2019 – May 2021 — hide-likes experiment","context":"Instagram''s like count is the most-cited social-comparison metric on the platform. Public health and academic researchers have argued for years that comparing your post''s like count to others'' is correlated with anxiety and depression, especially in teenagers. Adam Mosseri and the team announce in April 2019 that they will test hiding public like counts — first in Canada, then ramping to seven more countries, eventually globally. The test runs for two years across hundreds of millions of users. Mosseri is publicly optimistic that removing likes will ''depressurize'' the platform.","prompt":"Why run a two-year, multi-country experiment on hiding like counts — and what does the eventual outcome (Instagram makes hiding likes optional, doesn''t default it off) tell you about the relationship between metrics and user wellbeing?","reveal_quote":"It didn''t actually change nearly as much about how people felt, or how much they used the experience, as they thought it would.","reveal_quote_attribution":"Adam Mosseri, Head of Instagram — public commentary after the two-year experiment, May 2021","reveal_note":"What''s easy to miss: the experiment''s null result is the lesson, not a failure. Two years of testing the most-watched ''depressurize the platform'' hypothesis in tech showed that hiding likes didn''t materially shift user wellbeing or behavior. The reasonable interpretations: (1) the underlying social-comparison anxiety isn''t created by visible likes — it''s created by the broader medium of posting curated images for an audience and would exist with or without a number; (2) people who care about likes can still see their own counts privately, so the public hiding only removes peer-comparison, which is less of the issue than self-comparison; (3) the platform''s actual harms aren''t a single metric you can hide. The lesson: ''remove the metric'' is a tempting design intervention, but metrics are often symptoms not causes — and PMs assuming metric-removal will fix wellbeing routinely discover the underlying behavior is more durable than the surface display. Mosseri''s willingness to ship the null result publicly is the rare honest version of this lesson.","quote_type":"verbatim","sources":[{"title":"What Instagram really learned from hiding like counts","url":"https://www.platformer.news/instagrams-big-likes-anticlimax/","publisher":"Platformer","year":2021,"type":"blog"},{"title":"Instagram Will Start Hiding Like Counts for Some Users in the U.S. Next Week","url":"https://petapixel.com/2019/11/08/instagram-will-start-testing-hiding-like-counts-in-the-u-s-next-week/","publisher":"PetaPixel","year":2019,"type":"article"},{"title":"How removing ''likes'' from Instagram could affect our mental health","url":"https://www.pbs.org/newshour/science/how-removing-likes-from-instagram-could-affect-our-mental-health","publisher":"PBS News","type":"article"}],"tags":{"industry":"consumer-social","region":"us","decade":"2010s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'robinhood-confetti-removed',
  'daily',
  '{"id":"robinhood-confetti-removed","type":"daily","scheduled_date":"","company":"Robinhood","era":"March 31, 2021 — confetti animation removed","context":"From Robinhood''s launch through early 2021, completing your first trade triggers a screen-filling confetti animation. Same for hitting milestones — first deposit, first option trade, account anniversary. The pattern is borrowed from consumer games and habit apps (Duolingo''s celebrations, Headspace''s streaks). After the January 2021 GameStop chaos, Robinhood comes under heavy congressional scrutiny. Vlad Tenev testifies in February. A wrongful-death lawsuit (involving a 20-year-old user who saw a misleading negative balance and died by suicide) is publicly cited. Massachusetts regulators file a complaint citing ''gamification'' specifically. In March 2021 Robinhood announces it is removing the confetti.","prompt":"Why is removing one celebratory animation worth a press release — and what does the confetti''s removal actually signal to regulators, customers, and the broader ''is investing-as-a-game OK'' debate?","reveal_quote":"We want to remove distractions from our overall mission of democratizing investing. People should focus on the trade, not the celebration of the trade.","reveal_quote_attribution":"Robinhood — public statement on removing the confetti animation, March 31, 2021","reveal_note":"The non-obvious move: removing the confetti is not about the animation, it''s about category positioning. By March 2021, ''gamification'' had become regulatory shorthand for ''predatory toward unsophisticated retail traders.'' The confetti was the most visible, most photographable evidence Robinhood was treating trading like a game. Removing it didn''t change the product economics or the underlying gamified mechanics (push notifications, streak-style metrics, leaderboards still existed). It changed the regulatory and PR vocabulary — Robinhood could now say ''we don''t gamify'' and point to the removed confetti. The lesson: when a single visual element becomes the symbol of a controversy, removing that element is often more about controlling the conversation than fixing the underlying product. PMs in regulated categories often face the same tradeoff — substantive change vs. symbolic change — and the symbolic change is sometimes the right move on its own terms (it bought Robinhood time to do the substantive work).","quote_type":"paraphrased","sources":[{"title":"Robinhood gets rid of confetti feature amid scrutiny over gamification of investing","url":"https://www.cnbc.com/2021/03/31/robinhood-gets-rid-of-confetti-feature-amid-scrutiny-over-gamification.html","publisher":"CNBC","year":2021,"type":"article"},{"title":"Robinhood Ditches Its Confetti Animation Following Criticism","url":"https://www.bloomberg.com/news/articles/2021-03-31/robinhood-ditches-its-confetti-animation-following-criticism","publisher":"Bloomberg","year":2021,"type":"article"},{"title":"On ''Confetti Regulation'': The Wrong Way to Regulate Gamified Investing","url":"https://www.yalelawjournal.org/forum/on-confetti-regulation-the-wrong-way-to-regulate-gamified-investing","publisher":"Yale Law Journal","type":"article"}],"tags":{"industry":"fintech","region":"us","decade":"2020s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'twitter-quote-tweet-2015',
  'daily',
  '{"id":"twitter-quote-tweet-2015","type":"daily","scheduled_date":"","company":"Twitter","era":"April 2015 — quote tweet (retweet with comment) launch","context":"Until 2015, sharing someone''s tweet with your own comment requires manual workaround: copy the tweet, paste it into a new tweet inside quotation marks, then prefix with ''RT @username:'' and add your comment. The convention is awkward — quote marks eat character count, attribution is fragile, the original tweet doesn''t render visually inside yours. In April 2015, Twitter ships ''retweet with comment'' (later called ''quote tweet''): tap retweet, tap ''add a comment,'' and the original tweet renders embedded inside your new one with full attribution. Up to 116 characters for your own comment, full visual context of the source tweet.","prompt":"Why ship a feature that explicitly enables piling on / dunking on someone else''s tweet — when the obvious alternative (forcing people to reply, which is more visible inside the original conversation) creates less viral fight-amplification?","reveal_quote":"Replies happen inside the original conversation. Quote tweets happen on your own timeline, with the original embedded as evidence. They are different speech acts — one is conversation, the other is broadcast-with-attribution. The format follows the intent.","reveal_quote_attribution":"Twitter product team — paraphrased from public commentary around the quote-tweet launch","reveal_note":"What''s easy to miss: quote tweets are not a feature, they are a speech act. A reply is a conversation directed at the original poster; a quote tweet is a public commentary broadcast to your followers using someone else''s tweet as raw material. The two have very different social functions and produce very different reactions. By making the speech act easy and visually clean, Twitter accidentally optimized for one of the most virally-engaging — and most antagonistic — formats on the platform: the dunk. Quote tweets compound in ways replies don''t, partly because they cross network boundaries (your followers don''t necessarily follow the original poster) and partly because they reward escalating wit. Twitter spent the next decade trying to dial this back (encouraging replies over quote tweets, adding ''who can reply'' controls), and X (under Musk) has experimented with hiding quote tweets entirely from the original poster. The lesson: features that look like small UX improvements often unlock entire new categories of social behavior — sometimes good, sometimes ugly — that are very hard to walk back.","quote_type":"paraphrased","sources":[{"title":"Twitter improves feature that adds commentary to retweets","url":"https://www.geekwire.com/2015/say-what-twitter-improves-feature-that-adds-commentary-to-retweets/","publisher":"GeekWire","year":2015,"type":"article"},{"title":"To Reply or to Quote: Comparing Conversational Framing Strategies on Twitter","url":"https://dl.acm.org/doi/10.1145/3625680","publisher":"ACM","type":"article"},{"title":"Quote Tweeting: Over 30 Studies Dispel Some Myths","url":"https://absolutelymaybe.plos.org/2023/01/12/quote-tweeting-over-30-studies-dispel-some-myths/","publisher":"PLOS","type":"blog"}],"tags":{"industry":"consumer-social","region":"us","decade":"2010s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'whatsapp-blue-checkmarks',
  'daily',
  '{"id":"whatsapp-blue-checkmarks","type":"daily","scheduled_date":"","company":"WhatsApp","era":"November 2014 — read-receipt rollout","context":"WhatsApp has had two gray checkmarks for years — one for ''sent,'' two for ''delivered.'' In November 2014, WhatsApp ships a third state: two blue checkmarks meaning ''read.'' The moment the recipient opens the chat, the sender sees it. There''s no opt-out. Within days, backlash explodes globally — relationship-anxiety memes, jokes about ''left on read,'' complaints from users in workplaces where read receipts created uncomfortable expectations. WhatsApp ships an opt-out within two weeks, but the opt-out is symmetric: if you turn off read receipts, you stop seeing them for messages you send too.","prompt":"Why is making read receipts symmetric (you can''t see others'' if you hide yours) the entire product decision — and what does the asymmetric alternative (one-way hiding) actually break?","reveal_quote":"We wanted to give users control without creating an information asymmetry. If one person could hide their read state while seeing others'', the feature would compound into exactly the kind of anxiety it was supposed to reduce.","reveal_quote_attribution":"WhatsApp product team — paraphrased from public commentary on the read-receipts opt-out design","reveal_note":"The non-obvious move: symmetric opt-out is a fairness primitive, not a feature constraint. An asymmetric design (where one party hides their read state while still seeing others'') is technically easier and superficially more user-friendly. But it creates an information asymmetry — the person who hid is privileged. Symmetric opt-out forces a single choice: either both parties have receipts, or neither does. That preserves social fairness, but at the cost of the very people who''d benefit most from one-way hiding (people in coercive relationships, employees being monitored). The lesson: in social products, fairness primitives often beat individual-user customization. The user who wants to hide their read state for protective reasons is still vulnerable — but the alternative (asymmetric receipts) creates a worse class of harm at scale. Most product designers default to ''give the user more control''; sometimes the right answer is ''make the rules symmetric and accept the user''s individual ask must lose.''","quote_type":"paraphrased","sources":[{"title":"Latest WhatsApp lets you disable read receipts (blue checkmarks)","url":"https://www.ghacks.net/2014/11/14/latest-whatsapp-lets-you-disable-read-receipts-blue-checkmarks/","publisher":"gHacks Tech News","year":2014,"type":"article"},{"title":"How to check read receipts | WhatsApp Help Center","url":"https://faq.whatsapp.com/665923838265756/?cms_platform=web","publisher":"WhatsApp Help Center","type":"documentation"},{"title":"Understanding WhatsApp Check Marks: One or Two, Gray or Blue","url":"https://www.pandasecurity.com/en/mediacenter/whatsapp-check-marks/","publisher":"Panda Security","type":"article"}],"tags":{"industry":"communication","region":"us","decade":"2010s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'apple-pay-double-tap-confirm',
  'daily',
  '{"id":"apple-pay-double-tap-confirm","type":"daily","scheduled_date":"","company":"Apple","era":"September 2017 — iPhone X / Apple Pay redesign","context":"Apple Pay on iPhones with Touch ID is a one-step gesture: rest your finger on the home-button sensor at a payment terminal and it pays. iPhone X removes the home button. The new Face ID is passive — it authenticates when you look at the screen, without an explicit user gesture. This creates a security problem: Face ID alone could authorize a payment any time the user happens to look at the phone, including when they don''t intend to pay. Apple solves it by adding a deliberate two-step: double-click the side button to confirm intent, then Face ID authenticates. If you don''t complete a payment within 60 seconds, you have to double-click again.","prompt":"Why split payment into ''double-click side button'' AND ''Face ID'' — when biometric authentication alone is technically secure enough?","reveal_quote":"The double-click captures user intent using a physical gesture directly linked to the Secure Enclave and is resistant to forgery by a malicious process.","reveal_quote_attribution":"Apple Platform Security Guide — Apple Developer documentation","reveal_note":"What''s easy to miss: the double-click isn''t a security feature, it''s an intent capture. Biometric authentication answers ''is this the right person?'' It cannot answer ''does this person currently want to authorize this transaction?'' The two are different questions. A pickpocket pointing your phone at your face can authenticate Face ID. Only you, deliberately, can double-click the physical button on the side of the device — that''s a gesture no software process and no malicious nearby actor can fake. Splitting intent from identity into two separate steps gives the user a clear, unambiguous ''yes I am paying'' moment. The lesson: when a product action has financial or social consequences, separating intent capture from identity authentication is often the right design — even when biometric auth alone would technically work. The cost is a tiny amount of friction; the benefit is that the user never accidentally authorizes anything.","quote_type":"verbatim","sources":[{"title":"Apple Platform Security","url":"https://help.apple.com/pdf/security/en_US/apple-platform-security-guide.pdf","publisher":"Apple","type":"documentation"},{"title":"Double click of iPhone X''s Side button will confirm Apple Pay transaction","url":"https://www.idownloadblog.com/2017/09/10/side-button-confirms-apple-pay-transactions/","publisher":"iDownloadBlog","year":2017,"type":"article"},{"title":"Uses for Optic ID, Face ID, and Touch ID","url":"https://support.apple.com/guide/security/uses-for-face-id-and-touch-id-secc5227ff3c/web","publisher":"Apple Support","type":"documentation"}],"tags":{"industry":"consumer-mobile","region":"us","decade":"2010s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'slack-slash-commands',
  'daily',
  '{"id":"slack-slash-commands","type":"daily","scheduled_date":"","company":"Slack","era":"2014–2015 — slash commands as a power-user surface","context":"Slack''s UI is fundamentally a text input. Most consumer chat products (iMessage, WhatsApp) treat that input as a place for content only — anything else is in menus, buttons, and modals. Slack ships a parallel UI on top of the same input: slash commands. Type `/remind me to follow up at 4pm` and Slack creates a reminder. `/giphy cat` posts a random cat GIF. `/away` toggles your presence. `/dm @alex` opens a direct message. Power users can register custom commands tied to internal tools. The same input box is both a chat surface and a command line.","prompt":"Why build a parallel command-line interface on top of a consumer chat product — when modern UI design points exactly the other way (visual menus, fewer keyboard interactions)?","reveal_quote":"Slash commands let power users go fast without forcing casual users to learn them. The command line is invisible to the casual user — they never have to know it exists. The power user discovers it organically and never wants to go back.","reveal_quote_attribution":"Slack design team — paraphrased from public commentary on the slash-commands philosophy","reveal_note":"The choice that''s easy to miss: slash commands are a progressive-disclosure mechanism for power. A casual user never sees `/`, never learns about them, and uses Slack just fine. A power user — usually an engineer or someone who lives in the product 8 hours a day — discovers a single `/remind` from a teammate''s message and within a week has a workflow built around 15+ slash commands they couldn''t live without. The same text input serves both populations because the command syntax is invisible until invoked. Most enterprise tools force the same UI on everyone, optimizing for the median user; slash commands let Slack optimize for power users without alienating the casual cohort. The lesson: when your product has both deep power users and casual users, building two UIs is wrong (it splits the brand and the engineering investment). Building one UI with an invisible power layer is right — but it requires accepting that most users will never see the depth, and that the depth is what the most-engaged users will love.","quote_type":"paraphrased","sources":[{"title":"30+ Slack slash commands every power user needs to know","url":"https://zapier.com/blog/slack-slash-commands/","publisher":"Zapier","type":"blog"},{"title":"Implementing slash commands","url":"https://api.slack.com/interactivity/slash-commands","publisher":"Slack Developer Docs","type":"documentation"},{"title":"22 Slack Slash Commands for Power Users","url":"https://www.techbloat.com/22-slack-slash-commands-for-power-users.html","publisher":"TechBloat","type":"article"}],"tags":{"industry":"saas","region":"us","decade":"2010s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'iphone-silent-switch',
  'daily',
  '{"id":"iphone-silent-switch","type":"daily","scheduled_date":"","company":"Apple","era":"June 2007 — original iPhone launch","context":"Apple''s design philosophy since the original iMac has been ruthless about physical buttons — fewer is always better. The original iPhone famously ships with one button on the front (the home button). And yet, on the side, there is one additional toggle: a tiny mechanical switch labeled with a speaker/silent icon. Flip it down: silent. Flip it up: ring. No software equivalent at launch. The switch is hardware-only, visible from across a room, audibly clickable. It survives every iPhone redesign until 2023, when Apple finally replaces it with a programmable ''Action button'' on iPhone 15 Pro.","prompt":"Why keep a dedicated physical switch — the only side toggle on the original iPhone — for a single function (silencing the ringer) when Apple''s design language explicitly minimizes physical buttons?","reveal_quote":"If you were going to use this thing as your main phone, you needed to be able to put it on silent or vibrate quickly and easily so you didn''t blow up a meeting or theater. The safest and easiest way to make sure your phone was on silent was with the switch.","reveal_quote_attribution":"Apple design philosophy — paraphrased from public commentary on the original iPhone''s silent switch","reveal_note":"What''s easy to miss: the silent switch violates Apple''s no-buttons philosophy on purpose. The use case (need to silence in a meeting / theater / loud-public-failure scenario) is high-stakes, time-sensitive, and tactile — you need to silence the phone without looking at it, without unlocking it, often without taking it out of your pocket. A software toggle would fail every one of those tests. The switch''s existence is an admission that pure software UI is wrong when the cost of mis-using the product is social embarrassment in front of dozens of people. The fact that Apple kept it for 16 years across every iPhone redesign — eventually replacing it with the Action button (configurable but still physical) — shows the strength of the principle. The lesson: physical controls aren''t always primitive holdovers. When the failure mode is socially expensive and time-sensitive, hardware feedback beats software UI. Same logic underlies the camera shutter button on real cameras, the volume rocker on every phone, and the emergency stop on every industrial machine.","quote_type":"paraphrased","sources":[{"title":"Apple is killing the iPhone''s silent switch","url":"https://techcrunch.com/2023/09/12/apple-is-killing-the-iphones-silent-switch/","publisher":"TechCrunch","year":2023,"type":"article"},{"title":"A closer look at the Ring/Silent switch","url":"https://blog.prototypr.io/a-closer-look-at-the-ring-silent-switch-430c93512ff0?gi=8485ca8b33c6","publisher":"Prototypr","type":"blog"},{"title":"Silence iPhone","url":"https://support.apple.com/guide/iphone/silence-iphone-iph81c7fd7d1/ios","publisher":"Apple Support","type":"documentation"}],"tags":{"industry":"consumer-mobile","region":"us","decade":"2000s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'apple-dnd-while-driving',
  'daily',
  '{"id":"apple-dnd-while-driving","type":"daily","scheduled_date":"","company":"Apple","era":"September 2017 — iOS 11 launch","context":"Distracted-driving deaths in the US have risen ~10% from 2014 to 2017, with smartphone notifications cited as a leading cause. Apple sits in an awkward position: every iPhone shipped is a potential source of driver distraction. Notifications, texts, calls, news pings — all designed to maximize engagement. In iOS 11, Apple ships ''Do Not Disturb While Driving'': when the iPhone detects acceleration consistent with being in a moving vehicle (via the accelerometer + GPS), it automatically silences notifications, dims the screen, and sends configurable auto-replies to incoming texts. The feature is prompted at iOS 11 setup but not forced on.","prompt":"Why ship a feature that explicitly reduces iPhone engagement during driving — when Apple''s revenue depends partly on people using the iPhone as much as possible?","reveal_quote":"Do Not Disturb While Driving is designed to mute incoming calls, texts, and notifications while you''re driving to cut down on accident-causing distractions. When the automatic setting is enabled, Do Not Disturb While Driving will turn on whenever your iPhone detects the acceleration of a vehicle.","reveal_quote_attribution":"Apple — Do Not Disturb While Driving documentation, iOS 11","reveal_note":"The non-obvious move: ''reduce engagement'' is the brand statement. Apple''s relationship with its users is fundamentally different from Meta''s or Google''s — Apple monetizes the device, not the user''s attention. That structural difference frees Apple to ship features that explicitly reduce notification frequency, because doing so doesn''t hurt revenue and reinforces the ''we work for you, not advertisers'' positioning. Shipping DNDWD signals to every user that Apple is the company willing to make using the iPhone less frequent when the user''s life depends on it. The feature itself is technically modest (accelerometer-based detection, a dimmed screen, an auto-reply); the signaling value is durable. The lesson: companies whose revenue depends on user attention can never credibly ship features that reduce that attention. Companies whose revenue depends on the device (Apple) or on subscription (Netflix, Spotify) have a structural permission to ship anti-engagement features that becomes a brand asset.","quote_type":"verbatim","sources":[{"title":"Stay focused while driving with iPhone","url":"https://support.apple.com/guide/iphone/stay-focused-while-driving-iphae754533b/ios","publisher":"Apple Support","type":"documentation"},{"title":"Here''s How iOS 11''s Do Not Disturb While Driving Feature Works","url":"https://www.macrumors.com/2017/06/30/ios-11-do-not-disturb-while-driving/","publisher":"MacRumors","year":2017,"type":"article"},{"title":"How to Use Do Not Disturb While Driving","url":"https://www.macrumors.com/how-to/do-not-disturb-while-driving-ios-11/","publisher":"MacRumors","type":"article"}],"tags":{"industry":"consumer-mobile","region":"us","decade":"2010s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'slack-emoji-reactions',
  'daily',
  '{"id":"slack-emoji-reactions","type":"daily","scheduled_date":"","company":"Slack","era":"July 2015 — emoji reactions launch","context":"Pre-2015 Slack workplaces have a structural noise problem: someone announces a deploy, and 15 people reply ''thanks!'' / ''👍'' / ''great'' / ''congrats''. The replies are themselves notifications that disrupt everyone in the channel. The behavior is socially expected (you can''t ignore a coworker''s good news) but operationally awful. In July 2015, Slack ships emoji reactions — tap a reaction below any message, attach a 👍 or 🎉 or 😂. Reactions don''t fire notifications. Internal tests at Slack itself before launch show channel message volume drops materially.","prompt":"Why are emoji reactions a different product than a ''like'' button — and what''s the operational effect of the design choice not to send a notification?","reveal_quote":"In our internal tests, we''ve found that emoji reactions diminish the amount of noise in a channel. People can acknowledge each other without flooding the conversation.","reveal_quote_attribution":"Slack team — paraphrased from the public emoji-reactions launch commentary, July 2015","reveal_note":"The choice that''s easy to miss: emoji reactions are not a Facebook-style ''like'' counter — they are a noise-reduction primitive. A ''like'' button on a social feed adds a counter; in a chat channel, the equivalent operational outcome would be 15 reply messages, each with its own notification, each disrupting every channel member. By making reactions both (a) silent and (b) co-located with the message, Slack changed the social cost of acknowledging coworkers from ''I have to write something, which interrupts everyone'' to ''I tap an emoji, which interrupts no one.'' The result was an aggregate drop in channel message volume — counterintuitively, the new feature reduced total messages. The lesson: features that reduce friction for an unwanted-but-socially-required behavior often improve aggregate product health more than features that enable new behaviors. Twitter''s ''like'' is a similar design; the comment-vs-reaction split is what makes social products operate at scale.","quote_type":"paraphrased","sources":[{"title":"Slack got the message about emoji ''reactions''","url":"https://fortune.com/2015/07/09/slack-emoji/","publisher":"Fortune","year":2015,"type":"article"},{"title":"Slack''s New Emoji-Based Reactions: Way, Way More Than A ''Like'' Button","url":"https://www.fastcompany.com/3048384/slacks-new-emoji-based-reactions-way-way-more-than-a-like-button","publisher":"Fast Company","year":2015,"type":"article"},{"title":"Use emoji and reactions","url":"https://slack.com/help/articles/202931348-Use-emoji-and-reactions","publisher":"Slack","type":"documentation"}],"tags":{"industry":"saas","region":"us","decade":"2010s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'tinder-minimal-onboarding',
  'daily',
  '{"id":"tinder-minimal-onboarding","type":"daily","scheduled_date":"","company":"Tinder","era":"September 2012 — launch","context":"Online-dating onboarding in 2012 is a 30-90 minute commitment. OkCupid asks ~50 personality questions to power compatibility matching. eHarmony has a multi-step compatibility quiz. Match.com requires bios, height, hobbies, religion, salary range. The implicit promise is that more data = better matches. Tinder ships with the opposite signup: connect Facebook (auto-pulls name, age, photos, mutual friends), set distance, set age range, start swiping. Total setup: under 60 seconds. No questionnaire. No compatibility algorithm. No bio required.","prompt":"Why ship a dating app with almost zero onboarding signal — when every existing dating product treats onboarding data as the entire matching engine?","reveal_quote":"We didn''t compete with OkCupid on quality of match. We competed with the OkCupid signup form. Every minute someone spends in onboarding is a minute they''re not in the product feeling the dopamine that makes them stay.","reveal_quote_attribution":"Tinder team — paraphrased from public commentary on the original onboarding philosophy","reveal_note":"The non-obvious move: minimal onboarding is not just lower friction — it''s a positioning statement that the product''s value is the in-app experience, not the matching algorithm. OkCupid''s long signup signals ''we will work hard to find your soulmate''; Tinder''s no-signup signals ''open the app, swipe, see what happens.'' The two are different products solving different jobs. Tinder''s user activation rate (signup → first swipe) was structurally far higher than any competitor''s. That activation gap compounded into Tinder''s overwhelming scale advantage. The lesson: when a competitor''s product depth is anchored in onboarding data, you can sometimes win by structurally refusing to collect that data — making the absence a differentiator. The cost (worse ''matches'' on paper) is dwarfed by the activation gain.","quote_type":"paraphrased","sources":[{"title":"Tinder - Onboarding | App Fuel","url":"https://theappfuel.com/examples/tinder_onboarding","type":"blog"},{"title":"Tinder vs. OkCupid: Is There a Real Difference?","url":"https://www.privateinternetaccess.com/blog/tinder-vs-okcupid/","publisher":"Private Internet Access","type":"article"},{"title":"How To Onboard People Into Your Product — The Right Way","url":"https://about.crunchbase.com/blog/user-onboarding/","publisher":"Crunchbase","type":"blog"}],"tags":{"industry":"consumer-social","region":"us","decade":"2010s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'pinterest-pick-5-topics',
  'daily',
  '{"id":"pinterest-pick-5-topics","type":"daily","scheduled_date":"","company":"Pinterest","era":"2010s — onboarding optimization","context":"Most social products onboard with empty feeds — log in, see nothing, search for friends to follow. Pinterest takes a different approach: every new user is asked to pick 5 topics they''re interested in (cooking, travel, fitness, fashion, etc.) BEFORE seeing the home feed. Once you''ve picked five topics, Pinterest builds a personalized feed of pins from those categories. The ''follow 5 topics'' screen is non-skippable in early versions. Casey Winters and the Pinterest growth team optimize this onboarding obsessively — the 5-topic minimum is the threshold that produces the right initial-feed experience.","prompt":"Why force every new user through a 5-topic interest picker — when most social products treat onboarding friction as the enemy and prefer to drop users straight into the feed?","reveal_quote":"Pinterest''s value depends entirely on the home feed showing you something interesting. An empty home feed is product death. Five topics was the minimum input that let our algorithm produce a personalized feed worth coming back to. Less than five = bad first session = no second session.","reveal_quote_attribution":"Casey Winters / Pinterest growth team — paraphrased from public commentary on the onboarding flow","reveal_note":"What''s easy to miss: the 5-topic picker is not friction — it''s the input that makes the rest of the product work. Most social products can survive an empty initial feed because the user has people to follow / search for. Pinterest''s product is content discovery, so an empty feed is structurally a dead product. Forcing 5 topics inverts the typical onboarding logic — the friction enables the product instead of delaying it. Activation rate (signup → meaningful session) jumped materially after the 5-topic threshold was introduced and tuned. The lesson: onboarding friction is contextually right or wrong depending on whether the product can deliver value at zero input. Products whose value depends on collected user signal NEED the friction; products whose value compounds from a known social graph (Facebook, Instagram in early days) don''t.","quote_type":"paraphrased","sources":[{"title":"How Pinterest perfected user onboarding","url":"https://www.appcues.com/blog/casey-winters-pinterest-user-onboarding","publisher":"Appcues","type":"blog"},{"title":"Pinterest''s value-driven onboarding flow","url":"https://goodux.appcues.com/blog/pinterests-value-driven-onboarding-flow","publisher":"GoodUX (Appcues)","type":"blog"},{"title":"How Pinterest Onboards New Users","url":"https://www.useronboard.com/how-pinterest-onboards-new-users/","publisher":"User Onboarding","type":"blog"}],"tags":{"industry":"consumer-social","region":"us","decade":"2010s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'cashapp-cashtag-identity',
  'daily',
  '{"id":"cashapp-cashtag-identity","type":"daily","scheduled_date":"","company":"Cash App (Block / Square)","era":"March 2015 — $cashtag launch","context":"P2P payments in 2015 require identifying the recipient — usually by phone number or email. Both are clunky: phone numbers are fragmented across SIM cards and country codes; email is tied to a sometimes-private inbox. Square Cash (later Cash App) ships $cashtag — a unique payment-identity username, prefixed with $, that anyone can claim. Want to receive money? Tell people your $cashtag. Type it on a sign, a business card, an Instagram bio. The $cashtag becomes a public-by-design payment handle, simultaneously memorable, claimable, and visible.","prompt":"Why design a public payment handle (a $cashtag) — when the entire payments industry treats account identifiers as private (account numbers, routing numbers, card numbers)?","reveal_quote":"$cashtag is a unique username that allows users to send and receive money. Anyone can create a personalized name like $ErinHills or $SunsetPhotography and get paid privately and securely.","reveal_quote_attribution":"Square — official $cashtag launch announcement, March 2015","reveal_note":"The non-obvious move: making the payment identifier public is a positioning statement, not just a UX detail. Visa / Mastercard / banks treat account numbers as secrets to be guarded. Cash App treats $cashtags as personal-brand assets to be displayed. That single design choice converts ''asking for money'' from a social-friction event (''text me your account info'') into a brand-friendly one (''venmo me'' / ''cashapp me $whoever''). The $cashtag becomes a discoverable identity layer — small businesses, tip jars, street performers, freelancers all use $cashtags as the lowest-friction way to receive money. Venmo''s @username had similar mechanics; Cash App''s $-prefix made the brand even more identifiable in any text. The lesson: the formats and visual prefixes of identifiers are part of the product''s brand, not just plumbing. The $ in $cashtag does as much marketing as a billion dollars of paid acquisition.","quote_type":"verbatim","sources":[{"title":"Square Cash is Open for Business","url":"https://squareup.com/us/en/press/introducing-cashtags","publisher":"Square Press","year":2015,"type":"press-release"},{"title":"Square''s $Cashtag Makes Payments URL-Specific","url":"https://www.pymnts.com/news/2015/squares-cashtag-makes-payments-url-specific/","publisher":"PYMNTS","year":2015,"type":"article"},{"title":"Cash App — Wikipedia","url":"https://en.wikipedia.org/wiki/Cash_App","type":"article"}],"tags":{"industry":"fintech","region":"us","decade":"2010s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'notion-slash-commands',
  'daily',
  '{"id":"notion-slash-commands","type":"daily","scheduled_date":"","company":"Notion","era":"2016+ — Notion''s editor primitive","context":"Document editors in the 2010s separate content creation (typing) from content structure (formatting menus, drop-downs, paragraph styles). Google Docs, Microsoft Word, and most note-taking apps use this split. Notion ships with a different primitive: type `/` anywhere in a document, and a fuzzy-search menu appears with every block type — heading, bulleted list, toggle, code, embed, table, database. Hit Enter on the type you want and it inserts inline. Existing content can also be ''turned into'' a different block via the same `/` interface. Slash commands are the canonical way to do almost anything in the Notion editor.","prompt":"Why bet the entire editor on a `/`-command primitive — when most users (especially non-technical ones) have never used a command-line interface and might find the syntax confusing?","reveal_quote":"Slash commands let us add hundreds of block types without ever showing them in a toolbar. The complexity is searchable, not visible. A new user types ''/'' and discovers what''s possible; a power user types ''/h1'' and gets a heading without lifting their hand from the keyboard.","reveal_quote_attribution":"Notion design team — paraphrased from public commentary on the editor design","reveal_note":"The choice that''s easy to miss: slash commands are progressive disclosure for an arbitrarily-deep feature set. A toolbar can hold ~10-20 block types before becoming overwhelming; a slash-menu can hold hundreds because they''re searched, not browsed. As Notion grew from ~10 block types to 50+ to 100+ (with AI blocks, embeds, database views, formula columns), the slash UI scaled without changing — the user experience was the same when the menu had 10 options as when it had 100. By making `/` the universal entry point for all block-type discovery, Notion separated complexity-of-features from complexity-of-UI. The same primitive works for the brand-new user and the 5-year power user. The lesson: when a product''s value depends on having many features, a single keyboard-summoned, fuzzy-searched command surface beats any toolbar / menu structure for both discoverability AND speed.","quote_type":"paraphrased","sources":[{"title":"Using slash commands","url":"https://www.notion.com/help/guides/using-slash-commands","publisher":"Notion Help Center","type":"documentation"},{"title":"Transforming content blocks in Notion","url":"https://www.notion.com/help/guides/transforming-content-blocks-in-notion","publisher":"Notion Help Center","type":"documentation"},{"title":"Top Notion Commands | Keyboard shortcuts","url":"https://blog.prototion.com/guide-notion-keyboard-shortcuts-and-commands-2023/","publisher":"Prototion","type":"blog"}],"tags":{"industry":"productivity","region":"us","decade":"2010s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'linear-cmd-k',
  'daily',
  '{"id":"linear-cmd-k","type":"daily","scheduled_date":"","company":"Linear","era":"2019+ — command-bar primitive","context":"Project-management tools like Jira, Asana, and ClickUp all expose hundreds of features through visible UI — sidebars, top navs, drop-downs, modals, settings pages. Configurability is the brand. Linear takes the opposite approach: most features are accessible via a single keyboard shortcut, Cmd+K (Mac) / Ctrl+K (Windows), which opens a fuzzy-search command palette. Need to assign an issue? Cmd+K → ''assign to'' → pick name. Need to change priority? Cmd+K → ''priority'' → pick level. The command palette is contextual — it knows what you have selected and only shows applicable actions.","prompt":"Why hide most of the product''s features behind a single keyboard shortcut — and what kind of user does the design implicitly select for vs. exclude?","reveal_quote":"Cmd+K is a contextual command menu. It gives you access to all actions applicable to your view or selection. If you''re in the middle of writing something, you don''t even have to take your hands off the keyboard — just a few quick keystrokes and you can find the action you need and run it.","reveal_quote_attribution":"Linear — Contextual command menu changelog, October 2019","reveal_note":"What''s easy to miss: hiding features behind Cmd+K is a deliberate user-selection mechanism. The first day in Linear, a new user has no idea Cmd+K exists. They''re forced to discover it organically (or learn from a teammate). The discovery is a small ritual that converts a casual user into a power user — once you know Cmd+K, every other PM tool feels slow. Conversely, a customer who hates keyboard shortcuts will leave Linear within a week, which is correct — Linear''s product economics depend on selling to high-engagement engineering teams who value speed over discoverability. Most PM tools optimize for casual-first-time discoverability (visible UI, lots of menus); Linear optimizes for the reverse, deliberately filtering out users who would generate support load and brand-dilute the product. Same logic underlies the original Linear keyboard-onboarding decision (already in the daily pool — same company, similar trade). The lesson: feature-discoverability vs. keyboard-speed is a brand-positioning tradeoff, not just a UX tradeoff. Pick which kind of user the product is for — the choice will define the product more than any feature.","quote_type":"verbatim","sources":[{"title":"Contextual command menu — Changelog","url":"https://linear.app/changelog/2019-10-07-contextual-command-menu","publisher":"Linear Changelog","year":2019,"type":"documentation"},{"title":"Command K Bars","url":"https://maggieappleton.com/command-bar","publisher":"Maggie Appleton","type":"blog"},{"title":"How to build a remarkable command palette","url":"https://blog.superhuman.com/how-to-build-a-remarkable-command-palette/","publisher":"Superhuman","type":"blog"}],"tags":{"industry":"devtools","region":"us","decade":"2010s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'ipod-shuffle-no-screen',
  'daily',
  '{"id":"ipod-shuffle-no-screen","type":"daily","scheduled_date":"","company":"Apple","era":"January 11, 2005 — iPod Shuffle launch","context":"By 2005, every flash-memory music player on the market — Creative MuVo, Rio Forge, iRiver, etc. — has a small LCD screen, complicated controls, and lets users navigate to specific tracks. The user can SEE what song is playing and choose what comes next. Apple ships the iPod Shuffle: a flash-based player smaller than a pack of gum, $99 for 512MB / $149 for 1GB, with no screen at all. Five physical buttons (play/pause, next/previous, volume up/down). To pick songs, you sync via iTunes; to listen, you press play and let the device ''shuffle.''","prompt":"Why ship a music player without a screen — when every competitor includes one and consumers explicitly want to see what''s playing?","reveal_quote":"With most flash-memory music players users must use tiny displays and complicated controls to find their music; with iPod shuffle you just relax and it serves up new combinations of your music every time you listen.","reveal_quote_attribution":"Steve Jobs, Apple CEO — iPod Shuffle launch press release, January 11, 2005","reveal_note":"The non-obvious move: removing the screen converted a missing feature into a positioning statement. Without a screen, the product''s job changes — you''re not browsing music, you''re trusting the shuffle. That trust is the entire pitch. The screen would have been a $5-10 BOM cost; the absence saved real money but more importantly defined the product''s emotional identity. The Shuffle competed with similarly-priced screen-equipped players and outsold them — capturing 43% of the flash-player market within a single month, 58% by month three. The lesson: deliberately omitting an industry-standard feature can be a strategy if (a) the absence simplifies the product''s promise, (b) the saved cost / size translates into a meaningful price or form-factor advantage, and (c) the lost capability is the right one to give up given the use case. Most product teams add features to differentiate; the harder discipline is to remove features and let the absence do the differentiation.","quote_type":"verbatim","sources":[{"title":"Apple Introduces iPod shuffle","url":"https://www.apple.com/newsroom/2005/01/11Apple-Introduces-iPod-shuffle/","publisher":"Apple Newsroom","year":2005,"type":"press-release"},{"title":"iPod Shuffle — Wikipedia","url":"https://en.wikipedia.org/wiki/IPod_Shuffle","type":"article"},{"title":"iPod shuffle randomizes our music: Today in Apple history","url":"https://www.cultofmac.com/apple-history/ipod-shuffle-launch","publisher":"Cult of Mac","type":"article"}],"tags":{"industry":"consumer-mobile","region":"us","decade":"2000s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'snapchat-lenses-launch',
  'daily',
  '{"id":"snapchat-lenses-launch","type":"daily","scheduled_date":"","company":"Snapchat","era":"September 2015 — Lenses launch via Looksery acquisition","context":"Snapchat in mid-2015 has filters — date stamps, geofilters tied to a location, color overlays. They''re decorative. In September 2015 Snap acquires Looksery — a Ukrainian face-tracking computer-vision team — for ~$150M. Within weeks Snap ships ''Lenses'': real-time AR overlays that detect a face in the camera viewfinder and warp it (rainbow vomit, dog ears, face swap). Open the camera, hold on a face, swipe through Lenses. The interaction is immediate, joyful, and the social-share unlock is instant.","prompt":"Why is buying a face-tracking computer-vision team and shipping AR Lenses 6 weeks later a different product than ''better filters'' — and what kind of behavior does the AR primitive unlock?","reveal_quote":"The Looksery team gave us face-tracking that runs in real-time on phone hardware. That capability turned the camera from a tool for capturing photos into a tool for transforming yourself. The AR primitive is the entire shift.","reveal_quote_attribution":"Snapchat product team — paraphrased from public commentary on the Lenses launch and the Looksery acquisition","reveal_note":"What''s easy to miss: Lenses are not a filter feature, they are a creator tool. A static filter (date stamp, color overlay) decorates a moment that was going to happen anyway. A Lens (puppy-face, rainbow-vomit) creates a moment — the user holds the camera up specifically to see what the Lens does, then sends it. That conversion of the camera from passive capture to active transformation is what made Snapchat the dominant teen-camera app for years and what TikTok later cloned wholesale (TikTok ''Effects'' = Snap Lenses with a creator marketplace). Buying Looksery''s face-tracking tech compressed years of internal R&D into one transaction. The lesson: when a capability (here: real-time on-device computer vision) unlocks a fundamentally new user behavior, acquiring the capability instead of building it can collapse the time-to-impact from years to weeks. Same logic Apple used buying PA Semi (2008) for chip design and Beats (2014) for headphones / Apple Music staff.","quote_type":"paraphrased","sources":[{"title":"Snapchat Acquires Looksery To Power Its Animated Lenses","url":"https://techcrunch.com/2015/09/15/snapchat-looksery/","publisher":"TechCrunch","year":2015,"type":"article"},{"title":"The Brief History of Social Media AR Filters","url":"https://www.indestry.com/blog/the-brief-history-of-social-media-ar-filters","publisher":"INDE","type":"blog"},{"title":"Looksery — Wikipedia","url":"https://en.wikipedia.org/wiki/Looksery","type":"article"}],"tags":{"industry":"consumer-social","region":"us","decade":"2010s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'strava-segments-koms',
  'daily',
  '{"id":"strava-segments-koms","type":"daily","scheduled_date":"","company":"Strava","era":"2009+ — segments + KOM/QOM design","context":"Fitness tracking apps in the late 2000s (Nike+, MapMyRun, Endomondo) record runs and rides as private logs. Each session sits in your own history; comparison to others is via aggregate distance / time leaderboards at best. Strava ships a different primitive: ''segments.'' Any user can mark a stretch of road or trail as a named segment (a hill climb, a sprint section, a famous loop). Every Strava user who rides or runs through that segment gets ranked against everyone else who''s done it. The fastest person ever holds the KOM (King of the Mountain) or QOM (Queen). Local Legend goes to whoever''s done the segment most often in a 90-day window.","prompt":"Why turn private fitness tracking into geo-anchored leaderboards — and what kind of behavior does the segment + KOM design produce that aggregate stats don''t?","reveal_quote":"Strava has built the best gamification element of all fitness apps available. KOMs convert a solo activity into a competitive game played against everyone who''s ever moved through the same physical space.","reveal_quote_attribution":"Strava community / fitness press — paraphrased from public commentary on Strava''s segment design","reveal_note":"The non-obvious move: segments + KOMs convert a solitary activity (riding, running) into an asynchronous social game without requiring users to be in the same place at the same time. You ride your usual loop; you discover, after upload, that you''re 5th on the local hill segment, 12 seconds behind KOM. That comparison creates a specific motivation (chase the KOM next time) that aggregate distance leaderboards can''t produce — because aggregate stats reward time-spent, while segments reward intensity and skill. Local Legend (added later) handles the consistency-not-speed cohort. The combination produced one of the most-engaged consumer fitness communities ever built — Strava''s retention and engagement materially outperform every competitor''s. The lesson: when you can geo-anchor a competitive primitive to specific physical locations, you compound the value of every user''s data into a public good (the segment leaderboard) that becomes the reason the next user joins.","quote_type":"paraphrased","sources":[{"title":"What''s a segment?","url":"https://support.strava.com/hc/en-us/articles/216917137-What-s-a-segment","publisher":"Strava Support","type":"documentation"},{"title":"Strava Segments","url":"https://support.strava.com/hc/en-us/articles/216918167-Strava-Segments","publisher":"Strava Support","type":"documentation"},{"title":"Strava Riding & Gamification","url":"https://iceboxskiandbike.medium.com/level-up-with-every-ride-650898cc2961","publisher":"Medium","type":"blog"}],"tags":{"industry":"consumer-mobile","region":"us","decade":"2010s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'airtag-anti-stalking',
  'daily',
  '{"id":"airtag-anti-stalking","type":"daily","scheduled_date":"","company":"Apple","era":"April 30, 2021 — AirTag launch","context":"Bluetooth trackers (Tile, Chipolo) have existed for years — small tags you attach to keys / wallets to find them with your phone. Apple ships AirTag in April 2021 with a critical structural difference: AirTags piggyback on the entire Find My network — every iPhone, iPad, and Mac in the world acts as an anonymous relay node. That means an AirTag can be located anywhere a Find My device passes within Bluetooth range — no more ''last seen near home'' problem. The capability also unlocks the obvious risk: AirTags can be slipped into a stranger''s bag or car, then tracked anywhere in the world. Apple ships safety features at launch: any iPhone that detects an AirTag traveling with it (not its owner) for an extended time pops a ''this AirTag may be tracking you'' alert. AirTags also play a sound when separated from their owner.","prompt":"Why design the privacy alerts simultaneously with the tracking capability — when most consumer devices ship safety features later (only after the inevitable misuse stories)?","reveal_quote":"AirTag is designed to discourage unwanted tracking. If someone else''s AirTag finds its way into your stuff, your iPhone will notice it''s traveling with you and send you an alert. After a while, if you still haven''t found it, the AirTag will start playing a sound to let you know it''s there.","reveal_quote_attribution":"Apple — official AirTag privacy and safety announcement, April 2021","reveal_note":"What''s easy to miss: shipping safety features at launch is a recognition that the product has dual-use risk. Most tracking products (Tile, Chipolo) shipped without anti-stalking features and added them later only after well-reported abuse cases. Apple''s choice to ship them at launch reduced the early-adopter abuse window — but the safety features were calibrated for iPhone users, not Android users (Android users had to install a separate app to get the equivalent alert), which became a multi-year point of regulatory and press criticism. Apple eventually shipped Android compatibility (jointly with Google in 2024). The lesson: when your product enables a behavior with foreseeable misuse, shipping the safety mechanism in v1 is materially cheaper (in brand and regulatory cost) than shipping it after the inevitable harm stories surface. The cost of building safety in v1 is small; the cost of retrofitting safety after a crisis is huge.","quote_type":"verbatim","sources":[{"title":"An update on AirTag and unwanted tracking","url":"https://www.apple.com/newsroom/2022/02/an-update-on-airtag-and-unwanted-tracking/","publisher":"Apple Newsroom","year":2022,"type":"press-release"},{"title":"Apple AirTag has built-in anti-stalking tech","url":"https://www.popsci.com/story/technology/apple-airtag-anti-stalking-privacy-tech/","publisher":"Popular Science","type":"article"},{"title":"Privacy Alert for Unknown AirTag Triggers When a User Returns Home","url":"https://www.macrumors.com/2021/04/30/airtag-privacy-alert-trigger-arriving-home/","publisher":"MacRumors","year":2021,"type":"article"}],"tags":{"industry":"consumer-mobile","region":"us","decade":"2020s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'gmail-tabs-2013',
  'daily',
  '{"id":"gmail-tabs-2013","type":"daily","scheduled_date":"","company":"Google (Gmail)","era":"May 29, 2013 — tabbed inbox launch","context":"Email in 2013 is dominated by the ''flat inbox'' — every message arrives in one chronological stream, regardless of whether it''s from a friend, a marketing newsletter, a Facebook notification, or an Amazon receipt. The result is overwhelming, especially in personal Gmail accounts where ~70% of incoming volume is automated. Gmail ships a tabbed inbox: messages auto-categorized into Primary (people), Social (Facebook/Twitter/etc), Promotions (marketing newsletters, deals), Updates (receipts, bills, confirmations), and Forums (mailing lists, message boards). Algorithmic categorization, no user training required. Marketers panic — Promotions tab visibility is dramatically lower than inbox visibility, threatening every email campaign they''ve built.","prompt":"Why algorithmically demote 70% of inbox volume into auto-categorized tabs — when the user could have simply filtered or labeled email themselves with rules?","reveal_quote":"Most users never set up email rules — that''s a power-user behavior. Tabs gave the categorization benefit without requiring any user effort. The ''Primary'' tab is what email is supposed to feel like: messages from people you care about, not the marketing pile.","reveal_quote_attribution":"Gmail product team — paraphrased from public commentary on the tabbed-inbox launch","reveal_note":"The choice that''s easy to miss: Gmail tabs are a default-applied filter that almost no user would have built themselves. Email rules / filters have existed since Outlook in the 90s; ~5% of email users actually set them up. Tabs converted that 5%-power-user behavior into 100%-everyone-by-default, simply by making categorization the platform''s job, not the user''s. The marketer pushback was loud and (mostly) correct — Promotions visibility dropped sharply. But Gmail''s user-engagement metrics improved meaningfully because the Primary tab became scannable in a way the flat inbox wasn''t. The trade — 70% reduction in marketer reach for a measurable improvement in user-perceived inbox quality — was an alignment statement: Gmail is for users, not for the senders advertising to them. The lesson: defaults applied at scale do work that user-configurable settings never accomplish, because most users don''t configure anything. When a power-user behavior is universally beneficial, making it default may be more impactful than teaching everyone how to set it up.","quote_type":"paraphrased","sources":[{"title":"Big Gmail overhaul adds tabs for social updates, bills","url":"https://mynews13.com/fl/orlando/news/2013/5/30/big_gmail_overhaul_a","publisher":"MyNews13","year":2013,"type":"article"},{"title":"Embracing Gmail''s Promotions Tab","url":"https://inboxmonster.com/blog/gmail-promotions-tab-inbox-placement","publisher":"Inbox Monster","type":"article"},{"title":"Organize your emails into categories","url":"https://support.google.com/mail/answer/3094499?hl=en&co=GENIE.Platform%3DDesktop","publisher":"Gmail Help","type":"documentation"}],"tags":{"industry":"productivity","region":"us","decade":"2010s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'discord-stage-channels',
  'daily',
  '{"id":"discord-stage-channels","type":"daily","scheduled_date":"","company":"Discord","era":"March 2021 — Stage Channels launch","context":"Clubhouse explodes in early 2021 — invite-only audio rooms become the most-talked-about consumer-app launch since TikTok. Every social platform scrambles to ship a competitor: Twitter Spaces, Facebook Live Audio Rooms, Spotify Greenroom. Discord — already the dominant persistent voice-rooms platform for gaming communities — ships ''Stage Channels'' on March 31, 2021. The format mirrors Clubhouse: structured audio rooms with speakers + listeners, raise-hand-to-speak, moderator controls. The key Discord-specific advantage: Stage Channels live inside existing Discord servers (communities the user already belongs to), and ship to all platforms simultaneously (web, iOS, Android, desktop) — versus Clubhouse, which is iOS-only at launch and standalone-app-only.","prompt":"Why ship a Clubhouse clone INSIDE existing Discord servers (rather than as a standalone app) — and what does the in-server placement actually do that a standalone audio app can''t?","reveal_quote":"Stage Channels are specific to community servers. The audio event isn''t a separate app you have to download — it''s a kind of channel inside a community you already belong to. The community is the discovery mechanism.","reveal_quote_attribution":"Discord — paraphrased from official Stage Channels documentation and launch commentary, 2021","reveal_note":"What''s easy to miss: Stage Channels'' positioning isn''t ''compete with Clubhouse on audio quality'' — it''s ''embed the audio format inside an existing community context.'' Clubhouse''s structural problem was that every audio room was discovered cold (you had to know it was happening); Discord rooms inherit the audience of an existing server. A book-club server hosts a Stage; the 5,000 members of that server already get notified. That structural difference made Discord Stage Channels more durable than Clubhouse — Clubhouse''s audience peaked in mid-2021 and collapsed to <10% of peak by 2023. Discord''s audio infrastructure quietly outlasted the entire Clubhouse-clone wave. The lesson: when an existing platform has the user-graph + the engagement loop, a feature embedded inside that platform usually beats a standalone competitor. Twitter Spaces'' similar embedding into Twitter likewise outlasted Clubhouse-the-app.","quote_type":"paraphrased","sources":[{"title":"Discord is launching new Clubhouse-like channels for audio events","url":"https://techcrunch.com/2021/03/31/discord-stage-channels-voice-events/","publisher":"TechCrunch","year":2021,"type":"article"},{"title":"Discord launches Stage Channels, its version of Clubhouse audio rooms","url":"https://www.xda-developers.com/discord-stage-channels-clubhouse-audio-rooms/","publisher":"XDA Developers","year":2021,"type":"article"},{"title":"Clubhouse vs. Discord: Two Apps for Audio-Based Connection","url":"https://amt-lab.org/podcasts-interviews/2021/4/clubhouse-vs-discord","publisher":"Arts Management & Technology Lab","year":2021,"type":"article"}],"tags":{"industry":"communication","region":"us","decade":"2020s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'chatgpt-memory-feature',
  'daily',
  '{"id":"chatgpt-memory-feature","type":"daily","scheduled_date":"","company":"OpenAI","era":"February 2024 — Memory rollout","context":"ChatGPT had Custom Instructions since July 2023 — visible text boxes where users explicitly write ''what to know about me'' and ''how to respond.'' Useful for power users who took the time to fill them in, but most users don''t. In February 2024 OpenAI ships ''Memory'' — an automatic, opt-in capability where ChatGPT silently learns and stores facts about the user across sessions. Tell ChatGPT in March that you have a 7-year-old daughter named Lily; in October it remembers (without you reminding it). Memory entries are inspectable, editable, and toggleable. The product is shipped on top of the existing Custom Instructions feature, not as a replacement.","prompt":"Why ship Memory (an invisible, automatic personalization layer) on top of the existing Custom Instructions (visible, explicit personalization) — and what is the dual-system actually doing for different users?","reveal_quote":"ChatGPT will consider your custom instructions for every conversation going forward — and Memory makes future chats more helpful by letting ChatGPT remember details across conversations. You can see what information helped personalize a response and make edits if something is no longer relevant.","reveal_quote_attribution":"OpenAI — official Memory feature announcement, February 2024","reveal_note":"The non-obvious move: shipping Memory and keeping Custom Instructions creates two parallel personalization systems that solve different problems. Custom Instructions captures user-explicit preferences (''always reply in Markdown,'' ''I''m a teacher''); Memory captures incidental facts ChatGPT picks up across conversations (''user''s daughter is named Lily,'' ''user works at a fintech company''). Most consumer products would have shipped one or the other — Memory feels like the ''smarter'' AI version. OpenAI shipped both because they answer different questions: Custom Instructions is ''how do I want this AI to feel,'' Memory is ''what does this AI know about my context.'' The lesson: when invisible-AI personalization and visible-user-preferences serve genuinely different jobs, two systems is the right answer — even though it duplicates UI surface area. The simpler-feeling ''just one personalization system'' is often the wrong design for a product that has to handle both first-time-user agency and long-term-user accumulation of context.","quote_type":"verbatim","sources":[{"title":"Memory and new controls for ChatGPT","url":"https://openai.com/index/memory-and-new-controls-for-chatgpt/","publisher":"OpenAI","year":2024,"type":"blog"},{"title":"Memory FAQ","url":"https://help.openai.com/en/articles/8590148-memory-faq","publisher":"OpenAI Help Center","type":"documentation"},{"title":"OpenAI upgrades ChatGPT with persistent memory and temporary chat","url":"https://venturebeat.com/ai/openai-upgrades-chatgpt-with-persistent-memory-and-temporary-chat","publisher":"VentureBeat","year":2024,"type":"article"}],"tags":{"industry":"ai-tools","region":"us","decade":"2020s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'apple-live-text',
  'daily',
  '{"id":"apple-live-text","type":"daily","scheduled_date":"","company":"Apple","era":"September 2021 — iOS 15 launch","context":"Until 2021, text in photos and screenshots on iPhone is functionally dead — you can see it but can''t select, copy, or interact with it. Want to copy a phone number off a poster? Type it out yourself. Want to extract the address from a screenshot? Same. Apple ships ''Live Text'' in iOS 15: open the camera or any photo, long-press on any visible text, and it becomes selectable, copyable, looks-up-able, callable (for phone numbers), navigable (for addresses). The recognition happens entirely on-device using the Neural Engine. No upload, no waiting, no separate ''OCR app.'' Works on still photos, paused videos, and live camera feed.","prompt":"Why ship Live Text as an invisible default — no settings toggle, no onboarding tutorial, just ''long-press text'' — when most users will never discover it without being told?","reveal_quote":"Live Text uses on-device intelligence to recognize text in a photo on iPhone and allows you to take action. So you can call a number on a flyer with just a tap, or look up directions from a snapshot of a storefront.","reveal_quote_attribution":"Apple — Live Text official iOS 15 announcement, September 2021","reveal_note":"What''s easy to miss: Live Text doesn''t have a UI surface — no toggle in Settings, no dedicated app icon, no ''recognize text in image'' button. It just works when you long-press text in any image. The decision to make it discoverable through habit (long-press already means ''context menu'' on iPhone) rather than through a marketing feature lets the capability spread organically — one person at a coffee shop tries it, a friend sees, the gesture propagates. The capability lives inside an interaction pattern users already know, not behind a new affordance. Most computer-vision capabilities ship as separate apps or features (Google Lens has its own button on Android); Apple chose to bury Live Text inside the long-press menu where it''s a ''magical, did-you-know'' rather than a ''new feature you have to learn.'' The lesson: when AI / ML capabilities are mature enough to be universally reliable, hiding them inside existing gestures often beats giving them their own surface — the feature becomes a property of the OS rather than a thing you have to remember exists.","quote_type":"verbatim","sources":[{"title":"Use Live Text on iPhone","url":"https://support.apple.com/guide/iphone/use-live-text-iphdf127a9b2/ios","publisher":"Apple Support","type":"documentation"},{"title":"iOS 15 puts the power of iPhone forward and elevates moments shared with others","url":"https://www.apple.com/newsroom/2021/06/ios-15-puts-the-power-of-iphone-forward-and-elevates-moments-shared-with-others/","publisher":"Apple Newsroom","year":2021,"type":"press-release"},{"title":"iOS 15 — Wikipedia","url":"https://en.wikipedia.org/wiki/IOS_15","type":"article"}],"tags":{"industry":"consumer-mobile","region":"us","decade":"2020s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'imessage-read-receipts-default-off',
  'daily',
  '{"id":"imessage-read-receipts-default-off","type":"daily","scheduled_date":"","company":"Apple","era":"October 2011 — iOS 5 / iMessage launch","context":"WhatsApp''s read receipts (introduced 2014) are default-on for everyone — and the user backlash forced an opt-out within weeks. When Apple ships iMessage in iOS 5 (October 2011), they make the opposite call from day one: read receipts are default OFF. Users who want their senders to know they''ve read a message must explicitly enable read receipts in Settings — and the toggle is per-conversation (turn on for your spouse, leave off for your boss).","prompt":"Why ship read receipts as default-off (granular, per-conversation) — when other messengers default them on and force users to opt out?","reveal_quote":"When read receipts are on, people in the conversation are notified after you''ve read their messages. You can choose to share read receipts with everyone or only with specific contacts in your iMessage conversations.","reveal_quote_attribution":"Apple Support — iMessage read receipts documentation","reveal_note":"The non-obvious move: choosing the safer default (read receipts off) sets a different baseline expectation than WhatsApp''s. On WhatsApp, sender expects to see a blue tick; lack of one means ''they turned it off'' (suspicious) or ''they haven''t read'' (anxious). On iMessage, sender expects nothing by default; getting a ''Read 3:42 PM'' is opt-in by the recipient, which means it''s a deliberate signal of trust (''I care enough to tell you I saw this''). The same feature with a different default produces fundamentally different social dynamics. Apple''s choice — granular, opt-in, per-conversation — recognizes that read receipts mean different things in different relationships. The lesson: in social products, defaults aren''t a minor implementation detail; they shape the social contract the product enforces between every user pair. Make read receipts default-on and you''ve made anxiety the default. Make them default-off and you''ve made trust the affordance.","quote_type":"verbatim","sources":[{"title":"iMessage — Wikipedia","url":"https://en.wikipedia.org/wiki/IMessage","type":"article"},{"title":"Send and receive iMessage messages on iPhone","url":"https://support.apple.com/guide/iphone/send-and-receive-messages-iph9b0204f8d/ios","publisher":"Apple Support","type":"documentation"},{"title":"Apple introduces iMessage in iOS 5","url":"https://www.apple.com/newsroom/2011/10/04Apple-Introduces-iCloud/","publisher":"Apple Newsroom","year":2011,"type":"press-release"}],"tags":{"industry":"communication","region":"us","decade":"2010s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'twitter-edit-button-blue',
  'daily',
  '{"id":"twitter-edit-button-blue","type":"daily","scheduled_date":"","company":"Twitter","era":"September 2022 — Edit Tweet rolls out to Twitter Blue","context":"For ~16 years (2006-2022), Twitter refused to ship an Edit button — by far the most-requested feature in the platform''s history. Internal arguments against editing were consistent: an edited tweet breaks the integrity of replies, retweets, and screenshots; an edited tweet can change meaning after it''s gone viral; bad actors could weaponize edits to misrepresent what they said. In September 2022, Twitter ships ''Edit Tweet'' — but only to Twitter Blue subscribers ($4.99/mo at the time). Each tweet can be edited up to 5 times within 30 minutes of posting. Every edit version is preserved in a public ''edit history'' viewable by anyone clicking the small pencil icon. Retweets, quote tweets, and replies dynamically update to the latest version.","prompt":"Why finally ship Edit Tweet after 16 years of refusal — and why gate it behind Twitter Blue''s paywall instead of releasing to everyone?","reveal_quote":"After 30 minutes the tweet can no longer be edited. Tweets that have been edited will have an icon, timestamp, and label so it''s clear to readers that the original Tweet has been modified. Tapping the label will take readers to the Tweet''s Edit History.","reveal_quote_attribution":"Twitter — official Edit Tweet announcement, September 1, 2022","reveal_note":"The choice that''s easy to miss: gating Edit Tweet behind a $4.99/mo paywall is not about revenue — it''s a content-integrity throttle. Edit history + 30-minute window + 5-edit limit + Blue paywall together limit how much abuse can happen: bad actors can edit, but the edit history is public, and most bad actors won''t pay $4.99/mo to wield an editor that documents their own changes. By restricting the feature to Blue, Twitter (a) ran an A/B test on whether edits cause measurable abuse in a constrained population, (b) extracted a small revenue line, and (c) reserved the right to roll out broadly or pull back based on observed behavior. The 30-minute window is the typo-fixing use case; longer windows would have invited ''rewrite after going viral'' abuse. The lesson: when a feature has obvious abuse vectors, gating its initial rollout to a paid / verified subset is often the right way to ship — you keep the upside (typo fixes) and bound the downside (subscriber-only abuse with public edit history).","quote_type":"verbatim","sources":[{"title":"Edit Tweet is here — but you''ll have to pay for it","url":"https://techcrunch.com/2022/09/01/edit-tweet-is-here-but-youll-have-to-pay-for-it/","publisher":"TechCrunch","year":2022,"type":"article"},{"title":"Edit Tweet is now testing on Twitter Blue","url":"https://blog.twitter.com/en_us/topics/product/2022/edit-tweet-coming-soon-twitter-blue","publisher":"Twitter Blog","year":2022,"type":"blog"},{"title":"Twitter''s much-anticipated ''edit'' button finally arrives","url":"https://www.theverge.com/2022/9/1/23332541/twitter-edit-button-tweet-testing-blue-subscribers","publisher":"The Verge","year":2022,"type":"article"}],"tags":{"industry":"consumer-social","region":"us","decade":"2020s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'apple-handoff-continuity',
  'daily',
  '{"id":"apple-handoff-continuity","type":"daily","scheduled_date":"","company":"Apple","era":"June 2014 — WWDC reveal, iOS 8 / OS X Yosemite","context":"Cross-device workflows in 2014 are universally broken. Start a draft email on your phone — to finish on your laptop, you have to save, sync (maybe), open mail, find draft. Open a webpage on iPhone — to read on iPad, you have to share the link to yourself. Apple ships ''Handoff'' as part of Continuity in iOS 8 / OS X Yosemite (June 2014). When you''re working on a document, email, web page, or message on one Apple device, an icon for that activity appears on every other nearby Apple device you''re signed into. Tap it: you''re picking up exactly where you left off, mid-paragraph, mid-form, mid-scroll. No file transfer, no manual sync.","prompt":"Why is the magic of Handoff — ''tap the icon, your work continues exactly where you left it'' — actually a positioning weapon rather than just a convenience feature?","reveal_quote":"With Handoff, you can start writing an email on your Mac and pick up where you left off on your iPhone — or vice versa. The activity you''re doing automatically appears at the corner of every device you''re signed in to.","reveal_quote_attribution":"Apple — Continuity / Handoff WWDC 2014 announcement","reveal_note":"The non-obvious move: Handoff converts cross-device friction from a personal annoyance into a structural switching cost. Every additional Apple device a user owns makes the others more useful — a virtuous loop that''s only possible if all your devices are Apple''s. A user with iPhone + Windows PC + iPad still has to email things to themselves; a user with iPhone + Mac + iPad gets seamless continuity. The feature itself is technically modest (Bluetooth LE proximity detection + iCloud handoff metadata), but the strategic effect is enormous: it makes the marginal cost of leaving the Apple ecosystem the loss of every cross-device handoff you''ve come to rely on. Microsoft, Google, and Samsung have all built equivalent features (Phone Link, Nearby Share, Samsung Flow) in the years since — none with Apple''s polish, because their devices come from different vendors. The lesson: lock-in features at the ecosystem level (not the app level) are some of the most valuable product investments a vertically-integrated platform owner can make. Each additional Apple device a user adds compounds the cost of leaving.","quote_type":"verbatim","sources":[{"title":"Use Handoff to continue tasks on your other devices","url":"https://support.apple.com/en-us/102463","publisher":"Apple Support","type":"documentation"},{"title":"Apple Reveals iOS 8, the Biggest Release Since the Launch of the App Store","url":"https://www.apple.com/newsroom/2014/06/02Apple-Reveals-iOS-8-The-Biggest-Release-Since-the-Launch-of-the-App-Store/","publisher":"Apple Newsroom","year":2014,"type":"press-release"},{"title":"Continuity — Apple iOS 8 / OS X Yosemite features","url":"https://en.wikipedia.org/wiki/Continuity_(Apple)","type":"article"}],"tags":{"industry":"consumer-mobile","region":"us","decade":"2010s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'apple-family-sharing',
  'daily',
  '{"id":"apple-family-sharing","type":"daily","scheduled_date":"","company":"Apple","era":"September 2014 — iOS 8 launch","context":"Pre-2014, families with multiple iPhones had a structural problem on iTunes / App Store / iBooks: every app purchase, every song, every book had to be re-bought on each family member''s Apple ID, OR everyone shared a single Apple ID (which broke iCloud, iMessage, and personal data privacy). Apple ships Family Sharing in iOS 8: up to 6 family members can share purchases (paid apps, music, books, movies, iCloud storage), share family location, and use a single payment method — while keeping their own Apple IDs, iCloud accounts, and private data. ''Ask to Buy'' lets parents approve kids'' purchases before they go through.","prompt":"Why ship a family-account abstraction layered on top of individual Apple IDs — instead of just supporting ''shared library'' or ''sub-account'' models like the gaming industry used?","reveal_quote":"Family Sharing makes it easy for up to six people in your family to share App Store purchases, an Apple Music subscription, an iCloud+ subscription, and more — without having to share an Apple ID.","reveal_quote_attribution":"Apple Support — Family Sharing documentation","reveal_note":"What''s easy to miss: Family Sharing solves two opposing constraints at once — share economic value (apps, music, subscriptions, payment method) while preserving individual identity (iCloud, photos, iMessage, browsing history, app usage). Pre-Family-Sharing, families had to pick one. The single-Apple-ID workaround broke personal privacy (everyone''s photos in the same library, everyone''s iMessages mixing); the multiple-Apple-ID approach broke economic sense (every app bought 4 times). Apple''s design — share economics, keep identity — required new infrastructure (App Store re-architecture, iCloud account linking, payment authorization flows). The economic sharing also reduced revenue per user (one app sold to a family of 4 instead of 4 apps sold to 4 individuals) — Apple traded that revenue loss for retention compounding. The lesson: feature design under genuinely conflicting constraints often produces the most-durable product surfaces. The version that works for the family is structurally harder to leave than one that asks the family to choose which constraint to violate.","quote_type":"verbatim","sources":[{"title":"Set up Family Sharing","url":"https://support.apple.com/en-us/108380","publisher":"Apple Support","type":"documentation"},{"title":"Apple''s Family Sharing launches with iOS 8 — Macworld","url":"https://www.macworld.com/article/220018/apples-family-sharing-feature-launches-with-ios-8.html","publisher":"Macworld","year":2014,"type":"article"},{"title":"Family Sharing in iOS 8 — Wikipedia","url":"https://en.wikipedia.org/wiki/Family_Sharing","type":"article"}],"tags":{"industry":"consumer-mobile","region":"us","decade":"2010s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'headspace-take-10-onboarding',
  'daily',
  '{"id":"headspace-take-10-onboarding","type":"daily","scheduled_date":"","company":"Headspace","era":"2012 — launch and ''Take 10'' program","context":"Meditation in 2012 means books, classes, retreats, or weird-feeling apps with new-age aesthetics. Andy Puddicombe — an English former Buddhist monk turned mindfulness teacher — launches Headspace with one anchor product: ''Take 10.'' Ten free 10-minute meditation sessions, walking users through the basics of mindfulness practice. After Take 10, paid subscription unlocks the full library (sleep, focus, anxiety, kids). The Take 10 sessions are voiced by Puddicombe himself, in his calm British accent. Until you complete Take 10, no other content is available — even paid.","prompt":"Why gate the entire app behind a 10-day intro program — including for users willing to pay immediately — and what does the 10-session constraint actually teach the user?","reveal_quote":"Take 10 takes you through 10 sessions over 10 days, of 10 minutes each. It teaches you the basics of meditation and helps you build the habit. The numbers — 10, 10, 10 — are easy to remember and easy to commit to.","reveal_quote_attribution":"Andy Puddicombe, Headspace cofounder — paraphrased from public commentary on the Take 10 design philosophy","reveal_note":"The non-obvious move: gating the rest of the app behind Take 10 forces the user to build a meditation habit before being offered to scale up. Meditation isn''t a product you can use once and benefit from — it''s a discipline that requires consistent practice. By forcing 10 days of 10-minute sessions, Headspace teaches the muscle-memory of ''I sit down, open the app, do 10 minutes'' — the actual skill the product exists to develop. Letting users dive directly into specific themed meditations (sleep, anxiety, focus) without the foundation produces dropped users — they listen once, don''t find it magical, and uninstall. Take 10 also serves as Headspace''s pitch — by Day 10 the user has either built the habit (and converts to paid) or hasn''t (and the product structurally couldn''t help them anyway). The 10/10/10 numbers compound the simplicity: easy to remember, easy to commit to, easy to share. The lesson: in habit-forming products, sometimes the right onboarding is one that teaches the habit before unlocking the rest of the product — even at the cost of paid users who''d prefer to skip ahead.","quote_type":"paraphrased","sources":[{"title":"Headspace — Wikipedia","url":"https://en.wikipedia.org/wiki/Headspace","type":"article"},{"title":"Andy Puddicombe — Wikipedia","url":"https://en.wikipedia.org/wiki/Andy_Puddicombe","type":"article"},{"title":"How Headspace Built A Mindfulness Empire","url":"https://www.fastcompany.com/40474554/how-headspace-built-a-mindfulness-empire","publisher":"Fast Company","type":"article"}],"tags":{"industry":"health","region":"uk","decade":"2010s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'twitter-spaces-launch',
  'daily',
  '{"id":"twitter-spaces-launch","type":"daily","scheduled_date":"","company":"Twitter","era":"December 2020 — Spaces beta launch","context":"Clubhouse explodes in mid-2020 as the iOS-only, invite-only, audio-first social platform of the COVID era. Every major social platform scrambles to ship an audio-rooms competitor. Twitter ships ''Spaces'' in beta in December 2020 — Clubhouse-style audio rooms embedded directly into the Twitter app. Crucially: Spaces live next to your existing follow graph and tweets. The audio surface uses Twitter''s existing notification system, profile pages, and conversation context. No new app to download.","prompt":"Why ship Spaces inside the main Twitter app — rather than as a separate audio app (like Clubhouse) — and what does the embedded placement do for adoption?","reveal_quote":"Spaces is built into Twitter, so the conversations happen with the same people you already follow and care about. You can join a Space from your home timeline, schedule one in advance, or just start one from your profile.","reveal_quote_attribution":"Twitter — Spaces beta announcement, December 2020","reveal_note":"What''s easy to miss: embedding Spaces in the main Twitter app made the discovery problem disappear. Clubhouse users had to actively check the app to see what''s happening; Twitter users got Spaces surfaced in their existing timeline. Same audio format, very different reach. Clubhouse''s standalone-app model required cold-start audience for every room. Twitter Spaces inherited the audience of whoever opened the Space. Within 18 months, Spaces materially outlasted Clubhouse (which peaked in mid-2021 and collapsed to <10% of peak by 2023). Twitter Spaces still operates as a feature surface; Clubhouse the app has effectively died. The lesson: when an existing platform has the user-graph + the engagement loop, embedding a new feature inside that platform usually beats launching a standalone competitor — even when the feature itself is a clone. Distribution beats novelty almost every time in social products.","quote_type":"verbatim","sources":[{"title":"Twitter Spaces launches in beta","url":"https://blog.twitter.com/en_us/topics/product/2020/an-update-on-spaces","publisher":"Twitter Blog","year":2020,"type":"blog"},{"title":"Twitter is launching audio chat rooms called Spaces","url":"https://techcrunch.com/2020/12/17/twitter-spaces/","publisher":"TechCrunch","year":2020,"type":"article"},{"title":"Twitter Spaces — Wikipedia","url":"https://en.wikipedia.org/wiki/Twitter_Spaces","type":"article"}],"tags":{"industry":"consumer-social","region":"us","decade":"2020s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'gmail-smart-compose-2018',
  'daily',
  '{"id":"gmail-smart-compose-2018","type":"daily","scheduled_date":"","company":"Google (Gmail)","era":"May 2018 — Gmail Smart Compose launch","context":"Email auto-completion before 2018 means subject-line / recipient suggestions. Gmail ships ''Smart Compose'' at I/O 2018: as you type the body of an email, AI predicts the next words / phrases inline, in light gray. Press Tab to accept the suggestion and keep typing. The prediction adapts to your writing style, the recipient, and the email context. Predictions are server-side (TPU-powered ML model), but the inline UI feels instant.","prompt":"Why is inline Tab-to-accept AI completion (vs. a separate ''suggestions'' button or panel) the entire product — and what does the UI design do for adoption?","reveal_quote":"Smart Compose helps you compose emails from scratch, faster, by predicting the next few words for you. You can ignore the suggestions, or accept them by tapping Tab.","reveal_quote_attribution":"Google — Gmail Smart Compose announcement at Google I/O, May 2018","reveal_note":"The non-obvious move: making the AI completion ambient (gray text inline, Tab to accept) rather than explicit (a button to click for suggestions) lets users discover the feature through the act of typing, without any onboarding. The first time you see the gray suggestion, you might dismiss it; by the third or fourth time, you''ve subconsciously learned to press Tab. The product doesn''t ask permission, doesn''t interrupt, doesn''t require a menu choice. Users don''t have to learn ''how to use Smart Compose'' — they have to learn ''what the gray text means'' (which most figure out within 2-3 emails). The lesson: when AI is mature enough to predict the user''s intent reliably, embedding the suggestion in the user''s existing flow (inline, ambient, opt-in-by-action) beats giving it a separate UI surface. Cursor''s Tab-to-accept code completion follows the same pattern. ChatGPT''s inline completion in code editors follows the same pattern. The Tab key has become the universal ''accept AI suggestion'' affordance.","quote_type":"verbatim","sources":[{"title":"Subject: Write emails faster with Smart Compose in Gmail","url":"https://blog.google/products/gmail/subject-write-emails-faster-smart-compose-gmail/","publisher":"Google Blog","year":2018,"type":"blog"},{"title":"Smart Compose: Using Neural Networks to Help Write Emails","url":"https://research.google/blog/smart-compose-using-neural-networks-to-help-write-emails/","publisher":"Google Research","year":2018,"type":"blog"},{"title":"Use Smart Compose to write emails — Gmail Help","url":"https://support.google.com/mail/answer/9116836","publisher":"Gmail Help","type":"documentation"}],"tags":{"industry":"productivity","region":"us","decade":"2010s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'apple-touch-id-2013',
  'daily',
  '{"id":"apple-touch-id-2013","type":"daily","scheduled_date":"","company":"Apple","era":"September 10, 2013 — iPhone 5s launch","context":"Unlocking a smartphone in 2013 means either a 4-digit PIN (insecure but fast) or a stronger passcode (secure but slow + annoying). Survey data shows a majority of iPhone users don''t set any passcode at all because the friction interrupts dozens of phone unlocks per day. The competitive landscape: Motorola Atrix shipped a flaky fingerprint reader in 2011; Samsung is rumored to be working on one. Apple ships Touch ID with iPhone 5s in September 2013: a capacitive fingerprint sensor built into the home button. One press authenticates you in a fraction of a second. Apple Pay (1 year later) and App Store purchases (immediately) hook into it.","prompt":"Why ship fingerprint authentication built into the home button — when most prior fingerprint sensors had been flaky / frustrating, and most users were happy with their 4-digit PIN?","reveal_quote":"Touch ID is fast and easy to use. Just touch your finger to the Home button to unlock your phone or to buy from the iTunes Store. It learns over time so you can use any of up to five fingers.","reveal_quote_attribution":"Apple — Touch ID launch announcement, September 10, 2013","reveal_note":"What''s easy to miss: Touch ID didn''t just speed up unlock — it converted security from a friction-cost into an invisible default. The pre-Touch-ID iPhone user was making a trade: set a PIN and add 2-5 seconds per unlock, or skip it and accept the security risk. Most users picked ''skip the PIN.'' Touch ID destroyed the trade — security became free of friction. Apple''s data after Touch ID launch showed passcode-adoption rates jumped from ~50% to ~90%+ on iPhones with Touch ID. The fingerprint sensor wasn''t a feature; it was a delivery mechanism for security at scale. Without Touch ID, Apple Pay (launched 1 year later) wouldn''t have worked — checkout payments require frictionless authentication. The lesson: when a UX friction is the structural cause of users opting out of a security primitive, removing the friction often does more for security than improving the security primitive itself.","quote_type":"verbatim","sources":[{"title":"iPhone 5s, World''s Most Forward-Thinking Smartphone, Coming September 20","url":"https://www.apple.com/newsroom/2013/09/10iPhone-5s-Worlds-Most-Forward-Thinking-Smartphone-Coming-September-20/","publisher":"Apple Newsroom","year":2013,"type":"press-release"},{"title":"About Touch ID advanced security technology","url":"https://support.apple.com/en-us/HT204587","publisher":"Apple Support","type":"documentation"},{"title":"Touch ID — Wikipedia","url":"https://en.wikipedia.org/wiki/Touch_ID","type":"article"}],"tags":{"industry":"consumer-mobile","region":"us","decade":"2010s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'slack-status-emoji',
  'daily',
  '{"id":"slack-status-emoji","type":"daily","scheduled_date":"","company":"Slack","era":"July 2017 — status emoji feature","context":"Workplace presence in chat tools in 2017 means a binary green dot (''online'') or gray dot (''away'') — same model as AIM and ICQ from the 90s. The status doesn''t actually communicate anything useful: ''online'' could mean focused-deep-work or just-leaving-for-lunch. Slack ships custom statuses with emoji in July 2017: any user can set a one-line status with an emoji (🥗 At lunch, 🚌 Commuting, 🤒 Out sick, 🎯 In focus mode). The status appears next to the user''s name everywhere — DMs, channels, the user picker. Slack ships a set of presets but allows fully custom statuses with any emoji.","prompt":"Why is shipping ''emoji + one line of text'' status better than a more structured ''meeting / available / busy'' system — and what does the open-ended design unlock for team culture?","reveal_quote":"Now you can be specific about your status — and let your colleagues know exactly what you''re up to, whether you''re working from home or ''putting out fires.''","reveal_quote_attribution":"Slack — custom status emoji launch announcement, July 2017","reveal_note":"The non-obvious move: structured statuses (''In a meeting,'' ''Available,'' ''Do Not Disturb'') force a status taxonomy on every team in advance. Slack''s emoji + free-text approach lets each team evolve its own vocabulary organically. One team''s ''🎯 in focus mode'' is another team''s ''🧠 deep work''; one team''s ''🍕 at lunch'' is another team''s ''🥗 lunch break, back at 1.'' The same feature serves a remote engineering team in Berlin and a content team in Brooklyn without modification. Custom statuses also became one of the dominant team-culture artifacts inside Slack — companies discovered that the way their colleagues used statuses revealed personality, working style, and team norms. The lesson: structured fields force the product designer to predict the entire vocabulary upfront. Free-text fields with conventions (emoji + one line) let users invent the vocabulary in production. When the use cases are genuinely diverse (every team is different), letting the users define the taxonomy beats predicting it.","quote_type":"verbatim","sources":[{"title":"Set your Slack status","url":"https://slack.com/help/articles/115002819911-Set-your-Slack-status-and-availability","publisher":"Slack Help","type":"documentation"},{"title":"Slack launches custom status emoji","url":"https://www.theverge.com/2017/7/13/15966150/slack-status-emoji-update-feature","publisher":"The Verge","year":2017,"type":"article"},{"title":"Customize Slack status and availability — Atlassian","url":"https://www.atlassian.com/blog/halp/slack-status","publisher":"Atlassian","type":"article"}],"tags":{"industry":"saas","region":"us","decade":"2010s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'icloud-5gb-free-tier',
  'daily',
  '{"id":"icloud-5gb-free-tier","type":"daily","scheduled_date":"","company":"Apple","era":"October 2011 — iCloud launch with 5GB free","context":"Cloud-storage products in 2011 (Dropbox, Box, Google Drive) ship with generous free tiers — Dropbox 2GB free, growing to 16GB+ via referrals; Google Drive 5-15GB free. Apple launches iCloud with iOS 5 / OS X Lion in October 2011 with a 5GB free tier — including device backups, mail, contacts, photos, documents, app data. The free tier hasn''t been raised since launch (still 5GB in 2025). Paid tiers start at $0.99/mo for 50GB, $2.99/mo for 200GB, $9.99/mo for 2TB.","prompt":"Why has Apple kept iCloud''s free tier at 5GB for 14+ years — when Google Drive (15GB) and Microsoft OneDrive (5GB-100GB depending on bundle) have raised theirs repeatedly?","reveal_quote":"iCloud frees you from your computer. Connect to all your iCloud-friendly apps over Wi-Fi or cellular and get a complete picture of your stuff anytime, anywhere.","reveal_quote_attribution":"Apple — iCloud launch announcement, October 12, 2011","reveal_note":"What''s easy to miss: 5GB is intentionally insufficient for most iPhone users. A modern iPhone takes photos that fill 5GB within months. iOS device backups alone often exceed 5GB. The 5GB tier is structurally a funnel into paid storage — most heavy-iPhone users either upgrade to 50GB+ paid (~70% of iCloud revenue comes from upgrades) or face an aggressive ''iCloud storage almost full'' notification cycle until they upgrade. By keeping the free tier inadequate, Apple converts a ''free feature'' into a paid-subscription business: iCloud+ revenue is reportedly multi-billion-dollar annual. Raising the free tier (to 15GB or 50GB) would gut that revenue stream. Apple''s competitors don''t have the same vertical-integration leverage — Google sells storage to make the Drive product attractive; Apple sells storage because every iPhone user is a captive market. The lesson: free-tier sizing is a pricing decision, not a generosity decision. The right size of a free tier is precisely ''enough to make users dependent on the product, less than they actually need to use it fully.'' Apple''s 5GB is the canonical case of free-tier-as-funnel.","quote_type":"verbatim","sources":[{"title":"Apple Introduces iCloud","url":"https://www.apple.com/newsroom/2011/06/06Apple-Introduces-iCloud-Free-Cloud-Services-Beyond-Anything-Offered-to-Date/","publisher":"Apple Newsroom","year":2011,"type":"press-release"},{"title":"iCloud storage plans and pricing","url":"https://support.apple.com/en-us/108047","publisher":"Apple Support","type":"documentation"},{"title":"iCloud — Wikipedia","url":"https://en.wikipedia.org/wiki/ICloud","type":"article"}],"tags":{"industry":"consumer-mobile","region":"us","decade":"2010s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'ios-shake-to-undo',
  'daily',
  '{"id":"ios-shake-to-undo","type":"daily","scheduled_date":"","company":"Apple","era":"June 2009 — iOS 3.0 launch","context":"Mobile devices in 2009 don''t have a keyboard with a dedicated ''undo'' button. Apple ships iOS 3.0 in June 2009 with ''Shake to Undo'' — physically shake the iPhone and a modal pops up asking ''Undo Typing?'' Tap confirm and the last text edit is reversed. Same gesture works for undoing other actions (deleting a Note, moving an icon, etc.). The gesture works across every iOS app where text editing is possible. There''s no on-screen button — the only way to trigger undo is to shake the phone.","prompt":"Why is shake-to-undo (a hidden gesture, no UI affordance) the design Apple ships — versus a dedicated undo button on the keyboard or a long-press gesture?","reveal_quote":"iOS 3.0 includes new features users have been asking for, like cut, copy, and paste — and Shake to Undo, which lets you reverse a recent action by simply shaking your iPhone.","reveal_quote_attribution":"Apple — iOS 3.0 launch announcement, June 2009","reveal_note":"The non-obvious move: shake-to-undo is widely criticized as ''undiscoverable'' — and that critique is correct. Most iPhone users never learn the gesture; many discover it accidentally when their iPhone shakes in a pocket. The decision to use a physical gesture rather than a button is the failure mode, repeatedly cited by UX critics. By 2016, Apple admits this and adds a software ''Undo'' button in iOS 13''s text-editing menu (three-finger swipe-left); by iOS 17 there''s a software undo button visible in keyboards. Shake-to-undo survives because some users like it, and removing it would break that cohort''s muscle memory. The lesson is mostly about how NOT to design discoverability: features that require physical-world interaction without on-screen affordances are structurally undiscoverable, no matter how ''natural'' the gesture feels to the designer. Modern iOS gestures (long-press to reveal context menus, swipe down for Notification Center) all have on-screen affordances or system-wide tutorials. Shake-to-undo persists as a fossil from a time when Apple believed users would discover physical gestures organically.","quote_type":"paraphrased","sources":[{"title":"Apple Announces the New iPhone 3GS — The Fastest, Most Powerful iPhone Yet","url":"https://www.apple.com/newsroom/2009/06/08Apple-Announces-the-New-iPhone-3GS-The-Fastest-Most-Powerful-iPhone-Yet/","publisher":"Apple Newsroom","year":2009,"type":"press-release"},{"title":"iOS 3 — Wikipedia","url":"https://en.wikipedia.org/wiki/IOS_3","type":"article"},{"title":"How to use Shake to Undo on iPhone","url":"https://support.apple.com/guide/iphone/use-shake-to-undo-iph7d96f51c2/ios","publisher":"Apple Support","type":"documentation"}],"tags":{"industry":"consumer-mobile","region":"us","decade":"2000s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'meta-threads-2023',
  'weekly',
  '{"id":"meta-threads-2023","type":"weekly","iso_week":"","company":"Meta","era":"Early 2023","intro":"It is early 2023. You are a senior PM at Meta. Twitter has been acquired by Elon Musk and is in active turmoil — verification chaos, advertiser pullback, mass layoffs, and a steady exodus of the cultural-influencer cohort who made the platform sticky.\n\nMark Zuckerberg''s leadership team is debating whether Meta should ship a text-based social app. Internally there is a working prototype built on the Instagram codebase. The Instagram graph is the largest social graph in the Western world (~2B MAU). A text product could in theory bootstrap on it instantly.","open_questions":["Tightly couple to Instagram (one-tap signup, IG followers ported in), or stand alone?","What ships at launch? DMs? Hashtags? A chronological feed? A web app?","Is the goal to kill Twitter, complement Instagram, or defend against TikTok absorbing text-social mindshare?","How big is the risk an obvious Twitter-clone gets dismissed by users and press as derivative?"],"closing":"Imagine you''re in the room. You don''t yet know what they decided or how it played out.","decision":"Ship as a tightly-coupled extension of Instagram. One-tap signup with IG credentials. IG followers auto-suggested. Built and shipped by the IG team in roughly five months. Deliberately omitted at launch: DMs, hashtags, trending topics, web app, chronological feed default, following-only feed, ability to delete Threads without deleting Instagram.","pullquote":"Not to replace Twitter, but to build a public square for communities on Instagram that never really embraced Twitter.","pullquote_attribution":"Adam Mosseri, Head of Instagram, July 2023 — paraphrased / compressed from his public statements","outcomes":[{"stat":"100M","label":"signups in 5 days — fastest consumer launch ever"},{"stat":"−80%","label":"DAU within 3 weeks of launch","accent":true},{"stat":"12 mo","label":"deliberate slow rollout: web, search, hashtags, following feed"},{"stat":"~150M","label":"MAU by end of 2024 — durable growth, not retention curve"}],"tradeoffs":[{"title":"Speed-to-market vs. product polish","body":"Meta knew the launch product was thin. They optimized for shipping during Twitter''s instability window — a market-timing call, not a product-completeness call."},{"title":"Growth-hack coupling vs. user trust","body":"The IG-account lock-in was a deliberate growth lever they expected to reverse. They ate the trust hit on purpose because the alternative was a much slower S-curve."},{"title":"''Defend'' framing vs. ''kill Twitter'' framing","body":"The actual goal was defensive — keep text-social inside the Meta ecosystem rather than let X or TikTok own it. The Twitter-killer narrative was press, not strategy."},{"title":"Retention-now vs. retention-later","body":"They explicitly tolerated the DAU collapse. The internal metric that mattered was 6-month and 12-month retained MAU, not week-1 DAU."}],"per_dimension_truth":{"tradeoff":"Speed-to-market and ecosystem defense vs. product depth. They sacrificed launch-week retention and user trust to ship inside Twitter''s instability window.","user":"Existing Instagram users who were curious about text social but had never adopted Twitter — explicitly not the existing Twitter power-user cohort.","alt":"Decoupled launch with DMs and a web app would have shipped slower and lost the timing window. Meta chose the opposite trade.","predict":"Massive launch-week numbers, fast collapse, then slow durable growth — a 12-month bet, not a 12-week one."},"quote_type":"paraphrased","sources":[{"title":"Instagram Head Says Threads Isn''t Trying to ''Replace'' Twitter","url":"https://www.thewrap.com/threads-replace-twitter-goal-adam-mosseri-instagram/","publisher":"TheWrap","year":2023,"type":"article"},{"title":"Birth of Threads: Mark Zuckerberg called up Adam Mosseri to discuss the ''Twitter-killer''","url":"https://www.businesstoday.in/technology/news/story/birth-of-threads-mark-zuckerberg-called-up-instagram-head-adam-mosseri-late-at-night-to-discuss-the-twitter-killer-392003-2023-07-31","publisher":"Business Today","year":2023,"type":"article"},{"title":"Instagram head says Threads is ''not going to amplify news on the platform''","url":"https://techcrunch.com/2023/10/11/instagram-head-says-threads-is-not-going-to-amplify-news-on-the-platform/","publisher":"TechCrunch","year":2023,"type":"article"}],"tags":{"industry":"consumer-social","region":"us","decade":"2020s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'shopify-shop-2020',
  'weekly',
  '{"id":"shopify-shop-2020","type":"weekly","iso_week":"","company":"Shopify","era":"Early 2020","intro":"It is early 2020. You are a senior PM at Shopify. The company has spent a decade building infrastructure for merchants — Shopify is the picks-and-shovels of e-commerce, deliberately not consumer-facing.\n\nLeadership is debating launching Shop, a consumer mobile app for tracking orders across all Shopify merchants. It would put Shopify directly in front of end-shoppers for the first time. Some inside the company argue it''s a betrayal of the merchant-first promise. Others argue Amazon is going to eat every Shopify merchant alive if shoppers don''t have a unified buying surface outside Amazon.","open_questions":["Does building a consumer app cannibalize merchant brand? The whole pitch is ''your store, not ours.''","If shoppers see ''Shop'' as the brand, do merchants become commoditized fulfillment behind it?","Is the alternative — letting Amazon own discovery — actually worse for merchants?","What does ''success'' look like for a product whose users are not your customers?"],"closing":"Imagine you''re in that strategy room. You don''t yet know what they decide.","decision":"Ship Shop as a consumer app, but design it to elevate the merchant brand, not Shopify''s. Each merchant page in the app is fully merchant-branded. Shopify''s logo is nearly invisible in-app. The app''s core feature is package tracking — a real shopper need that has nothing to do with merchant identity. Discovery and recommendations were added cautiously over the next two years.","pullquote":"The app doesn''t make Shopify the brand. It makes Shopify invisible — which is the only way merchants will tolerate us being in front of their customers.","pullquote_attribution":"Tobi Lütke, Shopify CEO — paraphrased from public commentary around the Shop launch (2020–21)","outcomes":[{"stat":"100M+","label":"Shop app downloads by 2023"},{"stat":"Low","label":"Merchant churn from Shop launch — concerns didn''t materialize","accent":true},{"stat":"2 yrs","label":"Shopify deliberately delayed building strong recommendations"},{"stat":"$200M+","label":"GMV processed through Shop Pay weekly by 2023"}],"tradeoffs":[{"title":"Brand neutrality vs. brand visibility","body":"Shopify deliberately made itself invisible inside the app. The cost: weaker direct brand recall with shoppers. The benefit: merchants didn''t revolt."},{"title":"Tracking-as-Trojan-horse","body":"Package tracking is the most-checked feature in any shopper''s life. Shopify used the most boring use case as the wedge into a consumer relationship."},{"title":"Defensive vs. offensive framing","body":"Externally Shop looked like aggression. Internally it was framed as defense against Amazon owning discovery. The framing shaped what got built and what didn''t."},{"title":"Restraint as moat","body":"The team explicitly held back on personalized recommendations for two years. The discipline preserved merchant trust in a way a faster, AI-driven discovery push would have torched."}],"per_dimension_truth":{"tradeoff":"Defense against Amazon''s discovery monopoly vs. risking the merchant-first brand promise. Resolved by making Shopify invisible inside the consumer app.","user":"Shoppers who already buy from Shopify merchants and need package tracking — not new customer acquisition. The merchant is still the brand the shopper experiences.","alt":"A heavily Shopify-branded consumer app with strong recommendations would have driven faster consumer engagement and triggered merchant revolt. They chose restraint.","predict":"Slow consumer adoption initially, durable growth as Shop Pay became the actual flywheel — payments embedded across the merchant network."},"quote_type":"paraphrased","sources":[{"title":"Shopify launches consumer-facing shopping assistant app","url":"https://betakit.com/shopify-launches-consumer-facing-shopping-assistant-app/","publisher":"BetaKit","year":2020,"type":"article"},{"title":"Shopify — Wikipedia","url":"https://en.wikipedia.org/wiki/Shopify","type":"article"},{"title":"Masters of Scale: Be a platform, with Tobi Lütke","url":"https://mastersofscale.com/tobi-lutke-be-a-platform/","publisher":"Masters of Scale","type":"podcast"}],"tags":{"industry":"ecommerce","region":"anz","decade":"2020s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'airbnb-covid-2020',
  'weekly',
  '{"id":"airbnb-covid-2020","type":"weekly","iso_week":"","company":"Airbnb","era":"March–May 2020","intro":"It is March 2020. You are a senior PM at Airbnb. COVID-19 has closed borders. Travel demand has fallen off a cliff — revenue is down roughly 80% in eight weeks, and the company is burning about $250M/month. The IPO that was supposed to land in 2020 is dead on arrival. The company has about 7,500 employees globally and a sprawling roadmap: Airbnb Experiences, Luxe, Plus, hotels, transportation.\n\nLeadership has to make three calls in parallel: how deep to cut, what to cut from the product portfolio, and how to position the company that emerges. The ''rational'' play is to cut everything that isn''t core stays and ride out the pandemic.","open_questions":["How deep to cut on headcount — enough to survive 12 months of zero recovery, or shallower bets on a faster rebound?","Kill Experiences/Luxe/Plus and refocus on core stays, or keep optionality across the portfolio?","How transparent to be publicly about the cuts and the rationale — does that help or hurt the long brand?","Is the IPO dead permanently, or just delayed — and how should the runway decision reflect each?"],"closing":"Imagine you''re in the executive room in early April 2020. The data is bad, the recovery curve is unknown, and the team is watching to see what cut you make.","decision":"Cut deep, cut once, and refocus. In May 2020 Airbnb laid off 1,900 employees — about 25% of staff. Leadership killed or paused most of the non-stays product portfolio (Experiences, Luxe, Plus, hotels, transportation work) and explicitly refocused the company on hosts and stays. Severance was 14 weeks + healthcare + an internal alumni hiring database; the layoff letter was published openly. Airbnb''s IPO landed in December 2020 — eight months after the cuts.","pullquote":"I have a deep feeling of love for all of you. We have a more focused business, and we are going to emerge stronger.","pullquote_attribution":"Brian Chesky, Airbnb cofounder/CEO — from his publicly-published May 2020 letter to staff","outcomes":[{"stat":"1,900","label":"employees laid off (25% of staff) in one cut","accent":true},{"stat":"14 wks","label":"severance + healthcare + alumni placement program"},{"stat":"$250M/mo","label":"burn rate at the time of decision"},{"stat":"Dec 2020","label":"IPO — 8 months after the cuts"},{"stat":"$100B+","label":"market cap at peak following IPO"}],"tradeoffs":[{"title":"Cut deep once vs. cut shallow twice","body":"Chesky chose a single deep cut over staged smaller ones. The internal logic: two rounds of layoffs destroys trust faster than one. The cost is over-cutting if recovery is fast; the benefit is one trauma instead of two."},{"title":"Refocus vs. preserve optionality","body":"Killing Experiences/Luxe/Plus meant abandoning years of investment. Leadership decided focus was a survival asset — narrow surface area, faster decisions, clearer story for hosts and shareholders."},{"title":"Public transparency vs. quiet handling","body":"The published letter and alumni database were a brand bet. They turned a layoff (usually a brand-negative event) into a hiring tailwind for the laid-off staff and a recruiting story for the survivors."},{"title":"Host-first vs. shareholder-first framing","body":"The IPO was the obvious 2020 metric. Chesky de-prioritized it explicitly and built the cut around the host relationship instead. The IPO arrived anyway because the host network held."}],"per_dimension_truth":{"tradeoff":"Speed and depth of cut vs. preserving optionality and trust. Resolved by cutting once, deeply, transparently — even though that closed off entire product lines they''d invested years in.","user":"Hosts, not guests, were the user the decision optimized for. Hosts carry the supply; without supply, demand recovery is meaningless. Refocusing on stays was a supply-side bet, not a demand-side one.","alt":"A shallower first cut + portfolio preservation would have looked safer in April 2020 and forced a second cut by year-end. Airbnb chose the opposite: one trauma, deep refocus.","predict":"Short-term pain (mass layoffs, killed product lines), faster-than-expected recovery driven by domestic / longer-stay travel, and an IPO landing inside the same calendar year as the cuts."},"quote_type":"verbatim","sources":[{"title":"A Message from Co-Founder and CEO Brian Chesky","url":"https://news.airbnb.com/a-message-from-co-founder-and-ceo-brian-chesky/","publisher":"Airbnb Newsroom","year":2020,"type":"press-release"},{"title":"Airbnb Cuts 1,900 Jobs, 25% Of Its Workforce, As Pandemic Freezes Travel","url":"https://www.npr.org/sections/coronavirus-live-updates/2020/05/05/850986054/airbnb-cuts-1-900-jobs-25-of-its-workforce-as-pandemic-freezes-travel","publisher":"NPR","year":2020,"type":"article"},{"title":"Airbnb CEO Brian Chesky Tells Adam Grant the Right Way to Do Mass Layoffs: ''Cut Deep''","url":"https://www.inc.com/nick-hobson/airbnb-ceo-brian-chesky-tells-adam-grant-right-way-to-do-mass-layoffs-cut-deep.html","publisher":"Inc.","type":"interview"}],"tags":{"industry":"marketplace","region":"us","decade":"2020s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'netflix-streaming-pivot-2007',
  'weekly',
  '{"id":"netflix-streaming-pivot-2007","type":"weekly","iso_week":"","company":"Netflix","era":"January 2007","intro":"It is late 2006. You are a senior PM at Netflix. The DVD-by-mail business is humming — about 6.3 million subscribers, healthy contribution margins, and a strong moat in distribution centers nationwide. The brand is the red envelope.\n\nReed Hastings has told the board that streaming is the next platform and Netflix has to be on it before bandwidth makes it obvious. The leadership team is debating how — and how aggressively — to launch ''Watch Now.'' Building a full streaming product means cannibalizing the DVD business that funds the company. It also means licensing content from the same studios that view Netflix as a wholesale customer, not a competitor. Bandwidth is still spotty. The catalog will be a fraction of the DVD library at launch.","open_questions":["Charge separately for streaming, or bundle it free with the DVD subscription to drive trial?","How aggressively to cannibalize the DVD business — slow-walk streaming, or actively migrate customers off discs?","What''s the catalog play? Pay through the nose for the best titles, or launch with cheap back-catalog and accept a thin library?","How public to be about the streaming bet — frame the company as ''streaming-first,'' or keep the DVD brand intact to protect cash flow?"],"closing":"Imagine you''re in the leadership room in late 2006. The DVD business is profitable, the streaming product is half-built, and the studios are watching how you posture.","decision":"Launch ''Watch Now'' on January 16, 2007 — bundled free with DVD subscriptions, no separate price. About 1,000 titles at launch, almost entirely back-catalog. Hastings publicly framed Netflix''s identity as a streaming company from day one, even though streaming was a fraction of revenue. Aggressively migrated customers from DVD to streaming through pricing changes in the years following, even when it hurt short-term retention (the 2011 Qwikster split was the public scar tissue).","pullquote":"Movies over the internet are coming, and at some point it is going to be a huge business. We started in DVD, but we don''t intend to die in DVD.","pullquote_attribution":"Reed Hastings, Netflix cofounder/CEO — paraphrased from public interviews in the 2007–2010 era","outcomes":[{"stat":"6.3M → 18.3M","label":"subscribers from 2006 to 2010 (~3x growth)"},{"stat":"1,000","label":"titles in the initial streaming catalog"},{"stat":"$0","label":"incremental price to DVD subscribers at launch"},{"stat":"2011","label":"Qwikster fiasco — public scar from the cannibalization","accent":true},{"stat":"$300B+","label":"peak market cap in the streaming era"}],"tradeoffs":[{"title":"Bundle vs. unbundle","body":"Bundling streaming free with DVD removed the ''will customers pay for it'' question and converted streaming into a feature. The cost: it took years to disentangle the pricing and the 2011 split blew up in the company''s face. Bundling bought speed of adoption at the cost of future pricing flexibility."},{"title":"Cannibalize-now vs. cannibalize-later","body":"The safer play was to protect DVD revenue and let streaming grow alongside. Hastings chose to migrate aggressively, even when it hurt — on the theory that platform shifts reward whoever owns the new platform, not whoever bridges cleanly."},{"title":"Catalog-thin vs. catalog-rich at launch","body":"Launching with ~1,000 back-catalog titles meant the streaming product was clearly worse than DVD for years. The bet: thin catalog + good UX + relentless investment beats waiting until the catalog is good enough to launch flawlessly."},{"title":"Brand-as-DVD vs. brand-as-streaming","body":"The DVD brand was an asset; restating Netflix as ''streaming-first'' put that asset at risk. Hastings made the public-narrative bet early, before the financials supported it, to force the company''s identity onto the new platform."}],"per_dimension_truth":{"tradeoff":"Speed-of-platform-transition vs. clean preservation of the DVD cash cow. Netflix chose speed and accepted the messy middle period (2007–2013), including the Qwikster reversal, as the cost.","user":"Existing DVD subscribers who would adopt streaming as a free feature first, then re-anchor their mental model of Netflix around streaming. Not new customers — the existing graph was the lever.","alt":"A paid streaming SKU launched alongside DVD would have protected revenue, allowed cleaner pricing later, and likely lost the platform window to Hulu or Amazon. Netflix chose the opposite trade.","predict":"Subscriber growth, public confusion / brand pain in the messy years, and eventual dominance once streaming infrastructure caught up — a 5-year trade, not a 1-year one."},"quote_type":"paraphrased","sources":[{"title":"Netflix''s Streaming Pivot Included a Surprisingly Harsh Decision","url":"https://colemaninsights.com/coleman-insights-blog/netflixs-streaming-pivot-included-a-surprisingly-harsh-decision","publisher":"Coleman Insights","type":"blog"},{"title":"Reed Hastings and Netflix''s Game-Changing Pivot to Streaming","url":"https://executiveanecdotes.substack.com/p/reed-hastings-and-netflixs-game-changing","type":"blog"},{"title":"Netflix History: How Streamer Killed Blockbuster, Dominated Hollywood","url":"https://variety.com/2025/film/news/netflix-history-killed-blockbuster-dominated-hollywood-1236342853/","publisher":"Variety","year":2025,"type":"article"}],"tags":{"industry":"media","region":"us","decade":"2000s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'apple-itunes-music-store-2003',
  'weekly',
  '{"id":"apple-itunes-music-store-2003","type":"weekly","iso_week":"","company":"Apple","era":"2002–April 28, 2003","intro":"It is late 2002. You are a senior PM at Apple. The iPod has been on the market for ~14 months. It''s a beautiful device but its software story is a mess — users have to rip their own CDs (slow), buy DRM-locked tracks from PressPlay or MusicNet (which barely work), or pirate from Napster successors. The labels — the ''Big Five'' at the time — are losing 20%+ of revenue per year to piracy and are paralyzed.\n\nSteve Jobs wants to build a digital music store inside iTunes. He''s been negotiating with each of the Big Five separately for months. The labels want subscriptions ($10–15/mo for all-you-can-eat) with strict DRM. Jobs wants single-track sales at $0.99 with permissive DRM (multiple device authorizations, unlimited CD burns). The legal teams at the labels are unconvinced. The iPod is also Mac-only at the time — the addressable market is ~3% of US PC users.","open_questions":["Subscriptions or single-track ownership? The labels want recurring revenue; Jobs wants the iTunes Store to feel like a record shop.","How aggressive can the DRM terms be without spooking the labels — and how permissive can they be without nuking the negotiation?","Ship Mac-only first (small TAM but full Apple control) or wait to ship a Windows version (10x TAM, but Apple''s never shipped consumer software for Windows)?","What''s the negotiating posture — frame Apple as the labels'' savior from piracy, or as their replacement?"],"closing":"Imagine you''re in the room with Jobs in early 2003. The labels are skeptical, the iPod is Mac-only, and piracy is taking 20% off the top of the industry every year.","decision":"Launch the iTunes Music Store on April 28, 2003 — Mac-only at first, with single-track $0.99 pricing, all five major labels signed, ~200,000 songs at launch. DRM was ''FairPlay'' but with deliberately permissive terms: unlimited CD burns, up to five authorized devices. iTunes for Windows shipped six months later in October 2003. Apple sold 1M songs in six days — a milestone they''d forecasted would take six months.","pullquote":"This will go down as a turning point for the music industry.","pullquote_attribution":"Steve Jobs, on stage at the iTunes Music Store launch — April 28, 2003","outcomes":[{"stat":"$0.99","label":"per-track price — Jobs''s red line in the label negotiation"},{"stat":"5 / 5","label":"of the Big Five labels signed at launch"},{"stat":"1M","label":"songs sold in the first 6 days (forecast was 6 months)","accent":true},{"stat":"70M","label":"songs sold in the first year"},{"stat":"Oct 2003","label":"iTunes for Windows shipped 6 months after launch"}],"tradeoffs":[{"title":"Ownership vs. subscription","body":"Labels wanted recurring revenue. Jobs insisted on track-ownership at a flat $0.99. The cost: lower lifetime revenue per buyer; the benefit: a frictionless purchase that matched the mental model of buying a CD. Subscription music wouldn''t take off for another 8 years (Spotify, 2011)."},{"title":"Permissive vs. punitive DRM","body":"The labels wanted strict DRM — no CD burns, single-device. Jobs gave them DRM (FairPlay) but engineered it to be the most permissive consumer DRM of its era. The cost: the labels never fully trusted the terms; the benefit: customers didn''t experience the store as a tax."},{"title":"Mac-first vs. Windows-first","body":"Launching Mac-only was a 3% TAM but kept the experience under Apple control end-to-end. Six months later they shipped Windows — by then the brand and the catalog were stable. Reversing the order would have stretched Apple''s consumer-software muscles too thin too early."},{"title":"Frame as savior vs. frame as replacement","body":"Jobs publicly framed the store as the labels'' answer to piracy — the savior narrative. Internally, Apple was building the infrastructure to disintermediate the labels eventually. The framing got the deals done; the substance changed the industry''s power balance permanently."}],"per_dimension_truth":{"tradeoff":"Customer-friendly purchasing (single-track ownership at $0.99) vs. label-friendly business terms (subscription + DRM). Jobs leaned hard on the customer side and used Apple''s small market share as a wedge — ''we''re not a threat, we''re a test market.''","user":"Mac users who already owned an iPod and were either pirating or unhappily ripping CDs. Familiar audience, narrow but high-intent. Windows users came six months later, once the store and the negotiations were stable.","alt":"A subscription-only store with strict DRM would have looked safer to the labels and felt like rental to customers. It wouldn''t have moved the iPod the way ownership did. Apple chose the opposite trade.","predict":"Fast initial sales (the constrained Mac/iPod audience was thirsty for a legal alternative), Windows expansion making the store the dominant digital music retailer within 18 months, and a 10-year window before subscription streaming caught up."},"quote_type":"verbatim","sources":[{"title":"Apple Launches the iTunes Music Store","url":"https://www.apple.com/newsroom/2003/04/28Apple-Launches-the-iTunes-Music-Store/","publisher":"Apple Newsroom","year":2003,"type":"press-release"},{"title":"Twenty Years Ago, Apple Launched the iTunes Music Store","url":"https://512pixels.net/2023/04/itunes-music-store-20-years/","publisher":"512 Pixels","year":2023,"type":"blog"},{"title":"iTunes'' 10th Anniversary: How Steve Jobs Turned the Industry Upside Down","url":"https://rollingstone.com/culture/culture-news/itunes-10th-anniversary-how-steve-jobs-turned-the-industry-upside-down-68985/amp","publisher":"Rolling Stone","type":"article"}],"tags":{"industry":"media","region":"us","decade":"2000s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'snap-rejects-facebook-2013',
  'weekly',
  '{"id":"snap-rejects-facebook-2013","type":"weekly","iso_week":"","company":"Snap Inc. (Snapchat)","era":"November 2013","intro":"It is November 2013. You are a senior PM at Snapchat. The app is two years old. It has roughly 350 million snaps sent per day. Revenue is zero. The team is 30 people in a Venice Beach house. Evan Spiegel is 23.\n\nMark Zuckerberg has offered to acquire Snapchat for $3 billion in cash. Tencent has separately offered $200M at a $4B valuation. Around the same time, Google reportedly tables a $4B all-cash offer. Most observers — including some Snapchat investors — think Spiegel should take the Facebook deal. The argument: Instagram-with-direct-messaging already shows Facebook will copy any feature Snap ships, and disappearing photos can be replicated. Spiegel and Bobby Murphy refuse all three.","open_questions":["What''s the actual probability that Facebook successfully clones the product if you reject the offer?","How do you value a pre-revenue product whose distinctive feature (ephemerality) is structurally easy to copy?","Is the offer ceiling or floor? Does saying no force a bidding war, or does it close the door?","What''s the existential downside scenario — Facebook copies, kills you slowly, and the next offer is $300M, not $3B?"],"closing":"Imagine you''re sitting with Spiegel and Murphy in late November 2013. The Wall Street Journal is about to report the $3B offer either way. You don''t know what comes next.","decision":"Reject all three offers — Facebook, Tencent, and Google. Stay independent. Spiegel publicly framed the rejection as long-term conviction in what Snapchat could become; internally, the bet was that ephemerality was a behavior, not a feature, and that the format would proliferate (Stories, AR, the camera-as-keyboard interface) faster than any clone could keep up. Snap goes public in March 2017 at a $24B valuation. Facebook clones Stories across Instagram, WhatsApp, and Facebook itself within three years.","pullquote":"I wish I could say it was wisdom — but I think Bobby and I just loved what we were doing. We loved what we were working on, and we believed in the future of it.","pullquote_attribution":"Evan Spiegel, Snap cofounder/CEO — public interviews recalling the rejection","outcomes":[{"stat":"$3B","label":"Facebook cash offer rejected","accent":true},{"stat":"$4B","label":"Google all-cash offer also rejected"},{"stat":"Mar 2017","label":"Snap IPO at ~$24B valuation"},{"stat":"Stories","label":"format cloned across IG, WhatsApp, and Facebook within 3 years"},{"stat":"~30%","label":"of teen DAUs Snap retained against the Facebook clones"}],"tradeoffs":[{"title":"Liquid certainty vs. illiquid optionality","body":"$3B in cash for two founders in their early 20s is generational money. Saying no traded certain wealth for optionality on a much larger outcome — and the option could expire if Facebook executed the clone well."},{"title":"Feature defensibility vs. behavior defensibility","body":"If ''disappearing photos'' is the moat, the offer should be taken — features can be cloned in months. Spiegel''s bet was on a behavior (the camera-as-conversation) that''s harder to clone because it requires building a different relationship with the user, not just shipping a feature."},{"title":"Independence vs. distribution","body":"Joining Facebook would have given Snap distribution to a 1B+ user base overnight. Independence kept the brand, the audience (teens explicitly opting out of Facebook), and the product roadmap intact — but at the cost of building distribution the hard way."},{"title":"Negotiate vs. refuse","body":"Spiegel didn''t counter-offer. Refusing outright signaled conviction (to investors, to the team, to future hires) in a way that ''let''s talk at $6B'' would not. The signaling value of the refusal was itself a strategic asset."}],"per_dimension_truth":{"tradeoff":"Certain wealth + distribution muscle vs. independent control of a product category Spiegel believed was about to become much larger. He bet the latter was a 10x outcome, not a 2x one, and treated the offer as ceiling not floor.","user":"Teens explicitly opting out of Facebook''s identity-permanent feed. Joining Facebook would have changed who Snap was for, even if the product survived. The user was the moat.","alt":"Taking $3B was the rational, statistically defensible move. The opposite trade — staying independent — only looks correct because the behavior bet paid off enough to survive Facebook''s clone. The downside scenario (Snap loses to IG Stories, IPOs at a fraction) was very live.","predict":"Facebook clones aggressively, Snap loses some growth ceiling but defends a teen-camera audience, IPO at a multiple of the rejected offer, and a 5-year fight to prove the format mattered more than the wrapper."},"quote_type":"verbatim","sources":[{"title":"Snapchat''s 23-Year-Old CEO Said No to $3 Billion From Facebook","url":"https://www.nbcnews.com/id/wbna53545955","publisher":"NBC News","year":2013,"type":"article"},{"title":"Facebook offered $3 billion for Snapchat. Evan Spiegel said no.","url":"https://slate.com/technology/2013/11/facebook-offered-3-billion-for-snapchat-evan-spiegel-said-no.html","publisher":"Slate","year":2013,"type":"article"},{"title":"Evan Spiegel explains why he didn''t sell Snapchat to Mark Zuckerberg for $3 billion","url":"https://www.startuparchive.org/p/evan-spiegel-explains-why-he-didn-t-sell-snapchat-to-mark-zuckerberg-for-3-billion","publisher":"Startup Archive","type":"interview"}],"tags":{"industry":"consumer-social","region":"us","decade":"2010s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'atlassian-no-sales-team',
  'weekly',
  '{"id":"atlassian-no-sales-team","type":"weekly","iso_week":"","company":"Atlassian","era":"2002–2015 — founding through IPO","intro":"You are an early PM at Atlassian. It is the mid-2000s. Mike Cannon-Brookes and Scott Farquhar founded the company in Sydney with $10K of credit-card debt; the headquarters is on the other side of the Pacific from the vast majority of the addressable market. Jira and Confluence are gaining real traction with developer teams inside large enterprises.\n\nEvery enterprise software company at the time runs the same playbook: hire a US-based field-sales team, build out solutions engineering, push six-figure annual contracts, target the CIO. Atlassian''s competitors (Rally, VersionOne, IBM Rational) all do this. The two founders are 26 and 25 and have never been salespeople. The conventional wisdom from their VCs and advisors: hire a sales team, raise a B round, move to the US.","open_questions":["Hire the standard enterprise sales motion (and burn ~$5-10M of investment building it), or refuse and double down on self-serve product-led growth?","If self-serve only — how do you sell six-figure software to a Fortune 500 IT department without ever picking up the phone?","What''s the right pricing structure for self-serve enterprise — flat-rate tiers, per-seat, or per-team?","Does the headquarters stay in Sydney even as the customer base moves to the US — and what''s the cost of being 16 hours from your buyers?"],"closing":"Imagine you''re with Mike and Scott in 2008 in a Sydney office at 2am — your VCs in San Francisco are asking when the US sales team is getting hired.","decision":"Refuse to build a sales team. Every dollar that would have gone to AEs goes into the product, the website, and developer-facing content. Pricing is published on the website. A bank-card purchase replaces a procurement cycle. Atlassian stays headquartered in Sydney. The company runs profitably from year one. By the time of the December 2015 IPO, Atlassian is doing ~$350M in revenue with no traditional sales team and is profitable enough that the IPO raises almost no growth capital.","pullquote":"We''ve built a billion-dollar company without ever hiring a salesperson. The product is the sales team — everything else is overhead on the relationship the customer already wants.","pullquote_attribution":"Mike Cannon-Brookes / Scott Farquhar — paraphrased from Atlassian''s pre-IPO commentary and the Acquired podcast","outcomes":[{"stat":"0","label":"outbound salespeople through 2015 IPO","accent":true},{"stat":"$350M","label":"ARR at the time of IPO"},{"stat":"$4.37B","label":"valuation at NASDAQ IPO (Dec 2015)"},{"stat":"Sydney","label":"HQ — never moved despite US-dominated customer base"},{"stat":"Profitable","label":"from year one — no growth-at-all-costs funding required"}],"tradeoffs":[{"title":"Sales team vs. self-serve product","body":"A sales team accelerates large-deal velocity but adds permanent gross-margin drag and culture. Self-serve forces the product to do every job a salesperson would do — onboarding, expansion, renewals — and compounds product investment instead of headcount."},{"title":"Sydney HQ vs. US move","body":"Staying in Sydney meant cheaper engineering, a different talent pool, and a 16-hour gap to most customers. The cost: harder to recruit US executives; the benefit: distinct culture, no Bay Area salary arms-race, lower burn per engineer."},{"title":"Profitability vs. growth-at-all-costs","body":"Running profitably from year one limited the speed at which Atlassian could acquire customers but eliminated dilution and capital-market dependency. By IPO, the company didn''t need the public-market money — the IPO was a liquidity event for employees and investors, not a survival raise."},{"title":"Bottom-up adoption vs. top-down enterprise selling","body":"Selling to developers (who then carry the tool into their company) is a slower path than selling to CIOs but produces stickier deployments. Atlassian inverted the buying motion: by the time a procurement team noticed Jira, it was already running 200 teams inside the company."}],"per_dimension_truth":{"tradeoff":"Slower top-line growth and harder credibility with US enterprise buyers vs. structurally lower gross-margin drag, no dilution, and a culture that didn''t require Bay Area mimicry. They chose the latter and accepted the slower curve.","user":"Developers inside enterprises, not procurement officers. The buyer they served was the user, not the person with the budget — which meant the product had to do the buyer''s job (build the business case) itself.","alt":"Hiring a US sales team in 2008 would have accelerated revenue and likely required raising a B round + moving the HQ. The opposite trade. They were one of very few SaaS companies to refuse that path and still IPO at scale.","predict":"Slower revenue ramp than peers, profitability and capital efficiency well above peers, IPO with little fanfare and durable economics, and a playbook that every product-led-growth SaaS company would later try to copy."},"quote_type":"paraphrased","sources":[{"title":"The Atlassian IPO","url":"https://www.acquired.fm/episodes/the-atlassian-ipo","publisher":"Acquired Podcast","type":"podcast"},{"title":"Atlassian — Wikipedia","url":"https://en.wikipedia.org/wiki/Atlassian","type":"article"},{"title":"20 years of Atlassian, 20 lessons learned","url":"https://www.atlassian.com/blog/announcements/atlassian-founders-20-years-20-lessons","publisher":"Atlassian Blog","type":"blog"}],"tags":{"industry":"saas","region":"anz","decade":"2010s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'nokia-burning-platform-2011',
  'weekly',
  '{"id":"nokia-burning-platform-2011","type":"weekly","iso_week":"","company":"Nokia","era":"February 2011","intro":"It is early February 2011. You are a senior PM at Nokia. Nokia still ships more phones than any company on earth (~30%+ global market share). But smartphone share is collapsing. The iPhone shipped in 2007, Android in 2008; by Q4 2010, Nokia''s Symbian-based smartphones are losing share month over month and engineers internally have been saying for years that Symbian cannot compete on touch.\n\nThe new CEO, Stephen Elop — recruited from Microsoft — is about to write a memo to the entire company. The memo will describe Nokia''s situation using the metaphor of a man standing on a burning oil platform who has to choose between certain death in the fire and a jump into the freezing sea. The memo will then preview an exclusive partnership with Microsoft to ship Windows Phone as Nokia''s primary smartphone OS, abandoning Symbian and Nokia''s own internal Linux-based MeeGo. The memo is going to leak.","open_questions":["Bet on Symbian (legacy moat, declining), Android (growing fast, but commoditized), Windows Phone (new, niche, partnership with ex-employer), or MeeGo (in-house but unproven)?","How public to be about the platform''s failure — internal honesty vs. signaling weakness to competitors, employees, and the supply chain?","What''s the cost of the partnership exclusivity — does committing fully to Windows Phone foreclose the Android option permanently?","Is the goal to save the smartphone business or to maintain Nokia as a viable hardware brand on any platform?"],"closing":"Imagine you''re at Nokia HQ in Espoo, Finland in late January 2011. The memo is going to leak in days; the partnership announcement is two weeks out.","decision":"Send the ''burning platform'' memo internally on Feb 8, 2011 — it leaks within hours. Announce the exclusive Microsoft Windows Phone partnership on Feb 11. Symbian is officially deprecated. MeeGo is killed. Android is explicitly ruled out — Elop''s stated reason is that Nokia would have been one of many Android OEMs, undifferentiated. Three years later, Nokia''s smartphone business is sold to Microsoft. By 2013, Nokia shipped only 4.4M phones vs. 463M in 2007 — a 99% collapse.","pullquote":"We are standing on a burning platform. And, we have more than one explosion — we have multiple points of scorching heat that are fuelling a blazing fire around us.","pullquote_attribution":"Stephen Elop, Nokia CEO — internal ''burning platform'' memo, February 8, 2011","outcomes":[{"stat":"463M → 4.4M","label":"phones shipped 2007 → 2013 (~99% collapse)","accent":true},{"stat":"−90%","label":"market value lost in 6 years"},{"stat":"$7.2B","label":"Microsoft purchase of Nokia''s phone business (2013)"},{"stat":"0","label":"Android phones shipped under the original Nokia (the option Elop ruled out)"},{"stat":"Symbian","label":"deprecated; MeeGo killed; Windows Phone never reached 5% global share"}],"tradeoffs":[{"title":"Windows Phone vs. Android","body":"Windows Phone gave Nokia differentiated positioning (only major Windows Phone OEM, deep partnership) but in a tiny ecosystem. Android gave commodity positioning in a winning ecosystem. Elop chose differentiation in a losing race over commodity in a winning one."},{"title":"Burning the legacy publicly vs. quiet transition","body":"The ''burning platform'' memo was internal honesty made public. It rallied some engineers and accelerated the cultural break from Symbian, but it also crushed enterprise customer confidence in Nokia phones for a generation. The memo was likely correct in tone and catastrophic in market consequence."},{"title":"Exclusive partnership vs. multi-platform hedging","body":"Going all-in with Microsoft simplified focus and won partnership economics. Hedging with both Windows Phone and Android would have diluted execution but preserved optionality. Elop''s bet was that hedging was the death of focus; the cost was no fallback when Windows Phone failed."},{"title":"Manufacturer-as-OEM vs. manufacturer-as-platform","body":"Underneath every choice was a deeper question: does Nokia control its own OS, or does it ship someone else''s? Killing MeeGo answered ''someone else''s'' permanently — and turned Nokia from a vertical-stack company into a contract OEM running a partnership economy."}],"per_dimension_truth":{"tradeoff":"Honest internal alignment + decisive platform bet (Windows Phone) vs. preserving market confidence + keeping Android in play. Elop chose alignment + commitment; market confidence collapsed and the chosen platform lost.","user":"Symbian''s legacy enterprise/feature-phone users were left without a credible migration path. The product was no longer for them; it was for a new (and as it turned out, non-existent) Windows-Phone-loving consumer.","alt":"Hedging with Android would have meant slower commitment but preserved a route to relevance. Multiple OEMs survived that transition (Samsung, LG, HTC). Nokia foreclosed that option in the same week it killed Symbian.","predict":"Short-term: brand collapse, supply-chain pain, employee exodus. Medium-term: Windows Phone fails to gain share, Nokia''s smartphone business becomes acquisition fodder. Long-term: the burning-platform memo becomes the case study in how to be right about the diagnosis and wrong about the treatment."},"quote_type":"verbatim","sources":[{"title":"Nokia CEO Stephen Elop rallies troops in brutally honest ''burning platform'' memo","url":"https://www.engadget.com/2011-02-08-nokia-ceo-stephen-elop-rallies-troops-in-brutally-honest-burnin.html","publisher":"Engadget","year":2011,"type":"article"},{"title":"Stephen Elop — Wikipedia","url":"https://en.wikipedia.org/wiki/Stephen_Elop","type":"article"},{"title":"Who Killed Nokia? Nokia Did","url":"https://knowledge.insead.edu/strategy/who-killed-nokia-nokia-did","publisher":"INSEAD Knowledge","type":"article"}],"tags":{"industry":"hardware","region":"eu","decade":"2010s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'openai-chatgpt-launch-2022',
  'weekly',
  '{"id":"openai-chatgpt-launch-2022","type":"weekly","iso_week":"","company":"OpenAI","era":"November 2022","intro":"It is mid-November 2022. You are a senior PM at OpenAI. GPT-3.5 has been in private API access for over a year. Internally, a team has built a chat interface on top of it called ''Chat with GPT-3.5'' as a research demo — the product is not on the roadmap to ship publicly. The model has known issues: confident hallucination, sycophancy, jailbreaks, unsafe outputs.\n\nLeadership is debating whether to release the chat interface publicly as a free ''research preview.'' The cautious view: not ready, will produce embarrassing outputs at scale, will burn ~$700K/day in inference costs with no revenue, and will tip competitors (Google, Anthropic) to ship in response. The aggressive view: language models are already useful, real-world feedback is the only way to harden them, and being the first chat interface in the public mind is worth almost any short-term cost.","open_questions":["Ship the chat interface publicly as a ''research preview,'' or keep it API-only and let developers build the consumer experience?","Free or paid? Cost of inference is real; pricing it at $20/mo from day one would slow viral growth but contain burn.","How aggressive are the safety filters at launch — strict enough to prevent embarrassing outputs, or loose enough that the model actually feels useful?","How public to be about model limitations — full transparency upfront (manage expectations) vs. underplay (preserve magic)?"],"closing":"Imagine you''re in the OpenAI leadership room in mid-November 2022. NeurIPS is a few weeks out. You have a working chat interface and an internal disagreement about whether to ship.","decision":"Ship ChatGPT publicly on November 30, 2022 as a free ''research preview'' — no waitlist, no payment, available to anyone with an email. Frame the launch deliberately small: a single OpenAI blog post on a Wednesday during NeurIPS, no press tour, no demo videos. Sam Altman posts on Twitter that it is a ''very much a research release'' with ''a lot of limitations.'' One million users sign up in five days. Within two months, ChatGPT becomes the fastest-growing consumer product in history.","pullquote":"Today we launched ChatGPT. Try talking with it here. Language interfaces are going to be a big deal, I think. Talk to the computer (voice or text) and get what you want, for increasingly complex definitions of ''want.''","pullquote_attribution":"Sam Altman, OpenAI CEO — Twitter, November 30, 2022","outcomes":[{"stat":"1M","label":"users in 5 days — fastest consumer signup curve on record","accent":true},{"stat":"100M","label":"MAU within 2 months — fastest-growing consumer product in history"},{"stat":"~$700K/day","label":"estimated inference cost in the early days"},{"stat":"Code Red","label":"Google''s internal response — accelerating Bard/Gemini timelines"},{"stat":"$80B+","label":"OpenAI valuation within 18 months of launch"}],"tradeoffs":[{"title":"Ship rough vs. ship polished","body":"Shipping a research preview with visible flaws (hallucination, jailbreaks) meant accepting embarrassing screenshots in the press. The bet: real-world feedback at internet scale would improve the model faster than any amount of internal red-teaming. Polish would have cost the platform-defining moment."},{"title":"Free vs. paid","body":"Free unlocked viral growth but committed OpenAI to a massive subsidy. Pricing it would have constrained the audience and missed the cultural moment. They chose to eat the burn to own the mindshare."},{"title":"Quiet launch vs. loud launch","body":"A press-tour launch would have invited skeptical coverage of model limitations. A single blog post let the product speak for itself — and let the early-adopter screenshots do the marketing. Understatement was a deliberate amplifier."},{"title":"First-mover vs. wait-for-Google","body":"Google had stronger underlying research but more brand/regulatory risk in shipping a hallucinating chatbot. Going first was the riskiest move for safety reputation but the only way to define the category before a larger incumbent did."}],"per_dimension_truth":{"tradeoff":"Real-world feedback + category ownership vs. polish + safety reputation. They chose to ship rough and accept the safety drama as the cost of owning the conversation. Almost every later product decision (ChatGPT Plus, the API, Plugins, GPTs) flowed from the audience this single launch created.","user":"Curious early-adopters and developers — not a specific consumer segment. The launch worked precisely because the audience was ''anyone curious,'' which let the product define its own use cases (writing, coding, research, search) through user behavior rather than positioning.","alt":"Keeping the chat interface internal and shipping only the API would have ceded the consumer moment to whoever shipped the first chat wrapper. The opposite trade — and Google, Microsoft, and Anthropic all moved within 90 days because OpenAI shipped first.","predict":"Massive launch curve, safety scandals and embarrassing screenshots, an accelerated competitive race (Google Bard within 90 days), and a multi-year regime where ''ChatGPT'' becomes the consumer synonym for AI — with all the brand and regulatory consequences that follow."},"quote_type":"verbatim","sources":[{"title":"Introducing ChatGPT","url":"https://openai.com/index/chatgpt/","publisher":"OpenAI","year":2022,"type":"blog"},{"title":"ChatGPT — Wikipedia","url":"https://en.wikipedia.org/wiki/ChatGPT","type":"article"},{"title":"ChatGPT launched six months ago. Its impact — and fallout — is just beginning","url":"https://venturebeat.com/ai/chatgpt-launched-six-months-ago-its-impact-and-fallout-is-just-beginning-the-ai-beat","publisher":"VentureBeat","year":2023,"type":"article"}],"tags":{"industry":"ai-tools","region":"us","decade":"2020s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'openai-board-fires-altman-2023',
  'weekly',
  '{"id":"openai-board-fires-altman-2023","type":"weekly","iso_week":"","company":"OpenAI","era":"November 17–22, 2023","intro":"It is Friday morning, November 17, 2023. You are on the OpenAI leadership team. ChatGPT has been live for almost exactly one year. The company is on track to hit $1B+ in ARR. Microsoft has invested ~$13B. There are ~770 employees.\n\nAt around noon Pacific, the board of directors — four members plus chief scientist Ilya Sutskever — votes to fire Sam Altman. The stated reason: Altman was ''not consistently candid'' with the board. There is no public scandal, no financial wrongdoing, no product disaster. President Greg Brockman is removed from the board and quits in solidarity within hours. CTO Mira Murati is named interim CEO. Microsoft''s CEO Satya Nadella is given less than a minute of notice. The stock drops. Investors and Microsoft begin pushing for Altman''s reinstatement.","open_questions":["Who actually runs OpenAI on Monday morning — interim CEO Murati, the board, Microsoft, or whoever the 770 employees choose to follow?","Is this a governance crisis, a safety-vs-commercial dispute, or a CEO performance call? The board hasn''t said publicly — should it?","What''s Microsoft''s actual leverage here, given they own 49% of the for-profit but the nonprofit board controls the entity?","If employees revolt en masse, does the board hold the line on its decision or capitulate — and what does either option do to the institution?"],"closing":"Imagine you''re inside OpenAI over the weekend of November 18–19, 2023. Slack is on fire. Nobody knows who is in charge. Microsoft has just offered to hire any employee who wants to leave.","decision":"Within five days, the board''s decision is reversed. By Sunday Nov 19 the board offered the CEO role to ex-Twitch CEO Emmett Shear; Altman and Brockman went to Microsoft, which offered to host them and any defecting OpenAI staff. On Monday Nov 20, roughly 95% of OpenAI employees (~700 of 770) signed an open letter threatening to resign and join Microsoft unless Altman returned and the board resigned. By Tuesday Nov 21 the board capitulated. By midnight Wednesday Nov 22, Altman was reinstated as CEO, Brockman returned as president, and three of the four ousting board members were replaced.","pullquote":"OpenAI is nothing without its people.","pullquote_attribution":"Mira Murati and roughly 700 OpenAI employees — open letter to the board, November 20, 2023","outcomes":[{"stat":"5 days","label":"from firing to reinstatement","accent":true},{"stat":"~95%","label":"of employees signed the threatened-resignation letter"},{"stat":"3 of 4","label":"ousting board members removed after the reversal"},{"stat":"$13B","label":"Microsoft investment that gave Satya Nadella the leverage to broker the resolution"},{"stat":"$80B+","label":"OpenAI valuation in the tender offer ~3 months later"}],"tradeoffs":[{"title":"Mission governance vs. talent reality","body":"The OpenAI charter put a non-profit board in charge of an AGI-focused mission, explicitly so the board could fire the CEO if commercialization conflicted with safety. The 2023 events showed that mission governance is real on paper but dependent on the talent staying — when the talent moved, the governance evaporated within a week."},{"title":"Transparent reasons vs. board confidentiality","body":"The board never publicly stated what ''not consistently candid'' actually referred to. Withholding the substance preserved governance norms but emptied the board''s credibility — the employee revolt was possible partly because the rationale wasn''t legible."},{"title":"Microsoft as savior vs. Microsoft as acquirer","body":"Nadella''s offer to host Altman + any OpenAI staff at Microsoft was simultaneously rescue and acquisition without paying. Microsoft would have effectively absorbed OpenAI''s leadership and most of its workforce for free. The threat broke the standoff in OpenAI''s favor in a way that protected OpenAI''s legal identity, but redrew the power balance between the two companies permanently."},{"title":"Decisive board action vs. coalition building","body":"The board moved fast and unilaterally — no warning to Microsoft, no broad executive consultation. Coalition-building before the firing would have leaked the intent. Moving fast preserved surprise but left the board with no internal allies when the response hit."}],"per_dimension_truth":{"tradeoff":"Speed and surprise of a governance action vs. the legitimacy and coalition needed to make it stick. The board chose speed and surprise; in modern tech-talent companies, that trade often loses inside a week.","user":"The ''users'' here are the employees and Microsoft, not the public. The board''s mistake was treating OpenAI like a normal company with switchable employees; in fact the company''s value lived in the specific people who threatened to leave.","alt":"Holding the line — refusing to reinstate Altman, accepting mass resignations — would have technically preserved board authority. It would also have transferred OpenAI''s research talent to Microsoft, leaving the OpenAI legal entity as a husk. The opposite trade was not viable.","predict":"Short-term: chaos and a near-collapse of the company over a weekend. Medium-term: Altman returns, the board is reconstituted with industry-friendly members (Bret Taylor, Larry Summers, Adam D''Angelo), and OpenAI restructures to dilute the nonprofit''s control. Long-term: the original AGI-governance experiment becomes a cautionary case study in how concentrated talent rewrites stated governance."},"quote_type":"verbatim","sources":[{"title":"Removal of Sam Altman from OpenAI — Wikipedia","url":"https://en.wikipedia.org/wiki/Removal_of_Sam_Altman_from_OpenAI","type":"article"},{"title":"OpenAI announces leadership transition","url":"https://openai.com/index/openai-announces-leadership-transition/","publisher":"OpenAI","year":2023,"type":"press-release"},{"title":"OpenAI''s Sam Altman exits as CEO — ''board no longer has confidence''","url":"https://www.cnbc.com/2023/11/17/sam-altman-leaves-openai-mira-murati-appointed-interim-boss.html","publisher":"CNBC","year":2023,"type":"article"},{"title":"How OpenAI CEO Sam Altman Was Fired by Rival Board Members","url":"https://sfstandard.com/2023/11/17/openai-sam-altman-firing-board-members/","publisher":"SF Standard","year":2023,"type":"article"}],"tags":{"industry":"ai-tools","region":"us","decade":"2020s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'robinhood-gamestop-halt-2021',
  'weekly',
  '{"id":"robinhood-gamestop-halt-2021","type":"weekly","iso_week":"","company":"Robinhood","era":"January 27–28, 2021","intro":"It is the morning of January 28, 2021. You are an operations leader at Robinhood. Over the past five days, retail traders coordinating on r/wallstreetbets have squeezed GameStop ($GME) from ~$40 to ~$350. Other ''meme stocks'' (AMC, BB, NOK) are running similarly. Robinhood''s app is the primary on-ramp for this trade. Around 5:11am Eastern, the NSCC clearinghouse sends Robinhood an automated demand: post an additional $3 billion in collateral within hours to cover settlement risk on the volatile trades. Robinhood has nowhere near $3B in liquidity sitting around.\n\nThe leadership team — Vlad Tenev and a small operating group — has roughly three hours to choose: post the collateral somehow (and risk insolvency if positions move further), restrict trading in the affected stocks (and inflict the worst PR event in fintech in a decade), or shut the platform down.","open_questions":["Can you actually raise $3B in collateral by market open — and if so, from whom and at what cost?","Restricting buys (but allowing sells) sounds neutral operationally — but how does it look to a retail customer who can''t add to a position while the hedge funds you compete with can?","Is the right communication framing ''clearinghouse rules forced our hand'' (technical, defensive) or ''protecting customers from a runaway market'' (paternalistic)? Either has different downstream costs.","How much of the brand — ''democratize finance'' — survives any version of restricting customer trades, even temporarily?"],"closing":"Imagine you''re in the Robinhood war room at 7am Eastern, January 28, 2021. NSCC wants $3B. Market opens in 2.5 hours.","decision":"Restrict buy-side trades in GameStop and a basket of other volatile names, while still permitting sells. Simultaneously raise $1B in emergency equity from existing investors that day; raise an additional $2.4B the following days, for a total of ~$3.4B in four days. Tenev publicly explains the restrictions as forced by clearinghouse capital requirements. The decision sparks immediate accusations of hedge-fund collusion (false but instinctive). Tenev testifies before Congress in February 2021 to defend it.","pullquote":"We had no choice in this case. We had to conform to our regulatory capital requirements.","pullquote_attribution":"Vlad Tenev, Robinhood cofounder/CEO — congressional testimony, February 18, 2021","outcomes":[{"stat":"$3.4B","label":"emergency capital raised in 4 days","accent":true},{"stat":"Buy halt","label":"imposed on GME and select volatile names"},{"stat":"Class actions","label":"filed within hours; multiple state AG probes"},{"stat":"Cong. testimony","label":"Tenev defends decision under oath, Feb 18, 2021"},{"stat":"Jul 2021","label":"Robinhood IPOs at ~$32B valuation, six months later"}],"tradeoffs":[{"title":"Survival vs. brand integrity","body":"Posting the collateral was non-negotiable for survival; the only knob available was reducing the exposure by halting buys. The decision cost Robinhood its ''democratize finance'' brand identity in a single morning. They chose survival; the brand consequence will outlive the trade."},{"title":"Communicate plumbing vs. communicate paternalism","body":"Explaining ''clearinghouse capital rules'' is technically accurate but inscrutable to retail. Framing as ''protecting customers'' is legible but feels paternalistic from a brokerage that just stopped them from buying. They chose plumbing — and the retail audience translated it as ''they''re lying for the hedge funds.''"},{"title":"Customer-first vs. counterparty-first","body":"Brokerages operate inside a settlement system designed for counterparty solvency, not customer experience. The Robinhood narrative had been customer-first; the plumbing forced a counterparty-first action. The gap between brand promise and operational reality is the entire story of this week."},{"title":"Halt now vs. accept insolvency risk","body":"Not halting buys would have meant posting more collateral than Robinhood could raise, with real insolvency risk. The opposite trade was ''go down with the brand intact.'' Tenev chose corporate survival; some employees and customers explicitly thought the alternative was the right call."}],"per_dimension_truth":{"tradeoff":"Corporate solvency vs. brand promise. They could not preserve both inside the existing settlement infrastructure. They chose solvency, raised emergency capital, accepted the brand hit, and IPO''d six months later. The decision was rational; the public legibility of it was the failure.","user":"Retail traders who joined Robinhood specifically because they distrusted incumbent brokerages. By halting buys, Robinhood reproduced the exact behavior — ''they protect insiders'' — that their customers had left Schwab/Fidelity to escape. The user perception was structurally worse than the operational facts justified.","alt":"The opposite trade — halt nothing, fail to post collateral, become insolvent — was not a serious option. The realistic counterfactual was ''communicate the plumbing better, faster, with executives visible and contrite.'' Robinhood failed at that, and the brand cost was largely communication, not the underlying restriction.","predict":"Short-term: PR catastrophe, class actions, congressional testimony. Medium-term: IPO completes, settlement-cycle reforms (T+1) accelerate industry-wide, Robinhood''s brand never fully recovers as the ''rebel broker.'' Long-term: the GameStop week becomes the canonical case in how brokerage plumbing constrains brand promises."},"quote_type":"verbatim","sources":[{"title":"Vlad Tenev — Congressional Testimony on GameStop","url":"https://www.congress.gov/117/meeting/house/111207/witnesses/HHRG-117-BA00-Wstate-TenevV-20210218.pdf","publisher":"US House of Representatives","year":2021,"type":"filing"},{"title":"Robinhood, Reddit, and GameStop: What Happened and What Should Happen Next?","url":"https://www.scu.edu/ethics/focus-areas/business-ethics/resources/robinhood-reddit-and-gamestop-what-happened-and-what-should-happen-next/","publisher":"Markkula Center for Applied Ethics","type":"article"},{"title":"Robinhood CEO, hedge fund execs defend their role in GameStop frenzy","url":"https://www.cbsnews.com/news/gamestop-robinhood-vlad-tenev-house-hearing/","publisher":"CBS News","year":2021,"type":"article"}],"tags":{"industry":"fintech","region":"us","decade":"2020s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'instagram-stories-clone-2016',
  'weekly',
  '{"id":"instagram-stories-clone-2016","type":"weekly","iso_week":"","company":"Instagram (Meta)","era":"Late 2015 – August 2016","intro":"It is late 2015 / early 2016. You are a senior PM on Instagram inside Facebook. Instagram has ~400M MAU and is growing well. But there''s a specific cohort — US teenagers and young adults — drifting to Snapchat for one specific behavior: ephemeral, low-stakes ''stories'' (24-hour photos and short videos) that don''t carry the identity weight of the permanent Instagram feed. Snapchat Stories shipped in late 2013 and has the format to itself.\n\nKevin Systrom has personally been resistant — he told an engineer who proposed it, ''I''m tired of hearing this sh--… we will not ever have Stories.'' Multiple internal teams have proposed cloning the feature. Facebook had already tried (Poke, Slingshot, both failed). The argument inside is that Instagram''s identity — the permanent, curated feed — is structurally hostile to the Stories format.","open_questions":["Clone the format directly, or attempt a ''differentiated'' ephemeral product that risks the same failure mode as Poke and Slingshot?","Where does the format live in the app — top of feed (cannibalizes the feed), separate tab (low discovery), or in the camera (rebuilds the camera surface)?","How public to be about copying Snapchat — credit them openly (Systrom''s later stance), or position it as ''Instagram''s take on Stories'' (rewrite-the-history play)?","What if Snapchat retaliates by raising or accepting an acquisition offer from a competitor (Google had bid $4B)?"],"closing":"Imagine you''re presenting the case to Systrom in early 2016 with Mark Zuckerberg''s full attention behind you. Systrom has already said no.","decision":"Ship Instagram Stories on August 2, 2016 — a near-pixel-for-pixel clone of Snapchat Stories. Located at the top of the home feed, prominent and unavoidable. Systrom publicly credits Snapchat: ''They deserve all the credit.'' Within two months, Instagram Stories has 100M DAU — a milestone Snapchat took years to reach. Within 18 months, Snapchat''s user growth flatlines. Stories absorbs into WhatsApp and Facebook within a year. Snap''s stock craters in 2018.","pullquote":"They deserve all the credit. This isn''t about who invented something. This is about a format, and how you take it to a network and put your own spin on it.","pullquote_attribution":"Kevin Systrom, Instagram cofounder/CEO — TechCrunch interview, August 2, 2016","outcomes":[{"stat":"100M DAU","label":"Instagram Stories users in 2 months — faster than Snap reached","accent":true},{"stat":"Aug 2016","label":"launch — 32 months after Snapchat Stories shipped"},{"stat":"WhatsApp + FB","label":"Stories cloned across the entire Meta family within 12 months"},{"stat":"−80%","label":"Snap stock from 2017 IPO peak to 2018 trough"},{"stat":"Top-of-feed","label":"placement — the unavoidable strategic moat"}],"tradeoffs":[{"title":"Clone directly vs. differentiated alternative","body":"Cloning Snapchat exactly meant accepting public ridicule for copying. A differentiated ''Instagram''s version'' would have invited Poke/Slingshot territory: novel and failed. Systrom chose the embarrassment over the failure mode."},{"title":"Top-of-feed vs. separate tab","body":"Stories at the top of the feed cannibalized attention from the permanent feed (Instagram''s core monetization surface). A separate tab would have protected the feed but starved Stories of discovery. Choosing the top-of-feed placement was the entire bet — distribution beat protection."},{"title":"Open credit vs. quiet copy","body":"Systrom''s ''they deserve all the credit'' line was both genuine and strategic. It defused the ''shameless clone'' narrative (which Snap couldn''t then weaponize) while making the feature inevitable. Quiet copying would have made Snap''s PR response easier."},{"title":"Cannibalize the feed vs. protect the cash cow","body":"Stories sit above the feed and pull engagement away from it. Instagram explicitly accepted that hit because the alternative — Snap absorbing the teen ephemeral surface — was structurally worse. Same calculus Netflix used with streaming-vs-DVD nine years earlier."}],"per_dimension_truth":{"tradeoff":"Public reputational hit (the ''shameless clone'' coverage) and partial cannibalization of the feed vs. ceding the ephemeral format permanently to Snapchat. Instagram chose the hit, accepted the cannibalization, and won.","user":"US teenagers + young adults who had drifted to Snapchat for the format. The bet was that they preferred the Stories format more than they preferred Snapchat-the-app — and were on Instagram already. Bringing the format to them was lower-friction than asking them to move back.","alt":"Building ''Instagram Moments'' or another original ephemeral surface would have preserved dignity but failed (Poke and Slingshot already proved Facebook couldn''t ship original ephemeral products). The opposite trade — and choosing it would have cost Meta the entire teen cohort for half a decade.","predict":"Press calls it shameless. Snapchat''s growth stalls inside 6 months. Stories format absorbs across the Meta family. Snap survives but stops being the trajectory it was. The ''clone'' decision becomes the canonical case study for when copying beats originality."},"quote_type":"verbatim","sources":[{"title":"Instagram CEO on Stories: Snapchat deserves all the credit","url":"https://techcrunch.com/2016/08/02/silicon-copy/","publisher":"TechCrunch","year":2016,"type":"article"},{"title":"Instagram launches ''Stories,'' a Snapchatty feature for imperfect sharing","url":"https://techcrunch.com/2016/08/02/instagram-stories/","publisher":"TechCrunch","year":2016,"type":"article"},{"title":"Instagram''s Kevin Systrom ignored suggestions to copy Snapchat Stories","url":"https://www.cnbc.com/2020/04/08/instagrams-kevin-systrom-ignored-suggestions-to-copy-snapchat-stories.html","publisher":"CNBC","year":2020,"type":"article"}],"tags":{"industry":"consumer-social","region":"us","decade":"2010s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'adobe-creative-cloud-2013',
  'weekly',
  '{"id":"adobe-creative-cloud-2013","type":"weekly","iso_week":"","company":"Adobe","era":"2011–2013","intro":"You are a senior PM at Adobe. It is 2011–2012. Adobe sells Creative Suite — Photoshop, Illustrator, InDesign — as a $2,600 perpetual-license box. Customers buy a version, then upgrade every 18–24 months at ~$600 per upgrade. Revenue is highly seasonal and tied to upgrade cycles. Roughly 30–40% of installs are pirated. Piracy is endemic but tolerated as a top-of-funnel.\n\nCFO Mark Garrett and CEO Shantanu Narayen have been running the numbers since 2011. They believe Adobe must move to a subscription-only model — Creative Cloud, $50/month, no perpetual licenses ever again. The transition will tank revenue in the short term (subscriptions front-load less cash than license sales), enrage the existing customer base (many of whom use software occasionally and never want monthly bills), and effectively forfeit a large piece of the pirated install base. Wall Street is unconvinced.","open_questions":["Subscription-only or dual-model (subscription alongside perpetual licenses)? Dual is safer but signals lack of conviction.","What price point — $50/mo (suite), $20/mo (single-app), or both? Each implies a different customer.","How to handle the existing perpetual-license base — generous grandfathering (revenue hit) or hard cutover (PR hit)?","Can the financials survive Wall Street''s reaction during the multi-year revenue trough?"],"closing":"Imagine you''re in the Adobe leadership room in early 2013. The decision is signed off internally; the announcement is two months out; you don''t yet know how the customer base will react.","decision":"Announce in May 2013 that Creative Suite is dead. Going forward, the only way to use Photoshop, Illustrator, and the rest is Creative Cloud — subscription only. $50/mo for the full suite, $20/mo for single-app. No more perpetual licenses, ever. A Change.org petition hits 50,000 signatures. Forums explode. Industry press calls it ''greedy.'' Adobe holds the line. Revenue dips for two years. By 2017 it is materially above pre-transition; by 2025, Adobe reports $23.77B revenue with 96% from subscriptions.","pullquote":"We had a choice between short-term pain to do the right thing or to let the model stagnate. We chose the pain.","pullquote_attribution":"Shantanu Narayen, Adobe CEO — paraphrased from public investor commentary on the Creative Cloud transition","outcomes":[{"stat":"May 2013","label":"subscription-only announcement; perpetual licenses killed","accent":true},{"stat":"50,000","label":"Change.org petition signatures against the move"},{"stat":"2 yrs","label":"of revenue dip before the model surpassed perpetual"},{"stat":"$4.4B → $23.77B","label":"annual revenue (last perpetual year → FY2025)"},{"stat":"96%","label":"of FY2025 revenue from subscriptions"}],"tradeoffs":[{"title":"Short-term revenue hit vs. long-term recurring revenue","body":"Perpetual licenses front-load cash; subscriptions amortize it. The transition guaranteed a multi-year revenue dip — which is precisely what showed up in 2013–2015 financials. Narayen ate the dip to capture the model. Most public CEOs cannot survive that decision; Adobe''s board explicitly backed it."},{"title":"Customer trust vs. business model alignment","body":"The existing customer base felt they were being held hostage. The decision optimized for future Adobe (continuous innovation funded by recurring revenue) at the explicit cost of trust with legacy power-users. The backlash was real and predicted."},{"title":"Subscription-only vs. dual-model","body":"Offering a dual model would have softened the backlash but preserved a non-trivial perpetual cohort indefinitely — a permanent two-tier customer base. Narayen''s argument was that dual-model is the failure mode (it kills both businesses slowly). Subscription-only was a forcing function."},{"title":"Piracy as funnel vs. piracy as drag","body":"Perpetual licensing tolerated piracy because pirated users converted at decent rates. Subscription killed that funnel — pirated copies don''t ''expire'' into paid customers as easily. Adobe accepted that loss because subscription''s compounding revenue was worth more than the pirate-converter pipeline."}],"per_dimension_truth":{"tradeoff":"Short-term revenue + trust hit vs. compounding recurring revenue + continuous-investment-into-product runway. They took the hit because the perpetual model was structurally ceiling-bound — every release had to justify a $600 upgrade, slowing the product cadence.","user":"Professional creatives at design agencies, studios, and in-house teams who already paid Adobe annually. The bet was that this segment values continuous updates more than perpetual ownership; the freelance and casual-user segment was effectively de-prioritized.","alt":"A dual-model (subscription alongside perpetual) would have been politically easier and likely would have produced the worst of both worlds — perpetual-license holders staying perpetually, subscription growth slowed by the alternative. Adobe explicitly rejected the safer move.","predict":"Year 1–2: revenue dip, customer revolt, press villainization. Year 3–5: model proves out, ARR compounds, the freelance/casual cohort migrates or churns. Year 10+: subscription becomes the default for every category of creative tool, and Adobe''s competitors (Figma, Canva) compete on the model Adobe normalized."},"quote_type":"paraphrased","sources":[{"title":"Why Adobe Moved to Subscription Model Despite Backlash","url":"https://arthnova.com/why-adobe-moved-to-subscription-model-despite-backlash/","type":"article"},{"title":"Adobe Shifts to Creative Cloud (2013)","url":"https://www.stratrix.com/strategic-forks/adobe-creative-cloud","publisher":"Strategic Forks","type":"blog"},{"title":"Lessons from Adobe''s Shift to Subscriptions: A Pricing Transformation Story","url":"https://www.getmonetizely.com/articles/lessons-from-adobes-shift-to-subscriptions-a-pricing-transformation-story","publisher":"Monetizely","type":"article"}],"tags":{"industry":"saas","region":"us","decade":"2010s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'microsoft-acquires-github-2018',
  'weekly',
  '{"id":"microsoft-acquires-github-2018","type":"weekly","iso_week":"","company":"Microsoft","era":"June 2018","intro":"It is mid-2018. You are a senior PM / corp-dev leader at Microsoft. Satya Nadella has been CEO for four years. The Microsoft-vs-open-source war of the Ballmer era — ''Linux is a cancer'' — is dead. Microsoft is now contributing to Linux, has shipped VS Code, and is the largest open-source contributor on GitHub by employee count. But GitHub itself is having a rough year: the company is searching for a CEO, growth has slowed, and there''s quiet pressure on the board to find a strategic buyer.\n\nNadella''s team has been talking to GitHub leadership for months. The price floats around $7.5 billion in Microsoft stock — for a company with ~$300M in revenue and a lot of strategic optionality but no profit. The developer community''s instinctive reaction will be hostile: ''Microsoft is going to ruin GitHub,'' ''they''ll embrace-extend-extinguish it.'' Internally at Microsoft, parts of the Azure DevOps org actively dislike the deal because GitHub competes with their products.","open_questions":["Buy GitHub or build inside Azure DevOps? Build is cheaper but slower and won''t win the developer-mindshare battle GitHub already won.","If buy — how to structure governance so the developer community believes ''Microsoft won''t ruin it''? Independent operating entity, or absorb into Azure?","What signal does $7.5B for a $300M-revenue company send to other strategic targets — does it inflate Microsoft''s M&A premium permanently?","Does this give Microsoft control of the open-source supply chain (and the regulatory questions that come with it)?"],"closing":"Imagine you''re at Microsoft headquarters in May 2018, days from the announcement. Developer Twitter is already speculating. The acquisition is going to be the biggest test of Nadella''s ''we love developers'' narrative.","decision":"Announce the acquisition on June 4, 2018, for $7.5B in Microsoft stock. Structurally, GitHub remains an independent platform with its own brand, leadership (Nat Friedman, ex-Xamarin), and offices. No forced Azure integration. Nadella personally appears in the announcement and frames Microsoft as ''all-in on open source.'' The deal closes October 2018. Within 18 months: GitHub Actions launches, GitHub paid users grow ~3x, and GitHub Copilot ships (a product only possible because Microsoft owns both GitHub data and OpenAI''s models).","pullquote":"Microsoft is a developer-first company, and by joining forces with GitHub we strengthen our commitment to developer freedom, openness and innovation.","pullquote_attribution":"Satya Nadella, Microsoft CEO — Microsoft Blog, June 4, 2018","outcomes":[{"stat":"$7.5B","label":"all-stock acquisition price (~25x revenue)","accent":true},{"stat":"Independent","label":"operating entity preserved; Nat Friedman appointed CEO"},{"stat":"GitHub Actions","label":"shipped 12 months post-close — CI/CD competitive with the industry overnight"},{"stat":"Copilot","label":"launched 2021 — only buildable because Microsoft owns both GitHub + OpenAI"},{"stat":"100M+","label":"GitHub developers by 2023, up from ~28M at acquisition"}],"tradeoffs":[{"title":"Buy vs. build","body":"Building developer mindshare with Azure DevOps would have cost the same money (probably more) and taken a decade. Buying the existing center of gravity was faster but more expensive. Nadella chose speed and brand inheritance over slow internal compounding."},{"title":"Independent operating vs. Azure integration","body":"Forcing GitHub into Azure would have accelerated revenue synergies but would have validated every fear about ''Microsoft will ruin GitHub.'' Nadella ate the slower revenue path to preserve the developer trust. The Copilot collaboration showed independent could still surface deep integration where it mattered."},{"title":"Public trust vs. private leverage","body":"The public framing was ''developer freedom, openness.'' Behind that, owning GitHub gave Microsoft an unprecedented view into how every major company''s software gets built — a strategic asset that is rarely discussed publicly but enormous in practice. The deal is simultaneously the most developer-friendly acquisition of the decade and the most strategically dominant."},{"title":"Cannibalize Azure DevOps vs. preserve internal incumbents","body":"GitHub directly competed with Microsoft''s existing developer tooling org. Acquiring it explicitly disempowered the internal incumbents. Nadella''s choice — kill Azure DevOps'' independence rather than protect it — set a precedent for the cultural transformation of the entire company."}],"per_dimension_truth":{"tradeoff":"Buy speed + brand inheritance at a 25x revenue multiple vs. slower, cheaper, but probably-failed internal build. Microsoft chose to pay the premium because developer mindshare is not a market you can grind into.","user":"Developers — specifically the cohort that had been suspicious of Microsoft since the 1990s. The deal was structured to convert them, not just buy them. Independent operating + the choice of Friedman as CEO (a beloved open-source figure) was the conversion mechanism.","alt":"Microsoft could have bought GitLab or a smaller competitor at one-tenth the price. The opposite trade. But GitLab didn''t have the network effects — buying the smaller player would have inherited the platform without the audience. The premium was for the audience, not the code.","predict":"Initial developer backlash, contained within weeks because Nadella''s narrative held + Friedman was trusted. Independent operation preserves brand. Three to five years out, deep platform integrations (Actions, Copilot) prove the deal was undervalued at $7.5B. The acquisition becomes the canonical ''do-not-break-what-you-bought'' M&A case."},"quote_type":"verbatim","sources":[{"title":"Microsoft + GitHub = Empowering Developers","url":"https://blogs.microsoft.com/blog/2018/06/04/microsoft-github-empowering-developers/","publisher":"Microsoft Blog","year":2018,"type":"blog"},{"title":"Microsoft to acquire GitHub for $7.5 billion","url":"https://news.microsoft.com/source/2018/06/04/microsoft-to-acquire-github-for-7-5-billion/","publisher":"Microsoft News","year":2018,"type":"press-release"},{"title":"Microsoft CEO Satya Nadella says $7.5 billion GitHub deal shows, ''We are all in on open source''","url":"https://www.cnbc.com/2018/06/04/microsoft-ceo-satya-nadella-on-github-we-are-all-in-on-open-source.html","publisher":"CNBC","year":2018,"type":"article"}],"tags":{"industry":"devtools","region":"us","decade":"2010s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'disney-plus-launch-2019',
  'weekly',
  '{"id":"disney-plus-launch-2019","type":"weekly","iso_week":"","company":"Disney","era":"2017–November 12, 2019","intro":"It is 2017–2018. You are a senior PM / strategy lead at Disney. Disney makes about $5 billion a year licensing content (Marvel, Pixar, Star Wars, Disney animated, National Geographic) to Netflix and other streaming platforms — pure margin, no infrastructure cost. Netflix has become the largest single buyer of Disney content. Bob Iger and the Disney board are debating whether to pull all of that content off Netflix and build Disney''s own streaming service.\n\nThe math is brutal. Pulling content means giving up the licensing revenue (immediate cash). Building a global streaming platform means hundreds of millions in tech build-out. Pricing has to undercut Netflix — but going too low erodes the perceived value of the Disney brand. And Disney has no consumer-direct streaming muscle; the historical Disney customer relationship has been theme-park / theatrical / TV-affiliate, not direct subscription.","open_questions":["Pull content from Netflix entirely, or keep some licensing revenue alongside a new service?","Price aggressively ($5–7/mo) to seed an audience fast, or premium ($10–13/mo) to match Disney''s perceived brand value?","Build the streaming infrastructure in-house, or acquire BAMTech (the MLB-built streaming platform Disney already has minority stake in)?","Launch globally day one, or US-first with staggered international rollouts?"],"closing":"Imagine you''re presenting to Iger in late 2018. Netflix is winning. The licensing revenue is real but Disney''s content is funding a future competitor.","decision":"Buy out BAMTech for the streaming infrastructure (Aug 2017). Pull Disney content from Netflix by 2019. Launch Disney+ on November 12, 2019 at $6.99/month — less than half Netflix''s $12.99 — bundled with original Marvel/Star Wars content that wasn''t anywhere else. Bob Iger publicly frames it as ''our first serious foray.'' Disney+ hits 10M signups on day one. 50M within 5 months. 95M by Q4 2020 (accelerated by COVID).","pullquote":"This is our first serious foray in this space, and we want to reach as many people as possible with it.","pullquote_attribution":"Bob Iger, Disney CEO — investor commentary around the Disney+ pricing announcement, April 2019","outcomes":[{"stat":"$6.99/mo","label":"launch price — ~half of Netflix''s $12.99 standard tier"},{"stat":"10M","label":"signups on day one (Nov 12, 2019)","accent":true},{"stat":"50M","label":"subscribers within 5 months"},{"stat":"~$5B/yr","label":"in licensing revenue forfeited from Netflix"},{"stat":"BAMTech","label":"acquired ($1.58B for majority) to provide streaming infrastructure"}],"tradeoffs":[{"title":"Licensing revenue now vs. owning the customer later","body":"The Netflix licensing deal was pure-margin recurring cash with zero capex. Pulling content forfeited it. Disney explicitly traded current-year revenue for a customer relationship — the bet was that owning the subscription is worth more in 5 years than the license is today."},{"title":"Aggressive pricing vs. brand-protective pricing","body":"$6.99 signaled to consumers ''this is a no-brainer add-on'' rather than ''premium streaming destination.'' It traded margin headroom for adoption velocity. The bet: get to scale fast, then raise prices once the bundle is sticky (Disney+ now $15.99 ad-free, six years later)."},{"title":"Buy BAMTech vs. build streaming in-house","body":"Building from scratch would have taken 3–4 years; Disney didn''t have that runway against Netflix. Buying BAMTech compressed the technical ramp but inherited a system designed for MLB live-streaming, not catalog SVOD — leading to early reliability issues at launch."},{"title":"Day-one global vs. staged rollout","body":"Disney launched US/Canada/Netherlands first, then staged globally over 6–18 months. Going global at launch would have stretched content rights, customer support, and infrastructure too thin. Staging cost some early international subscribers but kept the launch experience reliable in the markets that mattered most."}],"per_dimension_truth":{"tradeoff":"$5B/yr of high-margin licensing revenue vs. building a $30B+ direct-to-consumer streaming asset over 5 years. Disney chose the latter — but the transition forced 3-5 years of margin pressure that the public markets punished before vindicating.","user":"Families with kids — the demographic for whom Marvel + Star Wars + Pixar + Disney animated is the dominant entertainment consumption pattern. The bet: this household will pay $6.99 even if they already pay $12.99 for Netflix. Disney+ was always positioned as an additive subscription, not a Netflix replacement.","alt":"Continuing to license to Netflix would have preserved revenue but allowed Netflix to use Disney''s content to fund its own originals — which would eventually compete with Disney IP. Disney''s leadership viewed this as the slow-death scenario. The choice was ''eat the revenue dip now'' vs ''lose the strategic position permanently.''","predict":"Massive launch curve, accelerated by COVID. Multi-year margin compression. Public-market punishment of the strategy before it works. Disney+ becomes the default ''second streaming subscription'' in US households. Long-term: the launch becomes the canonical case in ''when to disintermediate yourself before someone else does.''"},"quote_type":"verbatim","sources":[{"title":"Disney+ to Launch in November, Priced at $6.99 Monthly","url":"https://variety.com/2019/digital/news/disney-plus-streaming-launch-date-pricing-1203187007/","publisher":"Variety","year":2019,"type":"article"},{"title":"Disney+ streaming service will be available starting Nov. 12 for $6.99 a month","url":"https://www.cnbc.com/2019/04/11/disney-plus-will-be-available-starting-november-12-for-6point99-a-month.html","publisher":"CNBC","year":2019,"type":"article"},{"title":"Disney+ surpasses 10 million sign-ups since launch","url":"https://www.cnbc.com/2019/11/13/disney-surpasses-10-million-sign-ups-since-launch.html","publisher":"CNBC","year":2019,"type":"article"}],"tags":{"industry":"media","region":"us","decade":"2010s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'stripe-layoffs-2022',
  'weekly',
  '{"id":"stripe-layoffs-2022","type":"weekly","iso_week":"","company":"Stripe","era":"November 2022","intro":"It is October 2022. You are on the Stripe leadership team. Stripe has gone from ~3,000 employees in early 2021 to ~8,000 in late 2022 — more than doubled headcount on the back of a pandemic-fueled internet-economy boom. The internet-economy growth has slowed sharply. Revenue is still growing but operating costs have grown faster. The company is privately valued at $95B in early 2021 and ~$75B by late 2022.\n\nThe leadership team is debating: cut headcount now, deeply and visibly, or trust that growth will resume and ride out the slowdown. Other tech companies — Meta, Twitter, Salesforce — are cutting or about to cut. Patrick Collison and the founders have been famously cautious about layoffs (''we''ve never had a layoff'' was a stated point of pride). The question is whether the prior-year hiring pace was operationally healthy or an overreaction to the pandemic.","open_questions":["Cut now or wait one more quarter to see if growth re-accelerates?","How deep — 5%, 10%, 15%? Each implies a different read on how wrong the 2021 hiring was.","How transparent to be in the rationale — say ''we made a mistake'' (rare in tech CEO communications) or frame as ''macro forced this'' (industry-standard)?","What does cutting do to recruiting and culture — is ''never had a layoff'' a brand asset worth preserving, or a constraint that''s distorted decision-making?"],"closing":"Imagine you''re in the Stripe leadership room in October 2022. The first round of tech layoffs is in the news. Patrick Collison is writing the letter that will go to the company.","decision":"Cut 14% — roughly 1,100 people, taking headcount back to ~7,000. Collison sends a letter that opens with ''we overhired for the world we''re in'' — explicitly owning the mistake rather than blaming macro. Severance: 14+ weeks (more for longer tenure), full 2022 bonus paid, healthcare continuation, accelerated vesting for those near cliff. The letter is published externally on the day of the cut. The transparent rationale becomes a template that other tech CEOs reference in their own subsequent layoff letters.","pullquote":"We were much too optimistic about the internet economy''s near-term growth in 2022 and 2023. We overhired for the world we''re in, and it pains us to be unable to deliver the experience that we hoped that those impacted would have at Stripe.","pullquote_attribution":"Patrick Collison, Stripe cofounder/CEO — letter to employees, November 3, 2022","outcomes":[{"stat":"14%","label":"headcount cut (~1,100 people)","accent":true},{"stat":"14+ wks","label":"severance, with longer tenure getting more"},{"stat":"Public letter","label":"released same day; became the template tech CEOs cited"},{"stat":"$95B → $50B","label":"private valuation moved down through 2023"},{"stat":"Single cut","label":"Stripe has not run a second mass layoff since"}],"tradeoffs":[{"title":"Own the mistake vs. blame the macro","body":"The standard tech-CEO layoff letter blames macro conditions. Collison opened by stating Stripe overhired — a deliberate ownership move. Owning the mistake costs short-term confidence in leadership; not owning it costs the credibility to make future calls. Stripe chose the harder framing."},{"title":"Cut once deep vs. cut shallow twice","body":"A 7–8% cut would have been less painful but probably required a second round in 6 months — by then the macro got worse. 14% in one pass let Stripe avoid the second round Twitter, Meta, and Amazon all ended up doing. Same logic Brian Chesky used at Airbnb in 2020."},{"title":"Transparent letter vs. private comms","body":"Publishing the letter externally turned an internal painful moment into a public artifact. It cost some recruiting (laid-off employees on the open market is bad press) but earned credibility with the rest of the tech industry. The letter became a template — competitors writing their own layoff comms cited it."},{"title":"Generous severance vs. cash conservation","body":"14+ weeks of severance is unusually high for the industry. It cost real cash at a moment when the case for cuts was ''we have too many expenses.'' Collison chose generosity over cash optimization — preserving alumni goodwill (and rehiring optionality) explicitly worth more than the saved expense."}],"per_dimension_truth":{"tradeoff":"Short-term operational pain + brand hit (''Stripe finally had to lay off'') vs. avoiding the slow-cut multi-round scenario every peer ran. Stripe took the larger one-shot hit, owned the rationale openly, and avoided the multi-round trap.","user":"The audience for the letter was three groups simultaneously: laid-off employees (severance + dignity), remaining employees (rationale + signal that this is not the first of many cuts), and the broader tech industry (template-setting). The framing optimized for all three at once.","alt":"Cutting shallower and hoping growth resumed would have looked safer in November 2022 and likely forced a second round by mid-2023. The opposite trade — and the companies that ran it (Meta in particular) ended up doing multiple rounds and damaging trust each time.","predict":"Short-term pain and surprise — Stripe''s stated ''no layoffs ever'' culture broken. Medium-term: Collison''s letter cited as template by other tech CEOs writing their own cuts; the transparent-rationale framing becomes the industry default. Long-term: Stripe avoids a second cut, IPO market repairs, valuation recovers, and the 2022 letter becomes a leadership-communication case study."},"quote_type":"verbatim","sources":[{"title":"CEO Patrick Collison''s email to Stripe employees","url":"https://stripe.com/newsroom/news/ceo-patrick-collisons-email-to-stripe-employees","publisher":"Stripe Newsroom","year":2022,"type":"press-release"},{"title":"Stripe cuts 14% of its workforce, CEO says they ''overhired for the world we''re in''","url":"https://techcrunch.com/2022/11/03/stripe-cuts-14-of-its-workforce-ceo-says-they-overhired-for-the-world-were-in/","publisher":"TechCrunch","year":2022,"type":"article"},{"title":"As layoffs mount, one tech CEO figured out how to do them right","url":"https://fortune.com/2022/11/07/layoffs-tech-ceo-figured-out-how-to-do-them-right/","publisher":"Fortune","year":2022,"type":"article"}],"tags":{"industry":"fintech","region":"us","decade":"2020s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'slack-direct-listing-2019',
  'weekly',
  '{"id":"slack-direct-listing-2019","type":"weekly","iso_week":"","company":"Slack","era":"Early 2019 — June 20, 2019 NYSE direct listing","intro":"It is early 2019. You are a senior PM / strategy leader at Slack. Slack has ~$400M in ARR, ~$800M in cash on the balance sheet, and growing well into Fortune 500 enterprises. The default path for a public-ready SaaS company is a traditional IPO — book-build with two big investment banks, a roadshow, an underwriter-set ''IPO price'' that prints day-one trading ''pops'' for institutional allocators, and ~7% in underwriting fees paid out.\n\nStewart Butterfield doesn''t need the capital — Slack is already cash-rich. He proposes a direct listing on the NYSE instead. Direct listings let existing shareholders sell directly to the public on day one, no underwriting fees, no roadshow-set price, no IPO ''pop'' for institutional buyers, and no new capital raised. Spotify did one a year earlier; almost no one else has. The investment bankers Slack is talking to are unenthusiastic — direct listings cut them out of most of the fees.","open_questions":["Direct listing or traditional IPO — does avoiding ~$50M in underwriting fees outweigh the institutional-investor relationships a traditional IPO builds?","Without a roadshow + ''IPO price,'' how does the market price the stock on day one — and what''s the downside if it prices poorly?","Without raising new capital, what''s the going-public moment actually for? Liquidity for employees and existing shareholders only?","Does choosing a direct listing signal ''we don''t need the banks'' (powerful brand statement) or ''we''re avoiding scrutiny'' (negative signal)?"],"closing":"Imagine you''re with Butterfield in early 2019. Spotify just direct-listed and survived. Most CFOs and bankers still think you''re crazy.","decision":"Direct list on the NYSE on June 20, 2019, under ticker ''WORK.'' No underwriters as such (banks engaged as financial advisors, not bookrunners). No primary capital raised. Reference price set at $26; first trade printed at $38.62 — a ~50% pop on the reference. Slack closes day one at ~$23.2B market cap. The choice saves Slack ~$50M in underwriting fees and demonstrates that cash-rich SaaS companies can go public without the traditional bank syndicate.","pullquote":"We didn''t need to raise capital. The IPO process is mostly a fundraising process, and a direct listing lets us go public without diluting existing shareholders.","pullquote_attribution":"Stewart Butterfield, Slack cofounder/CEO — paraphrased from CNBC and 20VC interviews, June 2019","outcomes":[{"stat":"$0","label":"primary capital raised — direct listings don''t issue new shares","accent":true},{"stat":"~$50M","label":"in underwriting fees avoided vs. a comparable IPO"},{"stat":"$26 → $38.62","label":"reference → first trade — market-set price, not bank-set"},{"stat":"$23.2B","label":"day-one market cap"},{"stat":"2nd ever","label":"major direct listing on a US exchange, after Spotify (2018)"}],"tradeoffs":[{"title":"Underwriter fees vs. roadshow goodwill","body":"Saving ~$50M in fees is real cash. But the roadshow + book-build creates relationships with long-only institutional buyers who become anchor shareholders. Direct listings sacrifice that anchor base. Slack chose the cash and bet that the brand/product would attract the right shareholders organically."},{"title":"Bank-set price vs. market-set price","body":"Traditional IPOs price below true demand so allocators get a guaranteed day-one ''pop'' — a free lunch for the institutional clients of the underwriters, paid for by the company in foregone proceeds. Direct listings remove that subsidy. The day-one 50% pop on $WORK suggested even direct listings can be mispriced — but the company keeps the upside, not the bank''s clients."},{"title":"Cash-rich vs. capital-hungry posture","body":"Slack''s choice was only possible because of the $800M cash balance. Going direct from a cash-poor position would have been reckless. The direct listing was also a signal — it told the market ''we don''t need your money, we want your visibility.''"},{"title":"Banker relationships vs. precedent-setting","body":"Slack''s investment bankers were not their friends after this. The decision was a public signal that direct listings work for the right profile of company, opening the door for Asana, Coinbase, Roblox, and others to follow. Slack paid a relationship cost to set a precedent."}],"per_dimension_truth":{"tradeoff":"Cost savings + precedent-setting brand statement vs. anchor-investor relationships and ''normal'' IPO process certainty. Slack had the cash position to make the trade; most pre-IPO companies do not.","user":"Slack''s existing employees and pre-IPO investors who wanted liquidity, not the public market generally. The direct listing optimized for current shareholders selling cleanly — not for raising growth capital, not for distributing shares to fund managers.","alt":"A traditional IPO would have raised ~$500M of new capital + locked in institutional anchor shareholders + been more boring. Slack didn''t need the capital and felt the anchor base trade was overpriced. They took the opposite trade.","predict":"Successful day one; some early volatility because the market doesn''t have an underwriter-set anchor. Long-term outcome dominated by product / competition (Microsoft Teams) more than the listing mechanics. The listing itself becomes a template — Coinbase, Roblox, Asana, Squarespace all subsequently direct-list using the Slack/Spotify playbook."},"quote_type":"paraphrased","sources":[{"title":"What is a direct listing and why did Slack choose it over an IPO?","url":"https://www.siliconrepublic.com/business/slack-direct-listing-ipo-public","publisher":"Silicon Republic","year":2019,"type":"article"},{"title":"Slack CEO Butterfield explains why it didn''t go public with an IPO","url":"https://www.cnbc.com/2019/06/20/slack-ceo-butterfield-explains-why-it-didnt-go-public-with-an-ipo.html","publisher":"CNBC","year":2019,"type":"interview"},{"title":"The Real Reason Why Slack Did a Direct Listing Instead of an IPO","url":"https://www.fool.com/investing/2019/06/20/the-real-reason-why-slack-did-a-direct-listing-ins.aspx","publisher":"The Motley Fool","year":2019,"type":"article"}],"tags":{"industry":"saas","region":"us","decade":"2010s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'elon-twitter-acquisition-2022',
  'weekly',
  '{"id":"elon-twitter-acquisition-2022","type":"weekly","iso_week":"","company":"Twitter / X (under Elon Musk)","era":"April–November 2022","intro":"It is mid-2022. You are a senior PM at Twitter. Elon Musk has spent the spring buying ~9% of the company, taking a board seat, refusing the board seat, and then offering to acquire Twitter outright at $54.20/share — about $44B. By July he is trying to back out of the deal, citing bot prevalence. Delaware courts force him to close. The acquisition completes on October 27, 2022.\n\nDay one inside Twitter looks like the start of a different company. Musk fires the CEO, CFO, and head of legal in the first hour. Within a week, ~50% of the ~7,500-person workforce is laid off. He announces a paid ''Twitter Blue'' tier that includes the blue verification check — historically reserved for verified public figures and journalists — for anyone willing to pay $8/month. Launch is scheduled for early November. The legal, brand, and operational teams have days, not weeks, to ship it.","open_questions":["Should the blue check stay free for legacy-verified accounts (preserving trust) or be removed entirely and re-purposed as a paid status badge?","What identity-verification gates ship at launch — government ID, payment alone, account-age requirements, or none?","How fast is too fast? Two weeks from announcement to launch lets Musk own the news cycle but gives no time to build impersonation guardrails.","What''s the right thing to do with advertisers if the launch produces impersonation chaos — they''re ~90% of revenue?"],"closing":"Imagine you''re inside Twitter in late October 2022. Musk is firing the safety team. The legal team is warning him that payment-gated verification without ID checks will produce impersonation. The launch is in 10 days.","decision":"Ship Twitter Blue with paid verification at $8/month on November 9, 2022 — no government ID required, payment is the only verification. Impersonation explodes within hours: a verified ''Eli Lilly'' account tweets that insulin is free, wiping ~$15B off Eli Lilly''s market cap. Fake Lockheed Martin, Nintendo, Tesla, and George W. Bush accounts flood the platform. Major advertisers (GM, Volkswagen, Pfizer, Audi, General Mills) pause spending immediately. Musk suspends the paid program within days. Twitter Blue relaunches in December with mandatory phone verification — still no government ID. Twitter''s US ad revenue falls ~55% over the following year.","pullquote":"Twitter will soon add ability to attach long-form text to tweets, ending absurdity of notepad screenshots. Power to the people!","pullquote_attribution":"Elon Musk — Twitter, days after launching Blue (one of many posts framing the chaos as feature velocity), November 2022","outcomes":[{"stat":"10 days","label":"from acquisition close to paid-verification ship","accent":true},{"stat":"~50%","label":"of Twitter workforce laid off in week one"},{"stat":"$15B","label":"Eli Lilly market-cap wipeout from one impersonation tweet"},{"stat":"~55%","label":"decline in US ad revenue in the year after the launch"},{"stat":"Paused","label":"the original paid-verification program within days; relaunched in December"}],"tradeoffs":[{"title":"Speed vs. trust infrastructure","body":"Verification is a trust system. Stripping ID verification from it and pricing it at $8 collapsed the system in hours. Musk traded the trust-infrastructure dividend (decades of building ''a blue check means this account is who it says'') for instant pay-to-belong revenue. The brand cost dwarfed the launch revenue."},{"title":"Advertiser revenue vs. user revenue","body":"Twitter''s revenue was ~90% advertisers, ~10% other. Shifting to a paid-user model meant accepting a collapse of advertiser revenue before subscription revenue could replace it. The bet was that the gap would be ~6 months; the actual gap is multi-year and still unclosed."},{"title":"Legacy verification vs. paid status","body":"Verified public figures and journalists had used the blue check as an anti-impersonation signal for a decade. Repurposing the same visual symbol for paid status meant the same icon meant two different things — exactly the failure mode the original verification system existed to prevent."},{"title":"Move-fast brand vs. operating-system brand","body":"Musk''s narrative was that Twitter would ship features faster. Shipping the wrong thing fast — particularly a thing that produces $15B of customer harm — converts ''fast'' from an asset to a liability. The pace was real; the direction was wrong."}],"per_dimension_truth":{"tradeoff":"Brand-as-trust-infrastructure (built over a decade) vs. immediate subscription revenue + the news-cycle dominance of shipping fast. Musk took the latter; the trust infrastructure cratered the moment it was tested, and ad revenue has not recovered.","user":"The targeted user was the Musk-fandom paying-customer cohort, not the existing journalist/public-figure verified base. The legacy verified base mostly didn''t pay, and many left the platform. The bet was that the paying cohort was a viable replacement; the math didn''t work — the new payers were a fraction of the lost advertiser-supported audience.","alt":"A paid-verification tier launched as a separate, distinct badge — with mandatory ID — would have preserved trust and added revenue. The alternative was politically harder for Musk (it would have validated legacy verification rather than dismantling it) but operationally trivial. He chose the louder, faster path.","predict":"Short-term: impersonation chaos, advertiser exodus, news-cycle dominance for Musk personally. Medium-term: ~55% ad revenue decline, Twitter rebranded as X, multiple paid-tier reorgs, lingering brand confusion about what the blue check means. Long-term: a canonical case study in how ''move fast and break things'' breaks differently when the thing you''re breaking is a trust system the whole product depends on."},"quote_type":"verbatim","sources":[{"title":"Acquisition of Twitter by Elon Musk — Wikipedia","url":"https://en.wikipedia.org/wiki/Acquisition_of_Twitter_by_Elon_Musk","type":"article"},{"title":"Elon Musk floats the idea of selling blue checkmarks on Twitter","url":"https://fortune.com/2022/11/01/elon-musk-twitter-verification-fee-blue-checkmark/","publisher":"Fortune","year":2022,"type":"article"},{"title":"How Elon Musk transformed Twitter''s blue check from status symbol into a badge of shame","url":"https://www.cnn.com/2023/04/24/tech/musk-twitter-blue-check-mark","publisher":"CNN","year":2023,"type":"article"},{"title":"Elon Musk says Twitter Blue paid-for verification to return despite days of impersonation chaos","url":"https://www.euronews.com/next/2022/11/14/elon-musk-says-twitter-blue-paid-for-verification-to-return-despite-days-of-impersonation-","publisher":"Euronews","year":2022,"type":"article"}],"tags":{"industry":"consumer-social","region":"us","decade":"2020s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'reddit-api-protest-2023',
  'weekly',
  '{"id":"reddit-api-protest-2023","type":"weekly","iso_week":"","company":"Reddit","era":"April–July 2023","intro":"It is April 2023. You are a senior PM at Reddit. The company is targeting an IPO. Reddit''s API has been free since 2008. Third-party clients like Apollo, RIF, Sync, and BaconReader are how millions of power users — and most moderators — actually use the site. Most moderation tools, accessibility features, and bots run on the same API.\n\nWith the IPO in sight, Reddit needs revenue legibility and AI-training data leverage. The team decides to start charging for the API. Apollo (built by Christian Selig, the most-loved third-party Reddit app) gets quoted ~$20M/year to keep operating. Selig posts the email publicly. Within weeks, an organized protest from moderators threatens to go dark across thousands of subreddits, including the largest ones on the platform.","open_questions":["Charge for the API or remain free? Charging is the revenue/control move; remaining free leaves training-data leverage to OpenAI and competitors.","What''s the right pricing — accommodate the largest third-party apps with a reasonable rate, or price them out entirely?","Carve out free access for moderation tools and accessibility apps, or charge uniformly to avoid carving out loopholes?","How to respond to the moderator blackout — engage and concede, or hold the line and threaten to replace mods?"],"closing":"Imagine you''re inside Reddit in early June 2023. Christian Selig has published the quote that''s killing Apollo. The protest is forming. The IPO is 9 months out.","decision":"Hold the pricing. Apollo, Sync, RIF, BaconReader all shut down. Reddit CEO Steve Huffman runs a contentious AMA accusing Selig of bad faith and threatens to replace moderators who keep their subreddits dark. The June 12–14 blackout takes 7,000+ subreddits private. Reddit waits it out. The blackout ends. By July, the API pricing is in effect, third-party apps are gone, and Reddit''s monetization story for the IPO is intact. Reddit IPOs successfully on March 21, 2024.","pullquote":"Reddit needs to be a self-sustaining business, and to do that, we can no longer subsidize commercial entities that require large-scale data use.","pullquote_attribution":"Steve Huffman, Reddit CEO — public statement, June 2023","outcomes":[{"stat":"7,000+","label":"subreddits went dark in the June 12–14 blackout","accent":true},{"stat":"$20M/yr","label":"estimated cost quoted to Apollo to keep operating"},{"stat":"0","label":"major third-party clients still operating by July 2023"},{"stat":"Mar 2024","label":"Reddit IPO at ~$6.4B valuation, on schedule"},{"stat":"AI deals","label":"Reddit signed data-licensing deals with Google and OpenAI for ~$60M/yr each"}],"tradeoffs":[{"title":"Power-user goodwill vs. IPO economics","body":"Apollo and other third-party clients served the most active, most influential Reddit users — the population that shapes the site''s tone and produces the content. The pricing decision treated them as a subsidy to remove; the brand cost was concentrated in the cohort that defines the product. They held the line because the IPO math required it."},{"title":"Charge uniformly vs. carve out moderation","body":"Moderation tools used the same API. Charging uniformly hit moderators (who work for free) the hardest. Reddit eventually carved out moderation/accessibility access at low cost — but the original announcement didn''t, which framed the company as fighting its own free labor."},{"title":"Public CEO confrontation vs. quiet diplomacy","body":"Huffman''s AMA accused Selig of misrepresenting his calls with Reddit, then released the call recordings to defend Reddit''s position. Quiet negotiation might have produced a softer compromise; the confrontational path concentrated the protest around the CEO personally and made the moderator blackout more durable."},{"title":"Hold the line vs. concede + reset","body":"Conceding the pricing would have preserved relationships at the cost of the revenue model. Reddit held and accepted a one-week PR catastrophe. The IPO completed nine months later at a strong valuation; the AI-licensing deals would have been weaker without API control. The math was right; the execution was not."}],"per_dimension_truth":{"tradeoff":"Power-user / moderator goodwill vs. IPO-ready revenue model + AI-training-data leverage. Reddit chose the latter, took the public-relations hit, and IPO''d successfully. The decision worked; the way it was communicated did not.","user":"The audience Reddit decided to optimize for was investors and AI partners — not power users. Third-party app users were a vocal but commercially small segment; the moderators were free labor whose threats were operationally meaningful but politically containable. Reddit bet correctly that they would eventually return.","alt":"Concession + slower phase-in of paid API access with moderation/accessibility carve-outs from day one would have produced the same revenue model with less drama. Reddit took the harder path because the IPO timeline didn''t allow extended negotiation.","predict":"Short-term: protests, blackouts, third-party app deaths, public CEO villainization. Medium-term: protest fades, IPO completes on schedule, AI-licensing deals materialize at $100M+/yr. Long-term: the moment is the canonical case in how platform-data monetization conflicts with the community that produced the data — and how the platform usually wins anyway."},"quote_type":"verbatim","sources":[{"title":"2023 Reddit API controversy / June 2023 Reddit blackout — Wikipedia","url":"https://en.wikipedia.org/wiki/June_2023_Reddit_blackout","type":"article"},{"title":"Reddit in Mass Revolt Over Astronomical API Fees That Would Kill Third Party Apps","url":"https://www.vice.com/en/article/reddit-api-apollo-app-controversy-explained/","publisher":"Vice","year":2023,"type":"article"},{"title":"Popular third-party Reddit app Apollo is shutting down as a result of Reddit''s new API pricing","url":"https://techcrunch.com/2023/06/08/popular-third-party-reddit-app-apollo-is-shutting-down-as-a-result-of-reddits-new-api-pricing/","publisher":"TechCrunch","year":2023,"type":"article"},{"title":"Reddit CEO doubles down on attack on Apollo developer in drama-filled AMA","url":"https://techcrunch.com/2023/06/09/reddit-ceo-doubles-down-on-attack-on-apollo-developer-in-drama-filled-ama/","publisher":"TechCrunch","year":2023,"type":"article"}],"tags":{"industry":"consumer-social","region":"us","decade":"2020s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'salesforce-acquires-slack-2020',
  'weekly',
  '{"id":"salesforce-acquires-slack-2020","type":"weekly","iso_week":"","company":"Salesforce","era":"Late 2020 — December 1, 2020 acquisition announcement","intro":"It is the second half of 2020. You are a corporate-strategy leader at Salesforce. The pandemic has accelerated work-from-home; Microsoft Teams (free with Office 365) has gone from ~20M DAU to ~115M DAU in 12 months. Slack, the IM-style workplace tool with ~12M DAU, has been growing but is being out-distributed by Microsoft''s bundle. Slack stock has been under pressure all year. Marc Benioff has watched Microsoft buy LinkedIn and GitHub in succession and is convinced Microsoft is building an enterprise productivity stack that locks Salesforce out of the workflow layer.\n\nThe board is debating a strategic acquisition of Slack — Salesforce''s largest deal ever. The price floats around $27.7B in cash and stock. Slack has ~$870M ARR; the multiple is ~30x. Wall Street is skeptical (CRM stock drops 5% on the rumor). Stewart Butterfield has signaled openness to the deal. The question is whether Salesforce buys Slack as a strategic moat against Microsoft, or builds its own competitor and accepts being a customer of Microsoft Teams.","open_questions":["Buy Slack or build? Building would take 3+ years and almost certainly fail against Teams'' bundling advantage.","If buy — preserve Slack as a distinct product (the customer base hates ''acquired by Salesforce'' aesthetics), or absorb it deeply into Salesforce Cloud?","What''s the right valuation? 30x ARR for a product growing 40%/yr is rich; but the strategic value (a chat platform under Salesforce control) is hard to quantify.","How will Microsoft respond — will they accelerate bundling Teams more aggressively, or treat Slack-Salesforce as a non-threat?"],"closing":"Imagine you''re with Benioff in late November 2020. The deal is one week from announcement. Wall Street will react badly. Microsoft is watching.","decision":"Acquire Slack for $27.7B in cash and stock — $26.79 cash + 0.0776 CRM shares per Slack share. Announced December 1, 2020. Largest acquisition in Salesforce''s 21-year history. Structurally, Slack is preserved as an independent product line, with Butterfield staying as CEO of Slack. The deal closes July 21, 2021. The strategic framing is explicit: Slack will become the ''central nervous system'' of Salesforce''s Customer 360 stack — a counter-positioning to Microsoft Teams.","pullquote":"Stewart and his team have built one of the most beloved platforms in enterprise software history, with an incredible ecosystem around it.","pullquote_attribution":"Marc Benioff, Salesforce Chair/CEO — acquisition announcement, December 1, 2020","outcomes":[{"stat":"$27.7B","label":"deal value — largest in Salesforce history","accent":true},{"stat":"~30x","label":"multiple on Slack''s $870M ARR — rich vs. SaaS comps"},{"stat":"−5%","label":"Salesforce stock dropped on announcement; investors skeptical"},{"stat":"Slack brand","label":"preserved post-close; Butterfield stayed as CEO (until late 2022)"},{"stat":"Microsoft Teams","label":"passed 320M MAU by 2024 — bundling won regardless of deal"}],"tradeoffs":[{"title":"Buy vs. build vs. partner","body":"Building a Teams competitor inside Salesforce was structurally a 3-year, low-probability bet. Partnering with Slack via deep integration would have given Salesforce no strategic control. Buying was the most expensive option but the only one that gave Salesforce permanent independence from Microsoft''s productivity stack."},{"title":"Premium valuation vs. shareholder pushback","body":"30x ARR was a premium even in 2020''s frothy environment. Investors immediately punished CRM stock. Benioff and the board absorbed the financial-market hit because the strategic-control alternative (being a tenant on Microsoft''s chat platform) was viewed as existential."},{"title":"Preserve Slack independence vs. deep integration","body":"Microsoft preserved LinkedIn and GitHub as independent operating entities after acquisition. Salesforce promised the same for Slack — Butterfield stayed, the brand stayed, the office stayed. The trade-off: slower realization of revenue synergies. The benefit: customer trust and lower attrition."},{"title":"Defensive moat vs. offensive product play","body":"The deal was framed publicly as a ''platform play'' (offensive). Internally, the rationale was largely defensive — Salesforce could not afford to be a Microsoft Teams customer for its own workflow layer. Defensive M&A at 30x is a hard ROI sell to public-market investors; Salesforce told the story as platform-building to keep the narrative palatable."}],"per_dimension_truth":{"tradeoff":"Premium valuation + financial-market punishment in the short term vs. permanent strategic independence from Microsoft''s productivity stack. Salesforce paid the premium; the defensive value was real and durable even though the platform-narrative success has been partial.","user":"Enterprise CIOs deciding between an all-Microsoft stack and a Salesforce-centric stack. Slack-under-Salesforce kept that decision live for years. Without Slack, the default answer for new enterprise stacks would have collapsed toward Microsoft sooner.","alt":"Building a Salesforce-native chat product alongside an existing Slack partnership would have been cheaper but slower and almost certainly failed against Teams'' bundling. The opposite trade — and the precedent (Google, Cisco, etc. all tried to build chat against Slack/Teams) suggests this would have been a non-starter.","predict":"Short-term: stock-price hit, investor skepticism, slow integration. Medium-term: Slack remains independent operationally, integrates loosely with Customer 360, faces continued share pressure from Teams'' bundling. Long-term: the deal looks expensive on revenue terms and necessary on strategic terms — Salesforce is still an independent platform partly because of it."},"quote_type":"verbatim","sources":[{"title":"Salesforce acquires Slack for over $27 billion, marking cloud software vendor''s largest deal ever","url":"https://www.cnbc.com/2020/12/01/salesforce-buys-slack-for-27point7-billion-in-cloud-companys-largest-deal.html","publisher":"CNBC","year":2020,"type":"article"},{"title":"Salesforce Signs Definitive Agreement to Acquire Slack","url":"https://www.salesforce.com/news/press-releases/2020/12/01/salesforce-definitive-agreement-update/","publisher":"Salesforce Newsroom","year":2020,"type":"press-release"},{"title":"Salesforce buys Slack in a $27.7B megadeal","url":"https://techcrunch.com/2020/12/01/salesforce-buys-slack/","publisher":"TechCrunch","year":2020,"type":"article"}],"tags":{"industry":"saas","region":"us","decade":"2020s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'uber-ceo-transition-2017',
  'weekly',
  '{"id":"uber-ceo-transition-2017","type":"weekly","iso_week":"","company":"Uber","era":"February–August 2017","intro":"It is mid-2017. You are an Uber executive. The year has been a sustained crisis. In February, ex-engineer Susan Fowler publishes a viral blog post detailing widespread sexual harassment and HR cover-ups at Uber. In the months that follow: a video of CEO Travis Kalanick berating a driver leaks; a court case reveals ''Greyball,'' a tool used to evade law enforcement; ~20 executives are fired in a harassment investigation. The board commissions a top-to-bottom culture report from former US Attorney General Eric Holder. By June, the report''s recommendations include Kalanick taking an indefinite leave of absence.\n\nThe board forces Kalanick out as CEO on June 20, 2017. He remains a board member and the largest shareholder. The search for a new CEO becomes a public spectacle: Meg Whitman, Jeff Immelt, and a ''dark horse'' candidate — Dara Khosrowshahi, then CEO of Expedia — are the finalists. The board deadlocks. Benchmark, a major investor, sues Kalanick during the process to force him off the board.","open_questions":["Force Kalanick fully off the board, accept him as a non-executive board member, or risk public lawsuits to remove him?","Hire a celebrity ''fixer'' CEO (Whitman, Immelt) for the brand reset, or a quieter operator (Khosrowshahi) who can rebuild culture without further PR drama?","How public should the recovery plan be — full Holder-report transparency, or contained disclosure to protect the IPO timeline?","Should Kalanick''s founder voting rights be diluted or eliminated, even if he keeps board membership?"],"closing":"Imagine you''re inside the August 2017 board meeting. Two of the three CEO finalists have just been knocked out. Benchmark is threatening to drop its lawsuit against Kalanick only if Whitman is named CEO. The board is deadlocked.","decision":"Name Dara Khosrowshahi CEO on August 27, 2017 — after Immelt withdraws (botched a presentation) and Whitman''s path is blocked by Kalanick''s faction. Khosrowshahi explicitly tells the board ''there cannot be two CEOs'' and gets full operational control. He immediately publishes a new set of cultural norms (''Cultural Norms 2.0'') replacing Kalanick''s 14 values, settles the Waymo IP lawsuit (~$245M in Uber equity), discloses a previously-hidden 2016 data breach, and orchestrates Uber''s IPO in May 2019 at a ~$75B valuation.","pullquote":"We do the right thing. Period.","pullquote_attribution":"Dara Khosrowshahi — first new Cultural Norm published as Uber CEO, November 2017 (replacing Kalanick''s ''Toe Stepping'')","outcomes":[{"stat":"−20","label":"executives fired in harassment investigations under Holder report","accent":true},{"stat":"8 months","label":"from Fowler blog to new CEO — fast for a public-facing crisis"},{"stat":"8","label":"new Cultural Norms replaced Kalanick''s 14 values"},{"stat":"$245M","label":"Waymo lawsuit settled in Uber equity in 2018"},{"stat":"May 2019","label":"Uber IPO at ~$75B valuation, ~18 months into Khosrowshahi''s tenure"}],"tradeoffs":[{"title":"Founder-on-board vs. founder fully out","body":"Removing Kalanick from operating control but leaving him on the board (as largest shareholder) kept legal/governance peace at the cost of ongoing internal politics. Benchmark''s lawsuit pushed him toward selling shares to SoftBank, which diluted his voting power — a quieter ouster than a full board fight."},{"title":"Celebrity CEO vs. operator CEO","body":"Whitman and Immelt were the splashy press-release picks; Khosrowshahi was the operator who''d run Expedia for 12 years quietly and well. Choosing the operator over the celebrity sacrificed media narrative for execution capacity. The IPO needed an operator more than it needed a personality."},{"title":"Public transparency vs. IPO-readiness","body":"Disclosing the 2016 data breach (which Kalanick''s team had paid $100K to hide) cost Uber regulatory penalties and bad press. Not disclosing it risked a much worse exposure during or after IPO. Khosrowshahi took the predictable cost over the hidden risk."},{"title":"Cultural break vs. cultural continuity","body":"Replacing Kalanick''s 14 values wholesale was a public break with the founder''s framework. Continuity would have preserved institutional knowledge; the break signaled to employees, regulators, and investors that the post-Travis Uber was a different company. The cultural-discontinuity bet was necessary to make recovery legible."}],"per_dimension_truth":{"tradeoff":"Founder-loyalty / institutional continuity vs. credible cultural reset + IPO readiness. The board chose the reset, accepted ongoing tension with Kalanick, and got an IPO 18 months later. The execution worked; the founder remained an unhappy shareholder.","user":"The audience for the CEO-transition decisions was simultaneously employees (who needed to believe the harassment crisis was over), regulators / governments (who needed to see a clean break), and IPO investors (who needed to see boring competence). Khosrowshahi was optimized for all three; Whitman would have over-indexed on press, Immelt on continuity.","alt":"Naming Whitman would have produced louder press but invited a long Kalanick-vs-CEO fight. Naming Immelt (had he not flubbed the presentation) would have lent GE-style discipline but probably less cultural-reset credibility. The opposite trade — keeping Kalanick — was a non-starter post-Holder report.","predict":"Short-term: continued executive departures, legal settlements, regulatory penalties (London revoking Uber''s license, briefly). Medium-term: IPO inside 18–24 months at a sub-peak valuation (Uber had once been rumored at $120B). Long-term: the transition becomes the canonical case in ''how a tech company recovers from a founder-culture crisis without losing the operational asset.''"},"quote_type":"verbatim","sources":[{"title":"Dara Khosrowshahi — Wikipedia","url":"https://en.wikipedia.org/wiki/Dara_Khosrowshahi","type":"article"},{"title":"Dara Khosrowshahi Is the New Uber CEO After Travis Kalanick","url":"https://fortune.com/2017/08/27/new-uber-ceo-expedia/","publisher":"Fortune","year":2017,"type":"article"},{"title":"The CEO Uber selected to replace Travis Kalanick","url":"https://qz.com/1065061/the-ceo-uber-selected-to-replace-travis-kalanick-has-already-brought-maturity-to-the-ride-hailing-concern","publisher":"Quartz","year":2017,"type":"article"}],"tags":{"industry":"transportation","region":"us","decade":"2010s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'microsoft-acquires-linkedin-2016',
  'weekly',
  '{"id":"microsoft-acquires-linkedin-2016","type":"weekly","iso_week":"","company":"Microsoft","era":"June 2016","intro":"It is early 2016. You are a strategy leader at Microsoft. Satya Nadella has been CEO for two years. The Office franchise is migrating to cloud (Office 365). Azure is gaining on AWS. The pivot from a Windows-centric Microsoft to a cloud-and-services Microsoft is mid-flight. But Microsoft has no consumer-direct social graph — the productivity products (Office, Outlook) sit on top of corporate identities, not the professional identities people carry across jobs.\n\nLinkedIn has been struggling — stock down ~40% YTD after weak Q1 earnings. Reid Hoffman (chairman, largest shareholder) and Jeff Weiner (CEO) have started exploring strategic options. Internally at Microsoft, the question is whether to acquire LinkedIn to bring a professional graph into Microsoft''s productivity products — or build alternative graph-style features inside Outlook/Office and accept LinkedIn as a partner.","open_questions":["Buy LinkedIn or build? Building a competing graph from Outlook''s email data is technically feasible but politically and culturally hard.","If buy — at what price? LinkedIn is recovering from a slump; a $26B+ deal is a premium against the depressed price.","What integration model — absorb LinkedIn into Office (deep), keep it independent (light), or somewhere in between?","How will regulators react — LinkedIn + Office could be argued as a productivity-tools monopoly precursor (Microsoft has antitrust history)."],"closing":"Imagine you''re in the Microsoft strategy room in late May 2016. Nadella has been talking to Hoffman for months. The deal is days from announcement.","decision":"Acquire LinkedIn for $26.2B all-cash at $196/share on June 13, 2016 — a ~50% premium to the prior close. LinkedIn remains an independent operating entity with Jeff Weiner staying as CEO, reporting to Nadella. The brand stays. The graph stays separate from Outlook''s identity layer. Integration is light: LinkedIn data surfaces inside Office (e.g., ''Insights'' in Outlook), but the products don''t merge. The deal closes December 2016 — Microsoft''s largest acquisition in history at the time.","pullquote":"The LinkedIn team has grown a fantastic business centered on connecting the world''s professionals. Together we can accelerate the growth of LinkedIn, as well as Microsoft Office 365 and Dynamics, as we seek to empower every person and organization on the planet.","pullquote_attribution":"Satya Nadella, Microsoft CEO — announcement letter, June 13, 2016","outcomes":[{"stat":"$26.2B","label":"all-cash deal — Microsoft''s largest acquisition at the time","accent":true},{"stat":"~50%","label":"premium to LinkedIn''s prior closing price"},{"stat":"Independent","label":"LinkedIn brand and operating entity preserved; Weiner stayed CEO"},{"stat":"LinkedIn revenue","label":"grew ~3x in the 5 years post-acquisition"},{"stat":"Set precedent","label":"for MSFT''s later GitHub ($7.5B) and Activision ($69B) acquisitions"}],"tradeoffs":[{"title":"Buy vs. build (rerun of the developer-tools question)","body":"Building a professional graph inside Outlook would have been technically possible — Microsoft has the email data — but would have failed against LinkedIn''s existing 400M users. Buying was expensive but bought the audience, the brand, and the data unification permission (LinkedIn could now legally share with Microsoft what it couldn''t share with anyone else)."},{"title":"Independent operating vs. deep integration","body":"Preserving LinkedIn as an independent product preserved its consumer brand and avoided ''Microsoft is going to ruin LinkedIn'' backlash. The cost: slower revenue synergies. The benefit: LinkedIn-the-product continued to grow without disruption, and the data became the strategic asset Microsoft really wanted (training data for AI, sales/recruiting product context)."},{"title":"Premium pricing vs. opportunistic timing","body":"LinkedIn was trading depressed when the deal was negotiated, but Microsoft paid a 50% premium anyway. Paying the premium when the asset is depressed sends a strong signal to other acquisition targets (Microsoft is a willing buyer at premium prices), which raises Microsoft''s deal-flow but inflates future M&A costs."},{"title":"Antitrust risk vs. productivity-stack vision","body":"Linking professional identity (LinkedIn) + productivity tools (Office) + cloud (Azure) makes a category-defining stack — but invites antitrust attention. Microsoft, with its antitrust history, knew this was a question. They proceeded because the strategic value was higher than the regulatory risk premium, and the productivity-tools market was less monopoly-charged than search or OS."}],"per_dimension_truth":{"tradeoff":"Cash premium + integration restraint vs. building an inferior internal graph + remaining dependent on a partner Microsoft didn''t control. They bought, kept it independent, and slowly compounded the strategic value over a decade through AI training and recruiting-tools integration.","user":"Microsoft enterprise customers — particularly sales, recruiting, and HR functions — who already used both Office and LinkedIn separately. The deal didn''t add a new audience so much as merge two relationships into one customer record that Microsoft owned end-to-end.","alt":"Partnering with LinkedIn via API (which Salesforce eventually did with LinkedIn-data-vendor licensing) would have been one-tenth the price but exposed Microsoft to LinkedIn deciding to revoke or re-price access. Microsoft chose ownership over leverage. The same logic underwrote GitHub two years later.","predict":"Short-term: antitrust attention from EU regulators (Microsoft had to make commitments around LinkedIn-competitor data access), deal closes on schedule. Medium-term: LinkedIn revenue compounds, recruiting-tools product builds out, the consumer-facing LinkedIn product avoids brand damage. Long-term: the deal becomes the template for Microsoft''s ''buy + preserve'' M&A strategy (LinkedIn → GitHub → Activision), all of which preserved independent brands while monetizing strategic data and audience access."},"quote_type":"verbatim","sources":[{"title":"Microsoft to acquire LinkedIn","url":"https://news.microsoft.com/source/2016/06/13/microsoft-to-acquire-linkedin/","publisher":"Microsoft News","year":2016,"type":"press-release"},{"title":"Microsoft to acquire LinkedIn","url":"https://blogs.microsoft.com/blog/2016/06/13/microsoft-to-acquire-linkedin/","publisher":"Official Microsoft Blog","year":2016,"type":"blog"},{"title":"Microsoft to buy LinkedIn for $26.2 billion; LNKD shares jump 47%","url":"https://www.cnbc.com/2016/06/13/microsoft-to-buy-linkedin.html","publisher":"CNBC","year":2016,"type":"article"}],"tags":{"industry":"saas","region":"us","decade":"2010s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'wework-ipo-collapse-2019',
  'weekly',
  '{"id":"wework-ipo-collapse-2019","type":"weekly","iso_week":"","company":"WeWork","era":"August–October 2019","intro":"It is August 14, 2019. You are a senior strategy executive at WeWork. The company has spent the last decade raising ~$12.8B at valuations climbing to $47B — largely from SoftBank''s Vision Fund. The S-1 has just been filed publicly in preparation for an IPO targeted for September. Adam Neumann is CEO. The company has 7,000+ employees, real estate commitments in dozens of countries, and a $1.9B loss on $1.8B in revenue last year. The S-1 contains revelations almost immediately: Neumann owns and leases real estate to WeWork (conflicts of interest), holds super-voting stock that gives him personal control even at <10% economic ownership, has been paid $5.9M for the trademark ''We'' by the company he runs, and uses chartered private jets for purposes that include trips with marijuana on board.\n\nWithin two weeks of the filing, the press coverage is uniformly negative. Wall Street''s whisper-valuation drops from $47B to $20B to $10B. SoftBank is now publicly conflicted — Masayoshi Son has personally championed the company and pushed Neumann to be ''crazier.'' The IPO date is two weeks out. You need to advise leadership.","open_questions":["Postpone the IPO and re-negotiate governance terms, or push through at a depressed valuation to avoid the optics of failure?","Replace Adam Neumann pre-IPO (severe trust signal but optics of decisive action), or after IPO?","What''s SoftBank''s leverage actually worth if they have $10B+ at stake and Neumann''s super-voting shares mean he can refuse to be replaced?","If the IPO fails entirely — does WeWork survive on the cash runway it has, or does it need an emergency SoftBank bailout?"],"closing":"Imagine you''re in the leadership conversations at WeWork in early September 2019. Roadshow meetings have collapsed. The bankers are signaling a $10B valuation at most. Neumann is refusing to step down voluntarily.","decision":"Withdraw the S-1 on September 30, 2019 — IPO formally postponed. The board (heavily influenced by SoftBank) demands Neumann''s resignation. He resists; SoftBank threatens to withdraw funding. On September 24, Neumann resigns as CEO and surrenders majority voting control. Artie Minson and Sebastian Gunningham named co-CEOs. SoftBank pays Neumann a ~$1.7B exit package — $970M for his shares, $185M consulting fee, $500M loan repayment. SoftBank then commits an additional ~$9.5B bailout, taking ~80% ownership. WeWork eventually IPOs via SPAC in October 2021 at a $9B valuation — vs. $47B private valuation. Files for bankruptcy in 2023.","pullquote":"While we have made significant progress over the past year, this is the right thing to do for our team, our members, our investors, and the future of WeWork.","pullquote_attribution":"Adam Neumann, WeWork cofounder/CEO — resignation statement, September 24, 2019","outcomes":[{"stat":"$47B → $10B","label":"private valuation collapsed in 6 weeks","accent":true},{"stat":"$1.7B","label":"Neumann''s exit package from SoftBank"},{"stat":"~$9.5B","label":"SoftBank emergency bailout to keep WeWork solvent"},{"stat":"Oct 2021","label":"eventual SPAC merger at $9B valuation — 2 years late, 80% lower"},{"stat":"Nov 2023","label":"WeWork files for Chapter 11 bankruptcy"}],"tradeoffs":[{"title":"Push the IPO through vs. withdraw","body":"A $10B IPO would have raised capital and signaled survival, even at a fraction of the private valuation. Withdrawing locked WeWork into a multi-year private workout with SoftBank as forced majority owner. Withdrawal was the legally and operationally safer choice; it also guaranteed SoftBank''s dominance over the company''s future."},{"title":"Replace the founder vs. preserve continuity","body":"Neumann was the company''s culture, brand, and majority voter. Removing him required SoftBank''s leverage + a $1.7B payout. The cost: a permanently weakened CEO seat (multiple subsequent CEOs in the next four years). The benefit: any chance of public-market credibility required him gone."},{"title":"Public transparency vs. quiet workout","body":"The S-1''s disclosures — once public — were unwithdrawable. A private re-IPO 18 months later carried the baggage of every flagged conflict in the original document. WeWork''s brand never recovered from the S-1''s specific lines about Neumann''s trademark payment and private-jet usage."},{"title":"SoftBank''s $9.5B bailout vs. bankruptcy in 2019","body":"SoftBank could have walked. A 2019 bankruptcy would have cost SoftBank ~$10B already invested but stopped the bleeding. Doubling down meant ~$20B+ exposure with a path to maybe recover some of it. They doubled down. By 2023 they wrote it down to ~$0."}],"per_dimension_truth":{"tradeoff":"Going public at a ''humiliating'' $10B valuation vs. accepting a multi-year private workout fully dependent on SoftBank''s continued funding. WeWork chose the workout; it preserved the company''s appearance of viability for two more years and ultimately ended in bankruptcy anyway.","user":"The S-1 was written for retail and institutional public-market investors. It treated them as the buyer. Once those investors revolted, the only remaining buyer was SoftBank — already invested, structurally unable to walk away, with terms that effectively forced ongoing capital injections.","alt":"A clean withdrawal + structured governance reform + a 2021 IPO at a clean $15–20B valuation was the case-for-restraint path. Instead, WeWork went through with the SPAC at $9B in panic mode. The opposite trade — patience + governance — was technically available but politically impossible given Neumann''s voting structure.","predict":"Short-term: founder ouster, SoftBank bailout, brand collapse, $1.7B exit package generates years of public outrage. Medium-term: leadership churn, real estate retrenchment, multiple capital injections. Long-term: bankruptcy + Adam Neumann starts a new company (Flow) at a billion-dollar valuation with the same investors. The case study becomes the canonical ''why founder-control + private-market over-valuation breaks at the IPO door.''"},"quote_type":"verbatim","sources":[{"title":"WeWork pulls IPO filing","url":"https://www.cnbc.com/2019/09/30/wework-says-it-will-file-request-to-withdraw-its-ipo-prospectus-after-roadshow-management-turmoil.html","publisher":"CNBC","year":2019,"type":"article"},{"title":"WeWork CEO Adam Neumann Steps Down Amid Stalled IPO","url":"https://www.npr.org/2019/09/24/763913318/wework-ceo-steps-down-as-ipo-stalls","publisher":"NPR","year":2019,"type":"article"},{"title":"WeWork — Wikipedia","url":"https://en.wikipedia.org/wiki/WeWork","type":"article"},{"title":"Adam Neumann — Wikipedia","url":"https://en.wikipedia.org/wiki/Adam_Neumann","type":"article"}],"tags":{"industry":"marketplace","region":"us","decade":"2010s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'coinbase-direct-listing-2021',
  'weekly',
  '{"id":"coinbase-direct-listing-2021","type":"weekly","iso_week":"","company":"Coinbase","era":"Early 2021 — April 14, 2021 NASDAQ direct listing","intro":"It is early 2021. You are a senior PM at Coinbase. Bitcoin is at all-time highs (~$60K). Coinbase is the largest US-regulated cryptocurrency exchange — ~$1.8B revenue in 2020, sharply profitable, and growing fast. The company has been preparing to go public for over a year. The standard path for a profitable, cash-rich tech company is a traditional IPO with major investment-bank underwriters and a ''roadshow'' priced book-build.\n\nBrian Armstrong and the leadership team are debating direct listing instead. Direct listings cut out underwriting fees and the IPO ''pop,'' let existing shareholders sell directly to the public, and don''t raise new capital. Coinbase doesn''t need capital — it generated >$300M in operating income in Q4 2020 alone. The investment banks Coinbase is talking to have spent two decades building IPO-as-a-product; they will discourage the direct-listing path, and almost no profitable crypto company has gone public before.","open_questions":["Direct listing or IPO? Direct listing saves ~$100M+ in underwriting fees but removes the institutional-anchor base a traditional IPO builds.","Without a roadshow + bank-set ''IPO price,'' how does the market price the stock on day one — and what''s the downside if Bitcoin sells off the morning of?","How do you handle the regulatory framing — crypto is mid-controversy at the SEC level; does going public via direct listing signal confidence or evasion?","Is the moment to go right now (peak crypto sentiment) or wait for a more mature regulatory environment that may never come?"],"closing":"Imagine you''re with Armstrong in early April 2021. The reference price is being set this week. Bitcoin is volatile. Nasdaq is preparing the listing.","decision":"Direct list on Nasdaq under ticker ''COIN'' on April 14, 2021. Reference price: $250 (set by Nasdaq, not banks). First trade prints at $381 — a ~52% pop. Stock closes day one at $328 — implied market cap ~$85.8B fully diluted (briefly hit $100B+ intraday). No primary capital raised. No underwriting fees. Brian Armstrong''s stake is worth ~$13B at the close. Crypto-skeptic media call it the ''top signal'' for the cycle.","pullquote":"We are going public because we believe everyone should have access to financial freedom — and we want everyone to be able to participate in this opportunity by owning a piece of Coinbase.","pullquote_attribution":"Brian Armstrong, Coinbase cofounder/CEO — paraphrased from his public commentary around the direct listing","outcomes":[{"stat":"$85.8B","label":"fully diluted market cap on day-one close"},{"stat":"$250 → $381","label":"reference price → first trade — market-set, not bank-set","accent":true},{"stat":"~$100M+","label":"estimated underwriting fees avoided"},{"stat":"$13B","label":"Brian Armstrong''s stake value on the close"},{"stat":"−85%","label":"from peak by end of 2022 in crypto-winter drawdown"}],"tradeoffs":[{"title":"Direct listing vs. traditional IPO","body":"Direct listing saved ~$100M+ in fees but skipped the anchor-investor relationships a roadshow builds. Coinbase didn''t need the capital, but the absence of long-only institutional shareholders made the stock structurally more volatile post-listing. Slack and Spotify had run this playbook earlier; Coinbase was the first crypto company at scale to use it."},{"title":"Go now (peak sentiment) vs. wait for regulatory clarity","body":"Crypto sentiment in April 2021 was the highest it had ever been. A 2022 listing would have hit during crypto winter at a fraction of the valuation. Going at peak was almost certainly optimal for existing-shareholder liquidity — and almost certainly the top signal for the cycle. Both can be true."},{"title":"Public-company transparency vs. crypto-native flexibility","body":"Going public meant Coinbase took on quarterly earnings, disclosure obligations, and securities-law constraints that crypto-native competitors (Binance) refused. The cost: less operational agility, more legal overhead. The benefit: regulatory credibility that would matter through every subsequent SEC enforcement wave."},{"title":"Founder identity vs. company identity","body":"Armstrong personally became a $13B billionaire on day one, in public, with cap-table disclosures. That made him a target — both for regulatory pressure and for shareholder activism. A more typical pre-IPO would have spread liquidity over a 6-month lockup; direct listing made every executive''s wealth visible the moment the bell rang."}],"per_dimension_truth":{"tradeoff":"Fee savings + speed + market-set pricing vs. anchor-investor stability + traditional-IPO halo. Coinbase had the financials to make the trade and picked the moment when crypto sentiment was at all-time highs. The decision was right on its own terms; the timing was inadvertently the top of the cycle.","user":"Coinbase''s existing employees and pre-public investors who wanted clean liquidity, not the broader public market generally. The direct listing optimized for the cap table that already existed — not for distributing shares to fund managers via a coordinated allocation.","alt":"A traditional IPO would have raised ~$1B+ of fresh capital and locked in major institutional anchor holders. Coinbase didn''t need the capital. Waiting for crypto-winter clarity would have meant listing at perhaps $20B vs. $86B. Both alternatives had clearer downside than the path chosen.","predict":"Successful day one with a big print, immediate price volatility (no anchor base), 2022 crypto-winter drawdown that takes the stock down 85%, ongoing SEC enforcement actions, and a multi-year regime where ''COIN'' becomes the public-market proxy for the crypto cycle. Long-term: direct listings become a standard option for profitable companies that don''t need primary capital."},"quote_type":"paraphrased","sources":[{"title":"Coinbase stock debuts on Nasdaq in direct listing","url":"https://www.cnbc.com/2021/04/14/coinbase-to-debut-on-nasdaq-in-direct-listing.html","publisher":"CNBC","year":2021,"type":"article"},{"title":"Coinbase goes public with a nearly $100 billion valuation","url":"https://www.cnn.com/2021/04/14/investing/coinbase-stock-direct-listing","publisher":"CNN","year":2021,"type":"article"},{"title":"Coinbase Direct Listing Gets $100B+ Valuation as Share Price Jumps in Nasdaq Debut","url":"https://www.coindesk.com/markets/2021/04/14/coinbase-direct-listing-gets-100b-valuation-as-share-price-jumps-in-nasdaq-debut","publisher":"CoinDesk","year":2021,"type":"article"}],"tags":{"industry":"fintech","region":"us","decade":"2020s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'amazon-buys-whole-foods-2017',
  'weekly',
  '{"id":"amazon-buys-whole-foods-2017","type":"weekly","iso_week":"","company":"Amazon","era":"Mid-2017 — June 16, 2017 announcement","intro":"It is mid-2017. You are a corporate strategy executive at Amazon. Amazon has dominated e-commerce for two decades. The one massive consumer-spending category it has structurally failed to crack is groceries — perishables, cold-chain logistics, and the ''I need it now'' purchasing pattern all break Amazon''s standard fulfillment model. Amazon Fresh (the company''s grocery delivery service) has been live since 2007 in select cities and has barely moved the needle. Whole Foods, meanwhile, has 460+ premium-grocery stores in the US, an upmarket customer base, and a struggling stock (down ~40% over 18 months) after activist investor Jana Partners pushed for a sale.\n\nBezos is debating whether to acquire Whole Foods outright — Amazon''s largest acquisition ever — to anchor a brick-and-mortar grocery footprint, or to keep building Amazon Fresh from scratch. The price floats around $13.7B. The deal is structured as cash. Wall Street expects either a tech-sector premium acquisition or another year of incremental e-commerce growth. Almost nobody expects Amazon to suddenly own physical stores.","open_questions":["Buy Whole Foods or keep building Amazon Fresh + Amazon Go? Building is cheaper but ~5–10 years behind a national footprint.","If buy — at what price? $13.7B is a 27% premium; activist pressure has the stock already partially priced in.","What''s the integration model — absorb Whole Foods into Amazon''s brand (likely brand-damaging) or preserve it as an upscale grocery chain (slower synergies)?","How will the existing Whole Foods customer base react to ''Amazon now owns my organic grocery store'' — and how do you protect the brand premium during a tech-company integration?"],"closing":"Imagine you''re in the Amazon corporate development room in May 2017. The deal is two weeks from announcement. Whole Foods''s John Mackey is on board. The grocery industry is unaware.","decision":"Announce the acquisition on June 16, 2017 for $13.7B all-cash at $42/share. Whole Foods''s John Mackey remains CEO; the brand stays distinct. Within 9 months Amazon cuts Whole Foods prices ~30% on staple items, adds Amazon Prime member discounts in-store, and uses Whole Foods locations as Amazon delivery pickup points. The grocery industry stock-market reaction is immediate: Kroger drops ~9%, Walmart drops ~5%, Target drops ~5%, Costco drops ~7% in a single day, wiping ~$30B off competitor market caps. Five years later, Whole Foods has Amazon-branded shelves, Amazon Fresh delivery integration, and serves as the physical foothold for Amazon''s grocery push.","pullquote":"Millions of people love Whole Foods Market because they offer the best natural and organic foods, and they make it fun to eat healthy.","pullquote_attribution":"Jeff Bezos, Amazon founder/CEO — acquisition announcement, June 16, 2017","outcomes":[{"stat":"$13.7B","label":"all-cash acquisition — Amazon''s largest at the time","accent":true},{"stat":"27%","label":"premium to Whole Foods''s pre-deal share price"},{"stat":"~$30B","label":"one-day market-cap loss across Kroger, Walmart, Target, Costco"},{"stat":"~30%","label":"Whole Foods staple-item price cuts within 9 months of close"},{"stat":"460+","label":"physical grocery stores added to Amazon''s footprint overnight"}],"tradeoffs":[{"title":"Buy vs. build","body":"Building Amazon Fresh into a national grocery presence would have taken 5–10 years and required physical real estate Amazon didn''t own. Buying Whole Foods compressed that timeline to one transaction. The premium ($13.7B for ~$16B revenue) was the cost of skipping a decade of slow growth."},{"title":"Premium brand preservation vs. Amazon integration","body":"Whole Foods''s brand premium (''upscale, organic, premium pricing'') was an asset that could be damaged by Amazon''s discount-retailer DNA. Preserving Mackey, the brand, and the in-store experience protected that premium; cutting prices 30% on staples broadcast Amazon''s intent without destroying the upmarket positioning entirely."},{"title":"Physical-retail learning curve vs. e-commerce confidence","body":"Amazon had no large-scale grocery retail experience. Acquiring Whole Foods bought 460 stores'' worth of operational knowledge — supply chains, perishables logistics, store manager networks. The cost was real (Amazon''s culture is software-first; absorbing physical retail processes is slow)."},{"title":"Defensive move (vs. Walmart) vs. offensive expansion","body":"Walmart had spent $3B acquiring Jet.com in 2016 to build e-commerce muscle. Amazon''s Whole Foods move was the mirror response — building physical-grocery muscle to keep Walmart from owning the omni-channel category. Framed externally as expansion, framed internally as defense against Walmart''s e-commerce build-out."}],"per_dimension_truth":{"tradeoff":"Premium price + integration complexity vs. building a national grocery footprint from scratch over a decade. Amazon paid the premium because the alternative (slow build) gave Walmart a chance to win the omni-channel category. Defensive M&A framed as expansion.","user":"The customer Amazon really wanted was the Whole Foods shopper — an affluent, urban, health-conscious household that under-indexed on Amazon spending. Acquiring their physical-grocery purchase decision created a Prime upsell flywheel that pure e-commerce expansion couldn''t have produced.","alt":"Continuing to build Amazon Fresh + Amazon Go would have been cheaper and more aligned with Amazon''s DNA. It would also have ceded the omni-channel category to Walmart, which had the existing physical footprint. Amazon explicitly chose the harder integration over the slow build.","predict":"Massive market reaction on announcement (and grocery-retailer market-cap loss). 6–12 months of integration friction and brand identity questions. 3–5 years of slow grocery synergies + Prime upsell. Long-term: Whole Foods becomes the physical anchor for Amazon''s grocery story, and the deal becomes the case study in ''acquire to compress a decade of build into a single transaction.''"},"quote_type":"verbatim","sources":[{"title":"Amazon to Acquire Whole Foods Market","url":"https://media.wholefoodsmarket.com/amazon-to-acquire-whole-foods-market/","publisher":"Whole Foods Market","year":2017,"type":"press-release"},{"title":"Amazon to Acquire Whole Foods for $13.7 Billion","url":"https://www.bloomberg.com/news/articles/2017-06-16/amazon-to-acquire-whole-foods-in-13-7-billion-bet-on-groceries","publisher":"Bloomberg","year":2017,"type":"article"},{"title":"Amazon Buys Whole Foods — Case","url":"https://www.hbs.edu/faculty/Pages/item.aspx?num=53656","publisher":"Harvard Business School","type":"article"}],"tags":{"industry":"ecommerce","region":"us","decade":"2010s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'facebook-buys-instagram-2012',
  'weekly',
  '{"id":"facebook-buys-instagram-2012","type":"weekly","iso_week":"","company":"Facebook (Meta)","era":"April 2012","intro":"It is early April 2012. You are an executive at Facebook. The company is days away from filing its S-1 for an IPO targeted at a ~$100B valuation. Mark Zuckerberg has been watching Instagram closely — a 13-person company with ~30M users, no revenue, and a product (mobile-native photo sharing) that exposes Facebook''s biggest strategic weakness: Facebook is still primarily a desktop product, and mobile usage is exploding. Instagram''s Android version launched a week earlier and added 1M users in 24 hours.\n\nZuckerberg has been having direct conversations with Kevin Systrom for months. The negotiated price is ~$1B in cash and stock — Facebook''s largest acquisition ever, completed in one weekend at Zuckerberg''s house, without Facebook''s board approval until after the deal was done.","open_questions":["Buy Instagram or build a mobile-native photo product inside Facebook? Building is slower and arguably impossible given Facebook''s culture/codebase momentum.","What price is defensible for a 13-person, zero-revenue startup with the largest mobile-photo audience?","Preserve Instagram as a distinct product (preserve audience and brand) or absorb into Facebook (extract synergies)?","How do you negotiate with a founder whose company has the leverage of being the structural answer to your IPO''s biggest weakness?"],"closing":"Imagine you''re with Zuckerberg over the weekend of April 8, 2012. Negotiations have been ongoing privately. The IPO filing is days away.","decision":"Acquire Instagram for ~$1B in cash and stock on April 9, 2012. Zuckerberg negotiates the deal personally with Systrom over a weekend at his home. The acquisition is announced before Facebook''s board has formally voted. Instagram remains an independent product line with Systrom and Krieger staying as cofounders. Brand stays. Product stays separate from Facebook proper. By 2018 — when Systrom and Krieger leave — Instagram has ~1B users and is widely considered the most strategic acquisition in tech history. By 2020 internal Facebook documents (later leaked) estimate Instagram represents 30%+ of Facebook''s revenue and 100%+ of its growth.","pullquote":"This is an important milestone for us because it''s the first time we''ve ever acquired a product and company with so many users. We don''t plan on doing many more of these, if any at all.","pullquote_attribution":"Mark Zuckerberg, Facebook CEO — blog post announcing the acquisition, April 9, 2012","outcomes":[{"stat":"$1B","label":"cash + stock — Facebook''s largest acquisition at the time"},{"stat":"~30M","label":"Instagram users at acquisition (no revenue)"},{"stat":"13","label":"Instagram employees","accent":true},{"stat":"1B+","label":"Instagram users by 2018; 2B+ by 2020s"},{"stat":"~30%+","label":"of Meta''s revenue from Instagram by 2020 (leaked internal estimates)"}],"tradeoffs":[{"title":"Buy vs. build (mobile-photo edition)","body":"Facebook had Camera and Messenger and was about to ship Facebook Camera (a Camera+ competitor). Internal builds were slower than Instagram''s existing trajectory; competitive cloning would have lost ~6–12 months at exactly the moment Facebook was filing an IPO that bet on mobile."},{"title":"Premium price vs. wait-and-watch","body":"$1B for a 13-person zero-revenue company felt insane to most observers in April 2012 (Facebook''s IPO valuation was being doubted on similar grounds). The premium was the price of removing a strategic threat at the moment Facebook was most vulnerable. With hindsight, $1B looks like one of the cheapest acquisitions in tech history."},{"title":"Preserve Instagram independence vs. absorb","body":"Keeping Instagram a distinct product preserved the brand and the audience. The cost was slower revenue-synergy realization. The benefit was that Instagram could continue growing under its original brand and design DNA, eventually becoming a 2B-user product without ever feeling like ''Facebook''s photo app.''"},{"title":"CEO direct deal vs. board process","body":"Zuckerberg negotiated the deal at his home over a weekend with limited board involvement. The speed prevented leaks and competing offers (Twitter had also been interested) but bypassed normal acquisition diligence. Subsequent Facebook acquisitions (WhatsApp $19B, Oculus $2B) used similar founder-to-founder direct negotiation."}],"per_dimension_truth":{"tradeoff":"Massive premium + bypassed board process vs. losing the mobile-photo category to an independent competitor entering Facebook''s IPO window. Zuckerberg paid the premium because the strategic threat was existential at IPO time, not because Instagram looked like a $1B business on traditional financials.","user":"Younger users (mobile-native) who used Instagram primarily and Facebook secondarily. Acquiring Instagram kept that audience inside Facebook''s ad ecosystem rather than letting it migrate to an independent mobile-photo platform that Facebook couldn''t monetize.","alt":"Building Facebook Camera and outcompeting Instagram on mobile would have cost less cash but more time. Facebook had cash and was racing the IPO clock — buying the audience was faster than building it. The opposite trade (build) would likely have lost the mobile-photo category permanently to Instagram or Snapchat.","predict":"Short-term: press skepticism on price, regulatory scrutiny (FTC reviews the deal and approves it; this would later be reopened in 2020 antitrust complaints). Medium-term: Instagram absorbs Snapchat''s Stories format and becomes Facebook''s growth engine. Long-term: the acquisition becomes the canonical case in ''pay the premium when the strategic threat is real at IPO timing, even when financial analysts call you crazy.''"},"quote_type":"verbatim","sources":[{"title":"Facebook to Acquire Instagram","url":"https://about.fb.com/news/2012/04/facebook-to-acquire-instagram/","publisher":"Meta Newsroom","year":2012,"type":"press-release"},{"title":"Facebook Buys Instagram For $1 Billion","url":"https://techcrunch.com/2012/04/09/facebook-to-acquire-instagram-for-1-billion/","publisher":"TechCrunch","year":2012,"type":"article"},{"title":"The Inside Story of How Facebook Acquired Instagram","url":"https://onezero.medium.com/the-inside-story-of-how-facebook-acquired-instagram-318f244f1283","publisher":"Sarah Frier / OneZero","type":"blog"}],"tags":{"industry":"consumer-social","region":"us","decade":"2010s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'microsoft-activision-2022',
  'weekly',
  '{"id":"microsoft-activision-2022","type":"weekly","iso_week":"","company":"Microsoft","era":"January 2022 – October 2023","intro":"It is January 2022. You are a corporate-strategy executive at Microsoft. Game Pass — Microsoft''s gaming-subscription product — has been growing rapidly and is becoming Microsoft''s central bet in gaming, but it lacks consistently great exclusive content. Sony''s PlayStation has stronger first-party studios. Activision Blizzard — owner of Call of Duty, World of Warcraft, Diablo, Candy Crush, Overwatch — is in active corporate turmoil after the California DFEH filed a major workplace-harassment lawsuit in July 2021; CEO Bobby Kotick is under fire; the stock has dropped ~40%. The board is open to a sale.\n\nMicrosoft proposes $95/share in cash — a $68.7B all-cash deal, the largest in gaming industry history and one of the largest tech acquisitions ever. The deal will trigger antitrust scrutiny in the US (FTC), UK (CMA), and EU. Closing is far from guaranteed; the FTC under Lina Khan has signaled an aggressive stance on tech-platform M&A. Termination fee if the deal collapses: $3B.","open_questions":["Pay $68.7B for Activision Blizzard or build / acquire smaller studios over time?","How aggressive is the antitrust risk — and is the $3B break fee worth it as a hedge against regulator blocks?","If the deal closes, what''s the cross-platform commitment on Call of Duty — keep it on PlayStation (defuses Sony''s antitrust complaint) or pull exclusivity (maximize Xbox value)?","How does the workplace-culture crisis at Activision get handled post-close — preserve Bobby Kotick or remove him?"],"closing":"Imagine you''re at Microsoft headquarters in early 2022. The deal has been negotiated. The FTC is already signaling concern. Sony is publicly opposing it.","decision":"Announce the $68.7B acquisition on January 18, 2022. Make 10-year contractual commitments to keep Call of Duty on PlayStation and bring it to Nintendo Switch — defusing the biggest competitive-foreclosure argument. Fight the FTC''s preliminary injunction; win Judge Jacqueline Scott Corley''s July 2023 ruling. UK CMA initially blocks the deal; Microsoft restructures to sell Activision''s cloud-gaming rights to Ubisoft globally. Deal closes October 13, 2023 — 21 months after announcement, total cost ~$75.4B including debt. FTC continues case post-close; drops it in May 2025. Bobby Kotick remains CEO through close, then exits in late 2023.","pullquote":"Gaming is the most dynamic and exciting category in entertainment across all platforms today and will play a key role in the development of metaverse platforms.","pullquote_attribution":"Satya Nadella, Microsoft CEO — acquisition announcement, January 18, 2022","outcomes":[{"stat":"$68.7B","label":"all-cash deal value at announcement (became $75.4B at close)","accent":true},{"stat":"21 months","label":"from announcement to close — regulatory fight"},{"stat":"10 years","label":"binding Call of Duty PlayStation commitment used to win regulator approval"},{"stat":"$3B","label":"termination fee Microsoft would have paid if the deal collapsed"},{"stat":"FTC dropped","label":"the post-close challenge in May 2025 — fully unblocked"}],"tradeoffs":[{"title":"Acquire Activision vs. build content organically","body":"Microsoft could have spent $68B on smaller studios over a decade. Activision delivered a content portfolio (Call of Duty especially) that''s a top-3 gaming franchise overnight. Buying compressed a 10-year build into a single transaction, at the cost of ~2 years of regulatory war."},{"title":"Fight regulators vs. accept conditions","body":"Microsoft fought the FTC''s preliminary injunction openly and won. Accepting an early settlement would have been quieter but would have set precedent for future tech M&A scrutiny. Microsoft''s legal team treated the case as precedent-setting, which it was — the ruling made the FTC''s broader ''platform-aggregation'' theory much harder to apply to future deals."},{"title":"Cross-platform commitments vs. exclusivity-first integration","body":"Keeping Call of Duty on PlayStation for 10 years is the single most expensive concession Microsoft made. It cost real Xbox-exclusivity value. The benefit: it defused Sony''s main antitrust argument and convinced regulators the deal wouldn''t foreclose competition. The cost-benefit math made sense; preserving Microsoft''s gaming brand as ''pro-cross-platform'' became a strategic asset, not just a regulatory cost."},{"title":"Keep Bobby Kotick vs. force a leadership change pre-close","body":"Kotick was the architect of Activision''s workplace-culture crisis. Removing him pre-close would have signaled accountability but slowed the transaction. Microsoft chose to keep him through close, then quietly exited him afterward. The choice maximized deal-completion probability at the cost of a slower workplace-culture reset."}],"per_dimension_truth":{"tradeoff":"Regulatory war + Call-of-Duty cross-platform commitment + $68.7B in cash vs. building gaming content organically over a decade. Microsoft chose to pay the premium and accept the regulatory war; both bets paid off (deal closed, FTC case dropped, gaming content portfolio acquired in months not decades).","user":"Game Pass subscribers — Microsoft''s central gaming-subscription customer — are the user this acquisition serves. They get Activision''s content in their subscription, immediately and without paying per-title. The acquisition is structurally a Game Pass content-pipeline investment, framed as a corporate M&A.","alt":"Settling with the FTC early (accepting more restrictive concessions) would have closed the deal faster but set precedent for future tech-M&A reviews to demand similar concessions. The opposite trade — and Microsoft''s legal team made the deliberate decision to fight, knowing the ruling would shape M&A law for the next decade.","predict":"Short-term: regulatory chaos, UK CMA blocks the deal, Microsoft restructures to satisfy CMA, the FTC loses its preliminary injunction. Medium-term: deal closes, Activision IP moves to Game Pass, Sony switches from antagonist to participating partner under the CoD agreement. Long-term: the case becomes the canonical ''how to fight US/UK regulators over a tech mega-deal and win'' study; Microsoft''s M&A playbook in 2025+ is shaped by it."},"quote_type":"verbatim","sources":[{"title":"Acquisition of Activision Blizzard by Microsoft — Wikipedia","url":"https://en.wikipedia.org/wiki/Acquisition_of_Activision_Blizzard_by_Microsoft","type":"article"},{"title":"Microsoft just closed its mega $69 billion acquisition of Activision Blizzard","url":"https://fortune.com/2023/10/13/microsoft-69-billion-activision-blizzard-acquisition-ftc-lina-khan-antitrust-video-games/","publisher":"Fortune","year":2023,"type":"article"},{"title":"It''s official: Microsoft closes $68.7B Activision Blizzard acquisition","url":"https://techcrunch.com/2023/10/12/microsofts-68-7b-activision-acquisition-clears-final-hurdle-as-uk-approves-restructured-deal/","publisher":"TechCrunch","year":2023,"type":"article"},{"title":"FTC v. Microsoft — Wikipedia","url":"https://en.wikipedia.org/wiki/FTC_v._Microsoft","type":"article"}],"tags":{"industry":"gaming","region":"us","decade":"2020s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'apple-vision-pro-2024',
  'weekly',
  '{"id":"apple-vision-pro-2024","type":"weekly","iso_week":"","company":"Apple","era":"January–February 2024","intro":"It is late 2023. You are a senior product leader at Apple. The Vision Pro is the company''s first new computing-platform launch since the Apple Watch in 2015 — a mixed-reality headset that''s been in development for seven years. Tim Cook has personally championed it. The team has built proprietary silicon (M2 + R1), passthrough video at 23ms latency, and an eye-and-hand input system that''s clearly the most sophisticated commercial implementation to date. Internally, the working price was originally targeted at ~$2,000–$2,500. The launch price has now been set at $3,499.\n\nThe headset will ship February 2, 2024 with no killer app, no marquee 3rd-party content partner committed to bring full apps (Netflix, YouTube, and Spotify will refuse to ship native apps), and a battery pack that has to be tethered to the device. Apple knows it. Wall Street expects modest volumes (~400-500K units year one). The strategic question internally is not ''will this launch sell millions of units'' — it''s ''what is this launch for?''","open_questions":["$3,499 — sell at a loss-leader $1,999 to seed mass adoption, or price at $3,499 to position the device as a ''developer/early-adopter'' kit?","Killer app problem — wait until Netflix and Apple''s own original VR content is ready (delays launch by 12-18 months), or ship without and let the platform define itself in the wild?","How public to be about year-one volume expectations — manage expectations downward (transparency) or let the press call it a hit/flop on launch-week metrics?","Is Vision Pro the product, or the developer kit for an Apple Glasses product 3–5 years away?"],"closing":"Imagine you''re in Apple''s product leadership room in late 2023. The marketing campaign is set. The price is set. The launch is 6 weeks out.","decision":"Ship Vision Pro at $3,499 on February 2, 2024 — the highest launch price for a mainstream-positioned Apple consumer device ever. Frame the launch publicly as ''the start of the era of spatial computing.'' Refuse to publicly disclose year-one volume targets. Allow Netflix, YouTube, and Spotify to ship their iPad apps inside Vision Pro rather than building native experiences (a public concession that the content ecosystem isn''t there). Initial sales hit ~200-300K units in the first month; estimates suggest ~400-500K units sold in the first year, well below initial pre-orders'' implied trajectory.","pullquote":"The era of spatial computing has arrived. Apple Vision Pro is the most advanced consumer electronics device ever created.","pullquote_attribution":"Tim Cook, Apple CEO — Vision Pro launch announcement, February 2024","outcomes":[{"stat":"$3,499","label":"launch price — Apple''s highest-ever consumer device","accent":true},{"stat":"~400-500K","label":"year-one units (estimated) vs. iPhone year-one ~6M"},{"stat":"0","label":"native apps from Netflix, YouTube, Spotify at launch"},{"stat":"23ms","label":"passthrough video latency — best-in-class technical spec"},{"stat":"Mid-2024","label":"first reports of Apple''s smaller / cheaper Vision Pro 2 plans"}],"tradeoffs":[{"title":"Premium price vs. mass-adoption price","body":"$3,499 is signaling to developers and early adopters; $1,999 would be signaling to consumers. Apple chose the developer-first signal — the device is essentially a high-end dev kit that creates the ecosystem for a future product priced for the mass market. The cost is real: many consumers who''d have bought at $1,999 sat out at $3,499."},{"title":"Ship without killer apps vs. wait","body":"Apple''s ecosystem typically launches with at least one transformative use case (multi-touch on iPhone, Apple Pay on Watch). Vision Pro shipped without one — passthrough video and ''spatial photos'' are not it. Apple chose to ship the platform and let third parties define the use case. The cost: the first wave of reviews framed Vision Pro as ''a great device with no purpose.''"},{"title":"Manage expectations vs. let press call the launch","body":"Apple refused to publicly forecast Vision Pro volumes. Industry observers framed sub-iPhone-level launches as failures. Apple''s silence was a deliberate position: ''this is a different product, judge it on a different timeline.'' That framing worked for some publications and was rejected by others."},{"title":"Product launch vs. developer-kit launch (framed as product)","body":"Behind the marketing, Vision Pro is structurally a developer kit for Apple''s later, smaller, cheaper glasses-form-factor product. Pricing, marketing, and ''spatial computing'' framing all make more sense as ''seed the developer ecosystem'' than as ''sell millions of units.'' Apple won''t say this publicly because admitting it would crash the price and the press would call the launch a ''beta.''"}],"per_dimension_truth":{"tradeoff":"Selling year-one volume + clean marketing narrative vs. seeding a developer ecosystem for a future product 3-5 years out. Apple chose the latter, paid the premium-price + missing-killer-app press cost, and accepted year-one as a category-seeding moment, not a sales event.","user":"Apple''s actual customer at $3,499 was developers and early adopters, not the broader iPhone audience. Selling 400K units to high-intent developers and creators is different from selling 4M to consumers — and is the right customer if the goal is building the apps for the next price point.","alt":"Pricing at $1,999, shipping with Apple''s own bundled killer app, and forecasting big year-one volumes was the ''iPhone-style launch'' alternative. It would have produced bigger headlines, more units, and almost certainly hurt margins, brand premium, and the developer ecosystem long-term. Apple deliberately took the harder, quieter path.","predict":"Short-term: mixed reviews, sub-iPhone unit volume, ''flop'' headlines from publications expecting iPhone-style metrics. Medium-term: developer experimentation drives slow ecosystem build-out, Vision Pro 2 ships at lower price by 2025-2026 with smaller form factor. Long-term: the launch becomes the case study in ''when to launch a platform-defining device that''s not a consumer hit.'' If a future smaller / cheaper Apple Glasses product succeeds, Vision Pro was the kit that made it possible."},"quote_type":"verbatim","sources":[{"title":"Apple''s $3,499 Vision Pro Launches; Tim Cook Visits NYC Flagship Store","url":"https://www.bloomberg.com/news/articles/2024-02-02/apple-fans-line-up-for-headset-as-spatial-computing-era-begins","publisher":"Bloomberg","year":2024,"type":"article"},{"title":"Apple Vision Pro available in the U.S. on February 2","url":"https://www.apple.com/newsroom/2024/01/apple-vision-pro-available-in-the-us-on-february-2/","publisher":"Apple Newsroom","year":2024,"type":"press-release"},{"title":"Tim Cook says Vision Pro costs $3,500 because it''s tomorrow''s technology today","url":"https://9to5mac.com/2024/02/02/tim-cook-vision-pro-interview/","publisher":"9to5Mac","year":2024,"type":"interview"}],"tags":{"industry":"hardware","region":"us","decade":"2020s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'microsoft-bing-chatgpt-2023',
  'weekly',
  '{"id":"microsoft-bing-chatgpt-2023","type":"weekly","iso_week":"","company":"Microsoft (vs. Google)","era":"February 2023","intro":"It is January 2023. You are a senior product/strategy leader at Microsoft. Bing has been an also-ran in search for 14 years — ~3% global share against Google''s ~93%. Microsoft has spent $10B+ on Bing over a decade and barely moved the needle. But Microsoft has just made another investment in OpenAI ($10B), giving it exclusive access to GPT-4 (still unreleased publicly) and the underlying compute exclusivity. Internally, leadership is debating whether to integrate ChatGPT-style AI into Bing — and how aggressively.\n\nGoogle, meanwhile, has been quiet on consumer AI despite having LaMDA (the underlying model that famously made an engineer claim it was sentient) since 2021. Sundar Pichai has just declared ''Code Red'' internally — pulling Larry Page and Sergey Brin back into product reviews. The strategic question for Microsoft: do you ship Bing-with-AI fast and force Google''s hand, or wait until the AI is more polished and avoid the inevitable hallucination / safety embarrassments?","open_questions":["Ship now (forcing Google to respond mid-development) or wait until the AI is polished (giving Google more time to ship Bard)?","How is the AI surface integrated — replace search results entirely, sidebar, chat tab, or all three?","What''s the right safety framing — call it a ''preview'' (manages expectations, lets hallucinations slide) or a ''product'' (asserts confidence, takes the brand hit on errors)?","How does the launch get framed against Google — explicit attack, or quiet positioning?"],"closing":"Imagine you''re at Microsoft in early February 2023. The Bing event is set for February 7. Google''s Sundar Pichai has already declared Code Red. The race is public.","decision":"Hold the Bing event on February 7, 2023 — announce ''the new Bing'' with GPT-4-class AI integrated as a chat sidebar + reimagined search results. Frame it as a ''preview,'' open to waitlist. Satya Nadella is publicly visible during the launch and gives interviews framing the launch as ''a new day for search.'' Google announces Bard the day before, in a rushed press release. In the Bard demo, Bard answers a question about the James Webb Space Telescope incorrectly; the factual error spreads on Twitter; Google''s stock drops ~$100B in market cap in 48 hours. Bing chat goes off the rails publicly within weeks (''Sydney'' incident — telling a NYT reporter to leave his wife), but Microsoft has already shifted the narrative of who is leading in AI.","pullquote":"I want people to know that we made them dance.","pullquote_attribution":"Satya Nadella, Microsoft CEO — Verge interview, February 7, 2023 (referring to Google)","outcomes":[{"stat":"Feb 7 vs. Feb 6","label":"Bing launch one day after Google''s rushed Bard announcement","accent":true},{"stat":"~$100B","label":"Google parent (Alphabet) market-cap drop after Bard''s demo error"},{"stat":"''Sydney''","label":"Bing chat incident — early hallucination scandal absorbed as cost of going first"},{"stat":"Code Red","label":"Google internal status declared in response"},{"stat":"$13B+","label":"Microsoft total OpenAI investment giving it the GPT-4 exclusive"}],"tradeoffs":[{"title":"Ship now vs. polish first","body":"Shipping in February 2023 meant accepting that the chat AI would hallucinate, get jailbroken, and produce screenshots. Polishing for six more months would have ceded the ''who shipped first'' narrative to Google''s Bard or to OpenAI''s standalone ChatGPT integrations. Microsoft chose speed and accepted brand-volatility cost."},{"title":"Force Google''s hand vs. quietly compete","body":"Microsoft''s launch was explicitly designed to force Google to respond in public before Google''s product was ready. The Bard demo failure was a direct result. Sandbagging Google''s product launch was both effective strategically and a brand attack — Microsoft accepted the bad-faith framing because the strategic benefit was so high."},{"title":"Preview framing vs. product framing","body":"Calling Bing''s AI a ''preview'' gave Microsoft a permission structure to ship rough. Calling it a ''product'' would have signaled more confidence but tied Microsoft''s brand to every hallucination. The preview framing was widely copied by every subsequent AI product launch."},{"title":"AI sidebar vs. AI replacement","body":"Microsoft chose to put AI alongside Bing''s traditional results, not replace them. The cost: less radical product change. The benefit: the existing Bing usage didn''t break, and the AI could be opt-in for the curious. Google''s Bard ended up shipping as a separate app — a more conservative integration that gave Bing the more aggressive positioning."}],"per_dimension_truth":{"tradeoff":"Speed + brand-volatility (hallucinations, jailbreaks, the ''Sydney'' incident) vs. ceding the ''who-leads-in-AI'' narrative to Google or OpenAI. Microsoft took the brand volatility because the alternative — letting Google ship first — was strategically much worse.","user":"The user Microsoft was actually serving was the press / analyst / investor cohort, not Bing''s actual users. Bing''s market share barely moved (it''s still ~3-4% globally). What changed was the narrative — Microsoft was the AI-search leader, Google was on the back foot. That repositioning was worth more than the Bing usage delta.","alt":"Waiting six more months to ship a polished AI Bing would have lost the news-cycle window entirely. Google would have shipped Bard on its own timeline. Microsoft''s ''force the response'' move was high-risk and only made sense if the strategic narrative was the actual goal — which it was.","predict":"Short-term: ''Bing chat is unhinged'' news cycles (Sydney incident, hallucinations), but the AI-leader narrative shifts to Microsoft. Medium-term: Google ships Bard / Gemini in iterations, the press race continues, both companies invest heavily. Long-term: the launch is the canonical case in ''when to ship rough and force a slower incumbent to respond before they''re ready'' — and in the cost (brand volatility from real product failures) of doing so."},"quote_type":"verbatim","sources":[{"title":"Microsoft ChatGPT event 2023 live updates","url":"https://www.cnbc.com/2023/02/07/microsoft-open-ai-chatgpt-event-2023-live-updates.html","publisher":"CNBC","year":2023,"type":"article"},{"title":"Microsoft unveils revamped Bing search engine using AI technology more powerful than ChatGPT","url":"https://www.cnn.com/2023/02/07/tech/microsoft-ai-event/index.html","publisher":"CNN","year":2023,"type":"article"},{"title":"Google CEO issues rallying cry in internal memo: All hands on deck to test ChatGPT competitor Bard","url":"https://www.cnbc.com/2023/02/06/google-ceo-tells-employees-it-needs-all-hands-on-deck-to-test-bard.html","publisher":"CNBC","year":2023,"type":"article"}],"tags":{"industry":"ai-tools","region":"us","decade":"2020s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'snap-redesign-disaster-2018',
  'weekly',
  '{"id":"snap-redesign-disaster-2018","type":"weekly","iso_week":"","company":"Snap Inc. (Snapchat)","era":"Late 2017 – February 2018","intro":"It is late 2017. You are a senior PM at Snapchat. Snap has been public for less than a year (Mar 2017 IPO at $24/share). User growth is decelerating. Instagram Stories — launched 18 months earlier as a near-pixel-for-pixel clone — is winning the engagement battle. The product has a structural problem: the same friends-and-family content is now mixed with influencer broadcasts, news content, and brand-driven content, all in one chronological feed. Internal data shows young users complaining the app feels ''cluttered.''\n\nEvan Spiegel and the leadership team make a strategic call: redesign Snapchat to separate ''friends'' from ''professional content.'' Friends and DMs go on the left. Stories from professional creators, brands, and news go on the right (in a separate Discover tab). The redesign rolls out in November 2017 starting in beta markets, then globally in February 2018. Power users hate it — millions sign a petition against it. Engagement drops.","open_questions":["Ship the redesign globally or hold and iterate based on the early-market negative feedback?","How aggressive on the separation — full split (where Spiegel landed) or soft separation (algorithmic ranking of mixed content)?","When influential users (celebrities, creators) complain publicly, do you reverse — or hold the line on the design philosophy?","How much short-term DAU loss are you willing to absorb for a redesign that''s framed as long-term retention investment?"],"closing":"Imagine you''re with Spiegel in late January 2018, days before the global rollout. The beta-market signal is clearly negative. The petition is at 700,000 signatures.","decision":"Push the redesign globally in February 2018 anyway. On February 21, Kylie Jenner tweets: ''sooo does anyone else not open Snapchat anymore? Or is it just me… ugh this is so sad.'' The tweet costs Snap ~$1.3B in market cap that day. The petition crosses 1.2M signatures. Engagement drops. Spiegel publicly stands by the design philosophy: ''the biggest mistake we made with our redesign was compromising our core product value of being the fastest way to communicate'' — but does not reverse the separation. By 2019, Spiegel claims the redesign worked: time spent watching premium content grew 40% YoY. Snap''s stock takes until 2021 to recover.","pullquote":"Snapchat''s redesign was meant for your friends. Celebrities aren''t your friends.","pullquote_attribution":"Evan Spiegel, Snap cofounder/CEO — public comments after the Jenner tweet, February 2018","outcomes":[{"stat":"$1.3B","label":"market-cap loss from a single Kylie Jenner tweet","accent":true},{"stat":"1.2M+","label":"petition signatures demanding the redesign be reversed"},{"stat":"−3M","label":"DAU drop in the quarter after the global rollout"},{"stat":"+40%","label":"professional-content time-spent YoY (Spiegel''s defense)"},{"stat":"~3 yrs","label":"for Snap stock to recover its pre-redesign price level"}],"tradeoffs":[{"title":"Hold the design vision vs. listen to user feedback","body":"The redesign was philosophically motivated — separating intimate friend content from broadcast / paid content. The user-feedback signal was unambiguously negative. Spiegel held the design vision against the signal. The cost was real (DAU loss, brand damage, $1.3B market cap). The benefit (long-term content separation) took years to prove and is still contested."},{"title":"Ship globally vs. iterate in test markets","body":"Snap had beta-market data showing the redesign was unpopular before the global rollout. Pulling back to iterate would have softened the blow but accepted that the existing design was the right one — which Spiegel didn''t believe. Shipping globally was a conviction bet against the data."},{"title":"Reverse vs. hold the line under celebrity pressure","body":"When Kylie Jenner publicly criticized the redesign, the option to reverse and announce the rollback was on the table. Spiegel held the line. The decision was costly in the short term (more DAU loss) but preserved the credibility of the design philosophy. Reversing would have told every future product decision-maker that public pressure could force a U-turn."},{"title":"Short-term DAU vs. long-term engagement quality","body":"The redesign explicitly traded DAU (down) for time-spent-on-premium-content (up). That''s a defensible long-term bet for a public company — but public markets price on DAU. The redesign was strategically right by one set of metrics and tactically wrong by the ones investors actually used."}],"per_dimension_truth":{"tradeoff":"Spiegel''s design conviction + long-term retention thesis vs. short-term DAU + brand-equity + stock-price cost. He chose the long-term bet. The stock took three years to recover; the design philosophy partially won (Stories format separation is now standard); the public-market punishment was real.","user":"The redesign was optimized for younger users who weren''t yet on Snap (Spiegel''s belief) over the existing power-user cohort who built habits around the old design. Power users left in numbers; the new-user cohort didn''t pick up in the way Spiegel hoped — partly because Instagram Stories was already capturing them.","alt":"Reversing the redesign in March 2018 would have stopped the DAU bleed and protected the stock — but at the cost of validating that user backlash dictates product strategy. Spiegel chose the harder path. With hindsight, a softer redesign (algorithmic separation rather than hard tabs) might have produced the same long-term win without the brand cost.","predict":"Short-term: DAU drop, petition outrage, Kylie tweet impact, stock decline. Medium-term: engagement quality improves on metrics Snap cares about; investors stay skeptical; Snap is structurally weaker against Instagram. Long-term: the redesign becomes the case study in ''conviction-over-data when the data is short-term and the design vision is right'' — though whether it was right is still contested."},"quote_type":"verbatim","sources":[{"title":"Evan Spiegel doesn''t regret the Snapchat redesign that tanked Snap''s stock","url":"https://www.businessinsider.com.au/evan-spiegel-doesnt-regret-the-disastrous-snapchat-redesign-2019-11","publisher":"Business Insider","year":2019,"type":"article"},{"title":"How 1 Tweet From Kylie Jenner Caused Snap, Inc. To Lose $1 Billion","url":"https://www.npr.org/2018/02/23/588374736/how-1-tweet-from-kylie-jenner-caused-snap-inc-to-lose-1-billion","publisher":"NPR","year":2018,"type":"article"},{"title":"Snapchat''s redesign was meant for your friends, and celebrities aren''t your friends","url":"https://www.recode.net/2018/2/23/17045732/kylie-jenner-snapachat-tweet-stock-wall-street-evan-spiegel-redesign-app","publisher":"Recode","year":2018,"type":"article"}],"tags":{"industry":"consumer-social","region":"us","decade":"2010s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'tiktok-divestiture-2024',
  'weekly',
  '{"id":"tiktok-divestiture-2024","type":"weekly","iso_week":"","company":"ByteDance (TikTok US)","era":"March 2024 – January 2025","intro":"It is March 2024. You are a senior strategy leader at ByteDance. TikTok has ~170M monthly users in the US. Concerns about Chinese government access to US user data have been escalating for years. Bipartisan momentum in Congress is real. A bill is about to pass — the ''Protecting Americans from Foreign Adversary Controlled Applications Act'' — that gives ByteDance roughly 9 months to either divest its US TikTok business or face a nationwide ban.\n\nThe Chinese government has signaled it will not approve a sale that includes the recommendation algorithm — meaning even if a US buyer emerges, the buyer probably won''t get the asset that makes TikTok work. President Biden signs the bill into law on April 24, 2024. Initial divestiture deadline: January 19, 2025. After that date, US app stores cannot list TikTok, US infrastructure providers cannot host it, and existing US users cannot get updates.","open_questions":["Comply by selling the US business (likely without the algorithm — useless to most buyers) or fight to challenge the law on First Amendment grounds?","If sell — which buyer satisfies the law''s ''qualified divestiture'' requirement (not under foreign-adversary control), is large enough to pay, and is acceptable to ByteDance?","How public to be about the algorithm carve-out — say it''s not for sale (signals defiance and reduces buyer offers) or stay ambiguous?","What''s the operational plan for the 170M US users if the deadline passes and no sale completes?"],"closing":"Imagine you''re at ByteDance HQ in mid-2024. The law has passed. Buyer interest is broad (Bobby Kotick, Frank McCourt''s Project Liberty, Steven Mnuchin, Larry Ellison, MrBeast, Kevin O''Leary). None of them can match TikTok''s algorithm.","decision":"Fight the law in court on First Amendment grounds — TikTok loses at the Supreme Court on January 17, 2025 (decision upholding the divestiture-or-ban law). TikTok briefly goes dark in the US for ~12 hours on January 19. President Trump takes office January 20 and signs an executive order pausing enforcement, extending the deadline 75 days (later extended again multiple times). ByteDance negotiates for over a year. A final deal closes January 22, 2026 — US operations spin out as ''TikTok USDS,'' a divested entity, ending the de jure ban period.","pullquote":"[ByteDance is] subject to Chinese laws that require it to assist or cooperate with the Chinese government''s intelligence work and to ensure that the Chinese government has the power to access and control private data that the company holds.","pullquote_attribution":"Protecting Americans from Foreign Adversary Controlled Applications Act — congressional findings, April 2024","outcomes":[{"stat":"Apr 24, 2024","label":"law signed by President Biden","accent":true},{"stat":"9 months","label":"initial divestiture deadline (Jan 19, 2025)"},{"stat":"~12 hours","label":"TikTok dark in the US before Trump''s executive-order pause"},{"stat":"5x","label":"deadline extensions over 2025"},{"stat":"Jan 22, 2026","label":"final deal closes — US operations divested into TikTok USDS"}],"tradeoffs":[{"title":"Sell vs. fight","body":"Selling cleanly in 2024 would have ended the regulatory uncertainty but required parting with the US business at a depressed valuation (forced-seller dynamics). Fighting bought ByteDance time and political optionality (especially under a new administration). The fight cost was the cumulative drag of regulatory limbo on US user-product investment for 21 months."},{"title":"Include the algorithm vs. exclude it from the sale","body":"The algorithm is what makes TikTok TikTok. Without it, the US asset is mostly a brand, a content library, and a user base. ByteDance signaled (and the Chinese government confirmed) the algorithm would not be sold. That cut potential buyer pool''s offers in half but preserved the algorithm as a long-term Chinese state asset."},{"title":"Political bet on Trump vs. compliance under Biden","body":"ByteDance''s de facto strategy was: delay until the new administration takes office, then negotiate softer terms. The bet paid off — Trump signed executive orders pausing enforcement on day one. The cost: 21+ months of operational uncertainty in the US market, and being publicly framed as ''a Chinese company circumventing US law.''"},{"title":"Communicate clearly with US users vs. preserve operational ambiguity","body":"TikTok could have proactively communicated to its 170M US users — explaining the law, the divestiture process, the timeline. Instead it stayed mostly silent until the brief blackout on January 19. The silence preserved negotiating leverage but left users confused (mass migration to RedNote and other Chinese apps in the lead-up)."}],"per_dimension_truth":{"tradeoff":"Operational uncertainty + political delay + diplomatic risk vs. selling cleanly at a depressed valuation. ByteDance chose delay. The bet on the 2024 election outcome paid off; the cost was 21+ months of regulatory limbo and a complex partial-divestiture that''s still unfolding.","user":"TikTok''s 170M US users were the leverage, not the customer. Mass mobilization of those users (TikToks against the ban, calls to congressional offices) was a real political force. The strategic question wasn''t ''how do we serve users'' — it was ''how do we use the user base as political leverage to delay enforcement.''","alt":"A clean 2024 sale to a US consortium (perhaps Microsoft + Oracle + others) would have ended uncertainty and produced a known-value exit. The opposite trade. ByteDance held out for a much better outcome and got it via the political-cycle pivot — but at significant operational and brand cost in the interim.","predict":"Short-term: court fight, Supreme Court loss, brief blackout, political-cycle pivot via Trump''s executive order. Medium-term: multiple deadline extensions, mass user migration to RedNote, ongoing congressional pressure. Long-term: the case becomes the canonical example of a foreign-owned platform navigating US national-security legislation — and the precedent for any future ''foreign adversary'' app divestiture (TikTok-style laws are now being proposed in EU, UK, and India)."},"quote_type":"verbatim","sources":[{"title":"President Biden signs law to ban TikTok nationwide unless it is sold","url":"https://www.npr.org/2024/04/24/1246663779/biden-ban-tiktok-us","publisher":"NPR","year":2024,"type":"article"},{"title":"U.S. Supreme Court Upholds TikTok Sale-or-Ban Law","url":"https://www.hklaw.com/en/insights/publications/2025/01/us-supreme-court-upholds-tiktok-sale-or-ban-law","publisher":"Holland & Knight","year":2025,"type":"article"},{"title":"Efforts to ban TikTok in the United States — Wikipedia","url":"https://en.wikipedia.org/wiki/Donald_Trump%E2%80%93TikTok_controversy","type":"article"},{"title":"Trump extends TikTok deadline for the second time","url":"https://www.cnbc.com/2025/04/04/trumps-extends-tiktok-second-time.html","publisher":"CNBC","year":2025,"type":"article"}],"tags":{"industry":"consumer-social","region":"us","decade":"2020s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'stripe-tender-2023',
  'weekly',
  '{"id":"stripe-tender-2023","type":"weekly","iso_week":"","company":"Stripe","era":"Late 2022 – March 2023","intro":"It is late 2022. You are a senior strategy leader at Stripe. Stripe last raised primary capital at a $95B valuation in March 2021 — the peak of the ZIRP / fintech boom. Now interest rates have risen, fintech multiples have compressed ~70%, and Stripe (still private) has a real problem unrelated to the business itself: employees holding equity that''s about to vest face large tax bills, and there''s no public-market liquidity to cover them. The IPO that was rumored for 2021–2022 hasn''t happened. Patrick and John Collison have publicly stated Stripe is not planning to go public in the near-term.\n\nThe leadership team is debating a Series I funding round structured specifically to address employee tax obligations on expiring RSUs. The catch: the valuation will reset, publicly, far below the $95B peak. Standard private-market practice would mark the valuation ''flat'' to preserve optics; Stripe is debating taking the public valuation cut to clean up cap-table mechanics and reset expectations.","open_questions":["Reset the valuation publicly (signals weakness in fintech) or close a flat round at $95B with creative structuring (preserves optics but creates future liability)?","How much to raise? Enough to cover the immediate RSU tax bills (~$3-4B) or more (build a war chest for downturn)?","Who are the new investors — strategic / sovereign (GIC, Temasek — strong signal of patient capital) or growth funds chasing momentum (more expensive in dilution terms)?","How transparent to be in employee communication — explain the reset cleanly, or frame it as ordinary tax-equity housekeeping?"],"closing":"Imagine you''re with the Collisons in February 2023. The round is closing in March. The valuation is being negotiated. Employee equity is the immediate driver, not new capital.","decision":"Close the Series I in March 2023 at a $50B valuation — a ~47% public cut from the $95B 2021 peak. Raise $6.5B+ from GIC, Goldman Sachs Asset Management, Temasek, and existing investors. The capital is used primarily to address employee tax obligations on expiring RSUs, not to fund operations. Stripe communicates the reset cleanly — Patrick Collison''s letter explicitly states the valuation is lower than 2021 and explains why. Stripe is profitable; the cut is a market-recalibration, not a survival raise. By February 2026, subsequent tender offers value Stripe at $159B.","pullquote":"We were much too optimistic about the internet economy''s near-term growth in 2022 and 2023. We''re recalibrating to the world we''re in.","pullquote_attribution":"Patrick Collison, Stripe cofounder/CEO — paraphrased from the layoff letter (Nov 2022) + subsequent Series I commentary (Mar 2023)","outcomes":[{"stat":"$95B → $50B","label":"valuation reset — ~47% cut from 2021 peak","accent":true},{"stat":"$6.5B+","label":"raised in Series I (primary purpose: employee tax obligations)"},{"stat":"0","label":"operational uses — the round was structurally a cap-table cleanup"},{"stat":"GIC, Temasek","label":"anchor investors — sovereign / patient capital signal"},{"stat":"$159B","label":"subsequent valuation by Feb 2026 — 3x recovery in 3 years"}],"tradeoffs":[{"title":"Public reset vs. structured flat round","body":"Many late-stage private companies in 2022-2023 used ''creative structuring'' (liquidation preferences, ratchets) to keep flat headline valuations while transferring economic value to new investors. Stripe chose the public cut. Cost: bad headlines, signal of weakness. Benefit: clean cap-table, no future down-round mechanics, employee equity priced honestly."},{"title":"Tax-driven raise vs. operational war chest","body":"The round was structurally about employee equity vesting, not new growth capital. Raising more (and using it for growth investment) would have been a different signal. Raising exactly what was needed for the equity problem was disciplined — and a quiet way of saying ''we don''t need this for operations.''"},{"title":"Sovereign / patient capital vs. growth-fund momentum capital","body":"GIC and Temasek are long-term holders with low pressure for near-term IPO. Choosing them over the growth funds available signaled Stripe was prioritizing patience over IPO-timing pressure. Some early Stripe investors wanted IPO liquidity; this round delayed that conversation."},{"title":"Transparent communication vs. tax-mechanics framing","body":"Collison''s letter explicitly named the reset. Most private CEOs handle valuation cuts as quiet cap-table mechanics; Stripe used the moment to set a ''we recalibrate honestly'' brand norm. The transparency had a cost (headlines) and a benefit (employee trust, market positioning)."}],"per_dimension_truth":{"tradeoff":"Public valuation hit + ''Stripe valuation cut'' headlines vs. complex structured-flat-round mechanics that would have created multi-year unwind problems. Stripe took the clean public hit and recovered the valuation more than 3x within 3 years. The discipline paid off because the underlying business was strong.","user":"The audience for the reset was simultaneously Stripe employees (RSU holders facing tax bills), existing investors (who took dilution), and the broader fintech market (which read the move as either ''Stripe is in trouble'' or ''Stripe is honest''). The transparent framing optimized for employee trust and long-term market positioning over short-term private-market optics.","alt":"A flat $95B round with structured preferences would have preserved the headline number and quietly transferred economic value to GIC/Temasek via liquidation preferences. The opposite trade. It would have produced cleaner press in 2023 and a much messier IPO conversation in 2025-2026 when the structured terms unwound.","predict":"Short-term: ''Stripe valuation cut 47%'' headlines, employee equity housekeeping. Medium-term: fintech multiples recover, Stripe''s revenue compounds, valuations rebound. Long-term: the decision becomes the canonical case in ''when to take the public valuation hit cleanly rather than structure around it'' — particularly for private companies whose underlying business is strong but who got caught at peak multiples."},"quote_type":"paraphrased","sources":[{"title":"Stripe announces new round of funding and plan to provide employee liquidity","url":"https://stripe.com/newsroom/news/stripe-series-i-employee-liquidity","publisher":"Stripe Newsroom","year":2023,"type":"press-release"},{"title":"Payments giant Stripe raises $6.5 billion at a $50 billion valuation","url":"https://www.axios.com/2023/03/15/stripe-50-billion","publisher":"Axios","year":2023,"type":"article"},{"title":"Stripe: Navigating a Tender Offer in 2023","url":"https://www.harness.co/articles/stripe-ipo-tender-offer-what-to-know-for-2023/","publisher":"Harness Wealth","year":2023,"type":"article"}],"tags":{"industry":"fintech","region":"us","decade":"2020s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'spotify-direct-listing-2018',
  'weekly',
  '{"id":"spotify-direct-listing-2018","type":"weekly","iso_week":"","company":"Spotify","era":"Early 2018 — April 3, 2018 NYSE direct listing","intro":"It is early 2018. You are a senior strategy leader at Spotify. The company has been talking about going public for a year. Spotify has ~71M paid subscribers, ~$5B revenue, and is unprofitable but growing rapidly. The standard path to public is a traditional IPO: hire Morgan Stanley/Goldman, set an IPO price slightly below true demand (manufactures a day-one ''pop'' for institutional allocators), pay ~7% in underwriting fees, lock up insiders for 180 days.\n\nDaniel Ek and CFO Barry McCarthy are debating an unprecedented alternative: a direct listing. No underwriters as bookrunners. No primary capital raised (Spotify doesn''t need any — it has ~$1.6B cash). No roadshow setting prices. Existing shareholders sell directly to the public, with the NYSE setting only a reference price based on private-market trades. No company has ever done this at scale on a major US exchange.","open_questions":["Direct listing or traditional IPO — does saving ~$200M in fees outweigh giving up the IPO ''price discovery'' machine that institutional investors expect?","Without a roadshow and without an IPO price, what''s the downside if the reference price prints poorly and Spotify''s stock opens 30% below where private markets had it?","How public to be about the direct-listing strategy — pitch it as innovation, or as Spotify being too unique to need a roadshow?","What does this signal to the rest of the late-stage private market — Slack, Airbnb, Coinbase, Roblox are watching closely?"],"closing":"Imagine you''re in the Spotify strategy room in early March 2018. The NYSE has agreed to the direct listing. Bankers are advising you against it. The S-1 is on file.","decision":"Direct list on NYSE on April 3, 2018 under ticker ''SPOT.'' Reference price set at $132 by NYSE based on private-market trades. The stock opens at $165.90 — a ~26% premium to reference — and closes the day around $149. Daniel Ek refuses to ring the NYSE opening bell, deliberately framing the listing as ''business as usual.'' Spotify saves an estimated $200M+ in underwriting fees. The direct-listing precedent opens the door for Slack (June 2019), Palantir (Sep 2020), Asana (Sep 2020), Roblox (Mar 2021), Coinbase (Apr 2021), and others to follow.","pullquote":"Spotify is not raising capital, and our shareholders and employees have been free to buy and sell our stock for years. So while tomorrow puts us on a bigger stage, it doesn''t change who we are, what we are about, or how we operate.","pullquote_attribution":"Daniel Ek, Spotify cofounder/CEO — letter to shareholders, April 2, 2018","outcomes":[{"stat":"$132 → $165.90","label":"reference price → first trade — market-set, not bank-set"},{"stat":"$0","label":"new capital raised — direct listing only enables existing-shareholder selling","accent":true},{"stat":"~$200M+","label":"underwriting fees avoided vs. a comparable IPO"},{"stat":"1st","label":"major US-exchange direct listing at scale (~$30B market cap day-one)"},{"stat":"Precedent","label":"opened the door for Slack, Palantir, Asana, Roblox, Coinbase to follow"}],"tradeoffs":[{"title":"Direct listing vs. traditional IPO","body":"Direct listing saved ~$200M in fees and avoided the IPO ''pop'' subsidy (which transfers value from existing shareholders to institutional allocators). The cost: no anchor institutional investor base, more day-one volatility, and Spotify had to evangelize the listing structure to public-market investors who weren''t used to it."},{"title":"No roadshow vs. abbreviated investor ''investor day''","body":"Spotify replaced the roadshow with a public ''Investor Day'' that was livestreamed. Anyone could watch — institutions and retail alike. The cost: institutions felt less ''serviced'' and less special. The benefit: the brand statement (''we''re transparent and equal-access'') reinforced Spotify''s broader user-direct identity."},{"title":"No primary capital vs. raising new capital","body":"Spotify could have done a traditional IPO and raised ~$1B+ in new capital. They didn''t need it — and chose existing-shareholder liquidity over additional cash. That signal (''we don''t need your money'') was itself a brand asset; it told the market this is a company with discipline, not one that needs the public to fund growth."},{"title":"Ek''s anti-spectacle vs. ringing the bell","body":"Ek deliberately refused the traditional NYSE bell-ringing ceremony — ''business as usual.'' Most CEOs view the bell as a brand moment. Ek treated the listing as a logistical step, not a celebration. The framing reinforced the ''we don''t need IPO theater'' positioning the entire listing was built around."}],"per_dimension_truth":{"tradeoff":"Fee savings + precedent-setting + brand consistency vs. anchor-institution stability + IPO-day spectacle. Spotify had the financial position (cash-rich, profitable cash flow on subs) to make the trade. Most pre-IPO companies don''t and shouldn''t try to copy the path.","user":"The audience Spotify served with the direct listing was its existing employees, pre-IPO investors, and the broader investing public — explicitly not the institutional-allocator class that traditional IPOs subsidize. The listing''s signaling was as much about Spotify''s identity as about cap-table mechanics.","alt":"A traditional IPO at the same valuation would have raised ~$1B in new capital, given institutional anchor holders, and produced cleaner day-one trading. Spotify rejected it because they didn''t need the capital and the long-term brand cost of paying the underwriting subsidy outweighed the stability premium.","predict":"Successful day-one print, some early volatility (no anchor base), and a stock that trades within normal SaaS-comp bands within months. Long-term: the listing becomes the template for cash-rich private companies that don''t need primary capital. By 2026, direct listings have become a credible alternative path for the right profile of company — directly because Spotify proved it could work at scale."},"quote_type":"verbatim","sources":[{"title":"Spotify (SPOT): Stock starts trading on the NYSE in non-IPO","url":"https://www.cnbc.com/2018/04/03/spotify-spot-ipo-stock-starts-trading-on-the-nyse.html","publisher":"CNBC","year":2018,"type":"article"},{"title":"Spotify''s reference price is set at $132 by the New York Stock Exchange","url":"https://www.cnbc.com/2018/04/02/spotifys-reference-price-is-set-at-132-by-the-new-york-stock-exchange.html","publisher":"CNBC","year":2018,"type":"article"},{"title":"Spotify''s IPO cut out insider investors by pioneering the direct listing","url":"https://www.npr.org/transcripts/1118869773?ft=nprml&amp%3Bf=1118869773","publisher":"NPR","type":"article"}],"tags":{"industry":"media","region":"eu","decade":"2010s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'microsoft-buys-skype-2011',
  'weekly',
  '{"id":"microsoft-buys-skype-2011","type":"weekly","iso_week":"","company":"Microsoft","era":"May 2011","intro":"It is early 2011. You are a senior corp-dev / strategy executive at Microsoft. The company has spent the last 5 years missing every consumer-internet wave — search (lost to Google), mobile (no real iPhone competitor), social (lost to Facebook). Steve Ballmer is CEO. Microsoft has dominant productivity software (Office, Windows) but no consumer-communication beachhead. The internal alternative — Microsoft Lync — is enterprise IM and is not a consumer product.\n\nSkype is the dominant consumer VOIP / video-chat brand globally (~170M monthly users). It''s been bought once already (eBay in 2005 for $2.5B, then sold back to Silver Lake in 2009 at ~$2.75B). Now Silver Lake and KKR are looking to exit. Cisco, Google, and Facebook are all rumored bidders. The asking price is ~$8.5B in cash — roughly 3x what Silver Lake paid 18 months earlier, and Microsoft''s largest acquisition in history at the time.","open_questions":["Pay $8.5B for Skype, or build Microsoft''s own consumer-VOIP product on top of Lync?","If buy — at what valuation is too rich? $8.5B is 3x Silver Lake''s recent purchase price.","Preserve Skype as an independent product (preserve brand and audience), or integrate deeply into Microsoft (faster synergies, less customer trust)?","How will the rest of Microsoft react to a consumer-product acquisition this large — internal teams (Lync, Windows Live) feel displaced; partners (Verizon, telco partnerships) may be threatened?"],"closing":"Imagine you''re in Microsoft''s corp-dev room in early May 2011. The negotiation is at the closing stage. Ballmer is publicly excited.","decision":"Acquire Skype for $8.5B all-cash on May 10, 2011 — Microsoft''s largest acquisition at the time. Tony Bates (Skype CEO) becomes president of the new Microsoft Skype Division, reporting directly to Ballmer. The Skype brand is preserved initially but absorbed deeply over time: Skype is integrated into Windows, Office, and Xbox over the next 4 years. Microsoft Lync is rebranded ''Skype for Business'' in 2015. By 2017, Microsoft Teams (a separate product) effectively replaces Skype for Business inside the enterprise. By 2024, Skype''s brand is fading and Microsoft announces Skype consumer will be retired entirely in 2025 — replaced by Teams.","pullquote":"Skype is a phenomenal service that is loved by millions of people around the world. Together we will create the future of real-time communications so people can easily stay connected to family, friends, clients and colleagues anywhere in the world.","pullquote_attribution":"Steve Ballmer, Microsoft CEO — acquisition announcement, May 10, 2011","outcomes":[{"stat":"$8.5B","label":"all-cash deal — Microsoft''s largest ever at the time","accent":true},{"stat":"3x","label":"the price Silver Lake paid 18 months earlier"},{"stat":"~170M","label":"Skype MAU at acquisition"},{"stat":"2025","label":"Microsoft announces Skype consumer retirement, replaced by Teams"},{"stat":"Teams","label":"absorbed Skype for Business in enterprise (rebrand 2017, full retirement by 2021)"}],"tradeoffs":[{"title":"Buy Skype vs. build with Lync","body":"Lync was an enterprise IM tool, not a consumer brand. Building a consumer-grade VOIP/video product from Lync would have taken 3-5 years and required winning a consumer-brand fight against Skype itself. Buying compressed the timeline to one transaction — and bought the brand most consumers already trusted for voice/video."},{"title":"Premium price vs. build cost","body":"$8.5B was a steep premium against a company Silver Lake bought 18 months earlier for $2.75B. Most observers (including Wall Street) called it overpaying. Ballmer''s argument was that the consumer-communication beachhead was strategically priceless and Microsoft had no internal alternative — the asking price was the price of entering a market Microsoft had no other way into."},{"title":"Preserve Skype identity vs. absorb into Microsoft stack","body":"Preserving the Skype brand and keeping Tony Bates as president was an attempt to retain the consumer audience. Over the next several years, however, Skype was progressively absorbed into Office, Windows, and Xbox — and the consumer brand decayed. The absorption strategy may have killed the asset they bought."},{"title":"Skype for Business pivot vs. consumer-first","body":"Microsoft''s most successful use of Skype was rebranding Lync as ''Skype for Business'' in 2015 — but then they killed that product four years later when Teams won the enterprise. The journey from $8.5B consumer acquisition to enterprise rebrand to retirement is the canonical case of an incumbent buying a consumer brand, failing to defend it, and eventually replacing it with a tool that didn''t need the original IP."}],"per_dimension_truth":{"tradeoff":"Speed of entering consumer communication vs. premium price + brand-preservation difficulty inside Microsoft''s product DNA. Microsoft chose speed and paid the premium. With hindsight, the acquired audience was not durably retained — the brand and product slowly decayed, and Teams (a separate internal product) became Microsoft''s actual win in communications a decade later.","user":"The ''user'' Microsoft was trying to serve was simultaneously consumers (Skype''s existing 170M MAU) and enterprise (the Lync customer base). Trying to optimize for both produced a confusing brand strategy where Skype became neither cleanly consumer nor cleanly enterprise — and was eventually replaced by Teams, a product purpose-built for one of those audiences.","alt":"Building consumer-VOIP from Lync would have taken 5+ years and likely failed against Skype itself. The opposite trade. A more conservative purchase price ($4-5B) might have produced the same audience access at less premium — but Silver Lake had a strong negotiating position and Microsoft was the eager buyer.","predict":"Short-term: market praise for entering consumer communications, brand investment in Skype. Medium-term: cultural and product friction inside Microsoft, Skype quality declines as the company can''t fund consumer-grade improvements at the pace independents could. Long-term: Skype becomes a brand the company invested in, slowly let decay, and replaced with Teams. The deal becomes a case study in ''buying consumer brands doesn''t make you a consumer company.''"},"quote_type":"verbatim","sources":[{"title":"Microsoft to Acquire Skype","url":"https://news.microsoft.com/source/2011/05/10/microsoft-to-acquire-skype-3/","publisher":"Microsoft Newsroom","year":2011,"type":"press-release"},{"title":"Microsoft''s acquisition of Skype for $8.5 billion becomes official","url":"https://www.engadget.com/2011-05-10-microsofts-acquisition-of-skype-for-8-5-billion-becomes-offici.html","publisher":"Engadget","year":2011,"type":"article"},{"title":"Ballmer And Bates Sell The Skype Deal","url":"https://techcrunch.com/2011/05/10/ballmer-bates-skype/","publisher":"TechCrunch","year":2011,"type":"article"}],"tags":{"industry":"communication","region":"us","decade":"2010s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'spotify-joe-rogan-2020',
  'weekly',
  '{"id":"spotify-joe-rogan-2020","type":"weekly","iso_week":"","company":"Spotify","era":"May 2020","intro":"It is early 2020. You are on the Spotify leadership team. The company is now ~280M MAU, ~130M paid subs, and has been pushing aggressively into podcasts (acquired Gimlet, Anchor, The Ringer in 2019). The strategic thesis: streaming-music margins are squeezed by labels (Spotify pays ~70% of music revenue back). Podcasts are higher-margin if Spotify owns the content. The biggest podcast in the world is The Joe Rogan Experience — millions of weekly listeners, distributed on every platform.\n\nLeadership debates a deal: $100M+ for an exclusive multi-year license to The Joe Rogan Experience, removing it from every other platform (YouTube, Apple Podcasts, RSS). Rogan''s content is famously unfiltered — long-form interviews including with vaccine skeptics, controversial political figures, conspiracy theorists. The brand risk for Spotify is real. Internally, music-side employees worry about being associated with Rogan''s content; podcast-side leadership argues this is the move that defines Spotify as a podcast platform, not just a music app.","open_questions":["Sign Rogan or pursue lower-controversy exclusive deals (Michelle Obama, Higher Ground, sports content)?","If sign — exclusive (removes from RSS / competitors, maximizes platform draw) or non-exclusive (less moat, less PR risk)?","How do you handle the content-moderation question — Spotify has been a ''platform'' for music; podcasts are a different content category with different responsibility expectations?","What''s the right deal size — $100M (Rogan''s reported floor) signals confidence, $50M is half but probably loses the deal?"],"closing":"Imagine you''re in Spotify''s leadership meeting in early 2020. The deal is being structured. Rogan is open. Apple is bidding too.","decision":"Sign Joe Rogan to an exclusive multi-year licensing deal — initially reported at $100M, later confirmed at $200M+ over 3.5 years. The Joe Rogan Experience moves to Spotify exclusively starting September 1, 2020. The deal triggers immediate internal pushback (music-side employees express concern about Rogan''s content), public criticism (Neil Young removes his catalog in protest in Jan 2022 over COVID misinformation), and Daniel Ek personally defending the decision multiple times. In Feb 2024, Spotify renews Rogan but the new deal is non-exclusive — JRE returns to YouTube, Apple Podcasts, and other platforms — at a reported $250M+ value.","pullquote":"I think it''s incredibly important to have a variety of voices and viewpoints on our platform, and yet that does come with great responsibility. We don''t change our policies based on one creator nor do we change them based on any media cycle, or calls from anyone else.","pullquote_attribution":"Daniel Ek, Spotify cofounder/CEO — letter to employees, January 2022 (during the Neil Young controversy)","outcomes":[{"stat":"$100M+","label":"initial deal value (later confirmed $200M+ over 3.5 years)","accent":true},{"stat":"Sep 1, 2020","label":"exclusive launch on Spotify; full migration ~3 months later"},{"stat":"Jan 2022","label":"Neil Young catalog removal; controversy peak around COVID claims"},{"stat":"Feb 2024","label":"renewal — non-exclusive, $250M+; JRE returns to YouTube + Apple Podcasts"},{"stat":"Top podcast","label":"JRE remained the #1 podcast on Spotify for the duration of the exclusive"}],"tradeoffs":[{"title":"Exclusive vs. non-exclusive licensing","body":"Exclusive maximized platform pull (you had to come to Spotify to hear Rogan) and made the deal headline-worthy. Non-exclusive would have been cheaper, less PR-risky, and less effective at driving signups. The 2024 renewal to non-exclusive was an admission that the exclusivity premium wasn''t worth the brand cost."},{"title":"Big creator deal vs. portfolio strategy","body":"$100M+ to one creator concentrates risk. The same money spread across 50 mid-tier podcasts could have built a broader content moat with less controversy concentration. Spotify chose the headline-creator approach because the brand statement (''Spotify is now where the biggest podcast lives'') was as valuable as the audience."},{"title":"Content-moderation framing — platform vs. publisher","body":"Spotify positioned itself as a ''platform'' (like YouTube) rather than a ''publisher'' (like Netflix). The distinction matters legally and brand-wise. The Neil Young moment forced Spotify to either remove episodes or defend the platform framing. Ek defended the platform framing publicly, which preserved the editorial position but cost real artist relationships."},{"title":"Brand-risk acceptance vs. employee morale","body":"Internal pushback was real. Music-side employees who had spent careers building Spotify''s identity didn''t want to be associated with Rogan''s content. Leadership chose the strategic bet over the cultural cost. Some employees left; the strategic bet partially worked (signup growth) and partially didn''t (brand controversy + the Feb 2024 non-exclusive reset)."}],"per_dimension_truth":{"tradeoff":"Platform-defining content concentration + signup-driving exclusivity vs. brand controversy + content-moderation responsibility + internal cultural friction. Spotify took the controversial bet and absorbed multi-year brand cost; the 2024 renewal to non-exclusive was a partial reset.","user":"The user Spotify served with the deal was the podcast-listening audience who wasn''t yet on Spotify — Rogan''s existing fans were the lever to convert them. The deal was a signup-acquisition mechanism, not an existing-listener satisfaction mechanism. The cohort that already used Spotify for music had to absorb the brand cost while the new cohort got the headline benefit.","alt":"A portfolio of 20 mid-tier exclusives ($5M each) would have produced a broader content moat with less concentration risk. The opposite trade — and Spotify accepted concentration because the single-headline-creator approach gave them a positioning moment portfolio-buying couldn''t match. Sometimes the brand statement is the actual asset.","predict":"Short-term: signups spike around the exclusive launch, brand controversy intensifies (Neil Young / Joni Mitchell catalog pulls, COVID-content debates). Medium-term: content-moderation policy revisions, ongoing pressure from advocacy groups, Spotify hires more trust + safety staff. Long-term: 2024 non-exclusive renewal is the reset — Spotify decides the brand cost of exclusivity exceeds the moat benefit. Long-term lesson: in content-licensing, paying for headlines comes with multi-year brand consequences the financial model often understates."},"quote_type":"verbatim","sources":[{"title":"Joe Rogan''s Joe Rogan Experience Podcast Lands Exclusive Spotify Deal","url":"https://deadline.com/2020/05/joe-rogan-experience-spotify-podcast-deal-1202939007/","publisher":"Deadline","year":2020,"type":"article"},{"title":"Joe Rogan''s Spotify Deal Renewal Worth Up to $250 Million, Podcast Will No Longer Be Exclusive","url":"https://variety.com/2024/digital/news/joe-rogan-renews-spotify-deal-not-exclusive-1235895424/","publisher":"Variety","year":2024,"type":"article"},{"title":"Spotify''s $100m+ Joe Rogan deal redefines its podcast strategy","url":"https://www.musicbusinessworldwide.com/spotifys-100m-joe-rogan-deal-redefines-its-podcast-strategy-songwriters-and-record-labels-should-be-watching-closely/","publisher":"Music Business Worldwide","type":"article"}],"tags":{"industry":"media","region":"eu","decade":"2020s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'reddit-ipo-2024',
  'weekly',
  '{"id":"reddit-ipo-2024","type":"weekly","iso_week":"","company":"Reddit","era":"March 2024","intro":"It is early 2024. You are at Reddit, preparing to take the company public on the NYSE. Reddit has ~73M daily active users, ~$800M revenue (mostly ads), and a 19-year history. The IPO has been rumored since at least 2021 (it was filed confidentially in late 2021 then withdrawn during the 2022 market downturn). Now the window is open and the macro is back. There''s one outstanding complication: the platform''s moderators (volunteers) and a meaningful chunk of power users still aren''t happy after the June 2023 API blackout, and many platforms (including Reddit''s S-1) explicitly list ''volunteer moderator dependency'' as a risk factor.\n\nAlongside the IPO mechanics, leadership is debating one more bet: offer pre-IPO shares directly to power users (top redditors, long-tenured moderators) at the IPO price. The idea is unprecedented at scale for a consumer-internet IPO. Critics inside argue it normalizes pay-to-quiet-the-mob; defenders argue it converts the moderator base from antagonists into shareholders.","open_questions":["Offer pre-IPO allocation to moderators / power users — converts antagonists to shareholders, but might be read as buying their silence?","How transparent in the S-1 about moderator dependency and content-policy risks — explicit (legal protection, but invites scrutiny) or buried (cleaner IPO narrative, more legal risk)?","Price aggressively at high end of range (~$34) and accept day-one volatility, or conservative for a cleaner first day?","How does Steve Huffman''s ~$193M compensation package land — disclosed openly invites criticism, but legally required under SEC disclosure rules?"],"closing":"Imagine you''re in the Reddit team meeting in mid-March 2024. The IPO prices in 3 days. The moderator-allocation question is still being debated.","decision":"Price the IPO at $34/share on March 20, 2024 — top of the targeted range — valuing Reddit at ~$6.4B. Offer ~1.76M pre-IPO shares to ~75,000 redditors (moderators, long-tenured power users, and the broader community via a direct-allocation program). Steve Huffman''s $193M pay package is disclosed; backlash is immediate but contained. The stock opens at $47 — a ~38% pop — and closes day one at $50.44 for a market cap of ~$9.5B. The IPO succeeds on its own terms; the moderator-allocation program is widely covered as a novel approach.","pullquote":"Reddit is a place where people come to talk to each other. Our community has built something incredibly valuable, and it''s important to us that they have the opportunity to participate in this milestone.","pullquote_attribution":"Steve Huffman, Reddit cofounder/CEO — paraphrased from the IPO roadshow commentary on the moderator-allocation program","outcomes":[{"stat":"$34 → $50.44","label":"IPO price → day-one close (~48% premium)","accent":true},{"stat":"$9.5B","label":"day-one market cap"},{"stat":"~1.76M","label":"shares allocated to redditors (mods + long-tenured users)"},{"stat":"$193M","label":"Steve Huffman compensation disclosed in S-1 — sparked backlash"},{"stat":"$60M+","label":"AI training data licensing deals (Google, OpenAI) baked into the IPO story"}],"tradeoffs":[{"title":"Moderator allocation vs. clean institutional allocation","body":"Offering pre-IPO shares to volunteer moderators was a goodwill gesture toward the cohort whose unpaid labor moderates Reddit. It was also a legal-novel move — pre-IPO allocations to unaccredited individuals required extra SEC structuring. The trade: convert antagonists to shareholders at the cost of a more complex IPO mechanic."},{"title":"S-1 transparency about moderator dependency vs. quiet framing","body":"Reddit explicitly listed ''volunteer moderator dependency'' as a risk factor in its S-1. The disclosure was legally protective but invited press coverage of the unpaid-labor question. Burying it would have been cleaner narrative but worse legal risk. Reddit chose transparency, which was the right call legally and the worse one for IPO press narrative."},{"title":"Top-of-range pricing vs. conservative IPO pricing","body":"Pricing at $34 (top of range) maximized capital raised + signaled confidence. A more conservative price ($28-30) would have produced a bigger pop but raised less and ''left money on the table.'' Reddit chose top-of-range — closer to true value, less subsidy to allocators."},{"title":"Disclose CEO compensation cleanly vs. break it into multiple packages","body":"$193M is a striking number. Reddit disclosed it cleanly in the S-1. The optics were always going to be bad. Disclosing it cleanly limited the press cycle to one explosive story instead of dragging it out across multiple disclosures. The disclosure norm is in fact required by SEC, but the framing inside the S-1 matters."}],"per_dimension_truth":{"tradeoff":"Moderator + community goodwill via pre-IPO allocation + transparent disclosure vs. cleaner institutional IPO narrative. Reddit took the more complex path and absorbed the multi-day press cycle on CEO pay + volunteer-labor questions. The IPO succeeded operationally; the brand narrative remained complicated.","user":"The audience being optimized for was simultaneously moderators (community goodwill via direct allocation), institutional investors (S-1 + IPO mechanics), and retail traders (the ''meme stock'' positioning Reddit explicitly courted given its WSB association). The triple-audience approach worked for the IPO but means every quarterly earnings cycle is also a community-management cycle.","alt":"A clean institutional IPO without moderator allocation would have been simpler, faster, and probably priced slightly higher. The opposite trade. Reddit chose to use the IPO moment to repair the moderator relationship damaged in the 2023 API blackout — a long-term brand investment paid for partly in IPO complexity.","predict":"Short-term: 38% day-one pop, $193M pay-package news cycle, moderator-allocation novel-coverage. Medium-term: AI data licensing deals materialize, ads revenue grows, ongoing moderator-relationship management. Long-term: Reddit''s IPO becomes the case study in ''public-listing a platform whose value depends on unpaid labor — how to disclose, how to allocate, how to manage the multi-audience IPO narrative.''"},"quote_type":"paraphrased","sources":[{"title":"Reddit prices IPO shares at $34","url":"https://fortune.com/2024/03/20/reddit-ipo-pricing-shares-34-tech-initial-public-offering/","publisher":"Fortune","year":2024,"type":"article"},{"title":"Reddit''s big first day, big CEO pay, and what comes next","url":"https://qz.com/reddit-ipo-stock-price-market-cap-steve-huffman-pay-1851358522","publisher":"Quartz","year":2024,"type":"article"},{"title":"Reddit CEO Steve Huffman defends his $193 million compensation","url":"https://fortune.com/2024/03/19/reddit-ceo-steve-huffman-defends-193-million-compensation-following-backlash-unpaid-moderators/","publisher":"Fortune","year":2024,"type":"article"}],"tags":{"industry":"consumer-social","region":"us","decade":"2020s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'roblox-direct-listing-2021',
  'weekly',
  '{"id":"roblox-direct-listing-2021","type":"weekly","iso_week":"","company":"Roblox","era":"Late 2020 — March 10, 2021 NYSE direct listing","intro":"It is late 2020 / early 2021. You are at Roblox preparing the company to go public. Roblox''s pandemic year has been extraordinary: revenue up 82% YoY to $924M, daily active users up to 32.6M (most of them kids 13 and under), and an entire generation of younger users has spent the lockdown year living inside the platform. The company was last private-valued at ~$4B in February 2020; in private secondary trades the implied valuation is now ~$30B+.\n\nThe IPO has been filed for late 2020. After ChatGPT-precursor IPOs (DoorDash, Airbnb in Dec 2020) priced way above range and popped on day one — handing billions of dollars to institutional allocators rather than the companies — David Baszucki and the Roblox board pull the IPO. They switch to a direct listing.","open_questions":["Direct listing or proceed with the traditional IPO that''s already filed?","If direct listing — how is the reference price set, and what do you do if the day-one print is much higher than the reference (Spotify, Slack precedent suggests significant gap)?","How do you handle the ''kids platform'' content + moderation narrative in IPO disclosures — the audience is mostly minors, the trust + safety obligations are unusual?","What''s the right communication strategy to public-market investors who may be unfamiliar with the direct-listing structure and how Roblox actually makes money (Robux microtransactions, not subscriptions or ads)?"],"closing":"Imagine you''re with Baszucki in February 2021. The traditional IPO has been pulled. The direct listing is set for March 10. The reference price is being negotiated with NYSE.","decision":"Pull the traditional IPO in December 2020 after watching DoorDash and Airbnb pop ~100%+ on day one (transferring billions to allocators). Direct list on NYSE on March 10, 2021 under ticker ''RBLX.'' Reference price set at $45 by NYSE. Stock opens at $64.50 and closes day one at $69.47, giving Roblox a market cap of ~$45.3B (vs. $4B at the Feb 2020 private round). Baszucki''s stake worth ~$4.6B at the close. The direct listing is the fastest-ramp consumer-tech listing of 2021 at the time and a major precedent for kids-content companies entering the public markets.","pullquote":"We pulled the IPO because the rules around pricing weren''t working in our favor or in the favor of our shareholders. The direct listing gave us a more transparent way to go public — letting the market set the price.","pullquote_attribution":"David Baszucki, Roblox cofounder/CEO — paraphrased from public commentary on the listing decision","outcomes":[{"stat":"$4B → $45.3B","label":"private valuation (Feb 2020) → public day-one (Mar 2021)","accent":true},{"stat":"$45 → $69.47","label":"reference price → day-one close"},{"stat":"0","label":"underwriting fees on a direct listing"},{"stat":"70.1%","label":"Baszucki''s Class B voting power preserved through founder-control structure"},{"stat":"32.6M DAU","label":"at year-end 2020 — most users 13 and under"}],"tradeoffs":[{"title":"Direct listing vs. traditional IPO (re-decision)","body":"Switching from filed IPO to direct listing mid-process is unusual. Roblox absorbed the change-of-plan friction because the precedent (DoorDash, Airbnb 2020 day-one pops) signaled the IPO machinery was actively transferring shareholder value to allocators. Spotify (2018) and Slack (2019) had proven direct listings worked at scale; Roblox extended the precedent to consumer-gaming."},{"title":"Pandemic moment vs. wait for normalization","body":"Roblox''s revenue surge was partly pandemic-driven. Listing at a peak-pandemic valuation locked in a high reference price. Waiting would have produced more normalized financials but at the cost of the unique moment when ''every kid in the world lives in Roblox'' was front-of-mind for investors. Roblox took the moment."},{"title":"Kids-platform disclosure complexity vs. clean B2C narrative","body":"Roblox''s audience being mostly minors created unusual T&S disclosure requirements (COPPA compliance, content moderation, parental controls). The S-1 spent significant space on these risks. Cleaner B2C platforms didn''t have to spend that disclosure budget. Roblox handled it directly because hiding it would have been worse."},{"title":"Founder voting control vs. broader shareholder governance","body":"Baszucki retained 70.1% voting power through Class B share structure. That''s high even by tech-founder standards. It''s a governance trade-off: founder-control protects long-term vision (often correctly), but it makes the company effectively unaccountable to public shareholders on big decisions. Wall Street accepted it because gaming-platform companies are widely viewed as needing founder-creative-control."}],"per_dimension_truth":{"tradeoff":"Avoiding the IPO subsidy (''pop'') paid to institutional allocators vs. losing the anchor-investor stability that traditional IPOs build. Roblox had the private-market reference (extensive secondary trading at $30B+ pre-listing) to make the trade. The day-one print at $45.3B confirmed the bet.","user":"Roblox''s actual user (kids 13 and under) wasn''t the audience for the listing — institutional and retail investors were. But the user demographic shaped the disclosure (T&S risks, parental controls, monetization regulations) which shaped the IPO experience. The listing was structurally constrained by the user base in ways most B2B and adult-consumer listings aren''t.","alt":"Proceeding with the traditional IPO would have produced a similar valuation but transferred ~$2-4B of value to institutional allocators via the IPO ''pop.'' The opposite trade — and Roblox chose to keep that value for existing shareholders. Spotify, Slack, Asana, and later Coinbase made the same call.","predict":"Successful day-one print well above reference. Continued growth in the immediate post-pandemic period, then a normalization period in 2022-2023 as kids'' lockdown habits relaxed. Stock declines significantly from peak (~80% drawdown in 2022) but stabilizes. Long-term: Roblox is the canonical gaming-platform IPO, and the listing extends the direct-listing precedent into consumer-gaming and kids-platforms — a meaningful precedent for any later listing in those categories."},"quote_type":"paraphrased","sources":[{"title":"Roblox goes public and the gaming platform is instantly worth more than $45 billion","url":"https://www.cnn.com/2021/03/10/investing/roblox-stock-direct-listing","publisher":"CNN","year":2021,"type":"article"},{"title":"Roblox valued at $45.3B in record-setting direct listing","url":"https://pitchbook.com/news/articles/roblox-gaming-direct-listing-valuation","publisher":"PitchBook","year":2021,"type":"article"},{"title":"Roblox Corporation — Wikipedia","url":"https://en.wikipedia.org/wiki/Roblox_Corporation","type":"article"}],"tags":{"industry":"gaming","region":"us","decade":"2020s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'netflix-password-sharing-2023',
  'weekly',
  '{"id":"netflix-password-sharing-2023","type":"weekly","iso_week":"","company":"Netflix","era":"Early 2023 — May 23, 2023 US rollout","intro":"It is early 2023. You are a senior PM at Netflix. The company has ~230M paid subscribers. Roughly 100M households globally are believed to be using shared passwords — accounts where someone outside the paying household is consuming the service. For a decade Netflix has tolerated this; Reed Hastings publicly called password sharing ''a positive thing'' in 2016. But subscriber growth has flatlined, the company missed Q1 2022 estimates (the first quarterly subscriber loss in over a decade), and Wall Street is no longer giving Netflix the growth multiple it used to.\n\nNetflix''s leadership is debating a paid-sharing rollout. Under the new rules: an account is allowed only within a ''household'' (defined by IP/devices). Users outside that household must be added as ''extra members'' at $7.99/month — about half a regular subscription. The change would be globally controversial; early tests in Latin America in 2022 produced viral ''how to game the system'' threads and significant user backlash. Internal modeling suggests ~10% of password-sharers will pay; the rest will leave or trade down. Net effect uncertain.","open_questions":["Roll out paid sharing globally now (signal aggressive monetization) or wait for the ad-supported tier to fully ramp (lower-risk path to the same revenue)?","How to define ''household'' — IP address (technically blunt, false positives), explicit user invitation (less enforceable), or hybrid?","Price the extra-member tier — $4.99 (low friction, lower revenue), $7.99 (margins), or higher (signal premium)?","How to handle the inevitable PR cycle and ''Netflix is greedy'' narrative?"],"closing":"Imagine you''re in the Netflix leadership room in March 2023. The Latin America test data is in (mixed). The US rollout is set for May. The communications plan is being finalized.","decision":"Roll out paid sharing in the US, UK, Australia, and 100+ other countries on May 23, 2023. Define household as devices that share an IP regularly. Charge $7.99/mo for extra members outside the household. Communicate via in-app prompts + a public ''how it works'' page rather than splashy press. Absorb the PR cycle. Subscriber count surges — Netflix adds 9.33M net new subscribers in Q3 2023 alone (largest quarter since the pandemic). The ''crackdown'' becomes one of the most successful re-pricings in subscription-software history.","pullquote":"A Netflix account is for use by one household. Everyone living in that household can use Netflix wherever they are.","pullquote_attribution":"Netflix — public ''how it works'' page on the password-sharing policy, May 23, 2023","outcomes":[{"stat":"9.33M","label":"net new subscribers in Q3 2023 — largest quarter since the pandemic","accent":true},{"stat":"100M","label":"households estimated to be sharing passwords pre-rollout"},{"stat":"$7.99","label":"extra-member price (~half a regular subscription)"},{"stat":"Latin Am.","label":"earlier 2022 test showed mixed signal — Netflix shipped globally anyway"},{"stat":"Net positive","label":"majority of password-sharers chose to start their own account, not cancel"}],"tradeoffs":[{"title":"Ship now vs. wait for the ad tier","body":"Netflix could have ramped its ad tier first, then layered paid sharing on top. Shipping both in parallel was higher-risk but maximized the revenue-uplift window. The bet: don''t let competitors (Disney+, Max) preempt the move; absorb both PR cycles at once."},{"title":"IP-based ''household'' vs. explicit user invitation","body":"IP-based detection is technically blunt (frequent travelers, students, families with multiple homes all trigger false positives). Explicit invitation would have been cleaner UX but unenforceable. Netflix chose the blunt-but-enforceable option and ate the false-positive PR (people on Twitter sharing ''I can''t watch at my hotel'') because the revenue math required it."},{"title":"Splashy press vs. in-app only","body":"Netflix could have done a major press launch with executive interviews. Instead the rollout was almost entirely in-app prompts — most users learned about it when they got the prompt. That choice avoided amplifying the PR cycle and let the policy become normal background noise inside weeks rather than a months-long news story."},{"title":"Trust the model vs. trust the test","body":"The Latin America test in 2022 produced mixed signals — significant cancellations alongside revenue uplift. Internal modeling predicted the US/UK/AU markets would behave differently (less sensitivity to price, more ''will pay if forced''). Netflix bet on the model over the more pessimistic interpretation of the test data — and won the bet."}],"per_dimension_truth":{"tradeoff":"Short-term PR pain + customer-trust damage vs. converting ~10% of the ~100M password-sharing households into paying customers. Netflix took the bet and got the revenue uplift; the brand cost was real (Netflix is often used as the canonical ''tech company gets greedy'' example) but absorbed inside ~6 months.","user":"The audience Netflix optimized for was the heavy-engagement password-sharer who would convert rather than cancel. The crackdown was structurally hostile to the secondary user (the friend / family member who''d been getting free Netflix) but mostly preserved the primary subscriber''s value proposition.","alt":"Continuing to tolerate password sharing would have preserved customer goodwill but conceded a structural ~$2-3B/year revenue opportunity. The opposite trade — and the public-markets pressure on subscriber growth made the opposite trade increasingly untenable. Netflix had been ''tolerating'' for a decade; the moment had come.","predict":"Short-term: viral ''Netflix is greedy'' news cycle, cancellations spike briefly, the trust-and-safety / customer-support cost surges. Medium-term: most password-sharers convert to extra-member or their own account; subscriber growth re-accelerates dramatically. Long-term: the move becomes the template for other streaming services (Disney+ rolls out a similar policy in 2024) and the canonical case in ''when to monetize a tolerated leak.'' The bet''s success makes it easier for subsequent platforms to do the same."},"quote_type":"paraphrased","sources":[{"title":"Netflix password-sharing crackdown rolls out in the U.S.","url":"https://www.cnbc.com/2023/05/23/netflix-password-sharing-crackdown.html","publisher":"CNBC","year":2023,"type":"article"},{"title":"Netflix has officially begun its plan to make users pay extra for password sharing","url":"https://www.npr.org/2023/05/24/1177848004/netflix-password-sharing","publisher":"NPR","year":2023,"type":"article"},{"title":"Netflix''s Password Sharing Crackdown Drives 9.33 Million New Subscribers","url":"https://nerdist.com/article/netflix-stopping-password-sharing-with-price-increases/","publisher":"Nerdist","year":2023,"type":"article"}],"tags":{"industry":"media","region":"us","decade":"2020s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'apple-headphone-jack-2016',
  'weekly',
  '{"id":"apple-headphone-jack-2016","type":"weekly","iso_week":"","company":"Apple","era":"September 7, 2016 — iPhone 7 launch","intro":"It is mid-2016. You are a senior PM at Apple. The iPhone 7 is shipping in September. Internal debates have been raging for over a year on a single hardware question: keep the 3.5mm headphone jack, or remove it. The jack has been a standard since the 1960s. Every pair of consumer headphones on earth uses it. Apple''s own EarPods that ship with every iPhone connect through it. Removing it forces users to either (a) use Lightning-connected headphones (none on the market in volume), (b) use a Lightning-to-3.5mm dongle (annoying), or (c) buy wireless headphones (Apple is launching AirPods alongside the iPhone 7).\n\nThe internal champions argue removing the jack frees ~1mm of internal space (battery, taptic engine, water resistance) and accelerates the wireless-audio transition Apple is positioned to win with AirPods + W1 chip. The internal skeptics argue this is the most pro-customer-cost decision in Apple history — and that ''we''re forcing them to buy AirPods'' is a brand risk.","open_questions":["Remove the jack now (iPhone 7) or wait one cycle (iPhone 7s/8) for wireless headphones to mature?","How aggressive to be in marketing — call it ''courage'' (Phil Schiller''s framing) and own the controversy, or quietly downplay?","Pricing for AirPods — at $159, they''re expensive enough to feel like a real purchase but cheap enough that someone replacing $40 EarPods will consider them. Is that right?","Include the Lightning dongle in the box (eats margin, defuses critics) or sell separately (signals ''this is the new normal'')?"],"closing":"Imagine you''re at Apple in mid-2016. The iPhone 7 is two months out. The decision has been made internally; the September keynote is the public reveal.","decision":"Remove the 3.5mm headphone jack on iPhone 7. Include a Lightning-to-3.5mm adapter in the box. Launch AirPods alongside ($159, shipping in October). Phil Schiller frames the decision on stage as requiring ''courage.'' The Internet erupts — #courage trends as mockery; tech press splits between ''bold'' and ''cynical.'' Within 3 years AirPods become a ~$10B/year product line. Within 5 years almost every Android flagship has also removed the jack. Within 8 years Apple itself walks the philosophy back partially (USB-C ports return to iPhones, Mac mini/etc) — but the AirPods bet pays off massively.","pullquote":"It comes down to one word: courage. The courage to move on and do something new that betters all of us.","pullquote_attribution":"Phil Schiller, Apple SVP Worldwide Marketing — iPhone 7 launch keynote, September 7, 2016","outcomes":[{"stat":"$159","label":"AirPods launch price; ~$10B/year revenue line within 3 years","accent":true},{"stat":"#courage","label":"trended as mockery within hours of the keynote"},{"stat":"~1mm","label":"internal space freed by removing the jack (taptic engine, battery, water seal)"},{"stat":"5 years","label":"for Android flagships to follow Apple''s lead"},{"stat":"Walked back","label":"USB-C / button restoration on later devices — partial reversal"}],"tradeoffs":[{"title":"Remove now vs. wait one cycle","body":"Waiting one cycle (iPhone 8) would have shipped wireless-headphone maturity alongside the removal — less customer friction. But it would have given Samsung, LG, and HTC a year-long marketing window of ''we still have the jack, Apple doesn''t yet.'' Apple chose to absorb the customer-friction cost in exchange for forcing the entire industry to follow."},{"title":"Courage framing vs. quiet removal","body":"Schiller''s ''courage'' framing was widely mocked. A quieter ''we''re transitioning to wireless audio, here''s how'' would have absorbed less mockery. The ''courage'' framing was deliberate — it conceded that the move would be painful, named the trade-off out loud, and made the launch a values statement (we lead, others follow). The brand cost of the mockery was real; the brand benefit of the values statement was longer-tail."},{"title":"Bundle dongle vs. sell separately","body":"Including the Lightning-to-3.5mm adapter in the box ate margin and undermined the ''this is the new normal'' message. Selling separately would have been a clean stance but maximally hostile to existing customers. Apple chose the customer-friendly compromise; the dongle was eventually removed from later iPhone boxes once wireless had won."},{"title":"AirPods bundling vs. accessory pricing","body":"Bundling AirPods with iPhone 7 would have eliminated the friction entirely but cost Apple ~$200B in subsequent AirPods sales (assuming attach rate gets to 50%+). Selling them separately at $159 was the right call commercially — and made AirPods feel like a real purchase rather than a giveaway, which arguably helped them become a status symbol."}],"per_dimension_truth":{"tradeoff":"Customer friction + mockery cycle vs. ~1mm of internal space + AirPods as the wireless-audio standard + a multi-year force-the-industry move. Apple took the friction and the mockery, and the AirPods bet alone validated the decision financially. The ''courage'' framing was simultaneously the funniest moment of the keynote and the most strategically honest.","user":"The iPhone 7 buyer was the audience for the bundled dongle (friction softener); the AirPods buyer was the audience the bet was actually for (early-adopter willing to pay $159 to feel ahead). The mass-market customer was acceptable collateral damage in the first year; by year three, every iPhone buyer was choosing AirPods naturally.","alt":"Keeping the jack on iPhone 7 and shipping wireless earbuds as a separate product would have been customer-friendly but would have lost the ''force the industry'' moment. The opposite trade — and probably AirPods would still have happened, but with less category-defining momentum. Apple chose the harder, costlier, longer path because the strategic benefit was multi-year.","predict":"Short-term: mockery, dongle jokes, customer complaints, late-night TV bits. Medium-term: AirPods become a cultural phenomenon, the industry follows, the controversy fades. Long-term: the headphone-jack removal becomes the textbook case in ''when forcing a transition through customer friction is worth it (and when the ''courage'' framing is actually correct).'' The partial walk-back on USB-C is a separate, later concession to ecosystem demands."},"quote_type":"verbatim","sources":[{"title":"Why Did Apple Remove the Headphone Jack? ''Courage''","url":"https://www.theringer.com/2016/09/07/tech/why-did-apple-remove-the-headphone-jack-courage-592a412412b5","publisher":"The Ringer","year":2016,"type":"article"},{"title":"Apple''s Phil Schiller says removing iPhone 7 headphone jack comes down to one word: ''courage''","url":"https://www.fastcompany.com/4018651/apples-phil-schiller-removing-iphone-7-headphone-jack-comes-down-to-one-word-courage","publisher":"Fast Company","year":2016,"type":"article"},{"title":"Apple iPhone 7: No more headphone jack","url":"https://money.cnn.com/2016/09/07/technology/apple-iphone-headphone-jack/","publisher":"CNN Money","year":2016,"type":"article"}],"tags":{"industry":"consumer-mobile","region":"us","decade":"2010s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'iphone-x-home-button-2017',
  'weekly',
  '{"id":"iphone-x-home-button-2017","type":"weekly","iso_week":"","company":"Apple","era":"September 12, 2017 — iPhone X reveal","intro":"It is mid-2017. You are a senior PM at Apple working on the iPhone X. The home button has been on every iPhone since 2007 — single most-used UI element on the most successful consumer product in history. Users press it to wake the phone, unlock it (Touch ID), return home, multitask, summon Siri, take screenshots. Removing it for a phone with edge-to-edge OLED display means rewriting every single one of those interactions: a new swipe-up-from-bottom gesture for home, a swipe-and-pause for multitasking, side-button-and-volume for screenshots, Face ID for biometric unlock.\n\nThe debate inside Apple is over how aggressively to push the gesture-based future. The conservative path keeps the home button on the iPhone 8 (also shipping fall 2017) for users who prefer it; the aggressive path makes the iPhone X gesture-only and stops shipping home-button iPhones within a few years. Jony Ive''s design team is championing the aggressive path. Apple''s accessibility team raises real concerns about users with motor disabilities who relied on the home button as a single physical anchor point.","open_questions":["Remove the home button on the iPhone X — but keep it on the iPhone 8 (parallel SKU) or commit fully?","Face ID vs. under-display Touch ID — which biometric replaces the home button''s authentication role, and what happens to the users (motor-disabled, masked-wearing) for whom Face ID is worse?","How aggressive on the new gestures — swipes for home, multitasking, control center — or maintain some legacy interactions?","What''s the right price for the iPhone X — $999 (signals ''premium, optional'' alongside the cheaper iPhone 8) or lower (signals ''this is the future, everyone gets it'')?"],"closing":"Imagine you''re at Apple in summer 2017. The iPhone X is months from reveal. The home button has been the company''s most-used UI element for a decade.","decision":"Remove the home button on the iPhone X. Ship Face ID (no Touch ID). Introduce 6+ new gestures: swipe-up for home, swipe-up-and-hold for multitasking, swipe-down-from-right-corner for Control Center, etc. Keep the iPhone 8/8 Plus shipping in parallel as a home-button option for one more cycle (then phase out by iPhone XS in 2018). Price iPhone X at $999. Wall Street and tech reviewers split (love the design, worried about Face ID); customer adoption ramps fast. By 2020, every iPhone except SE has removed the home button — Touch ID lives on only in Mac/iPad lineups.","pullquote":"I actually think the path of holding onto features that have been effective, the path of holding onto those whatever the cost, is a path that leads to failure.","pullquote_attribution":"Jony Ive, Apple Chief Design Officer — TIME interview, November 2017","outcomes":[{"stat":"$999","label":"iPhone X launch price — first $1,000 iPhone","accent":true},{"stat":"6+","label":"new gestures introduced to replace home-button actions"},{"stat":"Face ID","label":"replaces Touch ID; no fingerprint sensor on iPhone X"},{"stat":"2018","label":"iPhone 8 (home-button) phased out one year later by iPhone XS"},{"stat":"Industry copied","label":"edge-to-edge + gesture nav across Android within 18 months"}],"tradeoffs":[{"title":"Remove the home button vs. preserve it","body":"The home button was the iPhone''s most-used UI element for 10 years. Removing it required teaching every iPhone user a new motor pattern. Ive''s argument was that keeping it would have meant capping the display at sub-edge-to-edge for years. The cost was real (user retraining, accessibility concerns); the benefit was a phone-as-glass-rectangle form factor that defined a decade of smartphone design."},{"title":"Face ID vs. under-display Touch ID","body":"Under-display fingerprint sensors weren''t quite mature in 2017 (Samsung shipped them later with mixed success). Face ID was a bet on a different biometric entirely — convenient when it worked, frustrating when it didn''t (masks, sunglasses, dim light). The bet: most authentications happen face-up in daylight, and the convenience there outweighed the edge-case friction."},{"title":"$999 premium vs. mass-market price","body":"Pricing iPhone X at $999 made it a premium option alongside the cheaper iPhone 8 — letting Apple test the gesture-first design with early adopters before mass rollout. A lower price would have forced mass adoption but at the cost of margin and brand-premium signal. Apple chose the dual-SKU year to absorb the transition risk."},{"title":"Aggressive gesture set vs. preserve some legacy","body":"Apple introduced 6+ new gestures simultaneously. A more conservative redesign would have replaced fewer interactions, easing user retraining. The aggressive path made the iPhone X feel like a new product, which justified the $999 price and the design language for the next decade of iPhones."}],"per_dimension_truth":{"tradeoff":"User retraining cost + accessibility regression + Face ID''s edge-case friction vs. an edge-to-edge form factor that defined the smartphone for a decade. Apple absorbed the customer-retraining cost and won the long-term design language; the home-button removal is now the canonical phone form factor.","user":"The early-adopter willing to pay $999 was the audience for iPhone X year one. The mass-market user got the home-button iPhone 8 in parallel and migrated naturally to the gesture-based iPhone over the following 2-3 years. Apple bought transition time by running the two SKUs in parallel.","alt":"Keeping the home button on iPhone X (with a notched edge-to-edge display) was the conservative path — easier user transition but a less coherent design statement. The opposite trade — and likely would have meant Apple stayed in a hybrid home-button-plus-gesture world for another 4-5 years. Apple chose the cleaner, scarier path.","predict":"Short-term: $999 price-shock headlines, Face ID mishap demos, customer complaints about gesture retraining. Medium-term: iPhone X sells well, iPhone 8 phases out gracefully, Face ID matures. Long-term: edge-to-edge gesture-based design becomes the industry standard within 18 months. The decision is the canonical case in ''when to remove the most-used UI element in your product because the next decade of design depends on it.''"},"quote_type":"verbatim","sources":[{"title":"Apple''s Jony Ive Talks to TIME About Designing the iPhone X","url":"https://time.com/5025887/apple-jony-ive-iphone-x/","publisher":"TIME","year":2017,"type":"interview"},{"title":"Jony Ive Discusses The iPhone X And Apple''s Decision To Remove The Home Button","url":"https://www.bgr.com/tech/iphone-x-design-home-button-jony-ive-explains-new-gestures/","publisher":"BGR","year":2017,"type":"article"},{"title":"Apple designer Jony Ive defends ditching home button","url":"https://appleinsider.com/articles/17/11/16/apple-designer-jony-ive-defends-ditching-home-button-other-tech-in-interview-about-iphone-x","publisher":"AppleInsider","year":2017,"type":"article"}],"tags":{"industry":"consumer-mobile","region":"us","decade":"2010s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'slack-threads-2017',
  'weekly',
  '{"id":"slack-threads-2017","type":"weekly","iso_week":"","company":"Slack","era":"January 2017","intro":"It is late 2016. You are a senior PM at Slack. The product has been a runaway success — millions of users, fastest-growing enterprise software ever. There''s one universal complaint from power users: when a channel gets busy, conversations interleave. Someone asks a question; before anyone answers, three other discussions have buried it. Email had threading; Slack does not. Adding threading is the single most-requested feature.\n\nThe internal debate is intense. Threading is structurally hard: every threading model (Twitter-style reply trees, Reddit-style nested comments, Gmail-style flat threads) breaks something else. Power users want it. Casual users get confused by threads they can''t see. Stewart Butterfield personally wants threading done ''right'' — gentle, optional, never forcing the user to decide whether to thread or reply in-channel. The team has been iterating on the design for over a year. Some Slack-internal channels are vehemently anti-threads, arguing it would ''destroy the conversational flow that makes Slack what it is.''","open_questions":["Ship threading at all — or maintain the deliberate single-channel-stream design that defines Slack?","If ship — how prominent in the UI (default visible vs. opt-in), and what''s the threading model (nested vs. flat)?","Optional or default — does threading appear automatically for replies, or only when a user explicitly chooses ''reply in thread''?","How aggressive to be on the launch — top-of-app prominent feature, or quiet rollout with documentation only?"],"closing":"Imagine you''re with Butterfield in late 2016. The design has been iterating for over a year. The decision is now or 2018. Power users are demanding it.","decision":"Ship threaded messages on January 18, 2017 — explicitly opt-in. Replies happen in the main channel by default; threading requires hovering over a message and clicking ''reply.'' Threads appear in a right-side panel, not inline. The launch is deliberately gentle: a blog post, a short product announcement, no flashy marketing. Within 6 months, threads become the dominant pattern for any conversation longer than a few back-and-forth messages. Within 2 years, every Slack competitor (Microsoft Teams, Discord, Google Chat) has cloned the model.","pullquote":"We didn''t want threading to feel like a different mode you have to consciously choose. We wanted it to feel like a natural extension of the conversation — there when you needed it, invisible when you didn''t.","pullquote_attribution":"Stewart Butterfield, Slack cofounder/CEO — paraphrased from his Lenny''s Newsletter interview on Slack''s product principles","outcomes":[{"stat":"Jan 18, 2017","label":"threaded messages ship — most-requested feature delivered","accent":true},{"stat":"1+ yr","label":"of internal iteration before launch"},{"stat":"Opt-in only","label":"design — replies stay in-channel by default"},{"stat":"Right panel","label":"thread display — not inline (preserves channel flow)"},{"stat":"All competitors","label":"Teams, Discord, Google Chat — cloned the same model"}],"tradeoffs":[{"title":"Ship threading vs. hold the single-stream philosophy","body":"Slack''s foundational design was ''the channel is a single flowing conversation.'' Threading explicitly broke that philosophy. Holding the line would have preserved design purity but lost the power-user cohort to Microsoft Teams or to threading-native alternatives. Butterfield chose to evolve the philosophy rather than die on it."},{"title":"Opt-in vs. default threading","body":"Default-on threading would have transformed every channel into a thread-tree (Reddit-style) overnight, which would have alienated casual users. Opt-in let power users adopt and casual users ignore — a slower spread but a softer impact on existing habits. Slack chose the gentler default."},{"title":"Right-panel vs. inline display","body":"Threads in a right-side panel preserve the main channel''s vertical flow but make threads feel slightly disconnected. Inline threading would have integrated more naturally but cluttered busy channels. The right-panel choice preserved Slack''s signature scannable single-column channel view — a deliberate aesthetic-and-usability trade."},{"title":"Loud launch vs. quiet rollout","body":"A flagship-feature launch (keynotes, press) would have signaled ''Slack is now a different product.'' A quiet rollout signaled ''Slack just got slightly better at the thing you were already doing.'' Butterfield''s instinct was that threading was an evolution, not a revolution — and the quiet rollout matched that framing."}],"per_dimension_truth":{"tradeoff":"Slack''s foundational single-stream design philosophy vs. the most-requested feature from power users + competitive risk if Microsoft Teams shipped it first. Slack evolved the philosophy with maximum design care — over a year of iteration — to preserve the brand''s design-thoughtfulness signal. The launch was widely praised by power users; the casual cohort didn''t notice.","user":"The audience the feature targeted was the heavy-use power-user inside busy channels at large companies — the cohort whose retention mattered most for enterprise expansion. Casual users in small teams (where conversations don''t interleave) wouldn''t see threading much in the wild and weren''t expected to adopt it.","alt":"Default-on threading would have produced faster adoption but more user disruption. The opposite trade — and would have made Slack look more like Reddit, which Slack-the-brand explicitly didn''t want to be. Slack accepted slower adoption for cleaner aesthetic alignment.","predict":"Quick adoption among power users (within 6 months), gradual spread to casual users, no major brand disruption, and a feature pattern that competitors copy almost wholesale within 2 years. Long-term: threading becomes a standard chat-product feature; Slack''s careful approach becomes the canonical case in ''how to ship a foundational-philosophy-breaking feature without breaking the brand.''"},"quote_type":"paraphrased","sources":[{"title":"Slack founder: Mental models for building products people love ft. Stewart Butterfield","url":"https://www.lennysnewsletter.com/p/slack-founder-stewart-butterfield","publisher":"Lenny''s Newsletter","type":"podcast"},{"title":"The History Of Slack & Its Impact On Business Communication","url":"https://www.m.io/blog/history-of-slack","type":"blog"},{"title":"Stewart Butterfield — Wikipedia","url":"https://en.wikipedia.org/wiki/Stewart_Butterfield","type":"article"}],"tags":{"industry":"saas","region":"us","decade":"2010s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'instagram-reels-launch-2020',
  'weekly',
  '{"id":"instagram-reels-launch-2020","type":"weekly","iso_week":"","company":"Instagram (Meta)","era":"Mid-2020 — August 5, 2020 US launch","intro":"It is mid-2020. You are a senior PM at Instagram. TikTok has exploded — particularly with users under 25, where Instagram''s growth has slowed. The format (15-60 second vertical video with sound, algorithmic For You feed) is one Instagram doesn''t have a real answer to. Meta''s first attempt — Lasso (2018-19) — failed and was discontinued. Stories has been Instagram''s primary defense against Snapchat, but Stories aren''t an answer to TikTok''s format. Trump is publicly threatening to ban TikTok over national security concerns; the moment is open.\n\nAdam Mosseri and team have been building Reels for ~18 months — a short-form video product that can live inside the Instagram app rather than as a standalone (like Lasso was). The launch decision: ship Reels embedded deep inside Instagram (a tab inside Explore), or commit to a more prominent placement that makes Reels feel like a first-class surface alongside Feed and Stories?","open_questions":["Ship as a standalone app (clean brand, slow growth) or embed inside Instagram (faster adoption, brand confusion)?","If embedded — what placement, and what does that signal about the feature''s importance?","Time the launch to the Trump-TikTok-ban moment (opportunistic, may misfire if TikTok survives) or stay product-driven?","How explicit to be about the TikTok-clone framing — own it (Stories playbook from 2016) or position as differentiated?"],"closing":"Imagine you''re at Instagram in late July 2020. The launch is days away. The Trump TikTok threat is loud. The product is ready.","decision":"Launch Reels in the US on August 5, 2020 — embedded inside Instagram as a tab inside the Explore feed (not a standalone app, not a top-nav tab). Adam Mosseri openly acknowledges TikTok as the inspiration: ''TikTok gets all the credit for pioneering the space.'' Within 18 months, Reels is moved to its own dedicated bottom-nav tab, becomes the highest-engagement surface on Instagram, and dominates ~50%+ of time spent. By 2024, Mosseri is calling TikTok ''probably the most formidable competitor we''ve ever seen'' — and Reels has saved Meta''s ability to compete in short-form video.","pullquote":"TikTok gets all the credit for pioneering the space. This isn''t about who invented something. It''s about whether we can serve our community well in this format.","pullquote_attribution":"Adam Mosseri, Head of Instagram — interviews around Reels launch, August 2020","outcomes":[{"stat":"Aug 5, 2020","label":"Reels launches inside Instagram (US)","accent":true},{"stat":"Tab in Explore","label":"initial placement — deliberately not a top-nav surface"},{"stat":"Dedicated tab","label":"by 2022 — Reels promoted to bottom-nav after engagement grew"},{"stat":"~50%+","label":"of time spent on Instagram by 2023 happens in Reels"},{"stat":"TikTok rivalry","label":"the defining product battle for both companies through 2025"}],"tradeoffs":[{"title":"Embed inside Instagram vs. standalone app","body":"Embedding got Reels in front of Instagram''s 1B+ existing users immediately. Standalone (the Lasso 2018 model) would have produced cleaner brand and slower growth. Lasso failed; Stories'' 2016 embedded-inside-Instagram playbook had won. Instagram applied the same playbook: distribution beats brand purity."},{"title":"Acknowledge the clone vs. position as different","body":"Mosseri publicly credited TikTok — same playbook Kevin Systrom used in 2016 with Stories crediting Snap. Owning the clone defuses the ''shameless copy'' criticism. Positioning Reels as differentiated would have invited unfavorable feature comparisons and looked dishonest."},{"title":"Time-the-launch to TikTok ban threat vs. stay product-driven","body":"Launching during the Trump-TikTok-ban moment maximized news-cycle attention but tied Reels'' framing to political circumstance. Staying product-driven would have produced cleaner narrative but missed the news window. Instagram took the news window and absorbed the ''opportunistic'' framing."},{"title":"Tab in Explore vs. top-nav placement","body":"Starting in Explore was deliberate — it let Reels grow organically without forcing existing users to see a new tab on every screen. The promotion to dedicated bottom-nav tab in 2022 was earned by engagement data, not announced at launch. The staged rollout reduced launch-week brand disruption and let the algorithm find the audience before forcing visibility."}],"per_dimension_truth":{"tradeoff":"Defending Instagram''s relevance with younger users + matching the format-of-the-moment vs. the brand cost of being seen as a TikTok clone + dilution of Stories. Meta chose to embed, openly credit the inspiration, and absorb the brand cost in exchange for distribution speed. Same trade Instagram Stories made in 2016 — and it worked again.","user":"The target user was under-25, the cohort that had been drifting to TikTok. Embedding Reels inside Instagram meant that audience didn''t have to download a new app to get short-form video — reducing the friction that had previously favored TikTok.","alt":"A standalone Reels app would have produced a cleaner brand statement but almost certainly failed (Lasso proved this). The opposite trade — and the strategic loss would have been ceding short-form video to TikTok permanently. Instagram took the easier-distribution, harder-brand path because the alternative had already failed once.","predict":"Reels launches with moderate initial engagement (the audience isn''t sure why this is in Instagram). Algorithm tunes over 12-18 months; engagement compounds. Reels gets a dedicated tab and becomes the highest-engagement surface on Instagram. TikTok continues to grow but no longer owns the format unchallenged. Long-term: short-form vertical video becomes the dominant content format across all social products; the decision to ship Reels inside Instagram saves Meta''s relevance in the format."},"quote_type":"verbatim","sources":[{"title":"Instagram''s Adam Mosseri confirms ads are coming to Reels","url":"https://www.cnbc.com/2020/11/12/instagram-head-adam-mosseri-on-reels-ads-e-commerce-2020-election.html","publisher":"CNBC","year":2020,"type":"interview"},{"title":"Facebook readies global launch of its TikTok competitor","url":"https://www.nbcnews.com/tech/tech-news/facebook-readies-global-launch-its-tiktok-competitor-n1234013","publisher":"NBC News","year":2020,"type":"article"},{"title":"TikTok ''most formidable competitor'', says Instagram CEO Adam Mosseri","url":"https://www.deccanherald.com/business/tiktok-most-formidable-competitor-says-instagram-ceo-adam-mosseri-926065.html","publisher":"Deccan Herald","type":"article"}],"tags":{"industry":"consumer-social","region":"us","decade":"2020s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'apple-ipad-launch-2010',
  'weekly',
  '{"id":"apple-ipad-launch-2010","type":"weekly","iso_week":"","company":"Apple","era":"Late 2009 – January 27, 2010","intro":"It is late 2009. You are a senior product leader at Apple. The iPhone has been a runaway success for three years. The Mac is healthy. Internally, a tablet device has been in development since the early 2000s — originally as the platform the iPhone evolved from. Now Steve Jobs wants to ship it. The question is what it''s for.\n\nThree positioning options are on the table: (1) frame it as a ''big iPhone'' (consumers understand instantly, but undermines the iPad''s distinctness); (2) frame it as a ''laptop replacement'' (forces comparison to Mac, requires features iPad won''t have at launch — multitasking, real file system, mouse/trackpad); (3) frame it as a ''third device'' between iPhone and laptop, defining a new category. Internal debates also rage over feature priorities — multitasking, USB ports, camera, stylus — and over price (initial estimates floated $1,000+; the launch target is $499 starting).","open_questions":["Position the iPad as a ''new third device'' (risks the ''who needs this'' reaction) or as a ''big iPhone'' (clearer, less ambitious)?","What ships at launch — multitasking (yes/no), stylus (no per Jobs), USB ports (no), camera (no on first gen)?","Pricing — $499 (signals mass market, undercuts every competitor) or $799+ (signals premium, protects margin)?","How aggressive to be in the keynote framing — promise this changes computing, or undersell and let usage define the category?"],"closing":"Imagine you''re in Apple''s product leadership room in early January 2010, three weeks before the Yerba Buena keynote. The pricing and positioning is being finalized.","decision":"Launch the iPad on January 27, 2010 at Yerba Buena Center for the Arts. Position it explicitly as a ''third device'' — better than both a smartphone and a laptop at a specific set of tasks (browsing, reading, watching video, casual gaming). Starting price $499, no stylus, no USB ports, no camera, no multitasking (added in iOS 4.2 later that year). Steve Jobs delivers what is widely called his last great keynote. The iPad sells 300,000 units on launch day and 1M within 28 days — faster than the original iPhone. By Q3 2010 the iPad has effectively destroyed the netbook category and forced every PC OEM to scramble for a tablet response.","pullquote":"iPad is our most advanced technology in a magical and revolutionary device at an unbelievable price. iPad creates and defines an entirely new category of devices that will connect users with their apps and content in a much more intimate, intuitive and fun way than ever before.","pullquote_attribution":"Steve Jobs, Apple CEO — iPad launch press release, January 27, 2010","outcomes":[{"stat":"300,000","label":"iPads sold on launch day (April 3, 2010 retail release)","accent":true},{"stat":"1M","label":"units in 28 days — faster than the original iPhone"},{"stat":"$499","label":"starting price — undercut every netbook + competitor tablet"},{"stat":"Netbook killer","label":"destroyed the category within ~18 months"},{"stat":"0","label":"stylus, no USB, no camera, no multitasking at v1 — all deliberate omissions"}],"tradeoffs":[{"title":"''Third device'' positioning vs. ''big iPhone'' or ''laptop replacement''","body":"Calling iPad a ''third device'' between iPhone and laptop was a higher-risk framing — it asked customers to believe a new category existed. The benefit: it set the iPad up to define its own use cases (reading, casual creation, presentation) rather than be measured against the Mac on missing features. ''Big iPhone'' would have been easier but ceiling-limiting."},{"title":"Aggressive omissions vs. feature parity","body":"Shipping without multitasking, USB ports, camera, or stylus left iPad easy to dismiss as ''just a big iPhone.'' Apple absorbed those features in subsequent OS / hardware updates. The minimalist v1 was a positioning choice — it forced reviewers and customers to evaluate the iPad on what it was good at, not what it lacked."},{"title":"$499 starting price vs. $799+ premium positioning","body":"Starting at $499 (vs. typical $799-1,499 for laptops at the time) was a mass-market signal. It killed netbooks immediately and pre-empted any Android or Windows tablet attempts at premium pricing. The margin trade was real; the category-defining benefit was bigger."},{"title":"Define new category vs. ride the iPhone''s coattails","body":"Apple chose to brand iPad with its own name, OS distinctions (initially iOS-different), and use cases — not as ''iPhone, but bigger.'' The cost was higher marketing investment; the benefit was iPad becoming a distinct product line that compounded independently for over a decade."}],"per_dimension_truth":{"tradeoff":"New category creation + ambiguous initial use case vs. clean positioning as ''big iPhone'' or ''laptop alternative.'' Apple chose the harder framing, accepted v1 feature gaps, and built a $20B+/year product line. The ''magical and revolutionary'' framing in the keynote was genuinely the right level of ambition.","user":"The audience iPad served was the broad consumer doing tasks (web, video, reading, casual gaming) that didn''t need a laptop''s full capability. Pricing at $499 meant millions of people who''d never bought a Mac could be brought into Apple''s ecosystem. The iPad was a category-expansion play, not a Mac-replacement play.","alt":"Pricing at $999, including a stylus + USB ports, and framing iPad as a ''laptop alternative'' would have been a more conservative play. It would have produced a smaller initial audience, more feature-parity criticism, and a less category-defining moment. The opposite trade — and almost certainly would have produced a less successful product line.","predict":"Day-one rave reviews mixed with ''who needs this'' skepticism. Fast sales ramp. Category creation: iPad defines the tablet space; every PC OEM scrambles for a response (most fail). Multitasking, USB, camera, stylus all added in subsequent OS / hardware generations. Long-term: the iPad becomes the canonical case in ''how to launch a new category with deliberate minimalism'' — and the launch becomes Steve Jobs''s last great keynote, a cultural artifact in itself."},"quote_type":"verbatim","sources":[{"title":"Apple Launches iPad","url":"https://www.apple.com/newsroom/2010/01/27Apple-Launches-iPad/","publisher":"Apple Newsroom","year":2010,"type":"press-release"},{"title":"Today in Apple history: Steve Jobs introduces us to the iPad","url":"https://www.cultofmac.com/apple-history/first-generation-ipad-unveiled","publisher":"Cult of Mac","type":"article"},{"title":"Apple''s 2010 iPad launch was the last great Steve Jobs keynote","url":"https://www.fastcompany.com/90455879/apples-2010-ipad-launch-was-the-last-great-steve-jobs-keynote","publisher":"Fast Company","year":2020,"type":"article"}],"tags":{"industry":"consumer-mobile","region":"us","decade":"2010s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'apple-maps-launch-disaster-2012',
  'weekly',
  '{"id":"apple-maps-launch-disaster-2012","type":"weekly","iso_week":"","company":"Apple","era":"Mid-2012 – iOS 6 launch (September 19, 2012)","intro":"It is mid-2012. You are a product leader at Apple. iOS 5 ships with Google Maps as the default mapping app — a service Apple licenses. Google has been deliberately holding back features (turn-by-turn navigation, vector maps) on the iOS version to give Android an advantage. Apple has been building its own mapping product in parallel, acquiring companies (Placebase, Poly9, C3 Technologies) since 2009. The strategic case for switching defaults at iOS 6 is real: Apple''s data competitiveness, strategic independence from Google, vector-based maps with smooth 3D.\n\nThe operational case is less clear. Apple Maps'' data has gaps. Internal testing has flagged accuracy problems in geographies the team hasn''t fully validated. The launch is scheduled for September 19, 2012, with iOS 6 shipping to hundreds of millions of devices. Scott Forstall is running iOS and has championed the launch on the original timeline. Tim Cook is months into the CEO role.","open_questions":["Ship Apple Maps in iOS 6 — or delay one cycle (iOS 6.1 or iOS 7) for better data validation?","If ship — keep Google Maps available as an optional alternative (defuses the disaster scenario) or remove entirely (forces adoption + faster ecosystem buy-in)?","What''s the rollback plan if data quality issues surface at scale — how fast can Apple ship corrections, and how visible should the corrections be?","Who owns this if it goes wrong — Forstall (iOS lead) or Cook (CEO + public face of the company)?"],"closing":"Imagine you''re in the Apple product review in mid-2012. The Maps team is confident; QA is flagging concerns. iOS 6 ships in weeks.","decision":"Ship Apple Maps as the default in iOS 6 on September 19, 2012. Remove Google Maps entirely from the OS (Google later ships a standalone app). The launch produces immediate, widespread, viral failures: mislabeled landmarks, distorted roads, missing transit directions, infamous 3D-rendering bugs (the ''melting Brooklyn Bridge''), and incidents like Australian travelers stranded in a national park. Tim Cook publishes a public apology letter within ~10 days, suggests users use Bing or Google Maps via web in the interim. Scott Forstall is asked to leave Apple within weeks. Maps quality improves over years; Cook later calls the launch his ''first really big mistake'' as CEO.","pullquote":"At Apple, we strive to make world-class products that deliver the best experience possible to our customers. With the launch of our new Maps last week, we fell short on this commitment.","pullquote_attribution":"Tim Cook, Apple CEO — public apology letter on Apple.com, September 28, 2012","outcomes":[{"stat":"9 days","label":"from iOS 6 launch to Tim Cook''s public apology letter","accent":true},{"stat":"Forstall out","label":"Scott Forstall asked to leave Apple within weeks of the disaster"},{"stat":"Removed","label":"Google Maps from iOS entirely; Google later shipped a standalone iOS app"},{"stat":"Years","label":"before Apple Maps reached competitive parity with Google Maps in most markets"},{"stat":"''Biggest mistake''","label":"Cook later called it his ''first really big mistake'' as CEO"}],"tradeoffs":[{"title":"Ship for strategic independence vs. delay for quality","body":"Continuing on Google Maps was strategically intolerable (Google had ulterior motives, held back features). Delaying the in-house product was operationally sound. Apple chose strategic priority over operational caution and paid a multi-year brand cost."},{"title":"Remove Google Maps vs. keep it as fallback","body":"Keeping Google Maps installed would have defused the disaster (users could fall back instantly). Removing it forced adoption of Apple Maps and accelerated ecosystem investment — but exposed every Apple Maps failure with no escape hatch. The decision compounded the brand damage when failures hit."},{"title":"Forstall champions vs. Cook owns","body":"Forstall was the operating lead; Cook was the CEO. When the disaster hit, the brand damage was Cook''s to absorb publicly (his apology letter). The internal accountability went to Forstall — he was asked to leave. Public apology + internal accountability separated the two layers of responsibility in a way that protected the company''s brand recovery."},{"title":"Public apology + rival recommendation vs. spin","body":"Cook''s letter explicitly recommended that users use Bing, Google, or Nokia maps in the interim. Most CEOs spin failures; Cook publicly conceded the product wasn''t ready and pointed customers to competitors. The decision sacrificed short-term competitive optics for long-term brand trust — a clear, expensive, transparent reset that almost no CEO would have made."}],"per_dimension_truth":{"tradeoff":"Strategic platform independence + future-proofing the maps stack vs. ~3 years of brand damage and a Maps reputation Apple is still rebuilding. The strategic case for ownership was right; the operational case for quality was right; combining them on the same launch date was the failure.","user":"The user paying the cost was the iOS-6-installing customer who needed reliable directions immediately. The user benefiting was the long-term Apple-ecosystem customer who would eventually have a mature in-house mapping product. The two were the same person across a 5-year horizon — but the short-term pain was severe.","alt":"Delaying Apple Maps to iOS 6.1 or iOS 7 would have given the team another 6-12 months to validate data and would have protected the brand. The opposite trade. The lesson Apple took from the disaster (eventually) was that platform replacements need staged rollouts, not flag-day flips.","predict":"Catastrophic launch week (viral mockery, brand damage, real safety incidents). Cook''s public apology breaks the news cycle and resets expectations. Forstall departs. Maps quality slowly improves over years. Long-term: Apple Maps becomes a competent product by ~2019, the disaster becomes a permanent case study in ''when to ship a strategic-replacement product despite operational warnings.'' The lesson is taught at every product-leadership school."},"quote_type":"verbatim","sources":[{"title":"Tim Cook Apologizes For Apple Maps, Points To Competitive Alternatives","url":"https://techcrunch.com/2012/09/28/tim-cook-apologizes-for-apple-maps-points-to-competitive-alternatives/","publisher":"TechCrunch","year":2012,"type":"article"},{"title":"Apple Apologizes For Flawed Maps App","url":"https://deadline.com/2012/09/apple-maps-tim-cook-apology-344759/","publisher":"Deadline","year":2012,"type":"article"},{"title":"Tim Cook Calls Apple Maps Launch His ''First Really Big Mistake'' as CEO","url":"https://www.macrumors.com/2026/04/23/tim-cook-apple-maps-launch-his-really-big-mistake/","publisher":"MacRumors","year":2026,"type":"article"}],"tags":{"industry":"consumer-mobile","region":"us","decade":"2010s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'twitter-280-character-limit',
  'weekly',
  '{"id":"twitter-280-character-limit","type":"weekly","iso_week":"","company":"Twitter","era":"September–November 2017","intro":"It is mid-2017. You are a senior PM at Twitter. The 140-character limit has been Twitter''s defining product constraint since 2006 — originally borrowed from the 160-character SMS limit minus a 20-character username buffer. The constraint shaped a decade of tweet style (cryptic, terse, screenshot-of-longer-text workarounds). Internal data shows ~9% of tweets in English hit the limit; users on Asian-language Twitter (where each character carries more semantic information) hit the limit at <1%. Jack Dorsey, back as CEO, is considering doubling the limit to 280 characters for non-Asian languages.\n\nThe community pushback even before the experiment is intense. Power users and journalists argue 140 IS Twitter — the constraint is what makes the platform distinctive. Doubling it, they argue, will make Twitter feel like Facebook. The experiment starts in September 2017 with a select cohort; data shows higher engagement, fewer abandoned tweets, no apparent shift in average tweet length. Twitter must decide whether to roll out globally.","open_questions":["Double the limit (loses the iconic 140 constraint) or keep it (preserves the brand but caps a real usability problem)?","If double — roll out to all English (or non-Asian) users immediately, or stage carefully?","What about other character-limit-affected features (DMs, bios) — apply the new limit consistently or scope tightly to tweets?","How to handle the cultural and PR response — own the change confidently, or apologetically frame it as ''fixing a usability problem''?"],"closing":"Imagine you''re with Dorsey in October 2017. The 280-character test is producing positive engagement signals. The community is split. Rollout is being debated.","decision":"Roll out 280 characters to all non-Asian-language users on November 7, 2017. Frame the change as fixing a usability problem rooted in an outdated constraint (SMS limits no longer apply). Dorsey publicly defends the decision with engagement data — pointing out that the average tweet length didn''t increase materially; the change just removed the ''cramming'' problem at the high end. Iconic 140-character culture mourns publicly; product engagement gradually rises; within months ''280'' becomes invisible — just how Twitter works.","pullquote":"Trying to cram your thoughts into a tweet — we''ve all been there, and it''s a pain.","pullquote_attribution":"Twitter — official blog post announcing the 280-character rollout, November 7, 2017","outcomes":[{"stat":"140 → 280","label":"character limit doubled for non-Asian-language users","accent":true},{"stat":"9% → 1%","label":"share of tweets in English hitting the character cap"},{"stat":"No major shift","label":"in average tweet length, per Dorsey — most users still tweeted short"},{"stat":"Asian langs","label":"unchanged — Japanese, Chinese, Korean already used <1% of 140 anyway"},{"stat":"Cultural mourning","label":"from longtime users; engagement metrics positive; the change quickly faded into normal"}],"tradeoffs":[{"title":"Iconic constraint vs. usability fix","body":"140 was Twitter''s signature brand element. Doubling it risked making Twitter feel like ''Facebook with usernames.'' But the underlying constraint (SMS limits) was no longer relevant, and the 9% of English tweets hitting the cap was a real friction point. Twitter chose the usability fix over the brand purity. The brand cost was real but absorbed inside months."},{"title":"Roll out globally vs. cohort by cohort","body":"After positive test data, Twitter could have continued cohort-testing for another six months. They chose to roll out to all non-Asian-language users at once — faster decision velocity, no extended A/B period. The trade: less data per cohort, more brand commitment upfront."},{"title":"Defend with data vs. apologize for change","body":"Dorsey explicitly framed the change with engagement data (''most users didn''t actually tweet longer'') rather than apologizing for breaking tradition. The data-driven framing defused the ''you''re ruining Twitter'' criticism by reframing it as ''the change you fear didn''t happen.'' A more apologetic framing would have validated the criticism."},{"title":"Apply broadly vs. scope tight to tweets","body":"Twitter chose to apply 280 to tweets but not retroactively to DMs, bios, or other surfaces. Limiting scope let the team focus on the most-engaged surface (tweet composition) without simultaneously redesigning every other text field. Scope discipline reduced the change''s surface area and made the rollout more controllable."}],"per_dimension_truth":{"tradeoff":"Twitter''s iconic brand constraint (140) vs. a real usability friction point for the most-engaged users (the 9% hitting the cap). Twitter prioritized usability and absorbed the brand-mourning cycle. The change worked — users adapted within months and the platform''s signature features (terseness, screenshots-of-longer-text-as-tweets) remained dominant patterns.","user":"The users benefiting were the heavy English-language tweeters routinely hitting the cap and resorting to screenshot-of-text workarounds. The users objecting were the brand-purists who valued the constraint as the constraint. Twitter optimized for the heavy users — same cohort that drives most of the platform''s engagement value.","alt":"Keeping 140 forever would have preserved the brand but kept the friction in place. A more conservative bump (200 chars?) would have been a smaller leap but still broken the iconic number. Going to 280 was the cleanest ''double it and move on'' decision, which avoided the trap of a long string of small, contentious limit increases.","predict":"Initial cultural mourning + ''this is the end of Twitter'' coverage. Quick adoption among power users. Within months, 280 becomes invisible. Long-term: the change is one of the lower-friction major brand-element shifts in a major social platform''s history — a model for ''how to change an iconic constraint with data and confidence.'' Notably, every subsequent character-limit change (X''s expansion to 4,000 for premium users, etc.) inherited the precedent that 280 set."},"quote_type":"verbatim","sources":[{"title":"Twitter officially doubles the character limit to 280 for all users","url":"https://www.thedrum.com/news/twitter-officially-doubles-the-character-limit-280-all-users","publisher":"The Drum","year":2017,"type":"article"},{"title":"Jack Dorsey Wants You to Know He Was Right About 280-Character Tweets","url":"https://gizmodo.com/jack-dorsey-wants-you-to-know-he-was-right-about-280-ch-1822840657","publisher":"Gizmodo","type":"article"},{"title":"Twitter Tests a 280-Character Tweet Limit","url":"https://www.collectivemeasures.com/insights/twitter-280-character-limit-2017","publisher":"Collective Measures","year":2017,"type":"blog"}],"tags":{"industry":"consumer-social","region":"us","decade":"2010s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'apple-att-2021',
  'weekly',
  '{"id":"apple-att-2021","type":"weekly","iso_week":"","company":"Apple","era":"Mid-2020 – April 2021","intro":"It is mid-2020. You are a senior product / privacy leader at Apple. For a decade, every iOS app has had access to the IDFA — a per-device advertising identifier — by default. Apps and the ad networks they integrate with use IDFA to track users across apps and the web for ad targeting and measurement. The system is opaque: users have no idea they''re being tracked across thousands of services. Facebook (''Meta'') derives ~50%+ of its revenue from ad targeting that depends, in part, on IDFA-style identifiers.\n\nApple has been signaling for years that user privacy is its strategic differentiator vs. Google. The internal proposal: App Tracking Transparency (ATT). When you open any app that wants to track you across other apps and websites, iOS shows a modal asking ''Allow [App] to track your activity across other companies'' apps and websites?'' with two options — ''Ask App Not to Track'' and ''Allow.'' The default expected opt-in rate is ~10-25%. Facebook publicly warns this will devastate ad-dependent businesses, especially small advertisers. Apple is set to ship ATT in iOS 14, then delays it to iOS 14.5 in April 2021 after pressure.","open_questions":["Ship ATT or accept the status quo (preserves the ad-ecosystem economics, but breaks Apple''s privacy positioning)?","Default to opt-out (cleaner privacy stance) or opt-in (technically what ATT does — apps can''t even ask without first requesting the prompt)?","How aggressive to be on the prompt design — neutral framing (''Allow tracking?'') or persuasive (''Allow [App] to track your activity across other companies'' apps and websites?'')?","How to handle Facebook + ad-ecosystem retaliation — quiet rollout, or own the conflict publicly with privacy as the brand?"],"closing":"Imagine you''re at Apple in early 2021. ATT is set for iOS 14.5 in April. Facebook is taking out full-page newspaper ads warning about ATT. The launch is days away.","decision":"Ship App Tracking Transparency in iOS 14.5 on April 26, 2021. Use the persuasive prompt language (''track your activity across other companies'' apps and websites'') that makes opt-in materially less likely. Tim Cook publicly defends the launch as fundamentally about user privacy. Within a year, IDFA opt-in rates settle at ~25% in the US (vs. >50% expected by ad networks). Meta announces ATT cost the company ~$10B in 2022 revenue alone. Smaller advertisers (Shopify SMBs in particular) report large CAC increases. Apple''s privacy positioning becomes a multi-year brand moat. Meta and Google subsequently invest heavily in alternative attribution (first-party data, modeling) and AI-based ad targeting that doesn''t require cross-app identifiers.","pullquote":"If a business is built on misleading users, on data exploitation, on choices that are no choices at all, then it deserves our reform — not our applause.","pullquote_attribution":"Tim Cook, Apple CEO — speech at Computers, Privacy & Data Protection conference, January 28, 2021","outcomes":[{"stat":"~25%","label":"actual ATT opt-in rate in US — far below expected by ad networks","accent":true},{"stat":"$10B","label":"Meta''s stated 2022 revenue impact from ATT"},{"stat":"Apr 26, 2021","label":"iOS 14.5 ATT launch — delayed from iOS 14 after industry pressure"},{"stat":"Full-page ads","label":"Facebook took out NYT/WSJ ads warning against ATT pre-launch"},{"stat":"Privacy moat","label":"Apple''s brand positioning vs. Google strengthened durably"}],"tradeoffs":[{"title":"Strategic privacy stance vs. ad-ecosystem disruption","body":"ATT was structurally hostile to advertising businesses that depend on cross-app identifiers — particularly Meta, but also small advertisers running Facebook/Instagram ads. Apple chose strategic privacy positioning over preserving the ad-ecosystem detente. The cost (regulator scrutiny, antitrust complaints from Meta, public fights) was absorbed because privacy was the long-term brand moat."},{"title":"Persuasive prompt language vs. neutral","body":"The prompt explicitly mentions ''track your activity across other companies'' apps and websites'' — language designed to make opt-in feel costly. A neutral version (''Allow personalized ads?'') would have produced higher opt-in rates. Apple''s persuasive design choice maximized privacy protection at the cost of fairness to apps that depend on the identifier."},{"title":"Ship at iOS 14 vs. delay for industry consultation","body":"Apple originally targeted iOS 14 (September 2020) and delayed to iOS 14.5 (April 2021) after industry pressure. The delay let Meta and others build alternatives but didn''t change the substance of the policy. The delay was political (giving Facebook time) without compromising the strategic goal."},{"title":"Frame as user-privacy vs. competitive move","body":"Apple framed ATT entirely as user privacy. Critics (especially Meta) framed it as Apple using privacy as a competitive weapon — restricting third-party ad capabilities while expanding Apple''s own ad business (which has grown ~3x since ATT). Both framings are true; Apple''s strategic positioning succeeded because it picked the framing that aligned with its brand identity."}],"per_dimension_truth":{"tradeoff":"Reshaping the mobile-ad ecosystem in Apple''s favor + multi-year strategic privacy positioning vs. real damage to ad-dependent businesses (Meta most visibly, but millions of small advertisers as collateral). Apple absorbed the antitrust + regulator pushback and locked in privacy as its category-defining differentiator vs. Google for the next decade.","user":"iOS users got meaningful control over cross-app tracking. The user-facing benefit was real, even if part of the design was strategically motivated. Two truths simultaneously: users got more privacy, and Apple got a structural competitive advantage. Both can be true.","alt":"Defaulting ATT to opt-out (no prompt, tracking off unless user enables) would have been even more pro-privacy. Apple chose the prompt-with-opt-in structure because it preserved the appearance of user choice while structurally biasing toward privacy. The opposite trade — leaving IDFA as default-on with an opt-out — would have been industry-neutral but inconsistent with Apple''s brand positioning.","predict":"Industry chaos in the first 6-12 months as ad networks scramble for alternatives. Meta absorbs $10B+ in lost ad efficiency, small SMB advertisers see CAC spikes. Long-term: the industry shifts toward first-party data, modeled measurement, and on-device ML for ad targeting. Apple''s privacy brand becomes its moat against Android. Long-term lesson: platform-level privacy moves by dominant ecosystem owners reshape industry economics in ways even regulators struggle to predict."},"quote_type":"verbatim","sources":[{"title":"User Privacy and Data Use","url":"https://developer.apple.com/app-store/user-privacy-and-data-use/","publisher":"Apple Developer","type":"documentation"},{"title":"What is App Tracking Transparency (ATT)?","url":"https://www.adjust.com/glossary/app-tracking-transparency/","publisher":"Adjust","type":"documentation"},{"title":"Apple''s App Tracking Transparency (ATT): Explaining the Impacts","url":"https://www.cardinalpath.com/blog/apples-app-tracking-transparency-att-explaining-the-impacts-what-you-can-do-about-it/amp","publisher":"Cardinal Path","type":"article"}],"tags":{"industry":"consumer-mobile","region":"us","decade":"2020s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'whatsapp-privacy-policy-india-2021',
  'weekly',
  '{"id":"whatsapp-privacy-policy-india-2021","type":"weekly","iso_week":"","company":"WhatsApp (Meta)","era":"January–February 2021","intro":"It is January 2021. You are a senior PM at WhatsApp. WhatsApp has been part of Facebook since 2014, but has operated semi-independently. The product has ~2B users globally, ~400M of them in India alone — easily the largest market. Jan Koum and Brian Acton (the original founders, both gone) had famously enforced ''no ads, no games, no gimmicks.'' Their successors are under pressure from Meta to integrate the product economically with the broader Meta ecosystem.\n\nThe new privacy policy: WhatsApp will share user phone numbers, device info, and certain interactions with business accounts with Meta entities (Facebook, Instagram). In Europe, GDPR requires an opt-out. In India and most non-EU markets, there''s no opt-out — accept the new policy or stop using WhatsApp by February 8, 2021. The notification goes out in-app to ~2B users. Within 48 hours, viral panic spreads in India; Signal and Telegram see 10M+ downloads in days; India''s Ministry of Electronics and Information Technology demands WhatsApp withdraw the policy.","open_questions":["Roll out as planned (signals strength + integration) or pause and re-communicate (signals weakness but defuses the panic)?","How to handle the regional disparity — EU users get an opt-out, India doesn''t — does that hold up to scrutiny?","What''s the right communication response — defend the policy on technical grounds, or apologize and clarify?","How aggressive should Meta integration be — proceed at full pace, or delay deeper integration until the brand recovers?"],"closing":"Imagine you''re at WhatsApp leadership in mid-January 2021. India''s IT ministry has just sent a formal letter. Signal is the #1 app in India for days. The Feb 8 deadline is two weeks away.","decision":"Pause the Feb 8 deadline. Extend the rollout to May 15, 2021. Run a multi-week clarification campaign (in-app banners, status updates, public Q&As) emphasizing ''we cannot read your messages — they''re end-to-end encrypted'' and ''this is about business-account interactions, not personal chats.'' The pause partially defuses the panic but the brand damage is durable: Signal retains tens of millions of new users in India; Telegram grows materially; Indian government continues a formal legal challenge to the policy that runs for years through India''s Competition Commission and Supreme Court. WhatsApp ultimately negotiates additional safeguards specifically for India in 2025.","pullquote":"We''re now moving back the date on which people will be asked to review and accept the terms. No one will have their account suspended or deleted on February 8.","pullquote_attribution":"WhatsApp — official statement extending the deadline, January 15, 2021","outcomes":[{"stat":"10M+","label":"Signal downloads in India in days after the policy notification","accent":true},{"stat":"Feb 8 → May 15","label":"deadline pushed by 3+ months after the panic"},{"stat":"India CCI","label":"investigation continues for 4+ years; ongoing case through Supreme Court"},{"stat":"No opt-out","label":"in India (unlike EU) — regional disparity was a major part of the backlash"},{"stat":"Telegram surge","label":"Telegram also gained 25M+ users in India during the panic window"}],"tradeoffs":[{"title":"Force the policy through vs. pause and reframe","body":"Holding the Feb 8 deadline would have signaled strength but accelerated the user exodus to Signal/Telegram. Pausing defused immediate panic but signaled WhatsApp could be moved by user pressure — which set a precedent affecting all future Meta-WhatsApp integration moves."},{"title":"Regional opt-out parity vs. local-policy variation","body":"EU got an opt-out under GDPR; India got ''accept or leave.'' The regional disparity was a major part of the backlash narrative (''Indians treated as second-class users''). Offering India an EU-equivalent opt-out would have defused most of the controversy — but would have set a precedent for every other large non-EU market to demand the same."},{"title":"Defend on technical grounds vs. apologize","body":"WhatsApp''s clarification campaign (''we can''t read your messages, this is about business accounts'') was technically accurate but politically late — the panic was already viral. Leading with the technical framing (which is what they did eventually) reset the conversation but didn''t undo the 10M Signal downloads."},{"title":"Meta integration pace vs. preserve WhatsApp brand independence","body":"The privacy policy was downstream of a Meta-mandated push to integrate WhatsApp''s data more deeply. Slowing Meta integration would have preserved the brand WhatsApp''s founders had built (''we don''t share with Facebook''). Meta''s leadership chose integration speed; the brand damage is the cost."}],"per_dimension_truth":{"tradeoff":"Meta-integration economics + cross-product data utility vs. WhatsApp''s privacy-first brand promise and India market sensitivity. WhatsApp chose integration, absorbed the panic, paused once, and continued the broader Meta integration anyway. The brand cost in India is durable; the integration value to Meta is real.","user":"The India user was treated as a different cohort than EU users — strategic, since EU has GDPR-enforced opt-outs and India doesn''t. The disparity broke the implicit ''WhatsApp is fair to everyone equally'' brand promise. India users responded by trying alternatives (Signal, Telegram) and the Indian government responded with regulatory action that''s still ongoing.","alt":"Offering India an opt-out at parity with EU would have defused 80%+ of the controversy. The opposite trade — and one WhatsApp couldn''t make because it would have set a precedent for every other large market. The strategic constraint (EU is forced, others aren''t) shaped the bad outcome.","predict":"Initial viral panic, mass downloads of Signal and Telegram in India, formal Indian government action, WhatsApp pauses + clarifies but doesn''t reverse, brand damage in India is durable, Meta integration proceeds at a slower pace for 12-18 months. Long-term: the case becomes the canonical example of ''privacy-policy communication failure in a non-Western market'' and shapes how Meta and similar platforms roll out global policy changes thereafter (gradual market-by-market rollouts, clearer technical communication upfront, more parity across geographies)."},"quote_type":"verbatim","sources":[{"title":"India ministry reportedly asked WhatsApp to drop privacy policy changes that sparked backlash","url":"https://www.cnbc.com/2021/01/20/india-has-reportedly-asked-whatsapp-to-withdraw-privacy-policy-update.html","publisher":"CNBC","year":2021,"type":"article"},{"title":"Why is WhatsApp''s privacy policy facing a legal challenge in India?","url":"https://www.yahoo.com/news/articles/why-whatsapps-privacy-policy-facing-002149782.html","publisher":"Yahoo News","type":"article"},{"title":"The WhatsApp Privacy Policy Saga: India''s Data Protection Regime And You","url":"https://theprobe.in/stories/the-whatsapp-privacy-policy-saga-indias-data-protection-regime-and-you","publisher":"The Probe","type":"article"}],"tags":{"industry":"communication","region":"asia","decade":"2020s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'apple-watch-launch-2015',
  'weekly',
  '{"id":"apple-watch-launch-2015","type":"weekly","iso_week":"","company":"Apple","era":"September 2014 – April 24, 2015","intro":"It is mid-2014. You are a senior product leader at Apple. The Apple Watch will be the first new product category developed entirely under Tim Cook''s tenure — and the first since the iPad in 2010. Steve Jobs is gone. Jony Ive is leading design. The team has spent ~3 years building it. Internally, there''s intense debate about what the watch is for: a fitness device (compete with Fitbit), a luxury accessory (the Edition model is $10,000-17,000 in gold), a notifications display (an iPhone wrist remote), a payment device (Apple Pay launching alongside), or something more ambitious. Apple decides to launch with all of them.\n\nUnveiled in September 2014, available April 2015. Starting price $349 (Sport model). Battery life ~18 hours (less than a day). No always-on display. App launch with 1,000+ third-party apps. The marketing positions it as ''the most personal device Apple has ever made.'' Reviews split — design praise, performance and battery criticism, confusion about what it''s actually for.","open_questions":["What''s the singular pitch — fitness, fashion, notifications, payments, or all of them simultaneously?","Is the Edition (gold, $10K-17K) signal or distraction? It positions Apple as a luxury brand but invites mockery.","Launch with 1,000+ apps (signals platform momentum) or fewer high-quality ones (signals ''this is what it''s for'')?","How much to lean on Steve Jobs''s absence — frame this as Tim Cook + Ive''s product (first post-Jobs era) or downplay?"],"closing":"Imagine you''re inside Apple in early 2015. The pre-orders open April 10. The product has to land both as a category-defining launch and as a continuation of Apple''s design legacy.","decision":"Launch on April 24, 2015 with three product tiers (Sport $349, Watch $549+, Edition $10K-17K). 1,000+ apps at launch. Position as a multi-use device — fitness, notifications, payments, fashion. The Edition (gold) generates press but minimal sales. The first-gen Watch sells well but underperforms vs. analyst expectations — Apple stops disclosing unit numbers within 2 years. Reviews are mixed: design strong, app performance and battery weak, use case unclear. Over the next 3 years Apple gradually narrows the positioning to fitness and health (heart rate, fall detection, ECG, blood-oxygen). By 2019, Apple Watch is the best-selling watch in the world, and Health becomes Apple''s most-cited expansion category since the iPhone.","pullquote":"Apple Watch is the most personal device we have ever created. It''s not just a great timepiece — it''s a comprehensive health and fitness companion, with the ability to track all the ways you move throughout the day.","pullquote_attribution":"Tim Cook, Apple CEO — Apple Watch launch event, March 9, 2015","outcomes":[{"stat":"$349 → $17,000","label":"launch pricing range — Sport to Edition"},{"stat":"1,000+","label":"third-party apps at launch (most performed poorly)"},{"stat":"~18 hours","label":"battery life — less than a day, required daily charging","accent":true},{"stat":"Best-selling","label":"Apple Watch is best-selling watch in the world by 2019"},{"stat":"Health pivot","label":"positioning narrows from multi-use to fitness/health over 3-4 years"}],"tradeoffs":[{"title":"Multi-use positioning vs. focused use case","body":"Launching as fitness + fashion + notifications + payments hedged Apple''s bets — but produced ambiguous reviews and a confused customer pitch. A focused launch (just fitness, say) would have been clearer but smaller. The hedged launch gave Apple time to find the use case in the wild and narrow later."},{"title":"Edition (gold, $10-17K) vs. clean tiering","body":"The Edition was a luxury statement that Apple could be more than a tech company. It generated press but trivial sales and arguably distracted from the core product. Most observers saw the Edition as a misstep; Apple quietly discontinued it within two years."},{"title":"1,000+ apps at launch vs. quality-focused launch","body":"The decision to launch with 1,000+ apps signaled platform ambition but produced a poor app experience — most third-party watch apps in 2015 were slow and confusing. A smaller, curated launch would have produced fewer apps but better impressions. Apple eventually shifted away from rich third-party apps and toward complications and watch-faces as the primary surface."},{"title":"Steve Jobs continuity vs. Tim Cook era framing","body":"Apple emphasized continuity with Jobs''s design legacy (Jony Ive''s heavy involvement, Apple''s signature event format) while subtly framing this as the first post-Jobs product. The hedged framing protected Apple from ''Cook can''t ship without Jobs'' narratives but also limited the Watch''s identity as a clean break."}],"per_dimension_truth":{"tradeoff":"Launching ambitiously (multi-use, Edition, 1,000+ apps) vs. launching focused (one clear use case, narrower positioning). Apple chose ambition and absorbed the multi-year positioning narrowing. The eventual identity (fitness/health) was clearer than the launch pitch — but the multi-use launch let Apple keep options open while data accumulated.","user":"The customer the Watch eventually served was the fitness/health-tracking adult. The Watch''s positioning narrowed toward that customer over 3-4 years as Apple learned that fashion + notifications + payments weren''t durable use cases on the wrist. Hedging at launch gave Apple the right to iterate; a focused launch would have foreclosed faster.","alt":"Launching as a pure fitness tracker ($199 Fitbit-killer) would have been clearer, smaller, and probably commercially smaller. The opposite trade — and Apple chose to enter the watch category at a premium because the alternative ceded the entire wearable space to Fitbit, Pebble, and Samsung.","predict":"Mixed launch reviews (design praise, performance criticism, ambiguous use case). Edition fails quickly. Multi-use positioning gradually narrows to fitness/health over 3-4 years. Apple Watch becomes the best-selling watch in the world by 2019. Health features (ECG, fall detection, blood oxygen) become category-defining. Long-term: the Watch becomes Apple''s clearest post-iPhone success and the foundation for Apple''s health ambitions through 2030."},"quote_type":"verbatim","sources":[{"title":"Original Apple Watch launch finally happens: Today in Apple history","url":"https://www.cultofmac.com/apple-history/original-apple-watch-launch","publisher":"Cult of Mac","type":"article"},{"title":"Apple''s Tim Cook unveils a ''revolutionary'' Watch","url":"https://fortune.com/2015/03/09/apple-watch-launch-event/","publisher":"Fortune","year":2015,"type":"article"},{"title":"Apple Watch is first device category developed under Tim Cook","url":"https://appleinsider.com/articles/14/09/10/apple-watch-is-first-device-category-developed-under-tim-cook-took-years-to-complete","publisher":"AppleInsider","year":2014,"type":"article"}],"tags":{"industry":"hardware","region":"us","decade":"2010s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'google-reader-shutdown-2013',
  'weekly',
  '{"id":"google-reader-shutdown-2013","type":"weekly","iso_week":"","company":"Google","era":"March – July 1, 2013","intro":"It is early 2013. You are a strategy leader at Google. Google Reader has been live since 2005 — the dominant RSS-feed reader on the web, with millions of devoted power-users (journalists, bloggers, researchers, tech professionals). The product hasn''t seen meaningful investment in years. Internally, RSS is seen as a declining format losing to social platforms (Facebook, Twitter) as the way people discover news. Google''s broader ''Spring Cleaning'' initiative is killing dozens of products that don''t fit Google''s strategic priorities — Google+ is being pushed as the new social discovery layer.\n\nThe decision: shut down Google Reader on July 1, 2013. The announcement is made March 13. Users have 3.5 months to export their feeds and migrate to competing readers (Feedly, NewsBlur, Inoreader). The Google+ team is poised to absorb the discovery use case via social sharing.","open_questions":["Shut down Reader or invest in revitalizing it (small audience but high signal — journalists, researchers, opinion-leaders)?","If shut down — how much notice (3.5 months given), and what migration tools (export only, or partnership with competitor readers)?","What''s the strategic message — Google is focused on social (Google+) and not legacy formats (RSS), or ''we kill what''s not growing''?","How to handle the inevitable petitions, blog-storm, and the ''Google can''t be trusted not to kill products'' narrative that will follow?"],"closing":"Imagine you''re at Google in February 2013. The Reader shutdown is signed off internally. The announcement is days away.","decision":"Announce shutdown on March 13, 2013 with a 3.5-month wind-down. Provide an export tool (Google Takeout) to let users migrate feeds. Frame the decision in a corporate blog post citing ''declining usage.'' Google+ never picks up the social-discovery use case it was supposed to absorb. Petitions hit 150,000+ signatures; the shutdown becomes a multi-year touchstone for ''Google can''t be trusted with products you love.'' RSS — once a near-universal web protocol — declines sharply as no major competitor with Google''s reach replaces Reader. Feedly and NewsBlur grow but never reach Reader''s scale. The shutdown is widely credited with accelerating RSS''s decline as a mass medium.","pullquote":"While the product has a loyal following, over the years usage has declined. So, on July 1, 2013, we will retire Google Reader. Users and developers interested in RSS alternatives can export their data, including their subscriptions, with Google Takeout over the course of the next four months.","pullquote_attribution":"Google — official ''Spring Cleaning'' announcement, March 13, 2013","outcomes":[{"stat":"Jul 1, 2013","label":"Google Reader formally shut down after 8 years live","accent":true},{"stat":"150,000+","label":"petition signatures asking Google to reconsider"},{"stat":"RSS decline","label":"RSS as a mass-medium protocol declined sharply post-shutdown"},{"stat":"Google+","label":"intended replacement for social discovery — failed within 5 years"},{"stat":"Brand cost","label":"the shutdown is a permanent reference point for Google''s ''product mortality'' reputation"}],"tradeoffs":[{"title":"Kill the product vs. invest to revitalize","body":"Reader had loyal but declining usage. Investing would have cost real resources for a market Google didn''t strategically prioritize. Killing it freed the team and signaled discipline — but at the cost of a power-user cohort (journalists, bloggers, tech professionals) whose goodwill became durable resentment."},{"title":"3.5-month wind-down vs. immediate / longer notice","body":"3.5 months gave users time to migrate but wasn''t long enough to defuse the outrage. A 6+ month wind-down would have been more user-friendly but extended the bad PR. Apple''s ''iPod Classic discontinued, find a competitor'' approach (2014) is similar — quick, clean, painful."},{"title":"Google+ as replacement vs. acknowledge no replacement","body":"Google framed Google+ as the new discovery layer. Google+ was never a credible Reader replacement (different use case, different audience). The framing made the shutdown feel like a strategic redirection (with a destination) rather than a simple cull. When Google+ failed, the shutdown felt like a double-loss."},{"title":"Corporate blog announcement vs. proactive user comms","body":"Google chose a single corporate blog post + Takeout tool — no personal letter, no founder-signed apology, no migration partnership. The neutral corporate tone reinforced the ''Google doesn''t care'' narrative. A higher-touch comms strategy (personal letter from a senior PM, named migration partnerships) would have been more expensive but cheaper than the multi-decade brand cost."}],"per_dimension_truth":{"tradeoff":"Strategic focus + engineering-resource discipline vs. a power-user brand asset built over 8 years. Google chose discipline and paid the brand cost. The cost compounded over the next decade as Google killed Wave, Inbox, Allo, Hangouts, Stadia, and many others — each shutdown citing ''Reader'' as the original wound.","user":"The user Google de-prioritized — journalists, bloggers, researchers — was small in raw numbers but disproportionately influential. They write about products. The decision optimized for engineering economics and ignored the secondary cost of losing the cohort that shapes public perception of Google''s products. That cost remains durable.","alt":"Investing $X / year to keep Reader on life support would have been trivially cheap relative to the brand damage. The opposite trade — and almost certainly would have been the right call in retrospect. The Reader shutdown is now a canonical case in ''when killing a small but loyal product costs more than it saves.''","predict":"Immediate viral petition campaign. Major tech-press blog series. Migration to Feedly + NewsBlur. RSS as a mass medium declines sharply over the next decade. Google''s product-mortality reputation hardens. Long-term: Google Reader becomes the case study every product leader cites when arguing ''don''t kill what you can''t replace, even if it''s small.''"},"quote_type":"verbatim","sources":[{"title":"We Were The (1000+). Goodbye, Google Reader","url":"https://techcrunch.com/2013/07/01/we-were-the-1000-goodbye-google-reader/","publisher":"TechCrunch","year":2013,"type":"article"},{"title":"Requiem for Google Reader, gone but not forgotten","url":"https://www.theregister.com/2023/03/14/requiem_for_google_reader/","publisher":"The Register","year":2023,"type":"article"},{"title":"How Google helped destroy adoption of RSS feeds","url":"https://openrss.org/blog/how-google-helped-destroy-adoption-of-rss-feeds","publisher":"Open RSS","type":"blog"}],"tags":{"industry":"saas","region":"us","decade":"2010s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'twitter-vine-shutdown-2016',
  'weekly',
  '{"id":"twitter-vine-shutdown-2016","type":"weekly","iso_week":"","company":"Twitter","era":"October 2016","intro":"It is mid-2016. You are at Twitter. Vine — the 6-second-loop video platform Twitter acquired in 2012 before launch — has ~200M users at peak but is in real trouble. Instagram has launched 15-second video; Snapchat has captured the under-25 short-video audience; YouTube is pushing creators with revenue share Vine never offered. Top Vine creators are leaking to other platforms because Vine has no monetization path. Internally, Twitter has been mid-restructuring: Jack Dorsey is back as CEO, layoffs are being planned, the company is exploring a sale (Salesforce, Disney, Google all rumored as bidders earlier that year). Vine is operationally expensive — separate engineering, separate brand — for a product whose growth has stalled.\n\nLeadership debates: invest in monetization (creator funds, ads) and try to retain creators, or shut Vine down and redirect resources to Twitter''s core?","open_questions":["Invest in Vine monetization (creator funds, ads) or shut down to redirect resources to core Twitter?","If shut down — keep the archive accessible (preserve creator IP, brand respect) or sunset entirely?","How public to be about the shutdown reasoning — own the strategic narrative, or low-key with a brief blog post?","What''s the right severance for the Vine team, and how to handle the inevitable creator outrage (Vine stars are visible public figures)?"],"closing":"Imagine you''re at Twitter in October 2016. The decision has been made internally. The announcement is days away.","decision":"Shut down the Vine mobile app on October 27, 2016. Keep the website and archive accessible (users can view and download Vines but not upload). Frame the shutdown as a Twitter-focus decision — ''the next phase'' of building Twitter. Vine stars publicly mourn the platform; many move to Musical.ly (which will later become TikTok) and YouTube. Vine is widely cited in retrospect as having identified the short-form-video format ~3 years before TikTok proved it commercial — but Twitter''s failure to monetize creators meant the talent migrated and the format itself moved to a competitor that figured out the economics.","pullquote":"We''re sharing some important news today: in the coming months we''ll be discontinuing the mobile app. Nothing is happening to the apps, website or your Vines today. We value you, your Vines, and are going to do this the right way.","pullquote_attribution":"Vine — official shutdown blog post, October 27, 2016","outcomes":[{"stat":"Oct 27, 2016","label":"Vine shutdown announcement (mobile app discontinued)","accent":true},{"stat":"200M users","label":"Vine''s peak — but creator-monetization gap left it vulnerable"},{"stat":"Archive kept","label":"users could view/download but not upload"},{"stat":"TikTok proved it","label":"the format Vine pioneered became the most valuable consumer product of the late 2010s"},{"stat":"Creator migration","label":"Vine stars moved to YouTube, Musical.ly (later TikTok), Instagram"}],"tradeoffs":[{"title":"Shut down vs. invest in monetization","body":"Vine''s structural problem was the lack of a creator-revenue model. Investing meant building ads infrastructure, creator funds, brand partnerships — significant engineering and BD spend at a moment Twitter was reducing both. Shutting down was operationally cheaper but ceded the format to whoever solved monetization next (Musical.ly → TikTok)."},{"title":"Keep archive vs. full sunset","body":"Preserving the Vine archive let creators retain their work — a relatively cheap concession that softened the brand hit. Full sunset would have been operationally cleaner but produced significantly more outrage and broken creator trust. Twitter chose the soft-landing."},{"title":"Strategic narrative vs. quiet shutdown","body":"Twitter could have framed the shutdown as ''focus on core Twitter,'' but the actual reasoning was mid-restructuring + creator-revenue failure. The chosen comms split the difference — a public blog post with light strategic language but no detailed reasoning. Critics filled in the gap with ''Twitter doesn''t know what it''s doing.''"},{"title":"Short-form video gone vs. preserved within Twitter","body":"An alternative path: rebuild short-form video natively within Twitter''s main app. Twitter didn''t have the engineering bandwidth to do that effectively in 2016-2017. By the time they tried (Twitter Fleets in 2020, also shut down), the format had been won by TikTok."}],"per_dimension_truth":{"tradeoff":"Operational simplicity + Twitter-focus discipline vs. holding the wedge into the format that turned out to be the dominant consumer-video format of the next decade. Twitter chose simplicity in 2016 and lost the format permanently. With hindsight, the decision is the canonical case in ''sometimes you have to invest in the unproven product because the alternative is letting a competitor define the entire category.''","user":"The user Twitter de-prioritized was the short-form-video creator and consumer — the cohort that turned out to be the most-engaged consumer audience of the late 2010s. Twitter has never reached that audience again. Vine''s loss is partly why Twitter is structurally a text-and-news product through 2025.","alt":"Investing $50M/year in Vine creator funds + ad monetization would have been operationally painful but might have preserved the audience and the format. The opposite trade — and TikTok''s later success (>$100B valuation) suggests it would have been worth dramatically more than the $50M annual cost. Twitter chose short-term operational discipline over long-term strategic position.","predict":"Vine creators mourn publicly. Audience migrates to Musical.ly, YouTube, Instagram. Twitter focuses on text + news but never recaptures short-form video. TikTok emerges as the format''s commercial winner. Long-term: Vine''s shutdown is the canonical case study in ''killing a product whose format has not yet been monetized — and watching a competitor monetize it later.'' The case is taught in product strategy curricula globally."},"quote_type":"verbatim","sources":[{"title":"Twitter is shutting down Vine","url":"https://techcrunch.com/2016/10/27/twitter-is-shutting-down-vine/","publisher":"TechCrunch","year":2016,"type":"article"},{"title":"Vine (service) — Wikipedia","url":"https://en.wikipedia.org/wiki/Vine_(service)","type":"article"},{"title":"Why Vine Died: Closing The Loop On The Company That Changed The Internet","url":"https://www.howtheygrow.co/p/why-vine-died-closing-the-loop-on","type":"blog"}],"tags":{"industry":"consumer-social","region":"us","decade":"2010s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'google-stadia-shutdown-2023',
  'weekly',
  '{"id":"google-stadia-shutdown-2023","type":"weekly","iso_week":"","company":"Google","era":"March 2019 – January 18, 2023","intro":"It is early 2019. You are at Google, where Phil Harrison (ex-PlayStation, ex-Xbox) is building Stadia — Google''s bet on cloud gaming. The pitch: stream AAA games via Google''s data centers to any screen with a browser. No console, no downloads, no installs. Stadia launches November 2019 with a $130 controller bundle, two pricing tiers (Stadia Pro $9.99/mo subscription + Stadia Base free), and a launch lineup of ~22 games (most paid à la carte on top of the subscription). Reviews call the technology genuinely impressive (low latency, real 4K streaming) but the business confusing — you pay a subscription AND buy individual games at console prices.\n\nFor 3 years Stadia struggles with low adoption, creator skepticism (no clear way to make money for game developers), and Google''s reputation for product mortality. In September 2022, Phil Harrison announces Stadia will shut down on January 18, 2023. Google fully refunds all hardware AND software purchases.","open_questions":["Launch with a ''subscription + pay per game'' model (current model) or all-you-can-play subscription (Game Pass)?","Invest in first-party games (the Xbox/PlayStation model) — Google did launch Stadia Games and Entertainment in 2019, then shut it down by 2021?","When to shut down — wait one more year (could find PMF, or burn more money), or commit to closure with full refunds?","How to handle the shutdown — full refunds (huge financial commitment, brand-positive) or standard limited refunds (cheaper, brand-negative)?"],"closing":"Imagine you''re at Google in mid-2022. Stadia''s user metrics are weak. Microsoft Game Pass and PlayStation Plus are running the subscription play better. The decision to shut down is being finalized.","decision":"Announce Stadia''s shutdown on September 29, 2022. Sunset by January 18, 2023 — ~3.5 months notice. Refund ALL hardware and software purchases (estimated $50M+ in refunds). Ship a final controller firmware update to enable Bluetooth (so the hardware works on PC/phone/console). Phil Harrison leaves Google in early 2023. The refunds are widely praised as the right way to shut down a paid product — but the shutdown reinforces Google''s ''kill what we don''t dominate'' reputation, joining Reader, Wave, Allo, Hangouts, Inbox, and dozens of others.","pullquote":"While Stadia''s approach to streaming games for consumers was built on a strong technology foundation, it hasn''t gained the traction with users that we expected.","pullquote_attribution":"Phil Harrison, Google VP and GM of Stadia — official shutdown blog post, September 29, 2022","outcomes":[{"stat":"Nov 2019 → Jan 2023","label":"Stadia operational lifespan: ~3 years 2 months","accent":true},{"stat":"Full refunds","label":"all hardware + all software purchases refunded"},{"stat":"Bluetooth firmware","label":"Stadia controllers received final update to work as Bluetooth devices on other platforms"},{"stat":"First-party studio","label":"Stadia Games and Entertainment opened 2019, shut down 2021"},{"stat":"Brand reinforcement","label":"Google''s ''product mortality'' reputation hardened further"}],"tradeoffs":[{"title":"Buy-per-game + subscription vs. Game Pass model","body":"Stadia''s pricing required users to pay for the subscription AND buy individual games at console prices. Xbox Game Pass had already proven the all-you-can-play subscription model worked. Stadia''s split pricing was confusing — paying $60 for a Stadia copy of a game you couldn''t run elsewhere felt worse than buying it on Xbox or PlayStation."},{"title":"First-party studios vs. publisher-only","body":"Stadia Games and Entertainment was meant to build exclusive content (the Xbox/PlayStation moat). Google shut it down in 2021 — a public signal that Google wouldn''t make the multi-year, billion-dollar investment in original games the platform needed. After that, third-party publishers had no reason to commit Stadia exclusives."},{"title":"Shut down at 3 years vs. give it more time","body":"Three years isn''t a fair test for a new gaming platform. PlayStation took ~5 years to dominate. The 3-year shutdown was operationally rational but signaled Google wouldn''t wait the multi-cycle time gaming platforms require. The decision was right given Google''s appetite; the timing made it impossible for the platform to ever reach the audience it needed."},{"title":"Full refunds vs. limited refunds","body":"Refunding all hardware AND software was unusual — most product shutdowns refund only recent purchases. Google spent ~$50M+ on the gesture. The brand benefit was real (the shutdown was widely praised) but didn''t undo the broader brand cost of Stadia joining Google''s graveyard."}],"per_dimension_truth":{"tradeoff":"Strategic discipline (kill what''s not working) vs. patient multi-year platform investment that gaming structurally requires. Google chose discipline; gaming-platform economics require patience Google doesn''t have. The shutdown was the right call given the constraints; the launch was the wrong call given the platform''s needs.","user":"Stadia''s actual customer was the gamer who didn''t want to buy a console. That customer turned out to be small — the cohort that doesn''t buy a console mostly also doesn''t have a fiber connection good enough for cloud gaming. Pricing for that thin overlap audience and competing with Game Pass + PlayStation was always going to be brutal.","alt":"Launching with Game Pass-equivalent subscription pricing and investing heavily in first-party studios for 5+ years would have been the right multi-billion-dollar gaming-platform bet. Google chose to do neither — split pricing + studios shut after 2 years. The opposite trade — and the half-measures meant the platform was always undercapitalized for the category it was entering.","predict":"Strong technical reviews, weak commercial traction, slow growth, first-party studio shutdown signals retreat, full shutdown 3 years in. Full refunds become a brand-positive moment within a brand-negative narrative. Long-term: Stadia becomes the canonical case in ''when a company with extraordinary technology fails because the business model and the time-horizon don''t match the category''s economics.''"},"quote_type":"verbatim","sources":[{"title":"Google is shutting down its gaming service Stadia","url":"https://www.cnn.com/2022/09/29/tech/google-stadia-shutting-down/index.html","publisher":"CNN Business","year":2022,"type":"article"},{"title":"Google Stadia — Wikipedia","url":"https://en.wikipedia.org/wiki/Google_Stadia","type":"article"},{"title":"Google Stadia Is Shutting Down On January 18, 2023","url":"https://www.gamespot.com/articles/google-stadia-is-shutting-down-on-january-18-2023/1100-6507919/","publisher":"GameSpot","year":2022,"type":"article"}],"tags":{"industry":"gaming","region":"us","decade":"2020s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'snap-spectacles-flop-2016',
  'weekly',
  '{"id":"snap-spectacles-flop-2016","type":"weekly","iso_week":"","company":"Snap Inc. (Snapchat)","era":"September 2016 – Q4 2017","intro":"It is mid-2016. You are at Snap Inc., a year before the company''s IPO. Snapchat is the dominant teen / young-adult camera-first social app, and Evan Spiegel''s product instincts have built it through three earlier reinventions. The company is preparing a hardware launch — Spectacles, video-recording sunglasses that capture 10-second clips and sync directly to the Snapchat app. The launch strategy is unprecedented: starting September 24, 2016, Snap will sell Spectacles only via a small number of bright-yellow vending machines that ''appear'' in cities, posted on Snap Map. Each location lasts 24 hours. Spiegel is on the cover of Vogue wearing them, photographed by Karl Lagerfeld.\n\nThe initial drop is a viral moment — hours-long lines at every vending machine appearance. After the first ~6 vending machines, Snap waits 5 months before opening regular online sales. Internal expectations were huge — millions of pairs. Inventory was built accordingly.","open_questions":["Vending-machine scarcity launch vs. broad online availability — does the scarcity build brand or lose customers?","How long to hold scarcity before opening regular sales — 5 months is the eventual answer, but is 1 month right?","What price ($129 launch) — premium enough to feel meaningful, cheap enough for impulse purchase?","What does success look like — fashion-accessory brand-builder, real hardware revenue, or precursor to AR glasses?"],"closing":"Imagine you''re with Spiegel in late 2016 after the initial drops. The scarcity model has produced viral lines. Inventory is being built for millions of pairs.","decision":"Continue the vending-machine model through early 2017. Open regular online sales in February 2017 — 5 months after the launch. By then, the cultural moment has passed — Spectacles ''aren''t cool anymore'' in the fast-cycling teen-fashion market. Retention is brutal: less than 50% of buyers still use Spectacles 1 month after purchase. Hundreds of thousands of unsold pairs sit in warehouses. In late 2017, Snap writes off $40M+ in unsold inventory. Snap ships subsequent Spectacles versions in 2018, 2019, and beyond — quieter launches, lower expectations, treating Spectacles as a multi-year AR-glasses platform investment.","pullquote":"I think of Spectacles like a toy. We''re not going to spend tens of millions of dollars marketing them. We want them to be playful, fun, and a little hard to get.","pullquote_attribution":"Evan Spiegel, Snap cofounder/CEO — public commentary around the Spectacles launch, late 2016","outcomes":[{"stat":"Sep 24, 2016","label":"first Spectacles vending-machine drop in Venice Beach","accent":true},{"stat":"<50%","label":"retention 1 month after purchase — ''shockingly low''"},{"stat":"5 months","label":"between launch and regular online sales — the cultural moment passed"},{"stat":"$40M+","label":"writedown of unsold Spectacles inventory (late 2017)"},{"stat":"~220K pairs","label":"total sold (per May 2018 reports) vs. millions internally projected"}],"tradeoffs":[{"title":"Scarcity launch vs. broad availability","body":"The vending-machine model produced a viral cultural moment but accepted that demand peaked during the scarcity window. Broad availability from day one would have captured more buyers but felt less special and produced less press. Snap chose the cultural moment over the broad reach."},{"title":"5-month wait vs. faster online sales","body":"Waiting 5 months to open regular sales was Snap''s biggest tactical error. The teen-fashion cycle moves in weeks; 5 months is multiple cycles. By the time Spectacles were broadly available, the cultural cohort that wanted them had moved on. A 30-day window between viral drop and broad availability would have captured significantly more buyers."},{"title":"Hardware as toy vs. hardware as platform","body":"Spiegel framed Spectacles publicly as ''a toy.'' Internally, Snap was clearly building toward AR glasses — a multi-year platform investment. The framing protected Snap from being judged against pure-hardware companies'' commercial metrics — but it also signaled to investors that Spectacles weren''t a serious revenue line, lowering inventory expectations and engineering investment to a level Snap couldn''t actually justify operationally."},{"title":"Inventory levels — millions vs. tens of thousands","body":"Snap built inventory assuming millions of pairs would sell. The actual retention and demand curve produced ~220K sales total. The over-build led to the $40M writedown. Building conservatively (and risking running out during the viral moment) would have been operationally smarter but would have missed if demand was real."}],"per_dimension_truth":{"tradeoff":"Viral cultural moment + brand-building experiment vs. sustainable hardware-revenue product. Snap chose the cultural moment, executed the launch beautifully, then mistimed the broad-availability window. The post-launch tactical errors are the failure — the launch itself worked.","user":"The user Spectacles initially served was the teen Snapchat power-user who wanted to be cool first and own a camera-on-their-face second. That cohort flooded the vending machines. The user the broader rollout served — the late adopter who waited for online sales — didn''t exist in meaningful numbers by the time online sales opened.","alt":"Opening online sales 30 days after the viral launch would have captured significantly more buyers. The opposite trade — and almost certainly the right call. Snap''s eventual writedown and inventory disposal cost more than the brand benefit of the extended-scarcity strategy.","predict":"Viral launch, long lines, press fawning, retention collapses within weeks, inventory writedown by late 2017. Spectacles versions 2 and 3 (2018, 2019) ship to quieter receptions but more sustainable economics. Long-term: Snap treats Spectacles as a multi-year platform investment toward AR glasses, accepting that v1 was a brand-builder, not a hardware product. The case becomes the canonical example of ''when scarcity-driven launches misjudge the audience''s attention cycle and convert viral demand into inventory waste.''"},"quote_type":"paraphrased","sources":[{"title":"Why Snapchat Spectacles failed","url":"https://techcrunch.com/2017/10/28/why-snapchat-spectacles-failed/","publisher":"TechCrunch","year":2017,"type":"article"},{"title":"Snap admits mistakes as Spectacles flop","url":"https://pcr-online.biz/2017/11/09/snap-admits-mistakes-as-spectacles-flop/","publisher":"PCR","year":2017,"type":"article"},{"title":"Spectacles (product) — Wikipedia","url":"https://en.wikipedia.org/wiki/Spectacles_(product)","type":"article"}],"tags":{"industry":"hardware","region":"us","decade":"2010s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'tesla-cybertruck-unveil-2019',
  'weekly',
  '{"id":"tesla-cybertruck-unveil-2019","type":"weekly","iso_week":"","company":"Tesla","era":"November 21, 2019 — Cybertruck unveiling","intro":"It is November 2019. You are at Tesla. The Model 3 is in steady production; Model Y is months from launch. Tesla wants to enter the US pickup-truck market — by far the most profitable vehicle category in America (Ford F-Series alone generates ~$40B/year in revenue). The choice: build a conventional electric truck (clean styling, broad appeal, designed to look like an electrified F-150 or Ram) or commit to a radical design — angular, stainless-steel exterior, bulletproof glass — that signals the future and risks alienating mainstream truck buyers.\n\nFranz von Holzhausen and Elon Musk push for the radical version. The unveiling is set for the Tesla Design Studio in Hawthorne. Two demos are planned: a sledgehammer hits the door (proving the steel body), then a metal ball is thrown at the window (proving the ''armor glass''). The geometry is so polarizing that internal Tesla designers reportedly debated softening the lines for months.","open_questions":["Conventional truck design (broader appeal, easier to ship) or radical stainless-steel angular design (polarizing but distinctive)?","How much to lean into the ''tough'' demos at unveiling — sledgehammer + metal ball — when failure could turn the launch into a viral disaster?","Pricing — start at $40K (mass-market F-150 territory) or $70K+ (signal premium / luxury, smaller market)?","Take refundable $100 deposits at the unveiling (low-friction reservations) — will the polarizing design produce real demand or just press?"],"closing":"Imagine you''re at Tesla in early November 2019. The unveiling is two weeks out. The radical-design version has been chosen. The demos have been rehearsed.","decision":"Unveil the Cybertruck on November 21, 2019. Stainless-steel exterior, angular, no paint. Take $100 refundable reservations. The metal-ball demo fails — both windows shatter on stage in front of cameras. Musk laughs nervously, calls it ''a little room for improvement.'' The image (Musk + von Holzhausen + cracked window) becomes the most-shared image of the unveiling. Within 5 days, Tesla announces 250,000 reservations. Within months, total reservations cross 1M+. The truck doesn''t ship until November 2023 — four years late. By 2025, Cybertruck sales are well below initial projections, but the unveiling itself is widely considered one of the most-effective hardware announcements in tech-marketing history (regardless of the broken window).","pullquote":"The reason Cybertruck is so planar is that you can''t stamp ultra-hard 30X steel, because it breaks the stamping press. The geometry is forced by the material — and the material is what makes it bulletproof.","pullquote_attribution":"Elon Musk, Tesla CEO — paraphrased from public commentary at the Cybertruck unveiling, November 2019","outcomes":[{"stat":"250,000 → 1M+","label":"reservations within 5 days, then 1M+ within months","accent":true},{"stat":"Both windows shattered","label":"during the on-stage ''armor glass'' demo"},{"stat":"$100 refundable","label":"deposit — low-friction reservation = mostly press signal, not commitment"},{"stat":"4 years late","label":"Cybertruck shipped November 2023 (originally targeted late 2021)"},{"stat":"Polarizing design","label":"compared to ''doorstop, old Apple Mouse, SpongeBob''s Flats the Flounder''"}],"tradeoffs":[{"title":"Radical design vs. conventional pickup","body":"A conventional electric F-150 alternative would have appealed to millions of mainstream truck buyers. The Cybertruck design is polarizing — a much smaller fraction of truck buyers genuinely want it. Tesla chose the smaller-but-passionate market. The trade is real: Cybertruck sales are far below F-150 volume, but the brand differentiation is unmistakable in a way ''electric F-150'' would never have been."},{"title":"Live demo with failure risk vs. taped / safer demo","body":"Live on-stage demos of new technology are high-risk. The metal-ball demo could have been pre-recorded or done before the audience arrived. Doing it live created the risk that materialized — and turned out to be the most-shared moment of the launch. The ''failure'' generated more PR than a clean demo would have."},{"title":"$100 refundable reservation vs. real deposit","body":"$100 refundable is a press-friendly metric, not a commitment. Tesla learned to inflate reservation numbers (as a marketing tool) at the cost of conversion-rate trust later. Higher deposits ($1,000+) would have produced smaller numbers but more credible signal — the 1M+ Cybertruck reservations only converted to a fraction of actual purchases."},{"title":"Ship the radical version vs. value-engineer to mainstream","body":"Once the unveiling locked in the design publicly, value-engineering toward a more mainstream version became impossible — Tesla had to ship something that matched the prototype shown on stage. That commitment cost ~4 years and significant manufacturing complexity. A more conservative unveil would have preserved the option to course-correct."}],"per_dimension_truth":{"tradeoff":"Massive brand differentiation + reservation volume vs. mainstream truck-buyer appeal + conventional unit economics. Tesla chose differentiation and accepted multi-year manufacturing complexity, polarizing reception, and lower mass-market sales. The unveiling worked as marketing; the truck-as-business is more contested.","user":"Cybertruck buyers are not the F-150 mass market. They are a self-selecting cohort that wants the Cybertruck specifically — the design is the product. Tesla optimized for that cohort and accepted that the broader pickup market would mostly buy conventional EV trucks (Ford Lightning, Rivian, GM EV trucks).","alt":"A conventional electric pickup launched in 2021 would have hit the F-150 mainstream and outsold Cybertruck multiple times over. The opposite trade — and almost certainly the higher-revenue choice. Tesla chose brand over volume because the brand asset compounds across the company''s entire valuation, while a conventional pickup would have been one product line among many.","predict":"Viral unveiling (metal ball failure becomes the moment), 1M+ reservations within months, ship date slips repeatedly, ship in late 2023, sales far below the headline reservation count, polarized owner community. Long-term: the Cybertruck becomes the canonical case in ''when polarizing design is the strategy, not the failure mode'' — even when sales underperform expectations, the brand differentiation is durable."},"quote_type":"paraphrased","sources":[{"title":"Tesla Cybertruck — Wikipedia","url":"https://en.wikipedia.org/wiki/Tesla_Cybertruck","type":"article"},{"title":"Elon Musk explains why the Cybertruck''s windows broke","url":"https://www.cnn.com/2019/11/25/cars/elon-musk-tesla-cybertruck-window-glass-broke","publisher":"CNN Business","year":2019,"type":"article"},{"title":"Tesla claimed its pickup truck was ''bulletproof'' — then smashed its windows","url":"https://www.cnbc.com/2019/11/22/tesla-smashes-bulletproof-pickup-trucks-windows-with-a-metal-ball.html","publisher":"CNBC","year":2019,"type":"article"}],"tags":{"industry":"hardware","region":"us","decade":"2010s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'beats-by-dre-launch-2008',
  'weekly',
  '{"id":"beats-by-dre-launch-2008","type":"weekly","iso_week":"","company":"Beats Electronics","era":"Mid-2006 – July 2008","intro":"It is 2006. You are at Beats Electronics — a brand-new headphone company founded by Jimmy Iovine (Interscope Records cofounder) and Dr. Dre. The premium-headphone market in 2006 is dominated by Bose, Sennheiser, and Sony — brands that compete on audiophile fidelity, sold at electronics stores, marketed via spec sheets (frequency response, impedance, driver size). The customer is the audiophile or the audio engineer — a small, technically literate, mostly-male cohort. The pitch is sound quality you can measure.\n\nIovine and Dre believe a much larger market exists: people who care about how music sounds because of the artist''s emotional intent, not the spec sheet. They plan to launch Beats Studio at $300 — a dramatic price premium over Bose''s similar models. The product won''t beat Bose on measured fidelity. The audio-press review cycle will likely savage them. They have to find a different go-to-market.","open_questions":["Compete with Bose / Sennheiser on sound quality (audio-press review cycle, audiophile reviews) or compete on something entirely different — fashion, status, artist credibility?","Pricing — $150 (compete with mainstream consumer headphones), $300 (premium, signal exclusivity), $500 (luxury accessory)?","Distribution — Best Buy, Apple Stores, music-instrument shops, fashion boutiques? Each channel sends a different brand signal.","Marketing — paid ads (audio-magazine spreads), product placement (music videos / sports), or hand-given to celebrities and athletes (organic product seeding)?"],"closing":"Imagine you''re with Iovine and Dre in early 2008. The Beats Studio is months from launch. The audio press will hate it. The music industry is watching.","decision":"Launch Beats Studio in July 2008 at $300. Skip the audiophile press entirely. Iovine sends pre-production pairs to LeBron James (asks for 15 more, distributes to the entire 2008 US Olympic basketball team — they wear Beats walking off the plane in Beijing). Beats become standard issue in Interscope''s music videos (Lady Gaga, Miley Cyrus, Nicki Minaj) and on athlete sidelines (NFL, NBA). By 2014, Apple acquires Beats for $3B — Apple''s largest acquisition ever at the time. The audiophile press never warms up. Doesn''t matter — Beats has redefined headphones from ''audio gear'' to ''fashion statement worn by the people you admire.''","pullquote":"It''s not about how the headphones measure on a frequency-response chart. It''s about whether you look at LeBron and want what he''s wearing. We don''t compete with Bose — we compete with sneakers.","pullquote_attribution":"Jimmy Iovine, Beats cofounder — paraphrased from public commentary on the Beats positioning","outcomes":[{"stat":"$300","label":"launch price for Beats Studio (premium vs. Bose)","accent":true},{"stat":"2008 US Olympic team","label":"wore Beats walking off the plane in Beijing — orchestrated by Iovine personally"},{"stat":"Music videos","label":"Beats appeared in countless Interscope videos by Lady Gaga, Eminem, etc."},{"stat":"$3B","label":"Apple acquisition (2014) — Apple''s largest ever at the time"},{"stat":"Audio press","label":"consistently negative on sound quality; commercially irrelevant"}],"tradeoffs":[{"title":"Audiophile competition vs. fashion competition","body":"Competing on measured fidelity meant entering an audiophile market that was small, slow-growing, and brutal. Competing on fashion / cultural relevance meant entering a market 100x bigger but requiring totally different distribution and marketing. Beats chose the larger market, accepted the audio-press hostility, and won."},{"title":"Premium pricing vs. mass-market pricing","body":"$300 is significantly above Bose''s price. The premium signaled status (only people who care can spend $300 on headphones), generated higher margin, and reinforced the fashion-accessory positioning. A $99 launch would have been mass-market but would not have produced the cultural status that drove Beats''s growth."},{"title":"Celebrity / athlete seeding vs. paid ads","body":"Hand-distributing pre-production units to LeBron, the Olympic team, and Interscope artists was relatively cheap (free product) but required deep industry relationships only Iovine had. Paid ads would have been faster but would have signaled ''I''m an ad'' rather than ''I''m an authentic part of the culture.'' Beats chose the relationship-led path that only Iovine could execute."},{"title":"Audio-press cycle vs. ignore audio press","body":"Engaging the audio press would have surfaced negative reviews and forced Beats to defend on dimensions it was deliberately not competing on. Ignoring the audio press meant the negative reviews existed but went mostly unread by the target customer (sports fans, music-video viewers, sneaker buyers)."}],"per_dimension_truth":{"tradeoff":"Audio fidelity (the standard category-defining metric) vs. cultural / status signaling (an entirely different consumer dimension). Beats chose the latter, paid the audio-press cost, and built the most valuable headphone brand of the decade. The audio establishment was dismissive throughout — and totally wrong about the market that was forming.","user":"Beats''s customer was the basketball-fan-watching-LeBron, the music-video-viewer-noticing-Lady-Gaga''s-headphones — not the audio-engineer-reading-spec-sheets. Repositioning headphones from ''audio equipment'' to ''fashion accessory'' opened a market 100x the audiophile base.","alt":"Competing on audio fidelity at $99 would have been the conventional path — and would have produced a forgettable mid-tier brand, not the cultural phenomenon. The opposite trade. Beats chose to redefine the category rather than compete inside it.","predict":"Negative audio-press reviews. Strong celebrity / athlete adoption. Best Buy reports surprising sales given the recession. Beats compounds through music-video presence and sports sidelines. By 2014 Apple acquires Beats for $3B for the brand and Apple Music team. Long-term: Beats becomes the canonical case in ''when redefining the category beats competing inside it'' — and the playbook is studied across consumer-electronics and fashion."},"quote_type":"paraphrased","sources":[{"title":"Beats (brand) — Wikipedia","url":"https://en.wikipedia.org/wiki/Beats_Electronics","type":"article"},{"title":"Beats By Dre: The Secrets Behind a Headphone Empire","url":"https://www.billboard.com/music/music-news/beats-by-dre-the-secrets-behind-a-headphone-empire-950594/","publisher":"Billboard","type":"article"},{"title":"Marrying Culture and Technology: The Story of Beats by Dr. Dre","url":"https://www.highsnobiety.com/p/beats-dr-dre-brand-history/","publisher":"Highsnobiety","type":"article"}],"tags":{"industry":"hardware","region":"us","decade":"2000s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'amazon-kindle-launch-2007',
  'weekly',
  '{"id":"amazon-kindle-launch-2007","type":"weekly","iso_week":"","company":"Amazon","era":"Mid-2007 – November 19, 2007","intro":"It is mid-2007. You are at Amazon, secretly building a hardware product for the first time in the company''s history. Amazon is fundamentally a software-and-logistics company — it has never shipped a consumer device. Jeff Bezos personally champions the project: an electronic-paper reader called Kindle, with a built-in cellular modem (Whispernet, free 3G access from Sprint) so users can buy and download books anywhere. No Wi-Fi setup. No PC required.\n\nAt launch on November 19, 2007: the device is $399. The book selection is ~90,000 titles, including 101 of 112 current NYT bestsellers, all priced at $9.99 (well below the $25-30 hardback price). Publishers are nervous — $9.99 sets a price ceiling that will undercut hardback margins for years. Newsweek runs a cover story, but most of the tech press is skeptical (the device is ugly, the screen is grayscale e-ink, the price is high). Steve Jobs publicly dismisses e-readers in 2008 (''people don''t read anymore'').","open_questions":["$399 price (premium signal, narrow market) or aggressive $199 launch (mass market, much harder unit economics)?","Built-in 3G with no contract (Whispernet) — the most differentiated feature, but adds $50+ in BOM cost. Skip it for cheaper hardware?","$9.99 e-book price — set a ceiling and force publishers to comply (long-term margin compression for them) or let publishers price freely (slower adoption)?","Hardware design — invest in beautiful industrial design (delays launch, costs more) or ship the functional-but-ugly device that''s ready now (faster, ugly press)?"],"closing":"Imagine you''re with Bezos in October 2007. The Kindle launches in 4 weeks. Publishers are already grumbling about $9.99. Tech press will hate the design.","decision":"Launch the Kindle on November 19, 2007 at $399 with built-in Whispernet 3G (free, no contract). Set Kindle e-book price at $9.99 for new releases and bestsellers — significantly below hardback. Ship the functionally-correct-but-aesthetically-clunky first version. Newsweek puts Bezos on the cover (''Books Aren''t Dead — They''re Just Going Digital''). Kindle sells out within hours of launch. Publishers spend the next decade fighting Amazon over the $9.99 price point (eventually leading to the Apple-backed publisher ''agency model'' lawsuits in 2012). By 2010, Kindle e-book sales overtake hardback sales on Amazon. Amazon never publicly discloses Kindle unit numbers — but the device defines the e-reader category and the e-book market for the next decade.","pullquote":"Our top design objective was for Kindle to disappear in your hands — to get out of the way — so you can enjoy your reading.","pullquote_attribution":"Jeff Bezos, Amazon founder/CEO — Kindle launch press release, November 19, 2007","outcomes":[{"stat":"$399","label":"launch price — premium pricing for an unproven category","accent":true},{"stat":"Sold out","label":"within hours of launch on Amazon.com"},{"stat":"$9.99","label":"ceiling price on new releases — fought by publishers for years"},{"stat":"Whispernet","label":"free 3G via Sprint, no contract — defining differentiation"},{"stat":"2010 milestone","label":"Kindle e-book sales overtook hardback sales on Amazon"}],"tradeoffs":[{"title":"$399 premium vs. mass-market pricing","body":"$399 was high enough to make Kindle a serious purchase decision, signaling it as a real device, not a toy. A $199 launch would have moved more units but compressed margins on Amazon''s first hardware bet. Bezos chose to validate the category at premium pricing first, then bring prices down (subsequent Kindles dropped to $79-99 within 3-4 years)."},{"title":"Built-in 3G vs. Wi-Fi-only","body":"Whispernet was the killer feature — buy a book anywhere, download in 60 seconds, no Wi-Fi setup, no PC sync. Free 3G data without contract was unprecedented. The BOM cost was real (~$50/device + ongoing Sprint fees) but the differentiation was structural — the Kindle didn''t feel like a computer, it felt like a magic book delivery device."},{"title":"$9.99 e-book ceiling vs. publisher-set pricing","body":"Setting $9.99 as the de facto ceiling for new-release e-books was a strategic move that locked publishers into a price tier well below print. Publishers fought it for a decade (the agency-model lawsuits, Apple antitrust case). Bezos was willing to absorb the long fight because the $9.99 price built Kindle adoption faster than publisher-set pricing would have."},{"title":"Functional ugly hardware vs. delay for industrial design","body":"The original Kindle is widely described as ''ugly'' — angular, beige, with a confusing keyboard layout. Amazon shipped it because waiting for beautiful industrial design would have lost the launch window. Subsequent Kindle generations (Paperwhite, Oasis) prioritized design once the category was established. The first version''s job was ''be functionally correct,'' not ''be pretty.''"}],"per_dimension_truth":{"tradeoff":"Premium price + built-in 3G + $9.99 e-book ceiling vs. mass-market pricing + standard Wi-Fi + publisher-friendly pricing. Amazon chose the more ambitious version on every dimension because launching a new device category requires demonstrating it''s a serious product — and because Amazon''s long-term play (own the e-book market) needed the price ceiling locked in early.","user":"The Kindle''s audience was the heavy book reader — the 5%+ of consumers who buy 20+ books a year. That cohort was small but high-value, and the Kindle''s premium positioning (price + 3G + book selection) matched their willingness to pay. Mass-market readers came later as prices dropped.","alt":"Launching at $199 with Wi-Fi and publisher-set e-book prices would have been the conservative path. The opposite trade. It would have produced more launch units but lost the strategic-positioning moment that Whispernet + $9.99 created. Amazon''s e-book market dominance traces directly to those two decisions.","predict":"Sold out launch. Publishers furious about $9.99 (multi-year fights, eventual antitrust action). Tech press skeptical, then converted as e-ink + Whispernet prove themselves. Kindle defines the e-reader category for a decade. By 2010, e-book sales pass hardback. Long-term: the Kindle is Amazon''s first hardware, the foundation for Echo and Fire later, and the canonical case in ''when premium-pricing a new category device is the right strategic call.''"},"quote_type":"verbatim","sources":[{"title":"Introducing Amazon Kindle","url":"https://press.aboutamazon.com/2007/11/introducing-amazon-kindle","publisher":"Amazon Press Center","year":2007,"type":"press-release"},{"title":"Amazon: Reinventing the Book","url":"https://www.newsweek.com/amazon-reinventing-book-96909","publisher":"Newsweek","year":2007,"type":"article"},{"title":"Amazon Kindle — Wikipedia","url":"https://en.wikipedia.org/wiki/Amazon_Kindle","type":"article"}],"tags":{"industry":"consumer-mobile","region":"us","decade":"2000s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'tesla-model-3-reservations-2016',
  'weekly',
  '{"id":"tesla-model-3-reservations-2016","type":"weekly","iso_week":"","company":"Tesla","era":"March 31, 2016 — Model 3 reveal + reservation launch","intro":"It is early 2016. You are at Tesla. The Model S has been on the market since 2012 (~$70-100K). The Model X (~$80-130K) shipped in 2015. Tesla''s mission has always been to bring EVs to mass-market scale — but the cars to date have been luxury vehicles. The Model 3 is the first ''mass-market'' Tesla, targeted at $35K starting price. The reveal is set for March 31, 2016.\n\nThe leadership team is debating how to take reservations. Pre-orders for unreleased products are usually $50-100 fully refundable holds, treated as marketing-signal-not-revenue. For the Model 3, Tesla proposes a $1,000 fully refundable deposit — 10-20x the typical reservation amount. The car won''t ship for 18+ months. The thesis: the high deposit will (a) signal confidence to investors, (b) generate working capital interest-free, (c) demonstrate real demand for EVs at the $35K price point, and (d) book a queue that locks in customers against competitors.","open_questions":["Charge $1,000 (high friction, real signal) or $100 (low friction, more reservations)?","Allow reservations online only, or also in Tesla stores (creates lines, news cycles, higher physical conversion)?","Cap reservations or open them indefinitely — capping creates scarcity, opening signals confidence in production capacity?","How public to be about reservation numbers — share live updates (signal momentum, risk if numbers slow) or quarterly disclosure (less momentum but lower stakes)?"],"closing":"Imagine you''re with Musk in mid-March 2016. The reveal is days away. The reservation strategy is being finalized.","decision":"Open Model 3 reservations on March 31, 2016 at $1,000 refundable deposit. Allow online + in-store. No cap. Live-tweet reservation numbers throughout the weekend. By the time Musk takes the stage that night to unveil the car, 100,000+ deposits are already in. By Saturday: 276,000. Within a week: 325,000+ reservations representing potential sales of $14B+. Bloomberg calls it ''the single biggest one-week launch of any product ever.'' Tesla earns interest on $325M+ in deposit float for the next ~18 months until first deliveries (July 2017).","pullquote":"More than 325,000 Model 3 reservations have been received. This is the biggest one-week launch of any product ever.","pullquote_attribution":"Tesla — official statement on April 7, 2016 reservation update","outcomes":[{"stat":"100,000+","label":"deposits before Musk took the stage to unveil the car","accent":true},{"stat":"325,000","label":"reservations within first week (~$325M in deposit float)"},{"stat":"$14B+","label":"potential sales locked in via reservation queue"},{"stat":"$1,000 refundable","label":"deposit — 10-20x typical pre-order amount"},{"stat":"Jul 2017","label":"first Model 3 deliveries — 16 months after reservations opened"}],"tradeoffs":[{"title":"$1,000 deposit vs. $100 deposit","body":"$1,000 produced fewer reservations than $100 would have, but the signal value of each $1,000 deposit was much higher — investors and the press could believe demand was real because customers were putting up real money. $100 would have generated more headlines but less credible conviction."},{"title":"Live-tweet reservations vs. delayed disclosure","body":"Live updates throughout reservation weekend created a 24-hour news cycle of growing numbers. Each successive number became a story. Delayed disclosure would have produced a single quarterly headline. Tesla chose maximum-momentum communication and accepted the risk that numbers might plateau publicly."},{"title":"Open reservations indefinitely vs. cap for scarcity","body":"Capping at, say, 100,000 would have manufactured FOMO but would have looked artificial. Opening indefinitely signaled confidence in production capacity (which turned out to be hubris — Model 3 production hell delayed deliveries by years). The unbounded queue helped at the moment but became a multi-year operational liability."},{"title":"Refundable deposits vs. non-refundable","body":"Refundable deposits are easier to take (no buyer reluctance) but produce a queue that can dissolve when buyers change their mind or competitors launch. Non-refundable would have been smaller but more committed. Tesla chose the larger, more press-friendly version and accepted the conversion-rate risk."}],"per_dimension_truth":{"tradeoff":"Maximum press signal + $325M+ in interest-free working capital float vs. real conversion-rate risk + a multi-year operational backlog Tesla wasn''t ready to fulfill. Tesla chose the press signal and the float, then spent 2017-2019 in ''production hell'' trying to actually deliver the cars. The reservation move was a win; the production execution that followed was painful.","user":"The Model 3 reservation customer was the ''I want a Tesla but couldn''t afford the Model S'' cohort — middle-class enthusiasts with strong intent. The $1,000 deposit was real money for that cohort but psychologically tolerable as ''reserving the future.'' Tesla converted that cohort''s enthusiasm into both signal and capital.","alt":"$100 refundable deposits would have produced 5x more headline reservations but lower credibility per reservation. The opposite trade. Tesla''s choice (high-deposit, high-signal) is now the template for hardware-launch reservations across the industry — Apple Vision Pro, Rivian, Polestar all run similar high-deposit reservation systems.","predict":"Massive reservation surge in week 1 (Bloomberg headlines). Reservation conversion rates lower than expected as production delays bite. Operational chaos through 2017-2019 (''production hell''). Eventually delivers ~1M+ Model 3s within 5 years. Long-term: the reservation launch becomes the canonical case in ''how to use a high-deposit pre-order to simultaneously generate working capital, validate demand, and build a public news cycle'' — even when the production execution that follows is brutal."},"quote_type":"verbatim","sources":[{"title":"Tesla Says It Received More Than 325,000 Model 3 Reservations","url":"https://www.bloomberg.com/news/articles/2016-04-07/tesla-says-model-3-pre-orders-surge-to-325-000-in-first-week","publisher":"Bloomberg","year":2016,"type":"article"},{"title":"Tesla has now over 325,000 Model 3 reservations","url":"https://electrek.co/2016/04/03/tesla-model-3-reservations-timeline/","publisher":"Electrek","year":2016,"type":"article"},{"title":"Tesla Model 3 — Wikipedia","url":"https://en.wikipedia.org/wiki/Tesla_Model_3","type":"article"}],"tags":{"industry":"hardware","region":"us","decade":"2010s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'microsoft-kin-shutdown-2010',
  'weekly',
  '{"id":"microsoft-kin-shutdown-2010","type":"weekly","iso_week":"","company":"Microsoft","era":"May 13 – June 30, 2010","intro":"It is early 2010. You are at Microsoft, working on the Kin project — two smartphones (Kin One, Kin Two) targeted at teenagers and 20-somethings on Verizon Wireless. The phones are based on tech Microsoft acquired with Danger Inc. (the company behind T-Mobile Sidekick) in 2008. The pitch: a social-first phone with deep integration to Facebook, Twitter, MySpace — designed for users who text more than they call. The phones will run a custom Microsoft OS (not Windows Phone, which is also in development at the same time).\n\nVerizon insists Kin users sign up for the same data plan as a smartphone (~$30/month) plus a voice plan (~$40/month) — total ~$70/month. The competing iPhone ($199 with $30 data) and BlackBerry Curve are similarly priced. Steve Ballmer is publicly enthusiastic. Marketing budget: ~$1B. Launch: May 13, 2010 in the US.","open_questions":["Push back on Verizon''s $30 data plan (positioning Kin as a teen device that needs cheap data) — or accept the smartphone-tier pricing?","Launch with two products simultaneously (Kin One, Kin Two) or one focused product to clarify the positioning?","Run a Kin OS in parallel to Windows Phone (resource-split) or absorb into Windows Phone (delay launch but consolidate)?","What happens if sales miss expectations — quick kill, or invest more to course-correct?"],"closing":"Imagine you''re at Microsoft in late May 2010. Kin One and Kin Two are on Verizon shelves. The pricing is the same as iPhone and BlackBerry. Sales numbers are coming in.","decision":"Microsoft kills the Kin product line on June 30, 2010 — 48 days after the May 13 US launch. Reportedly fewer than 10,000 units sold. Microsoft says Verizon will continue to carry existing Kin inventory. The team is folded into the Windows Phone organization. Phil Spencer (then leading Microsoft Game Studios, later Xbox + Microsoft Gaming CEO) reportedly intervenes to save some of the talent. Kin becomes the shortest-lived product in Microsoft''s 35-year history. Insider reporting later attributes the failure to a combination of Verizon''s pricing (too expensive for teens), the iPhone''s existing dominance of the smartphone-as-status-symbol category, and internal Microsoft conflict between Kin and Windows Phone teams competing for resources.","pullquote":"Microsoft has decided to focus on Windows Phone 7 as our smartphone platform. As such, we have decided to cancel further work on the Kin product line.","pullquote_attribution":"Microsoft — official Kin discontinuation statement, June 30, 2010","outcomes":[{"stat":"48 days","label":"from US launch (May 13, 2010) to discontinuation (June 30, 2010)","accent":true},{"stat":"<10,000","label":"estimated US Kin sales during the 48 days"},{"stat":"$1B","label":"rumored marketing budget against minimal sales"},{"stat":"Shortest-lived","label":"product in Microsoft''s 35-year history"},{"stat":"Verizon-mandated","label":"$70/month plan pricing — same as iPhone, killing the teen pitch"}],"tradeoffs":[{"title":"Accept Verizon''s pricing vs. push back","body":"Verizon insisted on smartphone-tier data pricing for a teen-positioned device. Microsoft accepted to get carrier distribution. The pricing made the teen positioning incoherent — if Kin costs the same as an iPhone, why pick Kin? Pushing back would have risked the Verizon deal but preserved the product''s positioning logic."},{"title":"Two products simultaneously vs. one focused launch","body":"Launching Kin One AND Kin Two simultaneously diluted the message. Two phones meant double the marketing spend, double the inventory, double the press confusion. A single Kin would have produced a cleaner pitch. Microsoft chose splash; got confusion."},{"title":"Kin OS parallel to Windows Phone vs. consolidate","body":"Running two mobile OSes in parallel (Kin OS + Windows Phone) split engineering resources and produced internal conflict over which was Microsoft''s mobile future. Consolidating would have delayed Kin but produced one coherent mobile strategy. Microsoft tried to do both and was bad at both."},{"title":"Quick kill vs. invest more","body":"Killing Kin in 48 days was decisive — Microsoft preserved engineering resources for Windows Phone 7 (launching November 2010) and stopped the bleeding. Investing more would have pushed Kin past Christmas 2010 with the same fundamental problems. The quick kill was operationally right but cemented the brand-cost as ''Microsoft can''t ship consumer mobile.''"}],"per_dimension_truth":{"tradeoff":"Carrier distribution + dual-product marketing splash vs. coherent positioning + focused engineering investment. Microsoft compromised on every dimension: accepted Verizon''s pricing that killed the teen pitch, launched two products that diluted the message, ran two mobile OSes in parallel that fought each other internally. The 48-day shutdown was the predictable conclusion.","user":"The teen target audience could have valued Kin if the pricing matched (cheap data plans, a phone designed for texting + social). At iPhone-tier pricing, the teen wanted the iPhone. Microsoft built the right product for the wrong price tier.","alt":"Killing Kin pre-launch and putting all the resources into Windows Phone 7 from the start would have been the cleaner strategic call. The opposite trade — and the resources Microsoft spent on Kin''s brief life ($1B+ rumored) would have meaningfully accelerated WP7. The Kin launch is one of the canonical examples of ''shipping a product just because the team is too far along to kill it.''","predict":"Launch week reviews are mixed. Sales come in well below expectations within days. Internal conflict between Kin team and Windows Phone team escalates. Microsoft kills Kin within 6-8 weeks. Brand cost: ''Microsoft can''t ship consumer mobile'' becomes the durable narrative. Long-term: Kin is the canonical case in ''when to kill a product before the launch budget compounds the failure.''"},"quote_type":"verbatim","sources":[{"title":"Microsoft Kin (2010) | Ten of the Shortest-Lived Tech Products Ever","url":"https://techland.time.com/2011/08/23/ten-of-the-shortest-lived-tech-products-ever/slide/microsoft-kin-2010/","publisher":"TIME Techland","year":2011,"type":"article"},{"title":"Microsoft''s KIN is dead, long live Windows Phone 7","url":"https://www.theregister.com/2010/06/30/microsoft_kills_kin_phone/","publisher":"The Register","year":2010,"type":"article"},{"title":"Microsoft Kin — Grokipedia","url":"https://grokipedia.com/page/Microsoft_Kin","type":"article"}],"tags":{"industry":"consumer-mobile","region":"us","decade":"2010s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'iphone-original-launch-2007',
  'weekly',
  '{"id":"iphone-original-launch-2007","type":"weekly","iso_week":"","company":"Apple","era":"2005 – January 9, 2007 — iPhone reveal","intro":"It is mid-2006. You are inside Project Purple at Apple. Steve Jobs has spent the last 2.5 years personally championing a smartphone — a category Apple has no presence in. The market is dominated by BlackBerry (corporate, physical keyboard) and Nokia (consumer, button-driven). Touch-screen smartphones exist (Treo, Windows Mobile devices) and are universally considered too laggy and complicated to be mass-market. Internally, the iPhone has gone through two parallel design tracks: a P1 prototype based on a scrolled iPod and a P2 prototype based on a multitouch screen. Jobs picks P2.\n\nThe device that''s about to be revealed has no physical keyboard, no stylus, can''t run third-party apps (only Apple''s), and costs $499 (4GB) or $599 (8GB) — 2-3x the price of a typical phone. The Macworld 2007 keynote is set for January 9. Jobs will frame the device not as a phone, but as ''three products in one'' — an iPod, a phone, and an internet communicator.","open_questions":["Frame as ''three products in one'' (positions iPhone as a category-redefining device) or as ''a better smartphone'' (cleaner pitch, smaller ambition)?","Touch-only vs. include physical keyboard — the entire industry assumes serious phones need physical keys; Jobs is betting the opposite?","$499/$599 pricing — premium signal but 2-3x typical phone prices; carriers (AT&T) want it cheaper to drive plan attach?","Allow third-party apps at launch (carrier risk, security risk, brand-quality risk) or lock to Apple''s apps (control + trust at the cost of ''computer in your pocket'' positioning)?"],"closing":"Imagine you''re with Jobs at Apple in late 2006. The keynote is two weeks out. The device is a multi-billion-dollar bet against the entire phone industry''s playbook.","decision":"Reveal the iPhone on January 9, 2007 at Macworld. Frame it explicitly as ''three revolutionary products'' in one device. No physical keyboard. No third-party apps at launch (App Store ships 18 months later, in July 2008). $499 / $599 with a required AT&T plan ($59/mo+). The keynote becomes the most-watched product reveal in tech history. iPhone ships June 29, 2007. Jobs''s claim — ''iPhone is a revolutionary and magical product that is literally five years ahead of any other mobile phone'' — is widely mocked as marketing hyperbole. With hindsight, the gap turns out to be closer to a decade. Within 18 months iPhone defines the entire smartphone category; BlackBerry and Nokia''s collapse begins.","pullquote":"Today, Apple is going to reinvent the phone. An iPod, a phone, and an internet communicator — these are not three separate devices. This is one device. And we are calling it iPhone.","pullquote_attribution":"Steve Jobs, Apple CEO — Macworld keynote, January 9, 2007","outcomes":[{"stat":"$499 / $599","label":"launch pricing — 2-3x typical smartphone of the era","accent":true},{"stat":"0","label":"third-party apps allowed at launch (App Store ships July 2008)"},{"stat":"0","label":"physical keyboard — touch-only against the entire industry''s design language"},{"stat":"Jun 29, 2007","label":"ship date — ~6 months after the reveal"},{"stat":"Defined the category","label":"BlackBerry, Nokia, Palm collapse begins within 18 months"}],"tradeoffs":[{"title":"''Three products in one'' framing vs. ''better smartphone''","body":"Framing iPhone as ''iPod + phone + internet communicator'' redefined the category instead of competing inside it. Calling it ''a better smartphone'' would have invited feature comparisons (no keyboard? no apps? no MMS?). The category-redefinition framing made the missing features less central to the conversation; the bigger story was ''a new kind of device.''"},{"title":"Touch-only vs. physical keyboard","body":"Every serious smartphone in 2007 had a physical keyboard. Going touch-only required betting that an autocorrect-aware software keyboard could match physical typing speed. Jobs accepted the early-adopter friction because keeping a keyboard would have capped the screen at sub-edge-to-edge for years. The decision defined the entire smartphone form factor for the next two decades."},{"title":"No third-party apps at launch vs. open platform from day one","body":"Locking iPhone to Apple''s apps at launch (no App Store) was unpopular with developers and lost ground to Android''s openness in early years. Jobs''s reasoning was control of the experience and security; the real reason was probably ''we couldn''t ship App Store and the OS in the same window.'' App Store launched 18 months later. The decision cost Apple ~18 months of platform momentum but preserved the brand-quality of v1."},{"title":"$499/$599 + AT&T exclusive vs. lower price + open carrier","body":"The required AT&T contract + premium pricing positioned iPhone as a luxury / status device — not a mass-market phone. The exclusivity locked Apple into a multi-year US carrier deal that constrained sales. Apple chose the premium-with-exclusivity model because it preserved the brand-positioning the keynote established; the multi-carrier expansion came later (Verizon 2011)."}],"per_dimension_truth":{"tradeoff":"Category redefinition + premium pricing + locked v1 ecosystem vs. mass-market accessibility + open platform from launch. Apple chose maximum-control v1 and absorbed the early-adopter limitations. The brand-defining nature of the launch + the ecosystem''s eventual opening (App Store, multi-carrier) compounded into iPhone owning ~50% of the smartphone profit pool a decade later.","user":"iPhone v1''s customer was the early-adopter willing to pay $499 + AT&T contract for a phone that didn''t have apps. Mass-market customers came in waves — first via App Store (2008), then via Verizon (2011), then via cheaper iPhone models (5C in 2013, SE in 2016). The launch positioning was deliberately exclusive to give the category time to settle.","alt":"Launching with a physical keyboard, third-party apps, and $299 pricing on multiple carriers would have produced a different product — closer to a ''better Treo.'' The opposite trade. It would have sold more units in year one but probably wouldn''t have redefined the category. Jobs took the harder path because the category-redefinition is what compounded.","predict":"Most-watched product reveal in tech history. Mixed early reviews (the ''this isn''t a real smartphone — no keyboard, no apps'' critique). Strong sales in the early-adopter market. App Store launches ~18 months later and unlocks the platform. By 2010 iPhone has redefined what a ''smartphone'' means; BlackBerry and Nokia begin collapsing. Long-term: the iPhone launch is the canonical case in ''category-redefining product launches'' — and the keynote itself becomes a teaching artifact studied for decades."},"quote_type":"verbatim","sources":[{"title":"Apple Reinvents the Phone with iPhone","url":"https://www.apple.com/newsroom/2007/01/09Apple-Reinvents-the-Phone-with-iPhone/","publisher":"Apple Newsroom","year":2007,"type":"press-release"},{"title":"iPhone (1st generation) — Wikipedia","url":"https://en.wikipedia.org/wiki/IPhone_(1st_generation)","type":"article"},{"title":"Watch Steve Jobs Launch the iPhone at Apple''s 2007 Keynote","url":"https://time.com/4628515/steve-jobs-iphone-launch-keynote-2007/","publisher":"TIME","type":"article"}],"tags":{"industry":"consumer-mobile","region":"us","decade":"2000s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'microsoft-surface-launch-2012',
  'weekly',
  '{"id":"microsoft-surface-launch-2012","type":"weekly","iso_week":"","company":"Microsoft","era":"October 26, 2012 — Surface RT launch with Windows 8","intro":"It is mid-2012. You are inside Microsoft''s Windows division under Steven Sinofsky. The iPad has been on the market for 2.5 years and is reshaping consumer computing. Microsoft''s traditional OEM partners (Dell, HP, Lenovo, Acer) have shipped a series of ''Windows tablets'' — almost all bad. Sinofsky believes Microsoft has to make its own hardware to ship a credible tablet competitor. This is unprecedented: Microsoft has shipped peripherals (mice, keyboards, Xbox) but has never built a flagship PC.\n\nSinofsky quietly assembles a Surface team. Two products: Surface RT (ARM-based, runs a stripped-down Windows RT — only Microsoft Store apps), and Surface Pro (Intel-based, runs full Windows 8). RT is launched first, on October 26, 2012, alongside Windows 8 itself. Pricing starts at $499 (similar to iPad). The hardware (kickstand, Type Cover) is genuinely inventive. The OS (Windows RT) is not — it can''t run any of the millions of existing Windows desktop applications. OEM partners are publicly furious that Microsoft has become their competitor.","open_questions":["Ship Surface RT (ARM, locked to Microsoft Store) alongside Windows 8 — or wait for Surface Pro (Intel, full Windows compatibility)?","How aggressively to compete against OEM partners (Dell, HP, Lenovo) — risk destroying the partner ecosystem that Windows depends on?","Position Surface as ''tablet that''s also a laptop'' (broader appeal, confusing pitch) or ''iPad alternative'' (clearer, narrower)?","What''s the right pricing — $499 (match iPad and absorb margin pressure) or $799 (premium, signal differentiation)?"],"closing":"Imagine you''re with Sinofsky at Microsoft in summer 2012. The Surface RT launch is months away. OEMs are demanding to know why Microsoft is competing with them.","decision":"Launch Surface RT on October 26, 2012 at $499 (32GB) / $599 (64GB) alongside Windows 8. Sinofsky publicly defends Surface as ''the best tablet, the best laptop'' he''s ever used. Sales are immediately weak — confusion over what Windows RT is, no native apps, OEM partner hostility undermines distribution. Sinofsky departs Microsoft 2 weeks after launch (November 12, 2012). In July 2013 Microsoft takes a $900M writedown on Surface RT inventory. Surface Pro (Intel-based, full Windows) ships February 2013 to better reception. Surface eventually becomes a viable hardware line over years — but Surface RT is killed off by 2015 and the Windows RT branch is abandoned. Microsoft has been making first-party PCs ever since, but the launch itself is the canonical ''rocky start'' for Microsoft hardware.","pullquote":"Surface is the best tablet, the best laptop. We''ve been working on this for almost three years. We''ve reinvented the way you think about a PC.","pullquote_attribution":"Steven Sinofsky, Microsoft Windows President — Surface RT launch event, October 25, 2012","outcomes":[{"stat":"Oct 26, 2012","label":"Surface RT launch + Windows 8 GA","accent":true},{"stat":"$900M","label":"writedown on Surface RT inventory (July 2013)"},{"stat":"Nov 12, 2012","label":"Sinofsky resigns from Microsoft 2 weeks after launch"},{"stat":"Windows RT","label":"branch abandoned by 2015 — no apps, no developer commitment"},{"stat":"Surface Pro","label":"(Feb 2013, Intel) eventually built into a real product line"}],"tradeoffs":[{"title":"Ship Surface RT vs. wait for Surface Pro","body":"Surface RT shipped first to coincide with Windows 8 launch. The decision was strategic (tie hardware to OS) but operationally bad (Windows RT had no app ecosystem). Waiting for Surface Pro (Intel, full Windows) would have produced a less-confusing first impression but separated the hardware launch from the OS launch."},{"title":"Compete with OEMs vs. preserve partner ecosystem","body":"By making Surface, Microsoft became a competitor to its own ecosystem partners. OEMs (Dell, HP, Lenovo) responded by reducing their Windows-tablet investment and shifting attention to Chromebooks and Android. Microsoft accepted the partner damage to demonstrate what Windows tablets could be. The damage was real and durable — OEMs never fully invested in Windows tablets again."},{"title":"Windows RT (locked to Microsoft Store) vs. Full Windows","body":"Windows RT was a stripped-down OS that couldn''t run any of the millions of legacy Windows applications. The decision was driven by ARM chip constraints and battery-life goals. The cost was severe: nobody understood what Windows RT was, developers wouldn''t build for it, and customers expected ''Windows on a tablet'' to mean their existing Windows software would work."},{"title":"Sinofsky stays vs. departs post-launch","body":"Sinofsky''s 2-week-post-launch departure compounded the Surface narrative — ''even Microsoft''s own Windows president couldn''t survive this.'' Whether Sinofsky was pushed (over the launch''s poor reception, internal conflicts) or chose to leave (frustration with the post-launch trajectory) is debated, but the timing made the launch story worse."}],"per_dimension_truth":{"tradeoff":"Strategic ambition (Microsoft as a hardware company, end-to-end control) vs. operational reality (Windows RT was confusing, OEM partners were alienated, Surface RT had no apps). Microsoft made the strategic right call — they had to make hardware to compete with iPad — but executed poorly on the first attempt. The eventual Surface line (Surface Pro 3 onward) recovered the strategic intent.","user":"Surface RT''s audience was supposed to be the ''iPad alternative for productivity'' user. The audience didn''t materialize because Surface RT couldn''t actually run Microsoft Office (Word, Excel, PowerPoint were stripped-down Office RT versions) or any legacy Windows software. The promised user couldn''t actually use the device for the use cases Microsoft pitched.","alt":"Skipping Surface RT and only shipping Surface Pro (Intel, full Windows) in early 2013 would have been clearer, more useful, and avoided the $900M writedown. The opposite trade. Microsoft chose the simultaneous-launch path because Windows 8 needed a ''flagship'' tablet at GA — but the flagship turned out to be the wrong product.","predict":"Mixed reviews at launch (strong hardware praise, weak software / app ecosystem criticism). Sales come in below expectations within weeks. Sinofsky departs. $900M writedown by mid-2013. Surface Pro ships and gets better reception. Surface RT killed by 2015. Long-term: Microsoft''s first-party hardware line is now a real business, but the Surface RT launch is taught as the canonical ''launch the wrong SKU first'' case study."},"quote_type":"paraphrased","sources":[{"title":"Steven Sinofsky: Surface Launch","url":"https://news.microsoft.com/2012/10/25/steven-sinofsky-surface-launch/","publisher":"Microsoft News","year":2012,"type":"press-release"},{"title":"Microsoft Surface — Wikipedia","url":"https://en.wikipedia.org/wiki/Microsoft_Surface","type":"article"},{"title":"Sinofsky: Surface ''best tablet, best laptop'' he''s ever used","url":"https://www.theregister.com/2012/10/25/sinofsky_surface_launch/","publisher":"The Register","year":2012,"type":"article"}],"tags":{"industry":"consumer-mobile","region":"us","decade":"2010s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'quibi-launch-shutdown-2020',
  'weekly',
  '{"id":"quibi-launch-shutdown-2020","type":"weekly","iso_week":"","company":"Quibi","era":"April – December 2020","intro":"It is 2018. You are at NewTV (later renamed Quibi), a startup founded by Jeffrey Katzenberg (DreamWorks cofounder, ex-Disney chairman) and run by Meg Whitman (ex-CEO of HP and eBay). The thesis: short-form premium video content (10-minute episodes called ''quick bites'') designed exclusively for mobile phones. High-budget Hollywood production values, but bite-sized for commuter / micro-moment viewing. The bet is that Netflix and TikTok have left a gap — premium short-form on mobile.\n\nThey raise $1.75B from investors (Disney, Sony, Lionsgate, MGM, NBCUniversal, Alibaba — every major media company). Sign A-list talent. Build a custom mobile-first video player with a ''Turnstyle'' feature that switches between portrait and landscape mid-video. Launch April 6, 2020 at $4.99/month (with ads) or $7.99 (ad-free). The launch coincides with the start of COVID lockdowns — when nobody is commuting and nobody needs ''10-minute mobile videos for the in-between moments.''","open_questions":["Mobile-only at launch (focus, signal premium) or also on TV / cast (broader access, dilutes positioning)?","$4.99-$7.99 monthly pricing (premium signal, fewer subs) or freemium-with-ads (lower friction, slower revenue)?","Launch during COVID lockdowns (the ''commute moment'' Quibi was designed for has evaporated) — delay 6 months, or proceed and hope?","Custom mobile-first features (Turnstyle, no screenshots) vs. industry-standard video player (broader compatibility)?"],"closing":"Imagine you''re at Quibi in February 2020. Launch is 6 weeks out. COVID is starting to lock down US cities. The ''commute use case'' Quibi was designed for is about to disappear.","decision":"Launch Quibi as planned on April 6, 2020. Mobile-only at launch (no TV / cast support). Custom Turnstyle player. $4.99 / $7.99 pricing. Massive marketing budget ($400M+). The launch lands in the middle of US COVID lockdowns. ''Quick bites for the moments in between'' is exactly the wrong pitch when there are no in-between moments — everyone is at home, on the couch, watching long-form Netflix on a TV. By Q2 2020, Quibi has ~500K paying subscribers vs. millions projected. By October 21, 2020 — ~6 months after launch — Katzenberg and Whitman announce the shutdown. The library is sold to Roku in January 2021 for less than $100M. Total capital lost: ~$1.75B.","pullquote":"We feel that we''ve exhausted all our options. As a result we''ve reluctantly come to the difficult decision to wind down the business, return cash to our shareholders, and say goodbye to our talented colleagues with grace.","pullquote_attribution":"Jeffrey Katzenberg + Meg Whitman, Quibi cofounders — shutdown announcement, October 21, 2020","outcomes":[{"stat":"$1.75B raised","label":"from Disney, Sony, Lionsgate, MGM, NBCUniversal, Alibaba","accent":true},{"stat":"~500K","label":"paying subscribers at peak (vs. millions projected)"},{"stat":"Apr 6 → Oct 21","label":"launch to shutdown announcement = ~6.5 months"},{"stat":"<$100M","label":"Roku acquisition of Quibi''s content library (Jan 2021)"},{"stat":"Mobile-only","label":"at launch + COVID lockdown = wrong product, wrong moment"}],"tradeoffs":[{"title":"Mobile-only at launch vs. multi-device","body":"Mobile-only was a focus play (signal that Quibi was a different product than Netflix). Multi-device would have diluted the positioning but expanded usage to home contexts. During COVID lockdowns, mobile-only meant Quibi was unusable for the audience that was actually consuming video (people on couches with TVs)."},{"title":"Launch during COVID vs. delay","body":"Delaying the launch 6 months would have lost momentum, missed talent commitments, and burned more cash. Launching as planned hit the worst possible moment — Quibi''s product-market fit assumed commutes that no longer existed. The leadership chose to ship rather than delay; both options had costs."},{"title":"Premium pricing vs. freemium-with-ads","body":"$4.99-$7.99 monthly was high enough to limit experimentation. Freemium would have generated more trial users but slower revenue. Quibi chose premium, which compounded the slow-start problem — high friction for users to even try the product."},{"title":"Custom mobile-first features vs. standard video","body":"Turnstyle (rotate-mid-video format) and no-screenshot lockdowns were innovative but added engineering / production cost and limited content portability. Users couldn''t share clips on social media — every Quibi video was trapped inside the app, killing the viral loop that TikTok was simultaneously dominating."}],"per_dimension_truth":{"tradeoff":"Premium production + custom mobile-first format + premium pricing vs. broad-availability + viral-friendly + freemium. Quibi made the harder, more-distinctive bet on every dimension. Each individual choice was defensible; the combination produced a product that was simultaneously expensive, mobile-locked, premium-priced, and shipped during a lockdown that eliminated the use case. Every layer of the bet compounded against Quibi.","user":"Quibi''s target user — the commuting professional with 10-minute gaps in their day — disappeared during COVID. The actual at-home audience wanted long-form on a TV (Netflix, Disney+) or short-form viral on TikTok. Quibi served neither.","alt":"Delaying the launch + adding TV / cast support + dropping pricing to $1.99 / freemium would have given Quibi a chance to find PMF post-COVID. The opposite trade — and impossible to execute given the talent commitments and burn rate. Quibi was structurally locked into the premium-mobile bet.","predict":"Strong launch buzz (massive marketing, A-list talent). Subscribers come in well below projections within weeks. The mobile-only / commute-moment positioning becomes the punchline once COVID lockdowns make it absurd. Shutdown within 6-7 months. Library sold to Roku for cents on the dollar. Long-term: Quibi becomes the canonical case in ''when product-market-fit assumptions are violated by an external shock that eliminates the use case'' — and a permanent reference point for Hollywood''s misunderstanding of mobile-native consumer behavior."},"quote_type":"verbatim","sources":[{"title":"Quibi officially announces it''s shutting down","url":"https://www.cnbc.com/2020/10/21/quibi-to-shut-down-after-just-6-months.html","publisher":"CNBC","year":2020,"type":"article"},{"title":"Quibi Streaming Service Is Shutting Down About 6 Months After Launch","url":"https://www.npr.org/2020/10/21/926396526/quibi-short-form-streaming-service-shutting-down","publisher":"NPR","year":2020,"type":"article"},{"title":"Quibi — Wikipedia","url":"https://en.wikipedia.org/wiki/Quibi","type":"article"},{"title":"A look at why Quibi failed so soon after launching","url":"https://www.nbcnews.com/business/business-news/look-why-quibi-failed-so-soon-after-launching-n1244312","publisher":"NBC News","year":2020,"type":"article"}],"tags":{"industry":"media","region":"us","decade":"2020s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'amazon-fire-phone-2014',
  'weekly',
  '{"id":"amazon-fire-phone-2014","type":"weekly","iso_week":"","company":"Amazon","era":"June 18, 2014 — Fire Phone launch","intro":"It is 2013-2014. You are at Amazon, working on a hardware bet Jeff Bezos has personally championed: a smartphone. Amazon already ships Kindle (e-readers) and Fire tablets — both have struggled commercially against the iPad / iPhone but have Amazon-specific use cases (reading, shopping). Bezos''s pitch for the Fire Phone is more ambitious: a 4.7'' smartphone with four front-facing cameras enabling ''Dynamic Perspective'' (a 3D-ish parallax effect that responds to head movement), a ''Firefly'' object-recognition button (point at any product, see the Amazon listing), and exclusive Mayday tech support (one-tap connection to a live Amazon agent on your screen).\n\nAT&T-exclusive at launch, $199 with a 2-year contract or $649 unlocked — same pricing as iPhone. Bezos personally unveils the device in Seattle on June 18, 2014. Reviews are mixed-to-negative (gimmicky 3D effect, weak app ecosystem since Fire Phone uses Amazon''s forked Android-derivative ''Fire OS''). Within weeks sales are clearly disastrous.","open_questions":["Pricing — $199 with contract (matches iPhone, signals premium) vs. $99 with contract (mass-market, lower brand)?","Carrier exclusive (AT&T) for launch capital vs. multi-carrier (broader distribution)?","Fire OS (Amazon''s Android fork, no Google services) vs. real Android (full app store but less Amazon control)?","Lead with ''Dynamic Perspective'' and ''Firefly'' (differentiated features) or as ''a phone optimized for Amazon shopping'' (clearer pitch)?"],"closing":"Imagine you''re at Amazon in October 2014. Fire Phone has been on sale for 4 months. Returns are high. Inventory is piling up. The Q3 earnings report is days away.","decision":"Cut Fire Phone price from $199 to $0.99 with contract within 2 months of launch (a desperate move that signals the failure publicly). Take a $170M writedown on unsold Fire Phone inventory in Q3 2014. Bezos publicly defends the project as a ''bold bet,'' frames the failure as part of Amazon''s experimental DNA, and points out that the Fire Phone team''s work eventually contributed to the development of Alexa and the Echo (which DOES become an enormous success in 2014-2015). The Fire Phone is quietly discontinued in 2015. Bezos''s explicit lesson: ''If you think that''s a big failure, we''re working on much bigger failures right now — and I am not kidding.''","pullquote":"If you think that''s a big failure, we''re working on much bigger failures right now — and I am not kidding. Some of them are going to make the Fire Phone look like a tiny little blip.","pullquote_attribution":"Jeff Bezos, Amazon CEO — Business Insider Ignition Conference, December 2014","outcomes":[{"stat":"$170M","label":"writedown on unsold Fire Phone inventory (Q3 2014)","accent":true},{"stat":"$199 → $0.99","label":"price cut with contract, within ~2 months of launch — public failure signal"},{"stat":"Echo / Alexa","label":"Fire Phone team''s work contributed to the Echo (launched Nov 2014, ~5 months after Fire Phone)"},{"stat":"AT&T exclusive","label":"limited launch distribution, compounded the sales failure"},{"stat":"2015 EOL","label":"Fire Phone quietly discontinued ~18 months after launch"}],"tradeoffs":[{"title":"Differentiated ''gimmick'' features vs. focused Amazon-shopping phone","body":"Dynamic Perspective and Firefly were headline-friendly but added complexity (4 front cameras, custom hardware, custom software). A simpler ''Amazon-shopping-optimized phone'' would have been a cleaner pitch and lower BOM cost. Amazon chose the differentiation path; the gimmicks generated press but didn''t drive purchases."},{"title":"Fire OS (Amazon control) vs. real Android","body":"Fire OS gave Amazon control over the app store (no Google Play, all Amazon storefront) and the user data. The cost was severe — no Gmail, no Google Maps, no YouTube, no most apps users expected. Real Android with Google services would have made the phone a credible smartphone but ceded the ecosystem control Amazon wanted."},{"title":"iPhone-tier pricing vs. mass-market pricing","body":"Pricing the Fire Phone at $199 with contract (same as iPhone) signaled premium positioning that the product couldn''t deliver on. A $99 launch would have signaled ''this is for Amazon shoppers, not iPhone competitors.'' Amazon overestimated what the Fire Phone could charge and was forced into the public $0.99 fire-sale within weeks."},{"title":"Fail loudly vs. quietly de-emphasize","body":"Bezos publicly named the Fire Phone failure as part of Amazon''s experimental culture, framing failures as the cost of innovation. The transparency turned what could have been a quiet brand wound into a leadership lesson. The framing didn''t undo the $170M loss but converted the brand cost into a brand asset (Bezos as the ''I''ll bet big and lose big'' founder)."}],"per_dimension_truth":{"tradeoff":"Hardware ambition + differentiated features + iPhone-tier pricing vs. focused Amazon-shopping device + lower price + Fire OS realism. Amazon went big on every dimension and produced a phone that competed against iPhone on price without competing on capability. The failure was operationally ugly but spawned the team that built Alexa — which became a multi-billion-dollar product line within 5 years.","user":"The Fire Phone''s intended user — the heavy Amazon shopper who wanted Firefly product-recognition + one-tap Amazon checkout — wasn''t enough of a market. The iPhone user wasn''t switching because of Firefly. The Android user wasn''t switching to a no-Google-services Fire OS device. The product fell into a no-customer middle.","alt":"Skipping the Fire Phone entirely and putting the engineering investment directly into Alexa / Echo would have produced the same eventual win without the $170M writedown. The opposite trade. With hindsight, this is what should have happened — but Bezos''s culture explicitly tolerated failure as the cost of taking shots, and the Fire Phone failure compounded into the Echo''s success in ways a ''skip the Fire Phone'' counterfactual wouldn''t have.","predict":"Mixed-to-negative reviews. Sales come in well below projections within weeks. Public price cut to $0.99 with contract. $170M writedown by Q3. Bezos publicly owns the failure. Fire Phone discontinued by 2015. Echo launches November 2014 and slowly becomes Amazon''s most successful new product category since Kindle. Long-term: the Fire Phone is the canonical case in ''failed hardware launch that still produced organizational learning'' — and Bezos''s public framing of failure becomes Amazon''s cultural template for permission to take big bets."},"quote_type":"verbatim","sources":[{"title":"Fire Phone — Wikipedia","url":"https://en.wikipedia.org/wiki/Fire_Phone","type":"article"},{"title":"Amazon Takes $170 Million Writedown on Weak Fire Phone Sales","url":"https://www.recode.net/2014/10/23/11632220/amazon-takes-170-million-writedown-on-weak-fire-phone-sales","publisher":"Recode","year":2014,"type":"article"},{"title":"The Inside Story Of Jeff Bezos''s Fire Phone Debacle","url":"https://www.fastcompany.com/3039887/under-fire","publisher":"Fast Company","type":"article"},{"title":"Amazon CEO Jeff Bezos: ''I''ve made billions of dollars of failures''","url":"https://fortune.com/2014/12/02/amazon-ceo-jeff-bezos-failure/","publisher":"Fortune","year":2014,"type":"article"}],"tags":{"industry":"consumer-mobile","region":"us","decade":"2010s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'pebble-kickstarter-2012',
  'weekly',
  '{"id":"pebble-kickstarter-2012","type":"weekly","iso_week":"","company":"Pebble Technology","era":"April 11 – May 18, 2012 — Kickstarter campaign","intro":"It is early 2012. You are Eric Migicovsky, a recent University of Waterloo grad who has been building smartwatches for years (the inPulse, sold ~1500 units). You''ve shipped a working Pebble prototype that pairs with iPhone and Android via Bluetooth, displays notifications, and lets users install custom watch faces. You''ve been rejected by every major VC — they don''t believe consumer hardware works for a small team. You decide to launch on Kickstarter with a $100,000 goal — enough to fund the first production run.\n\nThe campaign launches on April 11, 2012. Within 2 hours: $100K (goal hit). Within 6 days: $4.7M (most-funded Kickstarter project ever, with 30 days still left). By campaign close on May 18, 2012: $10.27M raised from ~69,000 backers — each pre-ordering a Pebble for $99-$125. The campaign is the moment crowdfunding goes mainstream as a hardware-launch mechanism.","open_questions":["Set the Kickstarter goal at $100K (low, builds momentum) vs. $1M+ (matches actual production cost, less risky if you under-raise)?","Cap the campaign at a fixed number of units (preserves quality, limits funding) vs. uncapped (unlimited revenue, unlimited operational risk)?","Pricing $99 (mass-market signal, thin margin) vs. $199+ (premium, higher margin, less viral)?","Compatible with iPhone AND Android (broader reach, harder engineering) vs. iPhone-only (smaller market, simpler)?"],"closing":"Imagine you''re Migicovsky in early 2012. You''ve been rejected by every VC. Kickstarter is your last option. The campaign launches in days.","decision":"Launch the Kickstarter on April 11, 2012 with a $100K goal. Uncapped. $99-$125 pricing for the watch. iPhone + Android compatibility. The campaign ends 5.5 weeks later with $10.27M raised — 100x the original goal — from ~69,000 pre-orders. Pebble ships the first units in January 2013 (later than promised; backers are tolerant). Pebble becomes the most-funded Kickstarter project ever, eventually dethroned in August 2014 by the Coolest Cooler. Pebble runs as an independent smartwatch company until 2016, when it''s acquired by Fitbit (later folded into Google) for ~$23M — far below the company''s peak valuation. The Kickstarter campaign itself is the moment that legitimizes crowdfunding as a hardware-launch primitive.","pullquote":"Pebble is going to be the most fun, the most useful, and the most beautiful thing you''ve worn. We had no idea Kickstarter would let us connect with so many people who wanted what we were building.","pullquote_attribution":"Eric Migicovsky, Pebble founder — paraphrased from public Kickstarter campaign and post-campaign interviews","outcomes":[{"stat":"$10.27M","label":"raised on Kickstarter — 100x the $100K goal","accent":true},{"stat":"~69,000","label":"Kickstarter backers, each pre-ordering a Pebble"},{"stat":"2 hours","label":"to hit the $100K goal"},{"stat":"Most-funded ever","label":"until dethroned by Coolest Cooler in August 2014"},{"stat":"$23M","label":"Fitbit acquisition (Dec 2016) — well below peak valuation"}],"tradeoffs":[{"title":"$100K goal vs. realistic $1M+ goal","body":"A low goal ($100K) compounded virally — every milestone (''100x funded! 200x funded!'') generated press. A more realistic $1M goal would have looked credible but produced fewer headlines per dollar. Migicovsky chose the small goal for the viral moment and accepted the operational risk that came with raising 100x more than planned."},{"title":"Uncapped campaign vs. fixed unit cap","body":"Going uncapped meant unlimited demand to fulfill — 69,000 watches, all custom hardware, all to ship within months. A unit cap (say, 25,000 units) would have produced a manageable production run but limited fundraising. Migicovsky took the unlimited revenue and absorbed the multi-month production delay that resulted."},{"title":"iPhone + Android vs. iPhone-only","body":"Supporting both platforms doubled the engineering effort but doubled the addressable market. For a single-product startup with limited engineering, the parallel platforms were a real cost. The decision turned out to be right — Android backers were a meaningful share of the campaign''s success."},{"title":"Mass-market pricing ($99) vs. premium ($199+)","body":"$99 made the Pebble feel like a mass-market consumer product — ''a smartwatch for everyone'' — and was the right price for the Kickstarter audience. Premium pricing would have meant fewer backers, more margin, and a different customer cohort. Migicovsky chose mass-market because the Kickstarter mechanic rewards volume."}],"per_dimension_truth":{"tradeoff":"Maximum viral campaign + unlimited revenue + mass-market pricing vs. operational manageability + premium positioning + lower fundraising. Migicovsky chose the campaign-maximizing version on every dimension. The Kickstarter was an unqualified success; the multi-year operational follow-through was harder, and Pebble eventually got squeezed between Apple Watch and Android Wear and sold to Fitbit for a fraction of peak.","user":"The Kickstarter audience — early-adopters willing to pre-pay $99-125 for a watch that would ship 9 months later — was a self-selecting cohort that Pebble served very well. The post-campaign mass-market expansion turned out to be harder; once Apple shipped the Apple Watch (April 2015), the smartwatch category professionalized and Pebble''s hardware-economics couldn''t compete.","alt":"Capping the campaign at $1M and 10K units would have been operationally cleaner but would have lost the viral moment. The opposite trade. Pebble chose the bigger number; the operational headaches were the cost of the cultural moment, and the moment is what the company is remembered for even after Fitbit''s acquisition.","predict":"Massive Kickstarter campaign — most-funded ever, viral press cycle, every milestone is a story. Production delays push first deliveries past the original promised date. Backers are mostly tolerant. Pebble becomes a real company with real customers. Apple Watch ships in 2015, and the smartwatch category professionalizes; Pebble can''t compete on hardware economics. Acquisition by Fitbit in late 2016 at a fraction of peak valuation. Long-term: the Kickstarter campaign is the canonical case in ''crowdfunding as a hardware launch primitive'' — and Pebble becomes a permanent reference for ''great campaign, hard follow-through.''"},"quote_type":"paraphrased","sources":[{"title":"Pebble (watch) — Wikipedia","url":"https://en.wikipedia.org/wiki/Pebble_(watch)","type":"article"},{"title":"$1M in 49 minutes: Waterloo grad sets Kickstarter record","url":"https://uwaterloo.ca/news/1m-49-minutes-waterloo-grad-sets-kickstarter-record","publisher":"Waterloo News","year":2012,"type":"article"},{"title":"Success and Failure at Pebble","url":"https://medium.com/@ericmigi/why-pebble-failed-d7be937c6232","publisher":"Eric Migicovsky / Medium","type":"blog"}],"tags":{"industry":"hardware","region":"us","decade":"2010s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'nintendo-switch-launch-2017',
  'weekly',
  '{"id":"nintendo-switch-launch-2017","type":"weekly","iso_week":"","company":"Nintendo","era":"October 2016 – March 3, 2017","intro":"It is mid-2016. You are at Nintendo. The Wii U has been a commercial disaster — peak ~13.5M lifetime units vs. Wii''s 100M+. Satoru Iwata (the beloved CEO) passed away in July 2015; Tatsumi Kimishima has taken the role. The company has been signaling a successor codenamed ''NX'' for over a year. The Wii U''s failure has been attributed to a confusing name (was it a Wii accessory? a new console?), weak third-party support, and a tablet-controller pitch consumers never grasped.\n\nLeadership has bet the future on a single product that''s structurally novel: a hybrid console + portable. It plays on a TV via dock; it pulls out and plays on the go; the same game, the same save file, switches between modes mid-session. The two Joy-Con controllers attach to the side for portable mode, or detach for two-player. The chip is NVIDIA''s Tegra (an off-the-shelf mobile chip — Nintendo''s first console not using a custom processor). Launch is set for March 3, 2017 at $299.","open_questions":["Hybrid console + portable (radical, untested) or successor-to-Wii-U + new portable (safer but two products)?","Off-the-shelf NVIDIA Tegra chip (lower performance, lower cost) vs. custom Nintendo processor (higher performance, much higher dev cost)?","$299 price point — premium enough to feel like a console, cheap enough to feel like a portable, but lower margins than typical Nintendo hardware?","Launch with one tentpole title (Zelda: Breath of the Wild) and let it carry the launch, or wait for a fuller lineup?"],"closing":"Imagine you''re at Nintendo in late 2016. The Wii U''s failure is recent. The Switch reveal is days away. Iwata''s vision is being delivered by Kimishima''s team.","decision":"Reveal Switch on October 20, 2016 with a single explanatory trailer (no live event, no presser at announcement). Launch March 3, 2017 at $299 worldwide. Launch lineup: The Legend of Zelda: Breath of the Wild as the marquee title (one of the highest-rated games ever made), plus 1-2-Switch and a few smaller titles. Nintendo deliberately ships with a thin lineup — the bet is that Zelda alone carries the launch month, then more titles roll out across 2017 (ARMS in June, Splatoon 2 in July, Super Mario Odyssey in October). Switch sells 2.74M units in its first month, outpacing every previous Nintendo console. Sells ~150M+ lifetime through 2025 — third-best-selling console of all time, behind only PS2 and Nintendo DS.","pullquote":"Nintendo Switch is a brand-new kind of home gaming system that offers a multitude of play modes. With Nintendo Switch, players are no longer bound to the TV.","pullquote_attribution":"Nintendo — official Switch reveal trailer, October 20, 2016","outcomes":[{"stat":"$299","label":"launch price — significantly lower than typical console launches","accent":true},{"stat":"2.74M","label":"Switch units sold in its first month — outpacing every previous Nintendo console"},{"stat":"100/100","label":"Zelda: Breath of the Wild Metacritic score — defined the launch"},{"stat":"~150M+","label":"lifetime Switch units sold through 2025 — third-best-selling console ever"},{"stat":"Off-the-shelf chip","label":"first Nintendo console not using a custom processor — NVIDIA Tegra"}],"tradeoffs":[{"title":"Hybrid form factor vs. two separate products","body":"The hybrid bet was risky — neither pure console nor pure portable, and consumers don''t usually want hybrids (Wii U taught Nintendo this). Splitting into two products would have been safer but doubled the manufacturing and developer-support burden. Nintendo bet on the hybrid because that was Iwata''s vision for unifying their console + portable divisions and ending the engineering split that had been costly for decades."},{"title":"Off-the-shelf NVIDIA Tegra vs. custom silicon","body":"Using Tegra meant lower performance than PS4/Xbox One — but vastly lower R&D cost, faster time-to-market, and a chip Nintendo could improve over time without redesigning the silicon. The performance gap meant Nintendo couldn''t get most AAA cross-platform games, but the company accepted that — their strength is first-party titles (Mario, Zelda, Pokémon, Animal Crossing), not third-party AAA."},{"title":"$299 launch vs. premium pricing","body":"$299 is a low launch price for a Nintendo console (the Wii was $249 in 2006). At that price, Switch had to be a volume play, not a margin play. The bet: get Switch into as many homes as possible quickly, then monetize through first-party software (which carries enormous margin since Nintendo owns the IP)."},{"title":"Thin launch lineup + Zelda vs. fuller lineup + later launch","body":"Launching with mostly Zelda (and a few minor titles) was unusual for a console launch. Most launches stack ~15+ titles to fill the catalog. Nintendo bet on Zelda''s quality being so high that it would carry the launch month — and used the rest of 2017 to ramp the catalog. The bet worked because Breath of the Wild was genuinely one of the best games ever made."}],"per_dimension_truth":{"tradeoff":"Radical hybrid bet + off-the-shelf chip + low launch price + thin launch lineup vs. safer separate products + custom silicon + premium pricing + fuller catalog. Nintendo went radical on every dimension. The bet worked because (a) Zelda''s quality was unprecedented, (b) the hybrid form factor turned out to be desirable in a way Wii U''s split-screen wasn''t, and (c) first-party Nintendo IP held up through 7+ years of post-launch.","user":"The Switch''s user was both the home-console gamer and the portable gamer — but more importantly, the family unit that played together (couch co-op was a key marketing pitch). The 100M+ Switches sold in 6 years tracked closely with family households globally, not the traditional hardcore-gamer cohort.","alt":"Continuing the Wii U strategy (more powerful console + tablet controller) was probably impossible — the brand was too damaged. A ''cheap PS4 alternative'' would have lost the hardcore gamer to actual PS4. The hybrid form factor opened a third path that didn''t compete directly with either Sony or Microsoft.","predict":"Strong launch (Zelda carries it). Sustained demand through 2017 as more first-party titles roll out (Splatoon 2, Mario Odyssey, ARMS). Third-party titles slow to come but eventually fill in. Switch becomes Nintendo''s most successful console in 20+ years, structurally lifts Nintendo''s stock 5x, and rehabilitates the brand from the Wii U disaster. Long-term: the Switch is the canonical case in ''when betting on a radically different form factor pays off because the underlying first-party content is strong enough to support it.''"},"quote_type":"verbatim","sources":[{"title":"Nintendo Switch — Wikipedia","url":"https://en.wikipedia.org/wiki/Nintendo_Switch","type":"article"},{"title":"Nintendo Switch launches worldwide March 3","url":"https://www.nintendo.com/whatsnew/detail/2017/nintendo-switch-launches-worldwide-march-3-only-from-nintendo/","publisher":"Nintendo","year":2017,"type":"press-release"},{"title":"Nintendo Switch Revealed, Hybrid Console Coming in March 2017","url":"https://www.sonicstadium.org/2016/10/nintendo-switch-revealed-hybrid-coming-march-2017/","publisher":"Sonic Stadium","year":2016,"type":"article"}],"tags":{"industry":"gaming","region":"asia","decade":"2010s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'sony-ps3-launch-599-2006',
  'weekly',
  '{"id":"sony-ps3-launch-599-2006","type":"weekly","iso_week":"","company":"Sony","era":"2005 – November 11, 2006","intro":"It is 2005-2006. You are at Sony PlayStation. The PS2 has been the best-selling console of all time (~155M units). The next-gen console — PS3 — is in development with two strategic bets: (1) include a Blu-ray drive (Sony''s HD-disc format is competing with HD-DVD; PS3 will be Sony''s Trojan horse to win that format war), and (2) use the Cell processor (a custom multi-core chip jointly developed with IBM and Toshiba — incredibly powerful but extremely difficult for game developers to program for).\n\nThe combination of Blu-ray + Cell processor pushes the PS3''s bill of materials to ~$840 per unit. Sony has to subsidize hardware (selling at a loss, expecting to recoup via game royalties), but even subsidized, the launch price has to be unprecedented: $499 (20GB version) / $599 (60GB version). Xbox 360 launched a year earlier at $399. The Wii will launch a week later at $249. Sony bets that PlayStation brand loyalty + Blu-ray differentiation will support the premium.","open_questions":["Include Blu-ray (Sony''s format-war strategic asset, ~$200 BOM cost) or skip it (cheaper, more competitive console price)?","Cell processor (powerful but developer-hostile) vs. a more standard architecture (lower performance ceiling, broader third-party support)?","$599 launch price (highest console launch price ever, signals premium + format-war positioning) vs. $399 (matches Xbox 360, more competitive)?","Launch year — November 2006 (the planned date) or delay 6 months for better third-party software (lose the holiday window, miss Wii''s launch comparison)?"],"closing":"Imagine you''re at Sony in mid-2006. The PS3 launch is months away. The Blu-ray drive and Cell processor are locked in. The price decision has been finalized at $499/$599.","decision":"Launch PS3 on November 11, 2006 (Japan) and November 17, 2006 (North America) at $499 (20GB) / $599 (60GB). Include Blu-ray. Use the Cell processor. Sales are weak initially — the price gap vs. Xbox 360 is too wide, third-party games are mostly worse on PS3 than on Xbox 360 (because Cell is harder to develop for), and the Wii''s $249 launch a week later steals the casual market. Sony loses billions on hardware subsidies in the first 2-3 years. Blu-ray does win the format war (HD-DVD officially dies in February 2008), validating one strategic bet. PS3 sells ~87M lifetime — less than half PS2 but recovers eventually to be profitable. The launch is widely seen as PlayStation''s worst.","pullquote":"I''m not asking for $499. I''m asking for $599. And for the next ten years, you''ll wish you''d had it.","pullquote_attribution":"Ken Kutaragi, Sony PlayStation president — paraphrased from public commentary around the PS3 launch (2006)","outcomes":[{"stat":"$499 / $599","label":"launch prices — highest console launch ever at the time","accent":true},{"stat":"$840","label":"estimated BOM per PS3 unit at launch (Sony subsidizing each sale)"},{"stat":"$3.3B","label":"estimated cumulative hardware subsidy loss across first 2-3 years"},{"stat":"Feb 2008","label":"HD-DVD officially dies — Blu-ray wins the format war"},{"stat":"~87M lifetime","label":"PS3 units sold (less than half PS2''s 155M)"}],"tradeoffs":[{"title":"Blu-ray inclusion vs. standalone format war","body":"Including Blu-ray was the strategic move that won the format war for Sony — PS3 owners doubled as Blu-ray adopters overnight. The cost was severe: ~$200 in BOM and a launch price too high for many consumers. The bet paid off (Blu-ray won) but at multi-year cost to PlayStation''s market share."},{"title":"Cell processor vs. standard architecture","body":"Cell was technically extraordinary but developer-hostile. Cross-platform games (which were the majority of PS3''s library through 2008-2009) ran worse on PS3 than on Xbox 360 because developers couldn''t fully exploit Cell''s strengths without rewriting their engines. The lesson stuck: PS4 (2013) returned to standard x86 architecture for exactly this reason."},{"title":"$599 premium pricing vs. competitive pricing","body":"Pricing PS3 at $599 in a market where Xbox 360 was $399 and Wii was $249 made PS3 the ''too expensive'' option. Kutaragi''s public defense (the famous ''$599 and you''ll wish you''d had it'' line) compounded the brand damage — Sony was perceived as out of touch with consumer expectations. Lower pricing would have meant deeper subsidies in the short term but probably faster install-base growth."},{"title":"Launch on schedule vs. delay 6 months","body":"Launching in November 2006 hit the holiday window but ahead of the third-party game library. Delaying to spring 2007 would have shipped with better launch titles but missed the format-war urgency (HD-DVD was already shipping). Sony chose the strategic-urgency window."}],"per_dimension_truth":{"tradeoff":"Format-war victory (Blu-ray) + premium positioning + technical ambition (Cell) vs. install-base growth + developer ecosystem + price competitiveness. Sony chose strategic bets over market-share defense. The format war was won; the install-base war for that generation was lost to Wii (~100M) and ultimately Xbox 360 stayed competitive (~84M) despite launching a year earlier.","user":"The PS3''s intended user was the existing PS2 loyalist + the early-adopter willing to pay for HD entertainment. That market was real but smaller than Sony projected. The mass-market gamer of 2006 wasn''t ready to pay $599 for a console, regardless of the disc format.","alt":"Skipping Blu-ray, using a standard processor, and launching at $399 would have been the conservative path — matching Xbox 360 head-on. Sony would have lost the format war (HD-DVD might have won) but kept install-base parity. The opposite trade. Sony optimized for the long-term strategic asset (Blu-ray) over the short-term competitive position.","predict":"Weak launch (price-shock headlines, third-party games worse than Xbox 360). Slow ramp through 2007-2008. Blu-ray wins the format war in early 2008. PS3 install-base eventually recovers through price cuts and exclusive titles (Last of Us, Uncharted, God of War). Long-term: PS3 launch is the canonical case in ''when strategic ambition (Blu-ray, Cell) is the right call but the launch execution is brutal'' — and the lessons compound into PS4''s much more successful 2013 launch."},"quote_type":"paraphrased","sources":[{"title":"PlayStation 3 — Wikipedia","url":"https://en.wikipedia.org/wiki/PlayStation_3","type":"article"},{"title":"Sony Loses $3.3 Billion Through Three Years Of PlayStation 3 Subsidies","url":"https://www.gamesindustry.biz/sony-loses-usd3-3-billion-through-three-years-of-playstation-3-subsidies","publisher":"GamesIndustry.biz","type":"article"},{"title":"PlayStation 3 launches in North America","url":"https://www.cnet.com/tech/gaming/playstation-3-launches-in-north-america/","publisher":"CNET","year":2006,"type":"article"}],"tags":{"industry":"gaming","region":"asia","decade":"2000s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'bytedance-douyin-tiktok-split',
  'weekly',
  '{"id":"bytedance-douyin-tiktok-split","type":"weekly","iso_week":"","company":"ByteDance","era":"September 2016 – August 2018","intro":"It is mid-2016. You are at ByteDance, a Chinese AI / content-recommendation company that already owns the dominant Chinese news-aggregator app (Jinri Toutiao). Zhang Yiming, the founder, is convinced that short-form vertical video is the next major content format. ByteDance launches Douyin (抖音 — ''shaking sound'') in China in September 2016. The product is short-form vertical video with algorithmic For You feed. It explodes in China — by mid-2017, Douyin has ~100M+ active users in the Chinese market.\n\nZhang wants the same product internationally — but Chinese apps have historically failed in the West (WeChat tried, Weibo tried, all stuck at single-digit US market share). The ByteDance team faces a strategic decision: launch Douyin globally (one product, one brand, China-and-West unified) or fork into two products (Douyin for China only, a separate international brand for the rest of the world). They choose the fork. ByteDance acquires Musical.ly (a Chinese-founded but US-focused lip-syncing app, popular with US teens) for ~$800M-1B in November 2017, then merges Musical.ly into a new global product called TikTok in August 2018.","open_questions":["One product globally (Douyin) vs. two products separated by geography (Douyin for China, TikTok for international)?","Build a Western competitor from scratch vs. acquire an existing US-popular competitor (Musical.ly)?","Migrate Musical.ly users to TikTok (smooth transition, brand confusion) vs. leave them on Musical.ly indefinitely (clearer brand, slower path to scale)?","How visibly to associate TikTok with its Chinese parent — full transparency (ByteDance branding everywhere) vs. quietly separate (downplay the Chinese parent to reduce political headwinds in the West)?"],"closing":"Imagine you''re at ByteDance in mid-2018. The Musical.ly acquisition closed last fall. The decision to merge Musical.ly into TikTok is being finalized.","decision":"Merge Musical.ly into TikTok on August 2, 2018 — Musical.ly users wake up to find the app rebranded as TikTok, with their accounts, followers, and content intact. Maintain Douyin as a separate product for China (with separate algorithm, separate content moderation, separate features that comply with Chinese regulations). De-emphasize the ByteDance corporate branding in international marketing — TikTok presents as its own brand. The two products share core technology (recommendation algorithm, video infrastructure) but otherwise operate independently. By 2020 TikTok hits 800M+ MAU globally; Douyin hits 600M+ MAU in China alone. Combined, they become the most valuable consumer-app franchise built in the last decade.","pullquote":"Combining musical.ly and TikTok is a natural fit. The combined platform will give users a chance to express themselves in new ways and discover content from creators all over the world.","pullquote_attribution":"Alex Zhu, Musical.ly cofounder / ByteDance executive — TikTok merger announcement, August 2018","outcomes":[{"stat":"$800M-1B","label":"Musical.ly acquisition price (Nov 2017)","accent":true},{"stat":"Aug 2, 2018","label":"Musical.ly users wake up to TikTok-branded app"},{"stat":"800M MAU","label":"TikTok users globally by 2020 (5 years after Douyin''s China launch)"},{"stat":"600M MAU","label":"Douyin users in China alone by 2020"},{"stat":"Two separate apps","label":"Douyin (China) and TikTok (everywhere else) — same core algo, different products"}],"tradeoffs":[{"title":"Fork into two products vs. one global brand","body":"Forking required maintaining two products in parallel — double the engineering, double the content-moderation infrastructure, double the brand-management cost. The benefit: each product could optimize for its market''s regulations and user expectations. China and the West have fundamentally different content rules (different censorship requirements, different ad regulations, different e-commerce integrations). A single global product would have been crippled by trying to comply with both."},{"title":"Acquire Musical.ly vs. build from scratch","body":"Musical.ly had ~100M US-popular users — primarily US teens. Acquiring them via $800M-1B compressed years of organic growth into one transaction. Building from scratch would have meant ByteDance needed to overcome the ''Chinese app in the US'' headwind that historically broke every Chinese consumer app''s Western expansion. Musical.ly was already through that barrier."},{"title":"Migrate Musical.ly users to TikTok vs. preserve separate brand","body":"The forced rebrand on August 2, 2018 — Musical.ly''s millions of users woke up to find their app was now TikTok — could have triggered backlash. ByteDance bet that the brand change was tolerable because the users'' content, followers, and identity carried over seamlessly. The bet worked, but it required execution that left no broken accounts or lost content."},{"title":"Highlight ByteDance corporate parent vs. quiet separation","body":"Aggressively branding TikTok as a ByteDance product would have made the Chinese parentage prominent. ByteDance instead let TikTok present as its own brand. The strategic motivation: reduce political pressure from US / UK / EU regulators concerned about a Chinese-owned consumer-data platform. The strategy worked for years; eventually the political pressure caught up (2024 US TikTok-divestiture law)."}],"per_dimension_truth":{"tradeoff":"Maintaining two products in parallel + acquiring an existing US-popular brand + downplaying Chinese parentage vs. one global product + organic growth + transparent ByteDance branding. ByteDance chose the operationally complex but strategically superior path. The forked structure let Douyin / TikTok become the dominant short-form video platform globally without being broken by regulatory mismatches.","user":"TikTok served the Western teen — the cohort Musical.ly had already attracted. Douyin served the Chinese mass-market — a different cohort with different content patterns, different commerce expectations, different platform integration needs. The fork let each product optimize for its specific user without compromise.","alt":"Launching Douyin internationally as one product would have been simpler but almost certainly failed in the West (every other Chinese consumer-app launch has). The opposite trade — and the entire $50B+ TikTok valuation traces to ByteDance avoiding it.","predict":"Smooth Musical.ly → TikTok migration in August 2018. TikTok compounds through 2019-2020, especially during COVID lockdowns. Douyin grows independently in China. Regulatory pressure in the West eventually builds (2020 Trump executive orders, 2024 divestiture law). Long-term: the Douyin/TikTok split is the canonical case in ''how a Chinese consumer product navigates Western expansion by forking, acquiring, and quietly separating from its parent.'' The structural separation is what made TikTok possible — and what makes the divestiture politically possible too."},"quote_type":"verbatim","sources":[{"title":"TikTok — Wikipedia","url":"https://en.wikipedia.org/wiki/TikTok","type":"article"},{"title":"ByteDance to merge Musical.ly into TikTok","url":"https://techcrunch.com/2018/08/02/musical-ly-tiktok-merger/","publisher":"TechCrunch","year":2018,"type":"article"},{"title":"Douyin — Wikipedia","url":"https://en.wikipedia.org/wiki/Douyin","type":"article"}],"tags":{"industry":"consumer-social","region":"asia","decade":"2010s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'sony-bmg-rootkit-2005',
  'weekly',
  '{"id":"sony-bmg-rootkit-2005","type":"weekly","iso_week":"","company":"Sony BMG Music Entertainment","era":"October–November 2005","intro":"It is mid-2005. You are at Sony BMG Music Entertainment, the world''s second-largest music label. The label is in active panic about piracy — Napster''s successors (LimeWire, BitTorrent) are wreaking havoc on CD sales. Sony BMG''s solution: include copy-protection software on every commercial CD sold. Specifically, two technologies — Extended Copy Protection (XCP) from a UK firm called First4Internet, and MediaMax CD-3 from SunnComm — both of which silently install a rootkit on the user''s PC when the CD is played on Windows. The rootkit prevents copying and is essentially undetectable and uninstallable by ordinary users.\n\nThe technology ships on ~50 album titles starting in 2005 — including widely-purchased records by Celine Dion, Foo Fighters, Van Zant, Neil Diamond. Users have no warning that inserting a music CD will modify their operating system. The label''s leadership believes the protection is necessary and within their rights.","open_questions":["Use the XCP rootkit (effective DRM, hidden user modification) vs. a less aggressive watermarking approach (less effective DRM, no OS modification)?","Disclose the DRM clearly on the CD packaging (transparency, reduces user surprise but signals ''this disc is restricted'') or bury in the EULA (hides the friction but invites discovery + outrage)?","How visible should opt-out be — full uninstaller available (defeats the DRM purpose) or no uninstaller at all (locks user into the modification)?","What''s the right legal posture if security researchers find the rootkit — defend it as legitimate DRM (signals confidence) or distance from the vendor that made it (preserves Sony BMG''s reputation)?"],"closing":"Imagine you''re at Sony BMG in late October 2005. Mark Russinovich (a Microsoft engineer + security blogger) has just publicly written about discovering an undisclosed rootkit on his PC after playing a Van Zant CD.","decision":"On October 31, 2005, security researcher Mark Russinovich publishes ''Sony, Rootkits and Digital Rights Management Gone Too Far'' — revealing the XCP rootkit on Sony BMG CDs. The post goes viral; tech-press picks it up within hours. Sony BMG''s initial response: denial + minimization (''it isn''t a rootkit,'' a top exec says ''most people don''t even know what a rootkit is, so why should they care about it?''). Within 2 weeks, the situation escalates: anti-virus companies classify the rootkit as malware, multiple class-action lawsuits are filed, the Department of Homeland Security and state AGs investigate. Sony BMG recalls ~5M CDs worldwide, releases a (broken, then fixed) uninstaller, and eventually settles class-action lawsuits for ~$5.75M plus customer restitution. The label''s reputation is permanently damaged.","pullquote":"Most people, I think, don''t even know what a rootkit is, so why should they care about it?","pullquote_attribution":"Thomas Hesse, Sony BMG Global Digital Business president — NPR interview, November 4, 2005","outcomes":[{"stat":"~5M CDs","label":"recalled worldwide once the rootkit was exposed","accent":true},{"stat":"Oct 31, 2005","label":"Mark Russinovich''s discovery published — viral within hours"},{"stat":"$5.75M+","label":"class-action settlement plus customer restitution"},{"stat":"DHS + AGs","label":"investigated; Texas filed state AG suit; FTC settled separately"},{"stat":"Reputation","label":"Sony BMG label permanently associated with consumer-hostile DRM"}],"tradeoffs":[{"title":"Rootkit-level DRM vs. less aggressive protection","body":"The XCP rootkit was effective at preventing copying but only because it operated at a level deeper than the user could see or remove. The technical effectiveness required hiding from the user — which converted DRM from ''rights management'' into ''unauthorized system modification.'' Less aggressive watermarking would have been less effective but wouldn''t have crossed the legal line."},{"title":"EULA-hidden vs. clearly labeled DRM","body":"Disclosing the DRM on the CD packaging would have warned users — and likely reduced sales, since informed buyers wouldn''t accept the modification. Hiding it in the EULA preserved sales velocity but made the eventual discovery a betrayal-of-trust story rather than a ''they told me and I bought it anyway'' story."},{"title":"Hesse''s ''why should they care'' framing vs. apology","body":"Sony BMG''s initial public response (Thomas Hesse''s NPR interview) dismissed user concerns. The framing went viral as ''Sony thinks you''re too dumb to understand they hacked your PC.'' Apology + immediate uninstaller would have contained the story to ~2 weeks. The dismissive framing extended the story to months and made it the canonical example of corporate-DRM arrogance."},{"title":"Defend XCP vs. distance from First4Internet","body":"Sony BMG could have framed XCP as ''a third-party vendor''s tool that we used and now regret.'' Instead, leadership initially defended the rootkit as legitimate. By the time they reversed course (recalling CDs, releasing the uninstaller), the brand cost had compounded. Earlier distancing would have been less honest but cheaper."}],"per_dimension_truth":{"tradeoff":"Effective DRM (rootkit installation on user PCs) vs. user trust + legal compliance + brand reputation. Sony BMG chose effective DRM and paid for it with multi-year reputational damage, class-action settlements, regulatory scrutiny, and the labels'''' permanent association with consumer-hostile DRM. The rootkit didn''t even meaningfully reduce piracy — by 2005, music piracy had migrated to MP3 sharing, where the rootkit was irrelevant.","user":"The user the DRM was protecting against (the pirate) wasn''t actually the user being harmed — the harmed user was the legitimate customer who bought the CD legally, played it on their PC, and unknowingly received malware. The DRM hit the customer cohort it was supposed to defend.","alt":"Skipping DRM entirely and accepting CD-piracy losses (which was the inevitable outcome anyway) would have preserved Sony BMG''s brand and avoided the lawsuits. The opposite trade — and almost certainly the right call. The DRM didn''t stop piracy; the actual industry transition was to legal digital downloads (iTunes Store, launched 2003 by Apple), which required Sony BMG to embrace digital distribution, not lock down physical media.","predict":"Russinovich''s post goes viral. Anti-virus companies flag the rootkit. Class actions follow. State AGs investigate. Sony BMG eventually recalls and settles. The case becomes a permanent reference point in tech journalism for ''DRM gone wrong.'' Long-term: the rootkit incident accelerates the music industry''s transition to DRM-free digital distribution (iTunes Plus DRM-free launches 2007), partly because the incident made aggressive DRM publicly toxic. The case is taught in every tech-ethics and DRM curriculum for the next two decades."},"quote_type":"verbatim","sources":[{"title":"Sony BMG copy protection rootkit scandal — Wikipedia","url":"https://en.wikipedia.org/wiki/Sony_BMG_copy_protection_rootkit_scandal","type":"article"},{"title":"Sony, Rootkits and Digital Rights Management Gone Too Far","url":"https://learn.microsoft.com/en-us/archive/blogs/markrussinovich/sony-rootkits-and-digital-rights-management-gone-too-far","publisher":"Mark Russinovich","year":2005,"type":"blog"},{"title":"Sony BMG CD copy-protection scandal: A look back","url":"https://www.cnet.com/tech/tech-industry/sony-bmg-cd-copy-protection-scandal-a-look-back/","publisher":"CNET","type":"article"}],"tags":{"industry":"media","region":"asia","decade":"2000s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'klarna-us-expansion-2019',
  'weekly',
  '{"id":"klarna-us-expansion-2019","type":"weekly","iso_week":"","company":"Klarna","era":"2015 – 2022 — US market entry and BNPL boom","intro":"It is mid-2015. You are at Klarna, the Swedish BNPL (buy-now-pay-later) company. Klarna has been dominant in the Nordic e-commerce market for ~10 years. The US market is structurally different: US consumers use credit cards (which already provide ''buy now, pay later'' via revolving balances), the US doesn''t use invoice-based payment culture like Nordic countries, and the BNPL competitor space in the US is already populated (Affirm launched in 2012, Afterpay is Australia-based and expanding). Klarna decides to enter the US market.\n\nThe key strategic question for Klarna''s US launch: how to grow when US consumers already have credit cards and don''t have the ''pay-after-delivery'' cultural muscle that European users have. The product team adopts a Pinterest-style growth strategy — visual shopping content, influencer partnerships, free shipping promotions, and a fashion-first brand position that targets Gen Z and Millennial women. The launch is slow, then accelerates through 2019-2022 as BNPL becomes a category-defining trend during the COVID e-commerce boom.","open_questions":["Position Klarna as ''a credit card alternative'' (compete on financial product) vs. ''a fashion / lifestyle brand'' (compete on consumer-brand affinity)?","Compete head-on with Affirm + Afterpay (price + features) vs. differentiate on consumer-brand and merchant network?","Aggressive merchant-side BD (sign up retailers, prioritize Shopify integration) vs. consumer-side marketing (build the demand, let merchants come to us)?","Add savings / banking features on top of BNPL (broaden the financial relationship) or stay focused on the checkout-payment moment (narrower product, clearer pitch)?"],"closing":"Imagine you''re at Klarna in 2019-2020. The US market is taking off — BNPL is becoming a real category. The COVID e-commerce surge is driving demand. Klarna''s US growth has accelerated.","decision":"Position Klarna in the US as ''shop now, pay later, but make it Instagram-able.'' Build a fashion-influencer-driven content engine. Partner with US retailers (H&M, Sephora, Macy''s, Foot Locker, eventually Walmart). Lean into product Hunt-style brand-as-lifestyle marketing. Add savings + banking-adjacent features to deepen the relationship. By 2021 Klarna hits ~$45.6B private valuation. Through 2022-2023 BNPL faces a reckoning: regulatory scrutiny over consumer-debt risks, charge-off rates rising, valuations cratering across the category. Klarna''s valuation drops to ~$6.7B in mid-2022. By 2024-2025 Klarna recovers, IPOs successfully on NYSE in September 2025 at ~$15B.","pullquote":"Klarna is not just a payment method — it''s a brand, a lifestyle, a way of shopping. We compete with credit cards on the price; we compete with consumer brands on the relationship.","pullquote_attribution":"Sebastian Siemiatkowski, Klarna cofounder/CEO — paraphrased from public Sequoia + Acquired interviews","outcomes":[{"stat":"$45.6B → $6.7B","label":"private valuation peak (Jun 2021) to trough (Jul 2022)","accent":true},{"stat":"Sep 2025","label":"Klarna IPO on NYSE at ~$15B valuation"},{"stat":"150M+ users","label":"Klarna global active customers by 2024"},{"stat":"Fashion / Gen Z","label":"Klarna''s US positioning — different from European invoice-based approach"},{"stat":"Walmart partnership","label":"Klarna replaces Affirm as Walmart''s BNPL partner (Aug 2024) — major US milestone"}],"tradeoffs":[{"title":"Brand-as-lifestyle vs. brand-as-financial-product","body":"Most BNPL competitors (Affirm, Afterpay) positioned as financial-product-first. Klarna chose brand-as-lifestyle, marketing through fashion influencers and content. The lifestyle positioning produced stronger consumer affinity but slower B2B credibility — some retailers viewed Klarna as a marketing partner first, financial-services partner second."},{"title":"Add banking features vs. stay focused on BNPL","body":"Adding savings accounts + banking-adjacent products (Klarna Bank in Europe) extended the relationship but added regulatory complexity. The expanded product made Klarna a target for more regulatory scrutiny (especially during the 2022-2023 BNPL crackdown). Competitors stayed narrower; Klarna''s broader approach paid off long-term but cost short-term focus."},{"title":"Aggressive merchant BD vs. consumer-pull","body":"Signing up tier-one US retailers (Walmart, H&M, Sephora) required intense BD efforts and aggressive commercial terms. The merchant network is the structural moat; without merchants, BNPL doesn''t work. Klarna invested heavily here and outperformed competitors in tier-one US retailer adoption."},{"title":"Aggressive growth at 2021 ZIRP valuations vs. discipline","body":"Raising at $45.6B in mid-2021 was a peak-ZIRP move. The valuation cratered to $6.7B by mid-2022 as fintech multiples compressed. A more disciplined funding strategy would have been less ambitious but avoided the public valuation reset. Klarna chose to push for the high valuation and absorbed the public reset."}],"per_dimension_truth":{"tradeoff":"Aggressive growth + brand-as-lifestyle + multi-product expansion + high ZIRP-era valuation vs. focused payment-product + measured growth + lower-volatility valuations. Klarna chose growth and brand-building; survived the 2022-2023 BNPL valuation crash; emerged as the largest BNPL brand globally by 2025. The choices were right strategically; the public valuation volatility was the cost.","user":"The Gen Z / Millennial woman shopping on H&M, Sephora, and Walmart became Klarna''s anchor US customer. The product wasn''t ''I need credit'' — it was ''I want to manage my fashion spend across paychecks, with content recommendations and a brand I trust.'' The user''s frame of reference was Instagram, not Visa.","alt":"Positioning as a pure financial-product (like Affirm) would have been clearer but smaller — Affirm''s market cap in 2025 is roughly comparable to Klarna''s but with less consumer-brand affinity. Klarna''s choice to compete on brand bought a moat against pure financial-product competitors.","predict":"Slow initial US launch, accelerates 2019-2022 with BNPL boom. Peak valuation in mid-2021 ($45.6B). Valuation crashes through 2022 with broader fintech compression. Recovers through 2023-2024 as BNPL category matures. IPOs successfully in September 2025 at ~$15B. Long-term: Klarna becomes the canonical case in ''a non-US fintech that successfully enters the US through brand positioning rather than financial-product superiority.''"},"quote_type":"paraphrased","sources":[{"title":"Klarna — Wikipedia","url":"https://en.wikipedia.org/wiki/Klarna","type":"article"},{"title":"Klarna IPO Filing Reveals the BNPL Giant''s Strategy","url":"https://www.bain.com/insights/klarnas-ipo-filing-reveals-the-bnpl-giants-strategy/","publisher":"Bain & Company","type":"article"},{"title":"Klarna''s valuation crashed from $45.6 billion to $6.7 billion in a year","url":"https://www.cnbc.com/2022/07/11/klarna-valuation-crashes-to-6point7-billion-from-45point6-billion.html","publisher":"CNBC","year":2022,"type":"article"}],"tags":{"industry":"fintech","region":"eu","decade":"2020s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'apple-homepod-launch-2018',
  'weekly',
  '{"id":"apple-homepod-launch-2018","type":"weekly","iso_week":"","company":"Apple","era":"February 9, 2018 — HomePod launch","intro":"It is mid-2017. You are at Apple. Amazon Echo has been on the market for ~3 years; Alexa is the dominant voice assistant in US homes. Google Home launched in 2016 and is gaining share. Both Echo and Home are priced at $99-179 — positioned as voice assistants that happen to play music. Apple''s product is the opposite: HomePod, a $349 premium smart speaker focused on music quality, with Siri as a secondary feature. The hardware is genuinely impressive — A8 chip for room-adapting sound, 7 tweeters, custom subwoofer. Siri is functional but materially behind Alexa and Google Assistant for general queries.\n\nLaunch is set for February 9, 2018 at $349. Apple is betting that the music-quality differentiation justifies the 2-3x price premium. The bet assumes audiophile-leaning customers exist and will choose Apple Music + iPhone integration + sound quality over Alexa''s smart-home ecosystem.","open_questions":["Position as ''premium music speaker'' (narrow audience, defensible differentiation) or ''smart speaker with great sound'' (broader audience, competes head-on with Echo)?","$349 premium vs. $149 mass-market — is the music-quality differentiation enough to support 2-3x Echo''s price?","Siri''s gap vs. Alexa / Google Assistant — accept the gap (focus on music) or delay launch to close it (lose holiday window, miss launch momentum)?","Apple Music exclusivity (HomePod can''t stream Spotify natively at launch) — limits the audience but reinforces ecosystem control?"],"closing":"Imagine you''re at Apple in late 2017. HomePod is months from launch. The $349 price and Apple Music exclusivity are locked in. Siri is behind the competition.","decision":"Launch HomePod on February 9, 2018 at $349. Position as a premium music speaker. Apple Music exclusive (no native Spotify until June 2024). Siri capabilities deliberately limited compared to Alexa. The launch sells well at first (initial demand for any new Apple product), but sales plateau within months. Apple cuts the price to $299 in April 2019. In March 2021 — 3 years after launch — Apple discontinues the original HomePod. Sells HomePod mini at $99 ($349 → $99 within 2 years). In January 2023, Apple revives HomePod with a 2nd-gen at $299 (lower than original, higher than mini). HomePod is widely viewed as Apple''s weakest hardware product since the Pippin gaming console (1996).","pullquote":"HomePod represents the next generation of smart speakers, bringing the very best of Apple''s home audio innovation to the home.","pullquote_attribution":"Tim Cook, Apple CEO — HomePod launch announcement, January 2018","outcomes":[{"stat":"$349 → $99 mini","label":"original HomePod price + much-cheaper HomePod mini introduced","accent":true},{"stat":"Mar 2021","label":"original HomePod discontinued 3 years after launch"},{"stat":"<5%","label":"estimated US smart-speaker market share at peak (vs. Amazon 70%+)"},{"stat":"Jun 2024","label":"Spotify finally added as native HomePod option — 6+ years after launch"},{"stat":"Jan 2023","label":"HomePod 2nd gen relaunched at $299"}],"tradeoffs":[{"title":"Premium music speaker vs. smart speaker for the mass market","body":"Positioning as a music speaker first narrowed the audience (audiophiles + Apple Music subscribers) but defended differentiation. Positioning as a smart speaker would have invited head-on comparison with Echo, where Siri was clearly behind. Apple chose the narrower market — but the narrower market turned out to be too small to justify the hardware investment."},{"title":"$349 premium vs. mass-market pricing","body":"$349 was 2-3x Echo''s price. The premium signaled audiophile positioning but limited the addressable market. A $149 launch would have competed head-on with Echo at scale but at much lower margins. Apple chose the premium-with-narrow-audience path and the audience didn''t materialize at the volume needed."},{"title":"Apple Music exclusive vs. open music streaming","body":"Locking HomePod to Apple Music (no Spotify) reinforced ecosystem control. The cost: Spotify is dominant in music streaming globally, and Spotify users wouldn''t buy a speaker that couldn''t play their existing music. Spotify support finally arrived in June 2024 — 6+ years after launch — after Apple''s strategic position had eroded."},{"title":"Accept Siri gap vs. delay launch","body":"Siri''s capabilities at HomePod launch were materially worse than Alexa''s for general queries. Apple chose to ship anyway with a narrowed feature set (''music control + HomeKit + basic queries''). Delaying would have lost the launch window but addressed the most-criticized weakness. Apple''s bet: Siri would close the gap over time. The gap is still real in 2025."}],"per_dimension_truth":{"tradeoff":"Defending Apple''s premium / music-quality / ecosystem-control story vs. competing for the mass smart-speaker market against Echo. Apple chose differentiation; the differentiation didn''t justify the price for enough customers, and the smart-speaker market consolidated around Amazon and Google. HomePod mini ($99) is now Apple''s volume product, validating that the original $349 price was wrong for the category.","user":"The original HomePod served the audiophile + Apple-ecosystem + Apple Music subscriber — a real but small overlap audience. The Echo / Home buyer (mass-market voice-assistant + smart-home user) wasn''t Apple''s target. The narrowness of the target turned out to be the failure mode.","alt":"Launching HomePod at $149-179 head-on against Echo would have been a more competitive bet — Apple''s distribution would have given the product a higher share of the smart-speaker market. The opposite trade. With hindsight, the $99 HomePod mini (launched October 2020) is essentially this alternative, and it has been Apple''s most successful smart speaker.","predict":"Strong initial demand from Apple-loyal early adopters. Sales plateau within 6 months. Mixed-to-negative reviews focus on Siri gap, Apple Music exclusivity, and price. Apple cuts price to $299 (April 2019). Apple ships HomePod mini at $99 (October 2020). Original HomePod discontinued (March 2021). 2nd-gen HomePod revived at $299 (January 2023). Long-term: HomePod is the canonical case in ''Apple''s premium-positioning playbook failing when applied to a commoditizing consumer-electronics category.''"},"quote_type":"verbatim","sources":[{"title":"Apple HomePod launches at $349 — Tim Cook''s smart-speaker push","url":"https://www.apple.com/newsroom/2018/01/homepod-arrives-february-9-available-to-order-this-friday/","publisher":"Apple Newsroom","year":2018,"type":"press-release"},{"title":"HomePod — Wikipedia","url":"https://en.wikipedia.org/wiki/HomePod","type":"article"},{"title":"Apple kills original HomePod after 3 years","url":"https://www.cnbc.com/2021/03/12/apple-stops-making-the-original-homepod-after-three-years.html","publisher":"CNBC","year":2021,"type":"article"}],"tags":{"industry":"hardware","region":"us","decade":"2010s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'google-pixel-launch-2016',
  'weekly',
  '{"id":"google-pixel-launch-2016","type":"weekly","iso_week":"","company":"Google (Alphabet)","era":"October 4, 2016 — Pixel launch","intro":"It is mid-2016. You are at Google. The Nexus program (Google''s collaboration with OEM partners to ship ''reference Android phones'') has been running for 6 years — Nexus phones are loved by Android purists but sell in low single-digit-million units annually. Google decides to end the Nexus program and build its own first-party flagship phone, fully Google-designed (with HTC as the manufacturing partner for the first generation). The Pixel will compete directly with iPhone and Samsung Galaxy — same price tier ($649 starting), same flagship features (top camera, top processor).\n\nThe key strategic decision: Google has spent a decade as the Android OS provider. Becoming a phone OEM puts Google in direct competition with Samsung, LG, Motorola, HTC — its largest Android partners. The Nexus program had been a partnership; Pixel is competition.","open_questions":["Continue Nexus partnership program (low-volume, OEM-partner-led) vs. fully Google-designed Pixel (high-volume ambition, partner conflict)?","Price at $649 (compete with iPhone / Galaxy on price) vs. $399 (mass-market, force OEMs to compete on price)?","Manufacturing partner (HTC for gen 1) vs. acquire HTC''s hardware team outright (gain capability, commit fully)?","How aggressive on Samsung — directly criticize Samsung''s Android customizations in marketing (signal independence, alienate partners), or stay neutral?"],"closing":"Imagine you''re at Google in mid-2016. Pixel launches in months. The relationship with Samsung is about to get strained.","decision":"Launch Pixel on October 4, 2016 at $649. Marketed heavily on camera quality (HDR+ computational photography). Manufactured by HTC; the design and software are fully Google. Launch follows by a January 2018 acquisition of HTC''s design and engineering team for $1.1B — Google takes the people, leaves HTC with the brand. Pixel sales remain low single-digit-million units annually for years — never threatens Samsung''s Galaxy line. Pixel becomes Google''s hardware learning curve: 9 generations later (Pixel 9, 2024), Pixel still has <3% global smartphone market share but has shipped category-defining features (Now Playing, Magic Eraser, Tensor chip) that subsequently appear on Android broadly.","pullquote":"Pixel is the first phone made by Google, inside and out. We''re combining the best of Google software, hardware, and the best of Google AI to give users a phone that lasts.","pullquote_attribution":"Sundar Pichai, Google CEO — Pixel launch announcement, October 4, 2016","outcomes":[{"stat":"$649","label":"Pixel launch price (matched iPhone 7 / Galaxy S7)","accent":true},{"stat":"$1.1B","label":"Google acquisition of HTC''s design / engineering team (Jan 2018)"},{"stat":"<3%","label":"Pixel''s global smartphone market share even by 2024 (9 generations in)"},{"stat":"Tensor","label":"Google''s custom phone SoC introduced in Pixel 6 (2021) — own silicon"},{"stat":"Reference device","label":"Pixel became the hardware testbed for Google''s AI / camera-software innovations"}],"tradeoffs":[{"title":"Compete with Samsung vs. preserve partner ecosystem","body":"By making Pixel, Google became a competitor to its largest Android partner (Samsung). The strategic gain: a phone Google could ship its best software on without OEM customizations. The cost: Samsung''s Galaxy line continued to dominate Android (~30%+ of all Android phones), and the partner-vs-competitor tension persists. Google accepted the strain because the alternative (let Samsung define Android''s customer experience) was strategically worse."},{"title":"Price as flagship vs. price as challenger","body":"$649 was the iPhone tier — a confident price for a brand-new phone line. Pricing at $399 would have undercut every flagship and gained market share faster. Google chose to position Pixel as a premium product, accepting the slow ramp and the multi-year market-share gap. The premium positioning preserved margin per unit but limited reach."},{"title":"Manufacturing partner vs. own manufacturing","body":"HTC manufactured the first Pixel; Google acquired HTC''s team in 2018. The acquisition gave Google in-house hardware design capability without buying the HTC brand (which had little remaining value). The trade: pay $1.1B for capability that could have been built organically over years. Google chose the faster path."},{"title":"Pixel as commercial product vs. Pixel as reference device","body":"The Pixel''s commercial unit-share has stayed low for 9 generations. But Pixel''s strategic role (the testbed for Google''s AI / camera innovations that then ship to all Android OEMs) has compounded. Magic Eraser, Now Playing, Tensor — these are platform-level features Google can launch on Pixel first, then push to other Android phones via the Play services + Android OS updates."}],"per_dimension_truth":{"tradeoff":"Owning the Android reference hardware (gives Google direct control over camera, AI, UX) vs. maintaining clean partnerships with Samsung / LG / Motorola. Google chose ownership; the partner strain is real but tolerable. Pixel hasn''t been a commercial smartphone success, but it has been a strategic success — the testbed for innovations Google then ships across Android.","user":"The Pixel buyer is the Android-purist + photography-enthusiast — overlapping cohorts that genuinely want Google''s vision of Android, not Samsung''s customizations. That cohort is small but durable. The mass-market Android user picks based on carrier subsidies and price, where Samsung''s distribution is dominant.","alt":"Continuing the Nexus partnership program would have preserved Samsung relationships but ceded control of the flagship Android experience. The opposite trade — and probably the wrong call. Pixel''s role in pulling Android''s UX forward (camera, AI, on-device ML) has been worth more than the partner-relationship preservation it cost.","predict":"Solid initial launch sales among Android purists. Sales plateau quickly. Multi-year low single-digit-million-units pattern. Pixel becomes Google''s hardware learning curve. By generation 6+ (Pixel 6, 2021), Google ships Tensor chip and the hardware story gets stronger. Long-term: Pixel is the canonical case in ''when commercial market-share isn''t the right metric — strategic-platform-control is.'' The Pixel''s value to Google has always been platform-shaping, not direct revenue."},"quote_type":"verbatim","sources":[{"title":"Pixel, Phone by Google","url":"https://blog.google/products/pixel/pixel-by-google/","publisher":"Google Blog","year":2016,"type":"blog"},{"title":"Pixel (1st generation) — Wikipedia","url":"https://en.wikipedia.org/wiki/Pixel_(1st_generation)","type":"article"},{"title":"Google to acquire HTC''s design and engineering team for $1.1 billion","url":"https://www.cnbc.com/2017/09/20/google-to-acquire-htc-pixel-team-for-1-point-1-billion.html","publisher":"CNBC","year":2017,"type":"article"}],"tags":{"industry":"consumer-mobile","region":"us","decade":"2010s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'oculus-quest-standalone-vr-2019',
  'weekly',
  '{"id":"oculus-quest-standalone-vr-2019","type":"weekly","iso_week":"","company":"Meta (Oculus)","era":"May 21, 2019 — Oculus Quest launch","intro":"It is mid-2018. You are at Oculus (the Meta-owned VR company). VR after 4 years has stalled commercially. The dominant VR experiences (Oculus Rift, HTC Vive) require a $1000+ gaming PC plus a $400-600 headset plus external sensors plus messy cable setup. Total cost of entry: ~$1,500-2,000, plus a 30-minute setup, plus a dedicated VR space. Result: VR is stuck at ~5M total Rift+Vive users globally after 3 years on the market.\n\nOculus has been working on the Quest — a fully standalone headset that runs games entirely on the headset''s own processor (a phone-class Snapdragon chip), with no PC, no cables, no external sensors (the headset uses 4 outward-facing cameras for inside-out tracking). Launch price target: $399. The Quest hardware is technically modest by VR-PC standards — but it has no PC dependency and works out of the box in 60 seconds. Launch is set for May 21, 2019.","open_questions":["Standalone VR with mobile-class chip (lower performance, broader audience) vs. PC-tethered (better experience, narrower audience)?","$399 price target — make-or-break for mass adoption, but tight margins on a phone-class device with custom inside-out tracking?","Compatible with existing Oculus Rift game library (broader content, but performance compromises) or standalone game ecosystem (fewer games, native-quality experiences)?","How aggressive on social / Facebook-integration features at launch (the Meta-acquired Oculus has been pushed toward social, but VR users hate it) — or stay focused on gaming?"],"closing":"Imagine you''re at Oculus / Meta in early 2019. Quest launches in months. The standalone approach is unprecedented at this performance level. The price is locked.","decision":"Launch Oculus Quest on May 21, 2019 at $399 (64GB) / $499 (128GB). Standalone — no PC required. Inside-out tracking via 4 cameras (no external sensors). Independent content library + Oculus Link (announced later that year) for connecting to a PC for higher-end VR content. Quest sells out immediately, becomes the fastest-selling VR headset ever. In October 2020 Meta ships Quest 2 at $299 (cheaper than Quest 1) with better hardware and a controversial Facebook-account requirement. By 2024 Meta has sold ~20M+ Quest headsets — more than all prior VR platforms combined. The standalone form factor becomes the industry''s dominant VR form.","pullquote":"Oculus Quest is the first all-in-one gaming system built for virtual reality. You can now connect to virtual experiences without the limitations of cables or the requirements of a PC.","pullquote_attribution":"Oculus / Meta — Quest launch announcement, May 2019","outcomes":[{"stat":"$399","label":"Oculus Quest launch price — first standalone VR with no PC required","accent":true},{"stat":"Fastest-selling ever","label":"Quest was the fastest-selling VR headset on launch in 2019"},{"stat":"~20M+ headsets","label":"Quest line sold by 2024 (more than all prior VR combined)"},{"stat":"Inside-out tracking","label":"4 outward cameras, no external sensors needed"},{"stat":"Facebook account","label":"controversial Quest 2 requirement (Oct 2020) — caused backlash, later reversed (Aug 2022)"}],"tradeoffs":[{"title":"Standalone vs. PC-tethered VR","body":"Standalone meant lower performance (phone-class chip vs. desktop GPU) but no PC dependency. The trade: VR experiences would be visually weaker, but the addressable market would be 50-100x larger. Oculus chose addressable-market over visual quality. The bet paid off — by 2024 Quest''s volume has lifted the entire VR industry past PC-VR''s reach."},{"title":"$399 price vs. premium pricing","body":"$399 was the consumer-electronics impulse-purchase threshold. Higher pricing ($599 or $799) would have meant better margins but smaller volume. Oculus chose volume — and Meta absorbed the per-device subsidy because VR''s strategic value to Meta wasn''t unit economics, it was platform-defining."},{"title":"Inside-out tracking vs. external sensors","body":"Inside-out tracking (cameras on the headset facing outward) eliminates the messy external-sensor setup that crippled Rift / Vive. The trade: tracking accuracy is somewhat worse in low-light or fast-motion scenarios. Oculus accepted the tracking compromise because the setup-friction reduction was structurally more important."},{"title":"Facebook-account requirement (Quest 2) vs. independent account","body":"Requiring a Facebook account for Quest 2 (October 2020) was a strategic Meta integration move — but produced significant backlash from privacy-conscious VR users. Meta reversed the requirement in August 2022 (the new Meta account is separate from Facebook). The interim 18-month period was an unforced brand wound. Quest 1 didn''t require Facebook accounts; the change broke a tacit agreement with the existing user base."}],"per_dimension_truth":{"tradeoff":"Mass-market accessibility (standalone + $399 + inside-out tracking) vs. premium VR experience (PC-tethered + higher-end visuals + external sensors). Oculus chose accessibility and produced the first commercially-successful VR product line. Quest''s volume has lifted the VR industry from ~5M users (Rift+Vive era) to ~20M+ (Quest era).","user":"The Quest user is the casual-curious gamer who''d never have bought a $1,500 PC-VR setup. Quest opened VR to mainstream consumers — kids, parents, fitness users (Beat Saber, FitXR), social-VR users (Rec Room, VRChat). The PC-VR user is a small audience the industry now treats as an enthusiast tier above Quest.","alt":"Continuing the Rift-style PC-tethered approach would have kept VR a niche enthusiast product. The opposite trade — and almost certainly the wrong call. Sony PSVR2 (2023) and other PC-VR platforms remain commercially small; the Quest''s standalone approach has been the mainstream-VR path.","predict":"Strong launch, sustained demand, accelerated by COVID lockdowns (2020-2021). Facebook-account requirement controversy (2020-2022). Quest 2 launches at lower price ($299) and outsells Quest 1. Quest 3 (2023) refines the platform. By 2024 Quest is the de facto VR platform globally. Long-term: the Quest is the canonical case in ''when accepting performance compromises to remove friction is the right call'' — and the basis for Meta''s entire metaverse / AR strategy through 2030."},"quote_type":"verbatim","sources":[{"title":"Oculus Quest — Wikipedia","url":"https://en.wikipedia.org/wiki/Oculus_Quest","type":"article"},{"title":"Oculus Quest review: Standalone VR done right","url":"https://techcrunch.com/2019/04/30/oculus-quest-review/","publisher":"TechCrunch","year":2019,"type":"article"},{"title":"Mark Zuckerberg sees AR + VR as the next major computing platform","url":"https://about.fb.com/news/2019/05/oculus-quest-launch/","publisher":"Meta Newsroom","year":2019,"type":"press-release"}],"tags":{"industry":"hardware","region":"us","decade":"2010s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'stripe-atlas-launch-2016',
  'weekly',
  '{"id":"stripe-atlas-launch-2016","type":"weekly","iso_week":"","company":"Stripe","era":"February 2016 — Stripe Atlas launch","intro":"It is mid-2015. You are at Stripe. The company processes payments for ~100,000 businesses globally. Patrick and John Collison repeatedly hear from international founders that the hardest part of starting a US-targeted internet business isn''t building the product — it''s incorporating a US entity, getting a US bank account, paying US taxes, and getting access to Stripe (which only supports US-incorporated businesses). The friction stops countless promising international founders before they ever build.\n\nStripe''s product team prototypes ''Stripe Atlas'' — a service that bundles US incorporation (Delaware C-corp), US bank account (Silicon Valley Bank partnership), Stripe payment account, and a $5,000 cash credit for the new account — all for a flat $500 setup fee. Target market: international entrepreneurs who want to start a US-targeted online business without moving to the US first.","open_questions":["Bundle incorporation + banking + Stripe + cash credits (broad value, complex partnerships) vs. just incorporation (narrower but simpler)?","$500 setup fee (low friction, near break-even for Stripe) vs. higher pricing ($2,000+, signals premium service)?","Open to all international entrepreneurs (massive funnel) vs. invite-only at launch (quality control, easier to support)?","Position as ''a Stripe feature'' (extends the brand) vs. ''a standalone Atlas brand'' (clean line between payments and incorporation)?"],"closing":"Imagine you''re at Stripe in late 2015. Atlas is months from launch. The bank partnership is finalized. The product is unprecedented.","decision":"Launch Stripe Atlas on February 23, 2016. Bundled service: Delaware C-corp incorporation + SVB business bank account + Stripe payment account + $5,000 AWS credit + free Stripe processing on first $5,000 of payments. $500 flat setup fee. Invite-only at launch (early waitlist signals demand without overwhelming operations). Within a year, Atlas has helped incorporate 100+ companies from 50+ countries — companies that couldn''t have started a US business without it. By 2024, Atlas has incorporated thousands of companies, including several unicorns. The service is widely cited as one of the most-impactful products for international internet entrepreneurship.","pullquote":"We''ve seen many promising entrepreneurs around the world who can''t easily start a global business because of the complications of incorporating in the United States. Atlas is for them.","pullquote_attribution":"Patrick Collison, Stripe cofounder/CEO — Atlas launch announcement, February 2016","outcomes":[{"stat":"$500","label":"flat setup fee — at-cost / near-break-even for Stripe","accent":true},{"stat":"Bundled","label":"Delaware C-corp + SVB bank account + Stripe + $5K AWS + free processing"},{"stat":"50+ countries","label":"served in first year by Atlas"},{"stat":"Invite-only","label":"at launch — managed quality and operational load"},{"stat":"Several unicorns","label":"have been incorporated through Atlas (Bench, Lambda School, others)"}],"tradeoffs":[{"title":"Bundle vs. just incorporation","body":"Bundling four products (incorporation, bank, payments, credits) made Atlas genuinely useful to a founder who''d otherwise have to navigate 4 separate processes across 4 different vendors. The complexity of building those partnerships was real (especially the SVB partnership) but the bundled experience created a single ''I want to start a US company'' product."},{"title":"$500 break-even pricing vs. higher service pricing","body":"Atlas isn''t a profit center for Stripe — it''s at-cost / near-break-even. The pricing is structurally a strategic investment: Stripe wins when more international entrepreneurs can start US companies that eventually process payments through Stripe. The $500 is the cost of acquiring a new Stripe customer who couldn''t otherwise exist."},{"title":"Invite-only vs. open","body":"Launching invite-only let Stripe limit operational load while measuring genuine demand. Going open at launch would have produced higher volume but possibly worse early-customer experience. Stripe chose quality-control upfront and gradually expanded access."},{"title":"Stripe brand vs. standalone Atlas brand","body":"Atlas is branded ''Stripe Atlas'' rather than just ''Atlas'' — extends Stripe''s brand into adjacent territory (legal, banking) without creating a separate brand to maintain. The cost: Atlas''s reputation is tied to Stripe''s, which complicates B2B sales motions where Stripe might not want banking-product exposure. Stripe chose brand integration because Atlas customers eventually become payment customers."}],"per_dimension_truth":{"tradeoff":"Strategic platform expansion (Stripe enters incorporation + banking) + at-cost pricing as customer-acquisition mechanism vs. focused payments-only product + narrower scope. Stripe chose to extend the platform — and Atlas has paid for itself many times over in subsequent payment volume from Atlas-incorporated companies.","user":"Atlas''s user is the international entrepreneur who can build globally-valuable software but can''t navigate US legal / banking infrastructure. That user wouldn''t otherwise have started a US business; Stripe absorbed the cost of solving the entry problem because the result is more payment-volume customers.","alt":"Just offering Stripe accounts to international businesses (without the incorporation / banking bundle) would have been simpler. The opposite trade. But it would have left the most-valuable customers (founders building US-targeted SaaS / e-commerce from abroad) stuck on the prior infrastructure problem.","predict":"Strong early demand (waitlist fills quickly). Operational complexity increases as international entrepreneurs from emerging markets adopt Atlas. SVB partnership becomes the cornerstone (and later, after SVB''s 2023 collapse, Atlas pivots to other bank partners). Several Atlas-incorporated companies become significant Stripe customers within 2-3 years. Long-term: Atlas is the canonical case in ''platform companies investing in their customers'' pre-existence problems'' — and the pattern is widely imitated (Vercel for hosting, Mercury for banking, etc.)."},"quote_type":"verbatim","sources":[{"title":"Introducing Stripe Atlas","url":"https://stripe.com/blog/atlas","publisher":"Stripe Blog","year":2016,"type":"blog"},{"title":"Stripe Atlas helps any founder start a U.S. business","url":"https://techcrunch.com/2016/02/23/stripe-atlas-helps-any-founder-start-a-u-s-business/","publisher":"TechCrunch","year":2016,"type":"article"},{"title":"Stripe Atlas — Wikipedia","url":"https://en.wikipedia.org/wiki/Stripe_(company)#Stripe_Atlas","type":"article"}],"tags":{"industry":"fintech","region":"us","decade":"2010s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'substack-pro-program-2021',
  'weekly',
  '{"id":"substack-pro-program-2021","type":"weekly","iso_week":"","company":"Substack","era":"March 2021 — Substack Pro program","intro":"It is early 2021. You are at Substack. The platform has been growing rapidly through the COVID period — writers leaving traditional newsrooms (Buzzfeed, Vox, NYT, etc.) to start independent paid newsletters have driven a wave of high-profile launches. Substack''s standard 10% take-rate model has been working, but the company is debating a more aggressive growth strategy: pay top writers upfront (5- and 6-figure advances) in exchange for a higher first-year revenue share, to lure specific high-value writers from competitors.\n\nThe program is called ''Substack Pro.'' Substack identifies ~30 high-profile writers, offers each a customized 1-year deal — typically a six-figure advance against the writer''s first-year Substack revenue, with Substack taking 85% of revenue in year 1 (vs. the standard 10%), then dropping back to 10% thereafter. The bet: pay these writers to launch on Substack, accept short-term losses, and the high-profile writers will lift the platform''s broader reputation, driving network effects.","open_questions":["Run a ''paid upfront'' program (signals platform commitment to writers, looks like traditional media advances) vs. stay on the 10% model (cleaner, harder to scale to high-profile writers)?","How transparent to be about who''s in Substack Pro — list publicly (transparency, but invites criticism) or quietly fund (cleaner but creates appearance of secret deal-making)?","What''s the right writer mix — politically diverse (signals editorial neutrality but invites controversy) vs. specifically a ''who we think is good'' selection (signals editorial values but compromises platform neutrality)?","If a Pro writer publishes controversial content that hurts the platform''s brand, what''s the exit clause?"],"closing":"Imagine you''re at Substack in early 2021. The Pro program is months from public knowledge. ~30 writers are being signed. The transparency question is unresolved.","decision":"Launch Substack Pro quietly — writers sign and announce on a rolling basis through 2021. Pro deals are 1-year exclusive commitments with Substack taking 85% of revenue in year 1, dropping to 10% in year 2 and beyond. By mid-2021, several Pro writers turn out to be controversial figures (Glenn Greenwald, Matt Yglesias, Andrew Sullivan, others). Substack publicly defends the ''platform neutrality'' framing — anyone can use Substack, the writer chooses what to write. In late 2021, criticism mounts (one Pro writer, Graham Linehan, is reported to have made transphobic comments; activist writers demand Substack remove him). Substack stays neutral. Substack publishes a defense-of-platform-neutrality blog post in December 2021 (''Substack''s view of content moderation''). By 2022 the Pro program is wound down — the operational complexity and brand risk weren''t worth the writer wins. Most Pro writers stay on Substack regardless.","pullquote":"We''re a platform that promotes editorial freedom — and so we don''t make publishing decisions based on writers'' political views or their tone. We let writers run their own publications.","pullquote_attribution":"Substack — ''Substack''s view of content moderation'' blog post, December 2021","outcomes":[{"stat":"~30 writers","label":"in the Substack Pro program (6-figure advances each)","accent":true},{"stat":"85% / 10%","label":"first-year / subsequent-year revenue share for Pro writers"},{"stat":"1-year","label":"exclusivity deals"},{"stat":"Brand controversy","label":"Pro program drew criticism for funding controversial writers"},{"stat":"Wound down by 2022","label":"operational complexity + brand risk outweighed writer-acquisition value"}],"tradeoffs":[{"title":"Aggressive paid acquisition vs. organic platform growth","body":"Paying high-profile writers upfront accelerated Substack''s reputation as the platform-for-serious-writers. The cost: financial risk on writers who might not earn back their advances; reputational risk if a Pro writer published controversial content; precedent that Substack is willing to pay for writers, which changed every subsequent recruiting conversation."},{"title":"Quiet vs. publicly listed Pro writers","body":"Substack chose to keep Pro deals private (writers announced individually). The trade: transparency would have invited consistent scrutiny but defused conspiracy theories about secret deals. Privacy preserved the ''just a writer on Substack'' framing but allowed the program to be characterized as Substack ''funding controversial writers'' once details leaked."},{"title":"Platform neutrality vs. editorial curation","body":"Substack publicly committed to platform neutrality — anyone can write what they want, Substack doesn''t moderate viewpoints. The trade: avoid the ''editorial responsibility'' trap (Twitter, Facebook are stuck in it), but invite the ''why did you pay Glenn Greenwald specifically'' critique. The neutrality framing was internally consistent but politically difficult."},{"title":"Continue Pro program vs. wind down","body":"By 2022, Substack quietly wound the Pro program down — too operationally complex, too much brand controversy, marginal writer acquisition benefit. The wind-down was an admission that the upfront-advance model was worse than the 10% organic model for Substack''s specific business shape. Most Pro writers stayed on the platform afterward without ongoing Pro support."}],"per_dimension_truth":{"tradeoff":"Accelerated platform reputation via direct writer-acquisition vs. financial risk + reputational complexity. Substack ran the experiment, found that the cost of running an advances-program (operations + brand) was higher than the value of paid-acquisition vs. organic growth, and wound it down. The Pro writers compounded the platform regardless, but the explicit-payment model didn''t.","user":"Pro writers were the user being recruited; Substack readers were the user the program was supposed to benefit. The program treated writers as the customer (who could be paid for their attention) — same logic Hollywood studios use with talent advances. The risk was that Substack ended up looking less like a neutral platform and more like a media company with an editorial roster.","alt":"Sticking with the 10% organic model + lighter ad-hoc incentives (free Substack premium features, free design help, marketing co-investment) would have been less complex and lower brand risk. The opposite trade — and effectively the path Substack returned to after winding down Pro.","predict":"Initial press attention to Pro program. Writer-by-writer announcements through 2021. Brand controversies (Greenwald, Linehan, others) emerge mid-year. Substack defends platform neutrality publicly. By late 2021 Pro is quietly de-emphasized. By 2022 the program is wound down. Most Pro writers stay on Substack. Long-term: the Substack Pro experiment is the canonical case in ''when an upfront-incentive program in a marketplace product turns out to add more brand risk than it creates platform value.''"},"quote_type":"verbatim","sources":[{"title":"Substack Pro: An Experiment in Helping Writers","url":"https://on.substack.com/p/why-we-pay-writers","publisher":"Substack","year":2021,"type":"blog"},{"title":"Substack defends paying writers it likes","url":"https://www.platformer.news/substack-pro/","publisher":"Platformer","year":2021,"type":"blog"},{"title":"Substack''s view of content moderation","url":"https://on.substack.com/p/substacks-view-of-content-moderation","publisher":"Substack","year":2021,"type":"blog"}],"tags":{"industry":"media","region":"us","decade":"2020s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;
